INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-1', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Derivative Contract', 'Financial Instruments', 'A Derivative Contract is a sophisticated financial instrument commonly used in financial services for hedging, speculation, and arbitrage strategies. Its value is contingent on the price movement of an underlying asset such as stocks, bonds, commodities, interest rates, or market indices. Financial institutions employ derivatives in portfolio risk management, to enhance returns or to transfer specific financial exposures. Derivative contracts can take several forms, including options, futures, swaps, and forwards, each with unique risk and regulatory profiles. Implementation and life cycle management of these contracts require precise tracking of underlying asset performance, contract parameters, and market conditions.', E'"[{\\"name\\":\\"notionalAmount\\",\\"type\\":\\"decimal\\",\\"description\\":\\"The face value of the contract\\"},{\\"name\\":\\"underlyingAsset\\",\\"type\\":\\"string\\",\\"description\\":\\"Reference to the underlying asset\\"},{\\"name\\":\\"maturityDate\\",\\"type\\":\\"date\\",\\"description\\":\\"Contract expiration date\\"},{\\"name\\":\\"contractType\\",\\"type\\":\\"enum\\",\\"description\\":\\"Option, future, swap, or forward\\"}]"'::jsonb, E'"[{\\"type\\":\\"parent\\",\\"targetId\\":\\"fibo-2\\",\\"label\\":\\"Is a type of Financial Instrument\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"fibo-8\\",\\"label\\":\\"Subject to Market Risk\\"},{\\"type\\":\\"depends_on\\",\\"targetId\\":\\"fibo-10\\",\\"label\\":\\"Requires Trade Settlement\\"}]"'::jsonb, 'derivatives,trading,risk'::text[], 'Agents use derivative contract data for automated pricing, risk calculation, and compliance checks in capital markets workflows.', '2026-02-12 05:17:41.25327', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-2', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Financial Instrument', 'Financial Instruments', 'A Financial Instrument is a fundamental concept within financial services, referring to any contract or asset that can be traded and represents an enforceable claim or obligation with a monetary value. This category includes various products such as bonds, stocks, derivatives, and structured products. Financial instruments are central to capital markets, facilitating liquidity, investment, and risk management for institutional and individual investors alike. Accurate identification (via ISIN, CUSIP) and understanding of their attributes, such as currency denomination and issuing entity, are vital for transaction processing and regulatory reporting. In AI-driven environments, the management and analysis of financial instruments underpin a wide range of operational, analytical, and compliance-oriented activities.', E'"[{\\"name\\":\\"instrumentId\\",\\"type\\":\\"string\\",\\"description\\":\\"Unique identifier (ISIN, CUSIP)\\"},{\\"name\\":\\"currency\\",\\"type\\":\\"string\\",\\"description\\":\\"Denomination currency\\"},{\\"name\\":\\"issuer\\",\\"type\\":\\"string\\",\\"description\\":\\"Issuing entity\\"}]"'::jsonb, E'"[{\\"type\\":\\"child\\",\\"targetId\\":\\"fibo-1\\",\\"label\\":\\"Includes Derivatives\\"},{\\"type\\":\\"child\\",\\"targetId\\":\\"fibo-3\\",\\"label\\":\\"Includes Equities\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"fibo-9\\",\\"label\\":\\"Priced by Market Data\\"}]"'::jsonb, 'securities,trading,assets'::text[], 'Core entity for agent-driven portfolio management, trade execution, and regulatory reporting.', '2026-02-12 05:17:41.288746', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-3', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Equity Security', 'Financial Instruments', 'An Equity Security is a tradable financial instrument that signifies legal ownership in a corporation, typically represented by shares of common or preferred stock. Owners of equity securities are entitled to a proportionate claim on the company’s profits, usually through dividends, and may have voting rights in corporate governance. In financial services operations, equity securities are fundamental instruments for raising capital, conducting market transactions, and supporting portfolio management and trading strategies. These instruments are subject to price fluctuations driven by market forces and corporate actions. Accurate tracking and representation of equity securities are essential for portfolio valuation, trade settlement, and compliance monitoring.', '[{"name": "ticker", "type": "string", "description": "Stock ticker symbol"}, {"name": "exchange", "type": "string", "description": "Primary listing exchange"}, {"name": "sharesOutstanding", "type": "integer", "description": "Total shares issued"}, {"name": "isinCode", "type": "string", "description": "International Securities Identification Number for unique global identification."}, {"name": "securityType", "type": "enum", "description": "Classification of the equity security (e.g., Common Stock, Preferred Stock, Depository Receipt)."}, {"name": "dividendYield", "type": "decimal", "description": "Most recent annualized dividend as a percentage of share price."}, {"name": "listingDate", "type": "date", "description": "The date the equity security was first listed for trading."}]'::jsonb, '[{"type": "parent", "label": "Is a Financial Instrument", "targetId": "fibo-2"}, {"type": "related", "label": "Has Market Data", "targetId": "fibo-9"}]'::jsonb, 'equities,stocks,shares,ownership,equity-capital,listed-security,security-identifier,instrument-lifecycle'::text[], 'Agents process equity data for automated trading signals, portfolio rebalancing, and corporate action processing.', '2026-02-12 05:17:41.301624', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-4', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Fixed Income Security', 'Financial Instruments', 'A Fixed Income Security is a financial instrument representing a loan made by an investor to a borrower, typically corporate or governmental. The issuer promises to pay fixed interest (coupon) at regular intervals and repay the face value at a specified maturity date. In financial services operations, these instruments are crucial for risk management, diversification, and predictable income streams. Operationally, managing fixed income securities involves monitoring interest rate exposure, maturity profiles, and issuer creditworthiness. Their lifecycle—from issuance to settlement and redemption—requires precise data handling and regulatory reporting.', '[{"name": "couponRate", "type": "decimal", "description": "Annual interest rate"}, {"name": "yieldToMaturity", "type": "decimal", "description": "Expected rate of return"}, {"name": "creditRating", "type": "string", "description": "Rating agency assessment"}, {"name": "maturityDate", "type": "date", "description": "Scheduled maturity date for principal repayment"}, {"name": "issuePrice", "type": "decimal", "description": "Price at which the security was originally issued"}, {"name": "faceValue", "type": "decimal", "description": "Nominal amount to be repaid at maturity"}, {"name": "paymentFrequency", "type": "enum", "description": "Frequency of coupon payments (e.g., annual, semi-annual, quarterly)"}]'::jsonb, '[{"type": "parent", "label": "Is a Financial Instrument", "targetId": "fibo-2"}, {"type": "related", "label": "Subject to Credit Risk", "targetId": "fibo-8"}, {"type": "related", "label": "Requires Reference to Real-time Market Prices", "targetId": "fibo-9"}]'::jsonb, 'bonds,debt,fixed-income,structured-products,investment-grade,sovereign-debt,market-risk'::text[], 'Agents analyze fixed income securities for yield optimization, credit risk assessment, and duration management.', '2026-02-12 05:17:41.30515', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-5', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Counterparty', 'Parties & Roles', 'A counterparty represents the other participant in a financial transaction, such as in trading, lending, or derivatives contracts. Identifying and evaluating counterparties is a critical component of financial operations, as the creditworthiness and regulatory status of each counterparty directly influence transaction risk and compliance obligations. Financial institutions must maintain up-to-date records of all their counterparties, track exposure levels, and respond dynamically to changes in counterparties'' financial health or legal status. Counterparty data is central to processes including onboarding, risk assessment, settlement, and regulatory reporting. Effective AI-driven operations rely on high-quality counterparty information to enable real-time risk analytics, automate compliance checks, and optimize operational efficiency.', '[{"name": "legalEntityId", "type": "string", "description": "LEI identifier"}, {"name": "jurisdiction", "type": "string", "description": "Legal jurisdiction"}, {"name": "creditScore", "type": "integer", "description": "Internal credit rating"}, {"name": "onboardingDate", "type": "date", "description": "The date when the counterparty was onboarded."}, {"name": "sanctionsStatus", "type": "enum", "description": "Indicates if the counterparty is on any sanction lists (e.g., ''None'', ''OFAC'', ''EU'')."}, {"name": "ultimateParentEntity", "type": "string", "description": "Legal entity identifier of the counterparty''s ultimate parent."}, {"name": "sector", "type": "string", "description": "Industry sector classification for the counterparty."}]'::jsonb, '[{"type": "related", "label": "Requires KYC Verification", "targetId": "fibo-6"}, {"type": "related", "label": "Assessed for Credit Risk", "targetId": "fibo-8"}, {"type": "related", "label": "Must be screened against regulatory sanctions lists", "targetId": "fibo-27"}]'::jsonb, 'counterparty,entity,credit,kyc,aml,sanctions,onboarding,relationship-hierarchy'::text[], 'Agents perform automated counterparty due diligence, credit limit monitoring, and exposure calculations.', '2026-02-12 05:17:41.308884', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "confidential", "dataTypes": ["legalEntityId", "jurisdiction", "creditScore"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-6', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'KYC Verification', 'Risk & Compliance', 'KYC Verification is a foundational process in financial services, essential for verifying a customer''s or counterparty''s identity and evaluating their risk profile before establishing or maintaining a business relationship. This process involves collecting, validating, and monitoring client-provided information to prevent financial crimes such as money laundering, terrorist financing, and fraud. Efficient and thorough KYC Verification is crucial for onboarding new clients, updating customer profiles, and ensuring compliance throughout the customer lifecycle. In a dynamic regulatory landscape, continuous monitoring and periodic reviews underpin effective risk management and foster trust with regulators. AI agents can automate the labor-intensive aspects of KYC, improve accuracy, and respond rapidly to regulatory changes.', '[{"name": "verificationLevel", "type": "enum", "description": "Basic, enhanced, or simplified due diligence"}, {"name": "riskCategory", "type": "string", "description": "Client risk classification"}, {"name": "lastReviewDate", "type": "date", "description": "Most recent review date"}, {"name": "verificationMethod", "type": "enum", "description": "The method used for verification, such as biometric, document-based, or data-based."}, {"name": "sourceOfFunds", "type": "string", "description": "Declared or verified source of customer''s funds."}, {"name": "adverseMediaCheck", "type": "boolean", "description": "Indicates if adverse media screening was performed."}, {"name": "nextReviewDue", "type": "date", "description": "Scheduled date for the next KYC review."}]'::jsonb, '[{"type": "related", "label": "Verifies Counterparty", "targetId": "fibo-5"}, {"type": "related", "label": "Part of AML Screening", "targetId": "fibo-7"}, {"type": "depends_on", "label": "Required by Regulatory Framework", "targetId": "fibo-15"}, {"type": "related", "label": "Integral to the customer onboarding process", "targetId": "fibo-25"}]'::jsonb, 'kyc,compliance,identity,risk-assessment,customer-onboarding,anti-fraud,identity-proofing'::text[], 'Agents automate KYC document collection, identity verification, risk scoring, and periodic review scheduling.', '2026-02-12 05:17:41.312488', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "confidential", "dataTypes": ["verificationLevel", "riskCategory", "identityDocuments"], "retentionDays": 1825, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-7', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'AML Screening', 'Risk & Compliance', 'AML (Anti-Money Laundering) Screening is a critical compliance process used by financial institutions to proactively identify clients and transactions that may be associated with money laundering, terrorist financing, or sanctions breaches. The process includes matching customers, counterparties, and transactions against lists of sanctioned entities, politically exposed persons (PEPs), and monitoring for suspicious patterns in transactional activity. AML screening is a continuous lifecycle activity that operates across onboarding, periodic reviews, and real-time transaction processing stages. Effective AML screening ensures both adherence to regulatory mandates and minimization of reputational and financial risks from illicit finance. As financial services digitize, AI agents are increasingly deployed to automate, augment, and optimize these complex screening activities.', '[{"name": "screeningType", "type": "enum", "description": "Transaction monitoring, name screening, or PEP check"}, {"name": "alertThreshold", "type": "decimal", "description": "Threshold for triggering alerts"}, {"name": "sanctionsLists", "type": "string[]", "description": "Reference sanctions databases"}, {"name": "screeningFrequency", "type": "enum", "description": "How often the screening is applied (e.g., real-time, daily batch, onboarding only)."}, {"name": "caseReviewDuration", "type": "decimal", "description": "Average time (in hours or days) to resolve a flagged alert."}, {"name": "matchConfidenceScore", "type": "decimal", "description": "AI-determined probability score for name/entity matches during screening."}]'::jsonb, '[{"type": "related", "label": "Complements KYC", "targetId": "fibo-6"}, {"type": "depends_on", "label": "Mandated by Regulations", "targetId": "fibo-15"}, {"type": "related", "label": "Monitors Payments", "targetId": "fibo-12"}]'::jsonb, 'aml,sanctions,compliance,screening,customer-monitoring,fraud-detection,kyc,regtech'::text[], 'Agents perform real-time transaction screening, sanctions list matching, and suspicious activity report generation.', '2026-02-12 05:17:41.315994', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "restricted", "dataTypes": ["screeningType", "alertThreshold", "sanctionsLists", "suspiciousActivity"], "retentionDays": 1825, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-8', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Credit Risk Assessment', 'Risk & Compliance', 'Credit Risk Assessment is a foundational process in financial services, focusing on determining the probability that a borrower or counterparty will fail to meet their financial obligations. This process involves quantitative and qualitative analysis, integrating metrics such as Probability of Default, Loss Given Default, and Exposure at Default. Such assessments are fundamental to loan origination, derivative transactions, and daily risk monitoring across the organization. AI agents use advanced analytics to refine risk modeling, automate credit scoring, and enable rapid response to emerging risks. Robust Credit Risk Assessment supports informed capital allocation, pricing, and regulatory reporting requirements.', '[{"name": "probabilityOfDefault", "type": "decimal", "description": "Estimated default probability"}, {"name": "lossGivenDefault", "type": "decimal", "description": "Expected loss if default occurs"}, {"name": "exposureAtDefault", "type": "decimal", "description": "Total exposure amount at default"}, {"name": "creditAssessmentDate", "type": "date", "description": "The date on which the credit risk assessment was performed"}, {"name": "assessmentMethodology", "type": "string", "description": "Description or name of the methodology or model used for assessment"}, {"name": "creditGrade", "type": "string", "description": "Assigned risk grade or rating resulting from the assessment"}, {"name": "reviewFrequency", "type": "enum", "description": "Defined frequency for re-assessment (e.g., monthly, quarterly, annually)"}]'::jsonb, '[{"type": "related", "label": "Assesses Counterparty", "targetId": "fibo-5"}, {"type": "related", "label": "Evaluates Fixed Income", "targetId": "fibo-4"}, {"type": "related", "label": "Evaluates Derivatives", "targetId": "fibo-1"}, {"type": "related", "label": "Considers collateral in mitigating or pricing credit risk", "targetId": "fibo-20"}]'::jsonb, 'credit-risk,risk-management,default,regulatory-compliance,stress-testing,loan-origination,credit-scoring'::text[], 'Agents calculate real-time credit risk metrics, trigger limit breach alerts, and generate risk reports for portfolio managers.', '2026-02-12 05:17:41.319517', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "confidential", "dataTypes": ["probabilityOfDefault", "lossGivenDefault", "exposureAtDefault"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-9', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Market Data Feed', 'Market Data', 'A Market Data Feed provides critical streaming or batch information about financial instruments, including price, volume, and reference data, to support trading, risk management, and regulatory compliance functions in financial services. These feeds ensure timely access to accurate data required for decision-making, algorithmic trading, and financial instrument valuation. Market Data Feeds can originate from exchanges, data vendors, or internal sources, and may include real-time or delayed information depending on licensing and use case requirements. Dependence on high-quality, low-latency data feeds is vital for front, middle, and back-office operations, particularly in highly automated environments. Effective management and integration of Market Data Feeds underpin system reliability, compliance with reporting mandates, and the integrity of downstream analytics.', '[{"name": "dataSource", "type": "string", "description": "Provider (Bloomberg, Reuters, etc.)"}, {"name": "updateFrequency", "type": "string", "description": "Tick, second, minute, or end-of-day"}, {"name": "dataQuality", "type": "enum", "description": "Validated, indicative, or firm"}, {"name": "latencyMilliseconds", "type": "integer", "description": "Measured delay between source and system receipt of data, in milliseconds."}, {"name": "coverageUniverse", "type": "string", "description": "Description of instruments and markets included in the data feed."}, {"name": "licensedUse", "type": "enum", "description": "Permitted usage types (internal, redistribution, display-only, etc.)."}]'::jsonb, '[{"type": "related", "label": "Prices Financial Instruments", "targetId": "fibo-2"}, {"type": "related", "label": "Used in Portfolio Valuation", "targetId": "fibo-11"}]'::jsonb, 'market-data,pricing,real-time,data-feed-management,market-surveillance,reference-data-integration,latency-sensitive,compliance-data'::text[], 'Agents consume market data feeds for automated pricing, valuation, and signal generation across asset classes.', '2026-02-12 05:17:41.323227', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-10', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Trade Settlement', 'Payment Systems', 'Trade Settlement refers to the critical post-trade process in financial services where securities and corresponding cash are exchanged between counterparties in accordance with trade agreements. This process ensures that both parties receive what was contractually agreed upon, finalizing and closing out trade obligations. Efficient settlement is vital for market integrity, liquidity, and reducing systemic risk, especially in periods of high transaction volumes. The process can involve multiple intermediaries such as clearing houses and central securities depositories (CSDs), and it varies by asset class and geography. Failures or delays in settlement can have significant financial and reputational consequences for participating institutions.', '[{"name": "settlementCycle", "type": "string", "description": "T+1, T+2, or T+0"}, {"name": "settlementMethod", "type": "enum", "description": "DVP, FOP, or cash settlement"}, {"name": "clearingHouse", "type": "string", "description": "Central counterparty or CSD"}, {"name": "settlementStatus", "type": "enum", "description": "Current status of the settlement (e.g. pending, completed, failed, in dispute)."}, {"name": "actualSettlementDate", "type": "date", "description": "Date on which the settlement was successfully completed."}, {"name": "settlementAmount", "type": "decimal", "description": "Monetary value being transferred during the settlement."}, {"name": "participantIdentifiers", "type": "string", "description": "Unique identifiers for parties involved in the settlement."}]'::jsonb, '[{"type": "related", "label": "Settles Derivatives", "targetId": "fibo-1"}, {"type": "related", "label": "Settles Equities", "targetId": "fibo-3"}, {"type": "depends_on", "label": "Triggers Payment", "targetId": "fibo-12"}]'::jsonb, 'settlement,clearing,post-trade,risk-management,asset-servicing,transaction-processing,payment-infrastructure,compliance-operations'::text[], 'Agents automate settlement instruction matching, fail management, and reconciliation across custodians.', '2026-02-12 05:17:41.326341', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-11', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Portfolio Valuation', 'Market Data', 'Portfolio Valuation is a core financial operation involving the computation of the aggregate market value for all holdings within a specific investment portfolio, typically at a set valuation point. It incorporates the use of real-time or periodic market data to determine the value of each financial instrument, such as equities, bonds, derivatives, or alternative assets. This process forms the basis for net asset value (NAV) calculation, investor reporting, performance analysis, and risk assessment. Portfolio Valuation also underpins asset allocation decisions and investment mandate compliance. Given its financial and operational significance, accuracy and auditability of the valuation process are critical in supporting transparency and investor trust.', '[{"name": "valuationMethod", "type": "enum", "description": "Mark-to-market, mark-to-model, or fair value"}, {"name": "baseCurrency", "type": "string", "description": "Portfolio reporting currency"}, {"name": "navFrequency", "type": "string", "description": "Daily, weekly, or monthly"}, {"name": "valuationTimestamp", "type": "date", "description": "Exact date and time when the portfolio valuation was performed."}, {"name": "valuationStatus", "type": "enum", "description": "Indicates if the valuation is provisional, finalized, or under review."}, {"name": "priceSource", "type": "string", "description": "Primary data source(s) for security pricing (e.g., exchange, pricing vendor)."}]'::jsonb, '[{"type": "depends_on", "label": "Uses Market Data", "targetId": "fibo-9"}, {"type": "related", "label": "Values Instruments", "targetId": "fibo-2"}, {"type": "related", "label": "Reports to Regulators", "targetId": "fibo-14"}]'::jsonb, 'valuation,portfolio,nav,pricing,asset-management,fund-administration,transparency'::text[], 'Agents perform automated portfolio valuation, NAV calculation, and P&L attribution for fund managers.', '2026-02-12 05:17:41.329691', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-12', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Payment Instruction', 'Payment Systems', 'A Payment Instruction is a formal directive issued to a financial institution or payment service provider to execute the transfer of funds from a payer''s account to a beneficiary''s account. In financial operations, such instructions enable the execution of both domestic and international payments across various payment rails such as wire transfers, ACH, SEPA, and SWIFT networks. The lifecycle of a payment instruction includes initiation, validation, compliance checks, execution, and confirmation of settlement. AI agents can facilitate real-time monitoring and enrichment of these instructions, ensuring high STP (straight-through processing) rates and timely regulatory checks at each stage. Payment Instructions are foundational to liquidity management, cash positioning, reconciliation, and risk monitoring in modern financial services.', '[{"name": "paymentType", "type": "enum", "description": "Wire, ACH, SEPA, or SWIFT"}, {"name": "amount", "type": "decimal", "description": "Payment amount"}, {"name": "beneficiary", "type": "string", "description": "Recipient account details"}, {"name": "executionDate", "type": "date", "description": "Scheduled date for processing the payment instruction."}, {"name": "currency", "type": "string", "description": "Currency in which the payment amount is denominated."}, {"name": "instructionStatus", "type": "enum", "description": "Current status of the payment instruction (e.g., pending, executed, rejected)."}, {"name": "originator", "type": "string", "description": "Account details of the party initiating the payment."}]'::jsonb, '[{"type": "related", "label": "Triggered by Settlement", "targetId": "fibo-10"}, {"type": "related", "label": "Screened for AML", "targetId": "fibo-7"}]'::jsonb, 'payments,transfers,swift,cross-border,settlement,aml-compliance,iso20022'::text[], 'Agents process payment instructions, validate routing, perform sanctions screening, and handle exception management.', '2026-02-12 05:17:41.332967', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "pci", "dataTypes": ["paymentType", "amount", "beneficiary", "accountNumber", "routingNumber"], "retentionDays": 365, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-13', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Customer Account', 'Parties & Roles', 'A Customer Account in the context of financial services is a foundational data structure that records all monetary inflows, outflows, and ongoing balances for an individual or institutional client at a financial institution. It encompasses various types including checking, savings, investment, and margin accounts, each tailored to specific client needs and regulatory obligations. The account serves as the nucleus for tracking transactional activities, initiating payments, providing statements, and assessing customer risk and financial position. Maintaining accurate and up-to-date customer account data is critical for both day-to-day operations and client lifecycle management. In addition, these accounts represent a primary touchpoint for compliance, reporting, and customer relationship management.', '[{"name": "accountType", "type": "enum", "description": "Current, savings, investment, or margin"}, {"name": "accountStatus", "type": "string", "description": "Active, dormant, or closed"}, {"name": "balance", "type": "decimal", "description": "Current account balance"}, {"name": "dateOpened", "type": "date", "description": "The date when the customer account was opened."}, {"name": "currency", "type": "string", "description": "The currency in which the account is denominated."}, {"name": "accountHolderName", "type": "string", "description": "Legal name of the account’s primary holder."}, {"name": "lastActivityDate", "type": "date", "description": "The date of the most recent transaction or account activity."}]'::jsonb, '[{"type": "related", "label": "Belongs to Counterparty", "targetId": "fibo-5"}, {"type": "related", "label": "Subject to KYC", "targetId": "fibo-6"}]'::jsonb, 'accounts,banking,client,aml,onboarding,risk-assessment,compliance'::text[], 'Agents manage account lifecycle events, balance monitoring, dormancy detection, and cross-sell opportunity identification.', '2026-02-12 05:17:41.336081', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "pci", "dataTypes": ["accountType", "balance", "accountNumber"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-14', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Regulatory Report', 'Regulatory', 'A Regulatory Report is a formal, obligatory document or digital submission provided by financial institutions to supervisory authorities, covering aspects such as transaction activity, risk exposures, capital adequacy, or compliance breaches. These reports are granular, jurisdiction-specific, and vital for ensuring transparency and market integrity, often adhering to strict formatting and timeliness requirements. In financial services operations, Regulatory Reports underpin both routine supervisory monitoring and targeted investigations, forming the backbone of systemic risk oversight and enforcement actions. Accuracy, auditability, and traceability are paramount; erroneous or late submissions can incur significant penalties. Financial institutions must ensure end-to-end automation and validation of report content, from data sourcing to final submission.', '[{"name": "reportType", "type": "string", "description": "EMIR, MiFIR, CFTC, or internal"}, {"name": "submissionDeadline", "type": "string", "description": "Filing deadline"}, {"name": "regulatoryBody", "type": "string", "description": "Target regulator"}, {"name": "reportVersion", "type": "string", "description": "The schema or template version used for this regulatory report."}, {"name": "submissionStatus", "type": "enum", "description": "Current status of the report (e.g., pending, submitted, acknowledged, rejected)."}, {"name": "reportingPeriod", "type": "string", "description": "The time frame covered by the report (e.g., Q1 2024, 2023-07-01 to 2023-09-30)."}, {"name": "sourceSystem", "type": "string", "description": "Originating business system(s) from which report data was sourced."}]'::jsonb, '[{"type": "depends_on", "label": "Uses Valuation Data", "targetId": "fibo-11"}, {"type": "depends_on", "label": "Governed by Framework", "targetId": "fibo-15"}]'::jsonb, 'regulatory,reporting,compliance,regtech,data-quality,risk-management,auditability,deadline-tracking'::text[], 'Agents generate and validate regulatory reports, check data completeness, and manage submission workflows.', '2026-02-12 05:17:41.339355', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-15', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Regulatory Framework', 'Regulatory', 'A Regulatory Framework sets the boundaries and requirements for all financial services operations, ensuring that institutions act in a manner that is consistent with the regulatory goals of their jurisdiction. It covers laws, regulations, and guidelines, such as capital adequacy, market conduct, and customer protection rules, and drives the structure and process of compliance within organizations. In practical operations, the regulatory framework influences everything from onboarding clients and managing trades to reporting suspicious transactions and capital holdings. It is also the foundation upon which compliance processes, audits, and internal controls are built and regularly reviewed to mitigate legal and reputational risk. AI agents operating in financial services must be consistently aware of, and adapt to, dynamic regulatory frameworks to avoid infractions and ensure transparency.', '[{"name": "frameworkName", "type": "string", "description": "MiFID II, Basel III, Dodd-Frank, etc."}, {"name": "jurisdiction", "type": "string", "description": "Applicable jurisdiction"}, {"name": "effectiveDate", "type": "date", "description": "Date framework became effective"}, {"name": "frameworkVersion", "type": "string", "description": "The specific version or release of the regulatory framework."}, {"name": "supervisoryAuthority", "type": "string", "description": "The main regulatory body responsible for the framework''s oversight and enforcement."}, {"name": "complianceDeadline", "type": "date", "description": "The date by which regulated institutions must achieve compliance with the framework."}, {"name": "coverageScope", "type": "string", "description": "A short description of which financial activities and instruments are covered by the framework."}]'::jsonb, '[{"type": "child", "label": "Mandates KYC", "targetId": "fibo-6"}, {"type": "child", "label": "Mandates AML", "targetId": "fibo-7"}, {"type": "child", "label": "Requires Reports", "targetId": "fibo-14"}]'::jsonb, 'regulation,framework,law,compliance,supervision,governance,policymaking'::text[], 'Agents reference regulatory frameworks for automated compliance checking, policy enforcement, and change impact analysis.', '2026-02-12 05:17:41.342239', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-16', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Trade Order', 'Financial Instruments', 'A Trade Order represents an actionable instruction originating from a market participant to buy or sell a specific financial instrument under defined conditions, such as price limits or order duration. Within financial services operations, trade orders are central to trade lifecycle management, serving as the genesis for execution workflows and downstream processes like settlement and clearing. The accurate capture, classification, and processing of trade orders are crucial for optimal trading performance, auditability, and risk management. Modern electronic trading environments require real-time validation and routing of trade orders, integrating with various trading venues and compliance systems. Automated handling and enrichment of trade orders enable enhanced efficiency, reduced operational risk, and improved client service in highly regulated markets.', '[{"name": "orderType", "type": "enum", "description": "Market, limit, stop, or conditional"}, {"name": "side", "type": "enum", "description": "Buy or sell"}, {"name": "quantity", "type": "decimal", "description": "Number of units"}, {"name": "orderStatus", "type": "enum", "description": "Current lifecycle state such as ''Pending'', ''Executed'', ''Cancelled'', or ''Rejected''."}, {"name": "timeInForce", "type": "string", "description": "Specifies how long the order remains active before it is executed or expires."}, {"name": "clientIdentifier", "type": "string", "description": "Unique identifier for the client or account placing the order."}, {"name": "timestamp", "type": "date", "description": "Date and time when the order was received or created."}]'::jsonb, '[{"type": "related", "label": "References Instrument", "targetId": "fibo-2"}, {"type": "related", "label": "Leads to Settlement", "targetId": "fibo-10"}]'::jsonb, 'orders,trading,execution,pre-trade,order-management,compliance,automation'::text[], 'Agents handle order routing, best execution analysis, and algorithmic trading strategy implementation.', '2026-02-12 05:17:41.34502', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-17', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Compliance Check', 'Risk & Compliance', 'A Compliance Check in financial services is an essential control process that ensures transactions, activities, or processes align with regulatory directives and internal standards. These checks may be executed automatically by systems or manually by compliance officers, and are often embedded at critical points within workflows, such as trade initiation or settlement. They help prevent regulatory breaches by identifying potential issues before transactions are finalized, offering assurances to both regulators and internal stakeholders. In modern operations, Compliance Checks are closely monitored and can trigger alerts for exceptions, escalating them for further review or remediation. The digitization and automation of compliance controls have also enabled real-time surveillance and improved transparency for audit trails.', '[{"name": "checkType", "type": "enum", "description": "Pre-trade, post-trade, or periodic"}, {"name": "ruleSet", "type": "string", "description": "Applicable compliance rules"}, {"name": "outcome", "type": "enum", "description": "Pass, fail, or warning"}, {"name": "checkTimestamp", "type": "date", "description": "The exact date and time when the compliance check was performed"}, {"name": "initiatorId", "type": "string", "description": "Identifier for the system or individual who initiated the check"}, {"name": "exceptionReason", "type": "string", "description": "Detail of the reason if a compliance check fails or issues a warning"}]'::jsonb, '[{"type": "depends_on", "label": "Based on Framework", "targetId": "fibo-15"}, {"type": "related", "label": "Validates Orders", "targetId": "fibo-16"}]'::jsonb, 'compliance,checks,validation,regulatory,audit,monitoring,risk-control'::text[], 'Agents run real-time compliance checks on trades, detect violations, and generate exception reports.', '2026-02-12 05:17:41.347589', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-18', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Beneficial Owner', 'Parties & Roles', 'A Beneficial Owner is the individual who ultimately controls or profits from a legal entity or arrangement, regardless of its formal, registered ownership structure. This concept is crucial in financial services for combating money laundering, terrorist financing, and tax evasion by revealing the true parties behind corporate veils. Financial institutions must accurately identify and monitor beneficial owners during onboarding, ongoing due diligence, and when changes in ownership occur. Automated solutions and AI agents can facilitate the identification, verification, and monitoring of beneficial ownership throughout the entity''s lifecycle. This concept is foundational for transparency initiatives and regulatory compliance within capital markets, banking, and asset management.', '[{"name": "ownershipPercentage", "type": "decimal", "description": "Percentage of beneficial ownership"}, {"name": "controlType", "type": "enum", "description": "Direct, indirect, or through chain"}, {"name": "verificationStatus", "type": "string", "description": "Verified, pending, or expired"}, {"name": "nationality", "type": "string", "description": "Country of citizenship of the beneficial owner"}, {"name": "dateOfBirth", "type": "date", "description": "Date of birth of the beneficial owner"}, {"name": "sourceOfWealth", "type": "string", "description": "Description of how the beneficial owner acquired their wealth"}]'::jsonb, '[{"type": "related", "label": "Controls Counterparty", "targetId": "fibo-5"}, {"type": "related", "label": "Identified via KYC", "targetId": "fibo-6"}, {"type": "related", "label": "The beneficial owner is a key component of a customer account, as it identifies the individuals or entities that ultimately own or control the account.", "targetId": "Customer Account"}, {"type": "related", "label": "The identification of beneficial owners is governed by AML screening processes to prevent money laundering and ensure compliance with regulatory requirements.", "targetId": "AML Screening"}, {"type": "related", "label": "Beneficial ownership information is crucial for KYC verification, ensuring that financial institutions know their clients and understand the ownership structures.", "targetId": "KYC Verification"}, {"type": "related", "label": "Details about beneficial owners are required in regulatory reports to provide transparency and compliance with financial regulations.", "targetId": "Regulatory Report"}, {"type": "depends_on", "label": "The beneficial owner depends on the issuer profile to understand the context of ownership in relation to the entity that issues securities.", "targetId": "Issuer Profile"}, {"type": "related", "label": "Beneficial owners may need to declare conflicts of interest, especially in transactions involving their interests.", "targetId": "Conflict of Interest Declaration"}, {"type": "related", "label": "The identification and reporting of beneficial owners are measured against established regulatory frameworks to ensure compliance.", "targetId": "Regulatory Framework"}]'::jsonb, 'beneficial-owner,ubo,transparency,aml,kyc,compliance,ownership-structure,personal-data'::text[], 'Agents trace beneficial ownership chains, validate UBO declarations, and flag complex ownership structures.', '2026-02-12 05:17:41.350825', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "restricted", "dataTypes": ["ownershipPercentage", "controlType", "beneficialOwnerName"], "retentionDays": 1825, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-19', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Market Risk Model', 'Risk & Compliance', 'A Market Risk Model is a fundamental tool in financial services for quantifying the risk of losses associated with adverse movements in market variables such as interest rates, equity prices, or foreign exchange rates. These models provide risk managers and traders with critical insights required for capital allocation, hedging strategies, and day-to-day portfolio management. In the context of AI agent operations, Market Risk Models enable the automation of risk monitoring, reporting, scenario analysis, and rapid response to market fluctuations. The outputs from these models are essential for both internal risk control processes and for meeting external regulatory mandates. Typically, such models are calibrated and validated using historical market data and can encompass different methodologies such as Value-at-Risk (VaR), Expected Shortfall, and stress testing.', '[{"name": "modelType", "type": "enum", "description": "VaR, Expected Shortfall, or stress test"}, {"name": "confidenceLevel", "type": "decimal", "description": "Statistical confidence (e.g., 99%)"}, {"name": "holdingPeriod", "type": "integer", "description": "Time horizon in days"}, {"name": "lastCalibrationDate", "type": "date", "description": "Date when the model was last calibrated or updated"}, {"name": "regulatoryApprovalStatus", "type": "enum", "description": "Regulator approval state (e.g., pending, approved, rejected)"}, {"name": "backtestingFrequency", "type": "string", "description": "How often the model is backtested (e.g., daily, weekly)"}, {"name": "modelVersion", "type": "string", "description": "Current version identifier for the model"}]'::jsonb, '[{"type": "related", "label": "Uses Market Data", "targetId": "fibo-9"}, {"type": "related", "label": "Feeds Valuation", "targetId": "fibo-11"}]'::jsonb, 'var,risk-model,quantitative,frtb,stress-testing,model-validation,capital-calculation,market-data-ingestion'::text[], 'Agents compute risk metrics, run scenario analyses, and trigger alerts when risk thresholds are breached.', '2026-02-12 05:17:41.353778', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-20', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Collateral Management', 'Risk & Compliance', 'Collateral Management refers to the operational and strategic process of monitoring, mobilizing, valuing, and optimizing assets pledged by financial institutions or clients as security for various financial obligations. This process includes collateral selection, valuation, substitution, optimization, and margining to minimize counterparty and credit risk. Effective collateral management ensures that obligations are adequately secured while optimizing asset utilization and liquidity positions. In the context of financial services, it is critical for safeguarding contractual performance across derivatives, secured lending, repo, and securities lending markets. Automation and AI can significantly enhance the real-time monitoring, eligibility checks, and optimization aspects of collateral management.', '[{"name": "collateralType", "type": "enum", "description": "Cash, securities, or other assets"}, {"name": "haircutPercentage", "type": "decimal", "description": "Valuation discount applied"}, {"name": "marginCallThreshold", "type": "decimal", "description": "Trigger level for margin calls"}, {"name": "collateralValuationTimestamp", "type": "date", "description": "Most recent date and time the collateral value was updated"}, {"name": "counterpartyIdentifier", "type": "string", "description": "Unique identifier for the counterparty providing or receiving collateral"}, {"name": "jurisdiction", "type": "string", "description": "Regulatory jurisdiction governing the collateral arrangement"}, {"name": "eligibilityStatus", "type": "enum", "description": "Current eligibility status (e.g., eligible, restricted, ineligible) for use as collateral"}]'::jsonb, '[{"type": "related", "label": "Secures Derivatives", "targetId": "fibo-1"}, {"type": "related", "label": "Mitigates Credit Risk", "targetId": "fibo-8"}]'::jsonb, 'collateral,margin,security,credit-risk-mitigation,liquidity-management,regulatory-compliance,asset-optimization,counterparty-exposure'::text[], 'Agents automate collateral optimization, margin call processing, and substitution workflows.', '2026-02-12 05:17:41.356316', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-21', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Fund Structure', 'Financial Instruments', 'Fund Structure defines the legal, regulatory, and operational framework of an investment fund, detailing aspects such as its share classes, net asset value (NAV) calculation method, and organizational setup. This concept governs how a fund pools investor capital, allocates assets, and manages distributions and fees. It also influences operational processes such as subscription/redemption cycles, reporting obligations, and risk management practices. In financial services operations, precise modeling of fund structure is essential for compliance audits, investor communications, and lifecycle events like mergers or share class launches. Understanding fund structure ensures accurate fund administration, pricing, and investor servicing.', '[{"name": "fundType", "type": "enum", "description": "UCITS, hedge fund, PE, or ETF"}, {"name": "domicile", "type": "string", "description": "Fund domicile country"}, {"name": "aum", "type": "decimal", "description": "Assets under management"}, {"name": "shareClasses", "type": "integer", "description": "Number of distinct share classes within the fund structure."}, {"name": "navFrequency", "type": "string", "description": "The schedule for NAV calculation (e.g., daily, weekly, monthly)."}, {"name": "feeStructure", "type": "string", "description": "Description of the performance fees, management fees, and other charges applicable to the fund."}, {"name": "legalForm", "type": "string", "description": "The legal vehicle under which the fund is constituted (e.g., trust, SICAV, LP)."}]'::jsonb, '[{"type": "parent", "label": "Is a Financial Instrument", "targetId": "fibo-2"}, {"type": "related", "label": "Valued by Portfolio Valuation", "targetId": "fibo-11"}]'::jsonb, 'funds,investment,aum,fundOperations,legalEntity,regulatoryReporting,fundAdministration,shareClass'::text[], 'Agents manage fund operations including subscription/redemption processing, NAV calculation, and investor reporting.', '2026-02-12 05:17:41.359462', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-22', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Corporate Action', 'Market Data', 'A Corporate Action represents any event set in motion by a corporation that leads to changes in the shareholder''s position. Examples include cash or stock dividends, stock splits, mergers, acquisitions, and rights offerings. These events can impact securities valuation, liquidity, and investor decision-making processes. In financial services operations, proper handling and communication of corporate actions are critical for account tracking, reconciliation, and ensuring timely client notifications. Furthermore, missed or misprocessed corporate actions can result in financial discrepancies and regulatory breaches.', '[{"name": "actionType", "type": "enum", "description": "Dividend, split, merger, or rights issue"}, {"name": "exDate", "type": "date", "description": "Ex-date for the action"}, {"name": "electionDeadline", "type": "date", "description": "Deadline for holder elections"}, {"name": "recordDate", "type": "date", "description": "Date on which holders must be on record to be eligible for the action."}, {"name": "paymentDate", "type": "date", "description": "Date when payments or entitlements are distributed."}, {"name": "mandatoryOrVoluntary", "type": "enum", "description": "Specifies whether the corporate action requires a holder decision."}, {"name": "announcementDate", "type": "date", "description": "Date when the corporate action event was officially announced."}]'::jsonb, '[{"type": "related", "label": "Affects Equities", "targetId": "fibo-3"}, {"type": "related", "label": "Impacts Accounts", "targetId": "fibo-13"}, {"type": "related", "label": "Receives event notification from", "targetId": "fibo-9"}]'::jsonb, 'corporate-actions,dividends,events,mergers-acquisitions,stock-splits,rights-issues,entitlements,voluntary-actions'::text[], 'Agents process corporate action notifications, calculate entitlements, and manage election workflows.', '2026-02-12 05:17:41.362414', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-23', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Liquidity Risk', 'Risk & Compliance', 'Liquidity risk refers to the possibility that a financial institution or entity will be unable to fulfill its short-term financial commitments due to the inability to liquidate assets quickly or at a reasonable price. In financial services operations, this risk can disrupt settlement processes, force entities to sell assets at depressed values, or result in defaults during stressful market conditions. Managing liquidity risk involves monitoring cash flows, understanding funding sources, and anticipating contingent exposures under both normal and stressed scenarios. Financial institutions routinely conduct stress testing and scenario analysis to proactively address liquidity shortfalls and ensure ongoing operational stability. Effective liquidity risk management supports both daily transaction obligations and resilience during market disruptions.', '[{"name": "lcr", "type": "decimal", "description": "Liquidity coverage ratio"}, {"name": "nsfr", "type": "decimal", "description": "Net stable funding ratio"}, {"name": "stressScenario", "type": "string", "description": "Applied stress test scenario"}, {"name": "liquidityHorizon", "type": "integer", "description": "Number of days over which liquidity risk is assessed."}, {"name": "contingencyFundingPlan", "type": "string", "description": "Description of planned actions in case of liquidity shortfall."}, {"name": "liquidityBufferComposition", "type": "string", "description": "Breakdown of asset types in the liquidity buffer."}]'::jsonb, '[{"type": "related", "label": "Complements Market Risk", "targetId": "fibo-19"}, {"type": "depends_on", "label": "Regulated by Framework", "targetId": "fibo-15"}, {"type": "depends_on", "label": "Requires effective management of collateral for liquidity", "targetId": "fibo-20"}]'::jsonb, 'liquidity,risk,basel,liquidity-management,regulatory-reporting,treasury,stress-testing'::text[], 'Agents monitor liquidity ratios, forecast cash positions, and trigger early warning alerts for funding gaps.', '2026-02-12 05:17:41.364501', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-24', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Transaction Monitoring', 'Risk & Compliance', 'Transaction Monitoring in financial services refers to the real-time and batch analysis of financial transactions, focusing on identifying unusual activity that may indicate money laundering, terrorist financing, or other types of financial crime. It typically involves applying predefined and adaptive rules or machine learning models that assess transaction attributes, customer behavior, and entity relationships. The process is designed to flag transactions for further investigation or compliance action. Transaction Monitoring is a critical element in the operational control framework for risk management as it ensures rapid identification and escalation of suspicious activity. Robust transaction monitoring mechanisms support both regulatory obligations and the institution''s reputation by reducing exposure to financial crime.', '[{"name": "monitoringRules", "type": "integer", "description": "Number of active detection rules"}, {"name": "alertVolume", "type": "integer", "description": "Daily alerts generated"}, {"name": "falsePositiveRate", "type": "decimal", "description": "Rate of false positive alerts"}, {"name": "detectionLatency", "type": "decimal", "description": "Average time taken to detect a suspicious transaction after it occurs."}, {"name": "ruleUpdateFrequency", "type": "string", "description": "How often monitoring rules are reviewed and updated."}, {"name": "escalationRate", "type": "decimal", "description": "Proportion of alerts that are escalated for further investigation."}]'::jsonb, '[{"type": "related", "label": "Part of AML Program", "targetId": "fibo-7"}, {"type": "related", "label": "Monitors Payments", "targetId": "fibo-12"}]'::jsonb, 'monitoring,fraud,surveillance,AML,regulatory-compliance,real-time-analysis,anomaly-detection'::text[], 'Agents triage transaction alerts, reduce false positives through pattern learning, and escalate genuine suspicious activity.', '2026-02-12 05:17:41.366709', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "restricted", "dataTypes": ["transactionDetails", "alertData", "suspiciousPatterns"], "retentionDays": 1825, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-25', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Client Onboarding', 'Parties & Roles', 'Client Onboarding in financial services is the coordinated, multi-stage process of welcoming a new client, comprising data collection, identity and regulatory checks (such as KYC), risk assessment, and account creation. This process is crucial to establishing the initial legal and operational relationship between a financial institution and the client, ensuring that all compliance obligations are fulfilled before service activation. Efficient onboarding directly impacts client experience, operational costs, and organizational risk posture. In large financial institutions, onboarding can involve complex workflows spanning multiple internal and external systems, document handling, anti-money laundering checks, and approval hierarchies. The ability to automate, track, and analyze onboarding steps is increasingly essential for both regulatory adherence and competitive advantage.', '[{"name": "onboardingStage", "type": "enum", "description": "Application, verification, approval, or active"}, {"name": "documentsRequired", "type": "string[]", "description": "Required documentation list"}, {"name": "slaHours", "type": "integer", "description": "Target completion time"}, {"name": "onboardingChannel", "type": "enum", "description": "The method or platform used for onboarding (e.g., online, branch, mobile)."}, {"name": "clientType", "type": "enum", "description": "Classification of client (e.g., individual, corporate, trust)."}, {"name": "riskRating", "type": "string", "description": "Initial risk rating assigned during the onboarding process."}, {"name": "onboardedBy", "type": "string", "description": "Identifier of the staff member or system facilitating the onboarding."}]'::jsonb, '[{"type": "depends_on", "label": "Requires KYC", "targetId": "fibo-6"}, {"type": "related", "label": "Creates Account", "targetId": "fibo-13"}, {"type": "related", "label": "Identifies UBOs", "targetId": "fibo-18"}]'::jsonb, 'onboarding,client,workflow,AML,KYC,compliance,identity-verification,account-opening'::text[], 'Agents orchestrate onboarding workflows, auto-collect documents, verify identities, and track SLA compliance.', '2026-02-12 05:17:41.369431', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-26', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Interest Rate Swap', 'Financial Instruments', 'An Interest Rate Swap is a commonly used over-the-counter (OTC) derivative contract in which two parties agree to exchange a series of interest payments, typically where one party pays a fixed interest rate and the other pays a floating rate as defined by a reference index (such as SOFR or EURIBOR), all based on a notional principal amount. These contracts are crucial tools for managing or hedging interest rate exposure and aligning financial obligations with risk preferences. In the operations of financial institutions, Interest Rate Swaps support funding, risk management, and speculative strategies, with lifecycle events such as trade execution, collateral management, and valuation adjustments. Swap contracts are governed by legal agreements (often ISDA master agreements) and are monitored for regulatory compliance, collateralization, and counterparty credit risk. Effective and timely lifecycle management is paramount to avoid regulatory breaches and manage operational and credit risks.', '[{"name": "fixedRate", "type": "decimal", "description": "Fixed leg rate"}, {"name": "floatingIndex", "type": "string", "description": "Reference rate (SOFR, EURIBOR)"}, {"name": "tenor", "type": "string", "description": "Swap duration"}, {"name": "notionalAmount", "type": "decimal", "description": "The principal amount upon which swap payments are calculated."}, {"name": "tradeDate", "type": "date", "description": "The date on which the swap contract is executed."}, {"name": "maturityDate", "type": "date", "description": "Date on which the swap contract ends."}, {"name": "paymentFrequency", "type": "string", "description": "Frequency of interest payments exchanged (e.g., quarterly, semi-annual)."}]'::jsonb, '[{"type": "parent", "label": "Is a Derivative", "targetId": "fibo-1"}, {"type": "related", "label": "Requires Collateral", "targetId": "fibo-20"}]'::jsonb, 'swaps,interest-rate,otc,derivatives,risk-management,regulatory-reporting,isda-compliant'::text[], 'Agents price interest rate swaps, manage reset schedules, and calculate variation margin requirements.', '2026-02-12 05:17:41.371685', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-27', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Sanctions List', 'Regulatory', 'A Sanctions List is a critical regulatory compliance tool in financial services, comprising official compilations of individuals, organizations, and jurisdictions subject to economic or trade embargoes. Institutions must reference these lists to prevent transactions with prohibited parties, ensuring adherence to international laws and sanctions regimes. Updates to sanctions lists can occur frequently in response to geopolitical events, requiring ongoing vigilance from compliance teams and automated systems. In financial operations, AI agents help screen customers, transactions, and counterparties against these dynamic lists to mitigate risk and potential legal exposure. Failure to properly manage sanctions screening can result in severe financial penalties and reputational damage for institutions.', '[{"name": "listProvider", "type": "string", "description": "OFAC, EU, UN, or HMT"}, {"name": "lastUpdated", "type": "date", "description": "Most recent list update"}, {"name": "totalEntries", "type": "integer", "description": "Number of entries on list"}, {"name": "listType", "type": "enum", "description": "Specifies whether the list contains individuals, entities, vessels, countries, or a mix thereof"}, {"name": "jurisdiction", "type": "string", "description": "Defines the legal territory to which the list applies"}, {"name": "updateFrequency", "type": "string", "description": "How often the list is reviewed and refreshed (e.g., daily, weekly)"}]'::jsonb, '[{"type": "related", "label": "Used in AML Screening", "targetId": "fibo-7"}, {"type": "depends_on", "label": "Part of Regulatory Framework", "targetId": "fibo-15"}]'::jsonb, 'sanctions,ofac,screening,compliance,aml-ctf,risk-management,regulatory-technology'::text[], 'Agents perform real-time sanctions screening against multiple lists, handle fuzzy matching, and manage alert resolution.', '2026-02-12 05:17:41.374499', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('fibo-28', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Reconciliation Process', 'Payment Systems', 'The Reconciliation Process in payment systems serves as a critical operational control, ensuring that an institution''s internal transaction or balance records align with external data such as bank statements, clearing house reports, or custodian statements. This process is fundamental to error detection, fraud prevention, and financial integrity, as it systematically identifies and resolves data discrepancies. AI-driven automation in reconciliation enables timely exception management and root-cause analysis, reducing manual workload and accelerating issue resolution. For financial services providers, effective reconciliation underpins trust, risk management, and the accuracy of downstream functions such as settlements, reporting, and compliance audits.', '[{"name": "reconciliationType", "type": "enum", "description": "Cash, position, or transaction"}, {"name": "matchRate", "type": "decimal", "description": "Percentage of auto-matched items"}, {"name": "breakThreshold", "type": "decimal", "description": "Tolerance for discrepancies"}, {"name": "reconciliationFrequency", "type": "enum", "description": "How often the reconciliation is performed (e.g., intraday, daily, monthly)."}, {"name": "lastReconciledDate", "type": "date", "description": "The date when the last reconciliation was completed."}, {"name": "exceptionCount", "type": "integer", "description": "Number of items not matched or requiring investigation during the process."}]'::jsonb, '[{"type": "related", "label": "Validates Settlement", "targetId": "fibo-10"}, {"type": "related", "label": "Reconciles Accounts", "targetId": "fibo-13"}]'::jsonb, 'reconciliation,matching,breaks,exception-management,payments-operations,audit-readiness,regulatory-reporting'::text[], 'Agents automate reconciliation matching, identify breaks, suggest resolutions, and track aging items.', '2026-02-12 05:17:41.377618', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-1', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Clinical Assessment', 'Clinical Findings', 'A systematic evaluation of a patient''s health status through history taking, examination, and diagnostic reasoning.', E'"[{\\"name\\":\\"assessmentType\\",\\"type\\":\\"enum\\",\\"description\\":\\"Initial, follow-up, or emergency\\"},{\\"name\\":\\"clinicalDomain\\",\\"type\\":\\"string\\",\\"description\\":\\"Medical specialty area\\"},{\\"name\\":\\"acuityLevel\\",\\"type\\":\\"enum\\",\\"description\\":\\"Patient acuity classification\\"}]"'::jsonb, E'"[{\\"type\\":\\"child\\",\\"targetId\\":\\"sno-2\\",\\"label\\":\\"Includes Vital Signs\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-5\\",\\"label\\":\\"Leads to Diagnosis\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-3\\",\\"label\\":\\"May trigger Triage\\"}]"'::jsonb, 'assessment,evaluation,clinical'::text[], 'Agents assist clinicians with structured assessment workflows, symptom checking, and preliminary differential diagnosis.', '2026-02-12 05:17:41.380664', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["patientId", "clinicalNotes", "assessmentFindings", "medicalHistory"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-2', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Vital Signs Monitoring', 'Clinical Findings', 'Continuous or periodic measurement of essential physiological parameters including heart rate, blood pressure, and temperature.', E'"[{\\"name\\":\\"measurementFrequency\\",\\"type\\":\\"string\\",\\"description\\":\\"Monitoring interval\\"},{\\"name\\":\\"alertThresholds\\",\\"type\\":\\"object\\",\\"description\\":\\"Critical value thresholds\\"},{\\"name\\":\\"deviceType\\",\\"type\\":\\"string\\",\\"description\\":\\"Monitoring device used\\"}]"'::jsonb, E'"[{\\"type\\":\\"parent\\",\\"targetId\\":\\"sno-1\\",\\"label\\":\\"Part of Clinical Assessment\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-16\\",\\"label\\":\\"Recorded in EHR\\"}]"'::jsonb, 'vitals,monitoring,physiological'::text[], 'Agents monitor vital sign trends, detect deterioration patterns, and trigger early warning alerts for clinical teams.', '2026-02-12 05:17:41.383341', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["heartRate", "bloodPressure", "temperature", "oxygenSaturation", "patientId"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-3', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Patient Triage', 'Patient Management', 'The process of determining the priority of patient treatment based on the severity of their condition.', E'"[{\\"name\\":\\"triageScale\\",\\"type\\":\\"enum\\",\\"description\\":\\"ESI, MTS, or CTAS scale\\"},{\\"name\\":\\"priorityLevel\\",\\"type\\":\\"integer\\",\\"description\\":\\"Urgency classification (1-5)\\"},{\\"name\\":\\"reassessmentInterval\\",\\"type\\":\\"string\\",\\"description\\":\\"Time to reassess\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-1\\",\\"label\\":\\"Based on Assessment\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-4\\",\\"label\\":\\"Determines Bed Assignment\\"}]"'::jsonb, 'triage,emergency,priority'::text[], 'Agents assist with triage scoring, predict patient acuity, and optimize ED patient flow.', '2026-02-12 05:17:41.385919', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["patientId", "triageScore", "chiefComplaint", "acuityLevel"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-4', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Bed Management', 'Patient Management', 'The coordination of hospital bed availability, assignment, and discharge planning to optimize patient flow.', E'"[{\\"name\\":\\"bedStatus\\",\\"type\\":\\"enum\\",\\"description\\":\\"Available, occupied, cleaning, or blocked\\"},{\\"name\\":\\"ward\\",\\"type\\":\\"string\\",\\"description\\":\\"Hospital ward or unit\\"},{\\"name\\":\\"isolationRequired\\",\\"type\\":\\"boolean\\",\\"description\\":\\"Infection control requirement\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-3\\",\\"label\\":\\"Assigned after Triage\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-10\\",\\"label\\":\\"Released at Discharge\\"}]"'::jsonb, 'beds,capacity,flow'::text[], 'Agents predict bed demand, optimize assignments, and coordinate cleaning schedules to reduce wait times.', '2026-02-12 05:17:41.388764', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-5', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Diagnostic Coding', 'Diagnostic', 'Assignment of standardized codes (ICD-10, SNOMED CT) to clinical findings and diagnoses.', E'"[{\\"name\\":\\"codingSystem\\",\\"type\\":\\"enum\\",\\"description\\":\\"ICD-10, SNOMED CT, or DSM-5\\"},{\\"name\\":\\"primaryDiagnosis\\",\\"type\\":\\"string\\",\\"description\\":\\"Principal diagnosis code\\"},{\\"name\\":\\"coMorbidities\\",\\"type\\":\\"string[]\\",\\"description\\":\\"Associated condition codes\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-1\\",\\"label\\":\\"Codes Assessment Findings\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-17\\",\\"label\\":\\"Used in Billing\\"}]"'::jsonb, 'coding,icd,diagnosis'::text[], 'Agents suggest diagnostic codes from clinical notes, validate coding accuracy, and ensure reimbursement optimization.', '2026-02-12 05:17:41.391741', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["diagnosisCode", "primaryDiagnosis", "coMorbidities", "patientId"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-6', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Medication Administration', 'Pharmaceutical', 'The process of preparing and giving medications to patients according to prescribed orders.', E'"[{\\"name\\":\\"route\\",\\"type\\":\\"enum\\",\\"description\\":\\"Oral, IV, IM, or topical\\"},{\\"name\\":\\"dosage\\",\\"type\\":\\"string\\",\\"description\\":\\"Prescribed dose and frequency\\"},{\\"name\\":\\"verificationSteps\\",\\"type\\":\\"string[]\\",\\"description\\":\\"Safety check requirements\\"}]"'::jsonb, E'"[{\\"type\\":\\"depends_on\\",\\"targetId\\":\\"sno-7\\",\\"label\\":\\"Based on Prescription\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-8\\",\\"label\\":\\"Checked for Interactions\\"}]"'::jsonb, 'medication,administration,nursing'::text[], 'Agents verify medication orders against patient allergies, check interactions, and ensure five-rights compliance.', '2026-02-12 05:17:41.393719', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["patientId", "medication", "dosage", "route", "prescriber"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-7', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Prescription Order', 'Pharmaceutical', 'A formal instruction from a clinician for the preparation and administration of a medication.', E'"[{\\"name\\":\\"prescriber\\",\\"type\\":\\"string\\",\\"description\\":\\"Ordering clinician\\"},{\\"name\\":\\"medication\\",\\"type\\":\\"string\\",\\"description\\":\\"Drug name and formulation\\"},{\\"name\\":\\"duration\\",\\"type\\":\\"string\\",\\"description\\":\\"Treatment duration\\"}]"'::jsonb, E'"[{\\"type\\":\\"child\\",\\"targetId\\":\\"sno-6\\",\\"label\\":\\"Administered as Medication\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-8\\",\\"label\\":\\"Checked for Drug Interactions\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-9\\",\\"label\\":\\"Sourced from Formulary\\"}]"'::jsonb, 'prescription,ordering,cpoe'::text[], 'Agents assist with prescription decision support, formulary checks, and prior authorization processing.', '2026-02-12 05:17:41.396646', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["patientId", "medication", "prescriber", "duration"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-8', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Drug Interaction Check', 'Pharmaceutical', 'Automated screening of medication combinations for potentially harmful interactions.', E'"[{\\"name\\":\\"severityLevel\\",\\"type\\":\\"enum\\",\\"description\\":\\"Contraindicated, major, moderate, or minor\\"},{\\"name\\":\\"interactionType\\",\\"type\\":\\"string\\",\\"description\\":\\"Pharmacokinetic or pharmacodynamic\\"},{\\"name\\":\\"evidenceLevel\\",\\"type\\":\\"string\\",\\"description\\":\\"Quality of supporting evidence\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-6\\",\\"label\\":\\"Validates Medication\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-7\\",\\"label\\":\\"Checks Prescriptions\\"}]"'::jsonb, 'interactions,safety,pharmacology'::text[], 'Agents perform real-time interaction screening across patient medication lists and alert clinicians to risks.', '2026-02-12 05:17:41.399819', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, '{"level": "phi", "dataTypes": ["patientId", "medications", "interactions", "allergyList"], "retentionDays": 2555, "redactionRequired": true}'::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-9', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Formulary Management', 'Pharmaceutical', 'The process of maintaining an approved list of medications available within a healthcare organization.', E'"[{\\"name\\":\\"formularyStatus\\",\\"type\\":\\"enum\\",\\"description\\":\\"On-formulary, restricted, or non-formulary\\"},{\\"name\\":\\"therapeuticClass\\",\\"type\\":\\"string\\",\\"description\\":\\"Drug classification\\"},{\\"name\\":\\"costCategory\\",\\"type\\":\\"enum\\",\\"description\\":\\"Generic, preferred brand, or specialty\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-7\\",\\"label\\":\\"Referenced by Prescriptions\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-17\\",\\"label\\":\\"Impacts Billing\\"}]"'::jsonb, 'formulary,pharmacy,cost'::text[], 'Agents suggest formulary alternatives, calculate cost savings, and process therapeutic substitution requests.', '2026-02-12 05:17:41.402301', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-10', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Discharge Planning', 'Patient Management', 'The process of preparing a patient for safe transition from hospital to the next care setting.', E'"[{\\"name\\":\\"dischargeDestination\\",\\"type\\":\\"enum\\",\\"description\\":\\"Home, SNF, rehab, or hospice\\"},{\\"name\\":\\"followUpRequired\\",\\"type\\":\\"boolean\\",\\"description\\":\\"Post-discharge follow-up needed\\"},{\\"name\\":\\"dischargeMedications\\",\\"type\\":\\"string[]\\",\\"description\\":\\"Medications at discharge\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-4\\",\\"label\\":\\"Frees Bed\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-11\\",\\"label\\":\\"Generates Care Plan\\"},{\\"type\\":\\"depends_on\\",\\"targetId\\":\\"sno-6\\",\\"label\\":\\"Reconciles Medications\\"}]"'::jsonb, 'discharge,transition,planning'::text[], 'Agents coordinate discharge readiness checks, medication reconciliation, and follow-up appointment scheduling.', '2026-02-12 05:17:41.405203', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('sno-11', 'healthcare', 'SNOMED CT (Clinical Terms)', 'Care Plan', 'Patient Management', 'A structured document outlining the patient''s diagnosis, treatment goals, interventions, and outcomes.', E'"[{\\"name\\":\\"planType\\",\\"type\\":\\"enum\\",\\"description\\":\\"Acute, chronic, or preventive\\"},{\\"name\\":\\"goals\\",\\"type\\":\\"string[]\\",\\"description\\":\\"Treatment objectives\\"},{\\"name\\":\\"reviewDate\\",\\"type\\":\\"date\\",\\"description\\":\\"Next plan review date\\"}]"'::jsonb, E'"[{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-10\\",\\"label\\":\\"Created at Discharge\\"},{\\"type\\":\\"related\\",\\"targetId\\":\\"sno-1\\",\\"label\\":\\"Based on Assessment\\"}]"'::jsonb, 'care-plan,treatment,goals'::text[], 'Agents generate personalized care plans, track goal progress, and suggest evidence-based interventions.', '2026-02-12 05:17:41.407472', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
