INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-party-beneficiary', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Beneficiary', 'Party', 'Individual or entity entitled to receive benefits from a policy.', '[{"name": "beneficiaryName", "type": "string", "description": "Name of the beneficiary"}, {"name": "relationshipToInsured", "type": "string", "description": "Nature of relationship to policyholder"}]'::jsonb, '[{"type": "depends_on", "label": "Receives benefits if policyholder incurs loss", "targetId": "insurance-policy-policyholder"}]'::jsonb, 'Recipient,Trust,Inheritance'::text[], 'Defines recipients for insurance benefit payouts.', '2026-02-13 05:45:11.711714', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-party-underwriter', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Underwriter', 'Party', 'Professional responsible for risk evaluation and policy issuance.', '[{"name": "underwriterName", "type": "string", "description": "Name of the underwriter"}, {"name": "approvalStatus", "type": "enum", "description": "Approved, pending, or denied"}]'::jsonb, '[{"type": "depends_on", "label": "Reviews and approves contracts", "targetId": "insurance-policy-policycontract"}]'::jsonb, 'Risk,Evaluation,Approval'::text[], 'Crucial for risk selection and policy management.', '2026-02-13 05:45:11.714943', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-premium-premiumcalculation', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'PremiumCalculation', 'Premium', 'Methodology used to determine cost of insurance coverage.', '[{"name": "calculationMethod", "type": "enum", "description": "Rating factors used"}, {"name": "premiumAmount", "type": "decimal", "description": "Resulting premium value"}]'::jsonb, '[{"type": "depends_on", "label": "Amount varies by coverage", "targetId": "insurance-coverage-coveragetype"}]'::jsonb, 'Rate,Cost,Calculation'::text[], 'Ensures fair pricing and profitability for insurers.', '2026-02-13 05:45:11.720835', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-premium-premiumpayment', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'PremiumPayment', 'Premium', 'Process and documentation of paying insurance premiums.', '[{"name": "paymentDate", "type": "date", "description": "Date premium is paid"}, {"name": "paymentMethod", "type": "enum", "description": "Cheque, credit, or transfer"}]'::jsonb, '[{"type": "related", "label": "Keeps policy active through payment", "targetId": "insurance-policy-policycontract"}]'::jsonb, 'Finance,Transaction,Continuity'::text[], 'Maintains activeness of insurance policies.', '2026-02-13 05:45:11.726518', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-premium-premiumadjustment', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'PremiumAdjustment', 'Premium', 'Modification of premium based on updated risk assessment.', '[{"name": "adjustmentAmount", "type": "decimal", "description": "Difference in premium after adjustment"}, {"name": "adjustmentReason", "type": "string", "description": "Reason for adjusting premium"}]'::jsonb, '[{"type": "child", "label": "Derived from recalculation process", "targetId": "insurance-premium-premiumcalculation"}]'::jsonb, 'Change,Regulation,Rate'::text[], 'Allows dynamic response to changing risk profiles.', '2026-02-13 05:45:11.729904', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-risk-management-riskassessment', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'RiskAssessment', 'Risk Management', 'Evaluation of exposures and risk factors for insurance purposes.', '[{"name": "assessmentScore", "type": "decimal", "description": "Numerical value of risk"}, {"name": "assessmentDate", "type": "date", "description": "When assessment was performed"}]'::jsonb, '[{"type": "depends_on", "label": "Conducted by underwriter", "targetId": "insurance-party-underwriter"}]'::jsonb, 'Evaluation,Exposure,Analysis'::text[], 'Foundational to underwriting and pricing activities.', '2026-02-13 05:45:11.734691', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-risk-management-lossprevention', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'LossPrevention', 'Risk Management', 'Measures implemented to reduce risk and prevent insurance claims.', '[{"name": "preventionMethod", "type": "string", "description": "Technique used"}, {"name": "effectivenessLevel", "type": "decimal", "description": "Perceived effectiveness score"}]'::jsonb, '[{"type": "related", "label": "Informed by risk evaluation", "targetId": "insurance-risk-management-riskassessment"}]'::jsonb, 'Mitigation,Safety,Control'::text[], 'Decreases likelihood and impact of insured losses.', '2026-02-13 05:45:11.738164', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-risk-management-risktransfer', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'RiskTransfer', 'Risk Management', 'Shift of specified risk from one party to another, typically through insurance.', '[{"name": "transferType", "type": "enum", "description": "Insurance or reinsurance"}, {"name": "transferDate", "type": "date", "description": "Effective date of transfer"}]'::jsonb, '[{"type": "related", "label": "Risk accepted by insurer via policy", "targetId": "insurance-policy-policycontract"}]'::jsonb, 'Allocation,Reinsurance,Protection'::text[], 'Enables financial sharing of risk exposures.', '2026-02-13 05:45:11.744113', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-policy-insurancecontract', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'InsuranceContract', 'Policy', 'An InsuranceContract is the foundational legal instrument in insurance operations, formally documenting the obligations, entitlements, and terms that govern the relationship between the insurer and the policyholder. It delineates the scope of coverage, premium details, exclusions, and the processes for claims and dispute resolution. In automated environments, InsuranceContracts serve as authoritative references for all policy adjudication, risk assessment, and compliance monitoring. Accurate management of these contracts underpins regulatory reporting, customer service, and claims processing efficiency. AI agents interacting with InsuranceContracts must ensure data integrity, traceability, and real-time policy status awareness.', '[{"name": "policyNumber", "type": "string", "description": "Unique identifier for the insurance contract."}, {"name": "effectiveDate", "type": "date", "description": "Date when coverage starts."}, {"name": "terminationDate", "type": "date", "description": "Date when the insurance contract ceases to be in effect."}, {"name": "premiumAmount", "type": "decimal", "description": "The agreed monetary amount for contract premiums."}, {"name": "coverageType", "type": "string", "description": "The specified nature of risk or coverage class provided by the contract."}, {"name": "status", "type": "enum", "description": "Current operational status of the insurance contract (e.g., active, lapsed, terminated)."}]'::jsonb, '[{"type": "child", "label": "Contract belongs to a Policyholder.", "targetId": "insurance-policy-policyholder"}, {"type": "depends_on", "label": "InsuranceContract must comply with evolving regulatory requirements.", "targetId": "Regulatory Requirement"}, {"type": "child", "label": "InsuranceContract is funded and activated by linked premium payments.", "targetId": "PremiumPayment"}]'::jsonb, 'coverage,agreement,legal,policy-administration,underwriting,customer-obligation,risk-transfer'::text[], 'Central to ACORD standards for insurance processing and lifecycle.', '2026-02-13 06:02:50.626', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-policy-premium', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Premium', 'Policy', 'In insurance operations, ''Premium'' refers to the regular monetary payment made by a policyholder to maintain active insurance coverage, often structured as recurring installments such as monthly, quarterly, or annually. The premium is calculated based on various risk factors, coverage scope, underwriting criteria, and policyholder profile, serving as the insurer’s primary revenue stream. Fluctuations in the premium can occur due to endorsements, claims history, or regulatory changes. Accurate handling and processing of premium payments are crucial for policy validity, customer satisfaction, and insurer solvency. AI-powered automation can optimize premium collection, adjustment, and compliance monitoring with operational and regulatory guidelines.', '[{"name": "amount", "type": "decimal", "description": "Premium value due for policy."}, {"name": "paymentFrequency", "type": "enum", "description": "Interval for premium payment, e.g., monthly or annually."}, {"name": "dueDate", "type": "date", "description": "The scheduled date by which the premium must be paid."}, {"name": "paymentStatus", "type": "enum", "description": "Current status of the premium payment (e.g., paid, overdue, pending)."}, {"name": "currency", "type": "string", "description": "Currency in which the premium is denominated."}]'::jsonb, '[{"type": "depends_on", "label": "Premium is calculated based on InsuranceContract terms.", "targetId": "insurance-policy-insurancecontract"}, {"type": "depends_on", "label": "Premium is owed by the policyholder.", "targetId": "Policyholder"}, {"type": "related", "label": "Claim payout eligibility depends on premium payment status.", "targetId": "Claim"}]'::jsonb, 'financial,recurring,payment,regulatory,customer-owed,revenue,compliance'::text[], 'Critical for revenue and risk management in insurance operations per ACORD.', '2026-02-13 06:02:50.671495', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-risk-insuredasset', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'InsuredAsset', 'Risk', 'The InsuredAsset represents any tangible or intangible item covered and protected by an insurance policy within the insurance value chain. Common insured assets include homes, vehicles, equipment, inventory, and even intellectual property, depending on the policy terms. Accurate identification and management of insured assets are crucial for underwriting, claims processing, risk assessment, and reinsurance placement. AI agents interacting with InsuredAsset data enable streamlined operations through automated asset verification, dynamic risk profiling, and real-time valuation monitoring. This concept provides the foundation for advanced insurance analytics, fraud detection, and personalized coverage products.', '[{"name": "assetType", "type": "enum", "description": "Category of asset, such as vehicle, property, or equipment."}, {"name": "assetValue", "type": "decimal", "description": "Assessed value of the asset."}, {"name": "assetIdentifier", "type": "string", "description": "Unique identifier or serial number for the insured asset."}, {"name": "assetLocation", "type": "string", "description": "Physical address or location of the asset, relevant for risk assessment."}, {"name": "coverageLimit", "type": "decimal", "description": "Maximum coverage amount applicable to this asset under the policy."}]'::jsonb, '[{"type": "depends_on", "label": "Asset is covered under the InsuranceContract.", "targetId": "insurance-policy-insurancecontract"}, {"type": "related", "label": "Links the insured asset to any claims filed involving this asset.", "targetId": "Claims"}, {"type": "depends_on", "label": "The valuation of the InsuredAsset is based on one or more appraisals.", "targetId": "AssetAppraisal"}]'::jsonb, 'property,coverage,valued,risk-assessment,asset-management,underwriting'::text[], 'Supports risk assessment and underwriting per ACORD data models.', '2026-02-13 06:02:50.716648', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-risk-riskassessment', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'RiskAssessment', 'Risk', 'RiskAssessment in insurance is the systematic evaluation of an entity''s or asset''s exposure to a variety of risks, aiming to quantify the likelihood and potential financial impact of those risks. This process informs underwriting decisions, pricing strategies, and the structuring of policies. AI agents can automate and enhance this evaluation by processing vast data sources and applying advanced modeling techniques to detect nuanced risk factors. Risk assessment results underpin eligibility determination, premium calculation, and ongoing portfolio monitoring. Effective RiskAssessment ensures the insurer''s portfolio remains balanced relative to target risk tolerance and profitability.', '[{"name": "riskScore", "type": "integer", "description": "Quantitative score based on risk factors."}, {"name": "assessmentDate", "type": "date", "description": "Date the risk was evaluated."}, {"name": "assessmentMethod", "type": "enum", "description": "The methodology or technique (e.g., AI model, actuarial, manual) used for the risk assessment."}, {"name": "riskCategory", "type": "enum", "description": "Type or domain of risk being assessed (e.g., operational, natural hazard, cyber)."}, {"name": "reviewStatus", "type": "enum", "description": "Workflow status indicating whether the risk assessment is pending, reviewed, or finalized."}]'::jsonb, '[{"type": "related", "label": "RiskAssessment relates to InsuredAsset analysis.", "targetId": "insurance-risk-insuredasset"}, {"type": "depends_on", "label": "RiskAssessment is dependent on granular exposure information for accurate evaluation.", "targetId": "Exposure Data"}, {"type": "related", "label": "RiskAssessment outcomes inform Policy Issuance decisions.", "targetId": "Policy Issuance"}]'::jsonb, 'underwriting,evaluation,exposure,decision-support,solvency,regulatory-compliance'::text[], 'Used for setting premiums and policy terms per ACORD underwriting guidelines.', '2026-02-13 06:02:50.763563', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-risk-coveragelimit', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'CoverageLimit', 'Risk', 'CoverageLimit represents the upper threshold of financial responsibility an insurer will bear for a covered loss. It serves as a crucial determinant in risk assessment and premium calculation, directly impacting the insurer''s liability and the insured''s protection. In insurance operations, precise definition and management of coverage limits are vital for policy administration, claims adjudication, and product design. This concept is frequently used to define per event, per policy, or aggregate limits within insurance contracts. Adjustments to coverage limits can trigger recalculation of exposures and require regulatory notifications.', '[{"name": "limitAmount", "type": "decimal", "description": "Maximum payout specified by the policy."}, {"name": "limitType", "type": "enum", "description": "Type of limit, such as per occurrence or aggregate."}, {"name": "currencyCode", "type": "string", "description": "The ISO currency code of the coverage limit."}, {"name": "effectiveDate", "type": "date", "description": "The date from which the coverage limit becomes applicable."}, {"name": "expirationDate", "type": "date", "description": "The date until which the coverage limit is valid."}]'::jsonb, '[{"type": "parent", "label": "CoverageLimit is defined in InsuranceContract.", "targetId": "insurance-policy-insurancecontract"}, {"type": "related", "label": "CoverageLimit is referenced during claim adjudication processes.", "targetId": "Claim"}, {"type": "depends_on", "label": "CoverageLimit is informed by underlying risk assessment.", "targetId": "RiskAssessment"}]'::jsonb, 'maximum,protection,bound,liability,threshold,claims-processing,underwriting'::text[], 'Defines financial responsibility for insurers and insureds in ACORD frameworks.', '2026-02-13 06:02:50.807963', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-underwriting-underwriter', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Underwriter', 'Underwriting', 'An underwriter, in insurance operations, is either an individual professional or an automated system tasked with evaluating the risks associated with insuring individuals, assets, or entities. The underwriter analyzes various risk factors and determines pricing, coverage terms, and approval of insurance policies according to established guidelines and actuarial data. This role is crucial for maintaining the insurer''s portfolio health and profitability, as it helps ensure that premiums accurately reflect the underlying risk. Underwriting processes may be augmented or entirely managed by AI agents in modern insurance operations to increase efficiency, consistency, and scalability. The underwriter''s decisions are foundational to the policy issuance lifecycle and directly impact claims outcomes and risk management.', '[{"name": "underwriterId", "type": "string", "description": "Unique identifier for the underwriter."}, {"name": "authorizationLevel", "type": "enum", "description": "Approval authority, e.g. junior, senior."}, {"name": "underwritingSpecialty", "type": "string", "description": "The specific line(s) of insurance or risk class the underwriter is specialized in (e.g., life, property, commercial)."}, {"name": "decisionTimestamp", "type": "date", "description": "Date and time when the underwriting decision was finalized."}, {"name": "approvalStatus", "type": "enum", "description": "Status of the latest underwriting decision (e.g., approved, rejected, pending additional info)."}]'::jsonb, '[{"type": "related", "label": "Underwriter uses RiskAssessment to decide coverage.", "targetId": "insurance-risk-riskassessment"}, {"type": "related", "label": "Underwriter issues or rejects insurance policies based on evaluation.", "targetId": "Policy Issuance"}, {"type": "parent", "label": "Underwriter operates based on established policy guidelines.", "targetId": "Underwriting Guidelines"}]'::jsonb, 'expert,review,decision,compliance,risk-management,approval-process,insurance-operations'::text[], 'Central to risk and policy approval per ACORD underwriting processes.', '2026-02-13 06:02:50.996935', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-underwriting-underwritingguideline', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'UnderwritingGuideline', 'Underwriting', 'UnderwritingGuideline is a foundational component in insurance operations, serving as the structured set of rules and criteria by which insurers evaluate the risks and eligibility of insurance applications. These guidelines are tailored to specific product lines, such as health or property, and ensure consistency and fairness in risk assessment. They influence policy pricing, eligibility, required documentation, and the overall decision-making process. Modern underwriting guidelines are continually updated to reflect changes in risk environments, regulatory mandates, and emerging insurance trends, facilitating agility and compliance within insurance carriers. The application of underwriting guidelines directly impacts portfolio risk, profitability, and customer satisfaction.', '[{"name": "guidelineType", "type": "enum", "description": "Type of risk evaluated, e.g. health, property."}, {"name": "updateDate", "type": "date", "description": "Last revision date for guideline."}, {"name": "effectiveDate", "type": "date", "description": "Date when the guideline became active or applicable."}, {"name": "approvalStatus", "type": "enum", "description": "Current state of guideline approval such as ''Draft'', ''Reviewed'', or ''Approved''."}, {"name": "author", "type": "string", "description": "Name or identifier of the guideline creator or responsible party."}, {"name": "applicableRegion", "type": "string", "description": "Geographical region(s) where the guideline applies."}]'::jsonb, '[{"type": "parent", "label": "Guideline informs RiskAssessment criteria.", "targetId": "insurance-risk-riskassessment"}, {"type": "depends_on", "label": "Guidelines are shaped by regulatory requirements.", "targetId": "Regulatory Rule Set"}, {"type": "related", "label": "Each guideline is linked to specific insurance products.", "targetId": "Insurance Product Specification"}]'::jsonb, 'criteria,rule,policy,compliance,automation,risk-management,documentation'::text[], 'Defines standards and compliance per ACORD and regulatory needs.', '2026-02-13 06:02:51.04188', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-underwriting-application', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Application', 'Underwriting', 'An Application in the context of insurance underwriting is the formal submission of details by a potential insured that initiates the insurance process. This document or digital form captures personal, financial, and risk-related information necessary for an underwriter to assess the risk profile and determine pricing or eligibility. Applications are pivotal touchpoints, as errors or omissions can impact coverage and underwriting outcomes. In modern digital insurance operations, application data is increasingly collected and validated automatically using AI, enhancing accuracy and reducing human effort. Application quality and completeness directly affect quote turnaround time and overall customer experience.', '[{"name": "applicationDate", "type": "date", "description": "Date of application submission."}, {"name": "applicationStatus", "type": "enum", "description": "Current state, e.g. pending, approved, rejected."}, {"name": "applicantType", "type": "enum", "description": "Type of applicant, e.g. individual, business, group."}, {"name": "submittedBy", "type": "string", "description": "Identifier for the submitting agent, broker, or applicant."}, {"name": "coverageRequested", "type": "string", "description": "Type and amount of coverage being sought in the application."}]'::jsonb, '[{"type": "depends_on", "label": "Application status determined by Underwriter.", "targetId": "insurance-underwriting-underwriter"}, {"type": "related", "label": "Application may lead to issuance of Insurance Policy upon approval.", "targetId": "Insurance Policy"}, {"type": "depends_on", "label": "Application is created or owned by Applicant entity.", "targetId": "Applicant"}]'::jsonb, 'candidate,evaluation,submission,risk-assessment,customer-onboarding,eligibility,personal-information'::text[], 'Key entry point for new policies per ACORD documentation.', '2026-02-13 06:02:51.086552', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-product-insuranceproduct', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'InsuranceProduct', 'Product', 'An InsuranceProduct is a standardized insurance offering structured around specific terms, coverage boundaries, underwriting criteria, and features tailored to a target market or risk type. Within insurance operations, such products underpin portfolio management, pricing strategies, and policy administration systems. InsuranceProducts serve as templates from which individual contracts (policies) are created and managed, ensuring consistency in coverage definitions and compliance. Their lifecycle includes design, approval, distribution, updates, and eventual withdrawal or replacement. Accurate modeling of InsuranceProduct is critical for streamlining product rollouts, regulatory filings, and digital distribution channels.', '[{"name": "productCode", "type": "string", "description": "Unique identification code for the product."}, {"name": "productType", "type": "enum", "description": "Line of business, e.g. auto, health, property."}, {"name": "regulatoryStatus", "type": "enum", "description": "Current regulatory approval state, such as Draft, Filed, Approved, or Withdrawn."}, {"name": "effectiveDate", "type": "date", "description": "Date on which the InsuranceProduct becomes available or effective."}, {"name": "targetMarketSegment", "type": "string", "description": "Description of the intended customer or business segment for this product."}]'::jsonb, '[{"type": "parent", "label": "Product governs terms for InsuranceContract.", "targetId": "insurance-policy-insurancecontract"}, {"type": "depends_on", "label": "InsuranceProduct specifies required coverages.", "targetId": "CoverageDefinition"}, {"type": "child", "label": "InsuranceProduct may be specialized into one or more variants.", "targetId": "ProductVariant"}]'::jsonb, 'offering,catalog,coverage,template,regulatory-compliance,underwriting,distribution'::text[], 'Supports flexible design of insurance offerings in ACORD models.', '2026-02-13 06:02:51.131347', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-product-rider', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Rider', 'Product', 'A rider in insurance operations refers to an optional supplementary benefit or endorsement that policyholders may add onto their base insurance policy to extend or customize coverage. Riders allow insureds to tailor standard products to their specific needs, potentially filling coverage gaps or offering additional protection such as accidental death, critical illness, or waiver of premium. Effective management of riders involves handling their pricing, eligibility criteria, claim processes, and the interaction of multiple riders across different life events. Insurers track and process riders both during initial policy issuance and throughout the policy lifecycle, including renewals and amendments. Thorough capture and automation of rider data is critical for streamlined underwriting, policy administration, and claims adjudication.', '[{"name": "riderDescription", "type": "string", "description": "Textual explanation of the rider."}, {"name": "riderPremium", "type": "decimal", "description": "Added cost for including the rider."}, {"name": "riderEffectiveDate", "type": "date", "description": "Date on which the rider becomes active for the insured policy."}, {"name": "riderCoverageType", "type": "string", "description": "The specific type or class of coverage provided by this rider."}, {"name": "riderExpirationDate", "type": "date", "description": "The date when the rider coverage or endorsement expires."}]'::jsonb, '[{"type": "child", "label": "Rider extends InsuranceProduct features.", "targetId": "insurance-product-insuranceproduct"}, {"type": "depends_on", "label": "Rider applicability may depend on specific insured risk characteristics.", "targetId": "Insured Risk Profile"}, {"type": "related", "label": "Rider benefits are often triggered or limited by specific claims events.", "targetId": "Claims Event"}]'::jsonb, 'option,extension,benefit,customization,enhancement,supplementary,endorsement'::text[], 'Facilitates customization in policy definitions per ACORD insurance practices.', '2026-02-13 06:02:51.177362', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-product-exclusion', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Exclusion', 'Product', 'The ''Exclusion'' concept in insurance refers to specific events, perils, or property types that are not covered by an insurance policy. Exclusions help define the boundaries of coverage and are included to manage insurer risk and ensure that premiums accurately reflect potential liabilities. They can be categorical (such as natural disasters) or situational (such as damages resulting from intentional acts), and their documentation is crucial for both insurers and insured parties to understand the scope of protection. Exclusions are a central feature in product underwriting, claims eligibility, and policy transparency, and often require legal precision to avoid ambiguity. In AI agent operations, accurately identifying and reasoning about exclusions is critical to policy interpretation, claims automation, and regulatory compliance.', '[{"name": "exclusionType", "type": "enum", "description": "Nature of exclusion, e.g., flood, earthquake."}, {"name": "exclusionDescription", "type": "string", "description": "Details of the excluded event or item."}, {"name": "effectiveDate", "type": "date", "description": "Date the exclusion becomes effective in the policy."}, {"name": "jurisdiction", "type": "string", "description": "Legal region or country where the exclusion applies."}, {"name": "exclusionStatus", "type": "enum", "description": "Current status, e.g., active, pending, expired."}, {"name": "legislativeReference", "type": "string", "description": "Reference to law or regulation underpinning this exclusion."}]'::jsonb, '[{"type": "related", "label": "Exclusion is part of InsuranceProduct documentation.", "targetId": "insurance-product-insuranceproduct"}, {"type": "depends_on", "label": "Exclusion often depends on risk evaluation outcomes.", "targetId": "Risk Assessment"}, {"type": "related", "label": "Exclusion is used during claims assessment.", "targetId": "Claims Processing"}]'::jsonb, 'limitation,restriction,policy,contractual,coverage-boundary,underwriting,legal-reference'::text[], 'Clarifies policy boundaries as mandated in ACORD documentation.', '2026-02-13 06:02:51.222437', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-agent-agent', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Agent', 'Agent', 'In insurance operations, the ''Agent'' refers to a licensed individual or business entity empowered by insurance carriers to market, sell, or negotiate policy contracts on their behalf. Agents serve as a key intermediary connecting prospective policyholders with insurance products and provide support throughout the policy lifecycle from application to claims. This role involves regulatory oversight, client relationship management, and compliance with both insurer policies and regional laws. Agents are integral to new business generation, client onboarding, and ongoing policy servicing. Their activities directly influence the insurer’s risk pool and revenue generation.', '[{"name": "agentId", "type": "string", "description": "Unique identifier for the agent."}, {"name": "licenseStatus", "type": "enum", "description": "Current validity of agent''s license."}, {"name": "appointmentDate", "type": "date", "description": "Date when the agent was officially appointed by the insurer."}, {"name": "agentType", "type": "enum", "description": "Classification of agent, such as captive, independent, or broker."}, {"name": "commissionRate", "type": "decimal", "description": "Percentage rate at which the agent is compensated for policy sales."}]'::jsonb, '[{"type": "related", "label": "Agent assists in completing Application.", "targetId": "insurance-underwriting-application"}, {"type": "child", "label": "Agent receives commission payments for policy sales.", "targetId": "Commission Payment"}, {"type": "related", "label": "Agent provides service and advice to policyholders.", "targetId": "Policyholder"}]'::jsonb, 'sales,intermediary,authorized,compliance,producer,distribution-channel,client-facing'::text[], 'Facilitates distribution and regulatory compliance per ACORD agency standards.', '2026-02-13 06:02:51.266789', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-agent-broker', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Broker', 'Agent', 'Within insurance operations, a broker acts as an independent intermediary, advocating for the interests of clients by sourcing, recommending, and negotiating insurance solutions across multiple insurers. Brokers analyze client coverage needs, present comparative options, facilitate policy placement, and assist with claims processing, ensuring optimal outcomes and compliance with contractual obligations. Their expertise bridges gaps in client knowledge, aiding both personal and commercial lines of insurance, and often contributes to risk assessment and portfolio diversification. In modern insurance ecosystems, data-driven brokers enhance service delivery with analytics and personalized client engagement. Efficient management of brokers is integral to distribution strategy, customer satisfaction, and revenue growth for insurers.', '[{"name": "brokerRegistration", "type": "string", "description": "Official registration or certification for the broker."}, {"name": "brokerCommission", "type": "decimal", "description": "Commission earned for brokerage services."}, {"name": "brokerSpecialization", "type": "string", "description": "Primary lines of insurance or client types the broker specializes in."}, {"name": "activeStatus", "type": "boolean", "description": "Indicates whether the broker is currently authorized and operational."}, {"name": "lastComplianceReviewDate", "type": "date", "description": "Date of the most recent regulatory or internal compliance review for the broker."}]'::jsonb, '[{"type": "related", "label": "Broker recommends InsuranceProduct to clients.", "targetId": "insurance-product-insuranceproduct"}, {"type": "depends_on", "label": "Broker''s activities are dependent on client engagements.", "targetId": "Client"}, {"type": "related", "label": "Broker supports clients during the claims management lifecycle.", "targetId": "Claims Service"}]'::jsonb, 'advisor,market,commission,intermediary,distribution,compliance,licensing'::text[], 'Supports client-centric insurance buying and compliance for ACORD standards.', '2026-02-13 06:02:51.31408', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('insurance-agent-agency', 'insurance', 'ACORD (Association for Cooperative Operations Research and Development)', 'Agency', 'Agent', 'An Agency in insurance operations functions as a business entity responsible for employing, overseeing, and coordinating multiple agents engaged in the selling, servicing, and management of insurance products. Agencies act as intermediaries between insurance carriers and customers, managing compliance, compensation structures, and ensuring that policy administration aligns with both regulatory and company standards. They often aggregate client portfolios, provide marketing and support services, and sometimes handle premium collection and claims assistance processes. Agencies play a crucial role in expanding market reach, maintaining policy quality, and acting as custodians of customer data as well as compliance assurers. Their effectiveness directly impacts carrier relationships, client retention, and operational efficiency across the insurance value chain.', '[{"name": "agencyName", "type": "string", "description": "Legal name of the agency."}, {"name": "agencyType", "type": "enum", "description": "Classification, e.g. captive, independent."}, {"name": "licenseNumber", "type": "string", "description": "Official state or national license identification number for the agency."}, {"name": "parentCarrier", "type": "string", "description": "Name of the insurance carrier(s) for whom the agency primarily sells products."}, {"name": "region", "type": "string", "description": "Geographical area where the agency operates or is licensed."}]'::jsonb, '[{"type": "parent", "label": "Agency oversees Agent operations.", "targetId": "insurance-agent-agent"}, {"type": "related", "label": "Agency manages collections of insurance policies.", "targetId": "Policy Portfolio"}, {"type": "child", "label": "Agency oversees one or more sub-agencies.", "targetId": "Insurance Sub-Agency"}]'::jsonb, 'organization,distribution,network,compliance,sales-operations,partner-management,intermediary'::text[], 'Drives insurance sales channel management per ACORD.', '2026-02-13 06:02:51.358866', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-1', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Credit Rating Action', 'Credit Rating Operations', 'A formal rating decision that assigns, affirms, upgrades, downgrades, or withdraws a credit rating for an issuer or obligation. Each action must follow published methodology and be approved by a rating committee.', '[{"name": "ratingSymbol", "type": "string", "description": "Assigned rating symbol (e.g., AAA, AA+, BBB-)"}, {"name": "actionType", "type": "enum", "description": "Type of action: initial, upgrade, downgrade, affirm, withdraw"}, {"name": "outlookDirection", "type": "enum", "description": "Outlook: positive, negative, stable, developing"}, {"name": "effectiveDate", "type": "date", "description": "Date the rating action takes effect"}]'::jsonb, '[{"type": "related", "label": "Uses Rating Scale", "targetId": "cr-2"}, {"type": "related", "label": "Applies Methodology", "targetId": "cr-5"}, {"type": "related", "label": "Evaluated by Committee", "targetId": "cr-9"}]'::jsonb, 'credit-rating,rating-action,upgrade,downgrade,affirm,withdraw'::text[], 'Agents execute rating actions autonomously with committee oversight, ensuring methodology adherence and regulatory compliance for every rating decision.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g - NRSRO Requirements"}, {"name": "EU CRA Regulation Art. 8"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-10', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'SEC 17g-7 Disclosure', 'Regulatory Compliance', 'Mandatory disclosure document accompanying each rating action, providing the rating rationale, methodology used, data sources, sensitivity analysis, key assumptions, and limitations. Required for all NRSRO ratings under SEC Rule 17g-7.', '[{"name": "disclosureType", "type": "enum", "description": "Type: rating-action, annual-performance, methodology-change"}, {"name": "methodologyCited", "type": "string", "description": "Primary methodology referenced"}, {"name": "sensitivityScenarios", "type": "array", "description": "Key sensitivity analysis scenarios disclosed"}, {"name": "dataSourcesListed", "type": "array", "description": "Primary data sources used in the analysis"}]'::jsonb, '[{"type": "related", "label": "Accompanies Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "References Methodology", "targetId": "cr-5"}, {"type": "related", "label": "Includes Performance Statistics", "targetId": "cr-6"}]'::jsonb, 'credit-rating,SEC-17g-7,disclosure,transparency,NRSRO,rating-rationale'::text[], 'Disclosure agents auto-generate compliant 17g-7 forms from rating analysis outputs, ensuring completeness and consistency across all required fields.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g-7 - Rating Action Disclosure"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-11', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Credit Surveillance Event', 'Credit Rating Operations', 'A material event detected through ongoing monitoring that may impact the creditworthiness of a rated entity. Includes financial deterioration signals, governance changes, sector-wide stress, and regulatory actions that may trigger a rating review.', '[{"name": "eventType", "type": "enum", "description": "Type: financial-deterioration, governance-change, sector-stress, regulatory-action, M&A"}, {"name": "materialityLevel", "type": "enum", "description": "Materiality: high, medium, low"}, {"name": "detectionSource", "type": "string", "description": "Source of event detection (market data, news, filing, manual)"}, {"name": "responseAction", "type": "enum", "description": "Response: no-action, enhanced-monitoring, watch-placement, immediate-review"}]'::jsonb, '[{"type": "related", "label": "May Trigger Watch Placement", "targetId": "cr-4"}, {"type": "related", "label": "Affects Issuer Profile", "targetId": "cr-8"}, {"type": "related", "label": "May Lead to Rating Action", "targetId": "cr-1"}]'::jsonb, 'credit-rating,surveillance,event-detection,materiality,early-warning,monitoring'::text[], 'Surveillance agents continuously scan market data, news feeds, and financial filings to detect rating-relevant events and trigger appropriate review workflows.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "IOSCO Code of Conduct - Ongoing Monitoring"}, {"name": "EU CRA Regulation Art. 8"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-12', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Structured Finance Vehicle', 'Rated Entities', 'A special purpose entity created to pool and tranche credit risk from underlying assets, including ABS, MBS, CDO, CLO, and CMBS structures. Ratings are assigned to individual tranches based on credit enhancement and waterfall mechanics.', '[{"name": "structureType", "type": "enum", "description": "Structure type: ABS, RMBS, CMBS, CDO, CLO"}, {"name": "collateralType", "type": "string", "description": "Underlying asset type"}, {"name": "trancheCount", "type": "integer", "description": "Number of rated tranches"}, {"name": "creditEnhancement", "type": "decimal", "description": "Credit enhancement percentage for senior tranche"}]'::jsonb, '[{"type": "related", "label": "Subject of Tranche Rating", "targetId": "cr-1"}, {"type": "related", "label": "Contains Tranche Structure", "targetId": "cr-13"}, {"type": "related", "label": "Analyzed using SF Methodology", "targetId": "cr-5"}]'::jsonb, 'credit-rating,structured-finance,ABS,MBS,CDO,CLO,securitization,SPV'::text[], 'Structured finance agents model complex waterfall mechanics and assess tranche-level credit risk under multiple stress scenarios.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-13', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Tranche Structure', 'Structured Products', 'The hierarchical layering of credit risk within a structured finance vehicle, defining payment priority, loss allocation, and credit enhancement for each tranche. Senior tranches absorb losses last; equity tranches absorb first.', '[{"name": "seniority", "type": "enum", "description": "Tranche seniority: super-senior, senior, mezzanine, junior, equity"}, {"name": "attachmentPoint", "type": "decimal", "description": "Loss attachment point percentage"}, {"name": "detachmentPoint", "type": "decimal", "description": "Loss detachment point percentage"}, {"name": "couponRate", "type": "decimal", "description": "Tranche coupon rate"}]'::jsonb, '[{"type": "related", "label": "Part of Structured Finance Vehicle", "targetId": "cr-12"}, {"type": "related", "label": "Protected by Credit Enhancement", "targetId": "cr-14"}]'::jsonb, 'credit-rating,tranche,seniority,waterfall,attachment-point,subordination'::text[], 'Agents evaluate tranche structures using cashflow modeling and Monte Carlo simulation to determine appropriate tranche-level ratings.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-14', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Credit Enhancement', 'Structured Products', 'Mechanisms that improve the credit quality of a structured finance tranche beyond the credit quality of the underlying collateral pool. Includes subordination, overcollateralization, reserve accounts, excess spread, and third-party guarantees.', '[{"name": "enhancementType", "type": "enum", "description": "Type: subordination, overcollateralization, reserve-account, excess-spread, guarantee"}, {"name": "enhancementLevel", "type": "decimal", "description": "Enhancement level as percentage of pool balance"}, {"name": "provider", "type": "string", "description": "Third-party enhancement provider if applicable"}]'::jsonb, '[{"type": "related", "label": "Protects Tranche Structure", "targetId": "cr-13"}, {"type": "related", "label": "Within Structured Finance Vehicle", "targetId": "cr-12"}]'::jsonb, 'credit-rating,credit-enhancement,subordination,overcollateralization,reserve-account'::text[], 'Agents calculate required credit enhancement levels under stress scenarios and validate sufficiency for target rating levels.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-15', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Conflict of Interest Declaration', 'Regulatory Compliance', 'A formal declaration and screening process to identify and manage conflicts of interest in the credit rating process, including issuer-paid model conflicts, revenue concentration, analyst personal interests, and ancillary service restrictions.', '[{"name": "conflictType", "type": "enum", "description": "Type: issuer-paid, revenue-concentration, personal-interest, ancillary-service"}, {"name": "mitigationAction", "type": "string", "description": "Mitigation measure applied"}, {"name": "screeningResult", "type": "enum", "description": "Result: clear, flagged, escalated, recused"}, {"name": "attestationDate", "type": "date", "description": "Date of conflict attestation"}]'::jsonb, '[{"type": "related", "label": "Screened before Committee", "targetId": "cr-9"}, {"type": "related", "label": "Related to Issuer", "targetId": "cr-8"}]'::jsonb, 'credit-rating,conflict-of-interest,independence,firewall,IOSCO,recusal'::text[], 'Conflict screening agents automatically check analyst-issuer relationships, revenue dependency, and personal holdings before each rating action.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "IOSCO Code of Conduct - Conflict Management"}, {"name": "EU CRA Regulation Art. 6"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-16', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'NRSRO Registration', 'Regulatory Compliance', 'Registration status and ongoing compliance requirements for Nationally Recognized Statistical Rating Organizations under SEC oversight. Covers Form NRSRO filing, annual certification, examination readiness, and performance statistics publication.', '[{"name": "registrationStatus", "type": "enum", "description": "Status: registered, pending, suspended, withdrawn"}, {"name": "ratingClasses", "type": "array", "description": "Registered rating classes (financial institutions, insurance, corporate, ABS, government)"}, {"name": "lastExaminationDate", "type": "date", "description": "Date of last SEC examination"}, {"name": "annualCertificationDate", "type": "date", "description": "Date of most recent annual certification"}]'::jsonb, '[{"type": "related", "label": "Requires 17g-7 Disclosures", "targetId": "cr-10"}, {"type": "related", "label": "Publishes Performance Statistics", "targetId": "cr-6"}]'::jsonb, 'credit-rating,NRSRO,SEC-registration,examination,certification,Form-NRSRO'::text[], 'Compliance agents track NRSRO registration requirements, upcoming examination dates, and annual certification deadlines.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g - NRSRO Registration"}, {"name": "Dodd-Frank Title IX"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-17', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Sovereign Credit Analysis', 'Rating Methodologies', 'A comprehensive analytical framework for assessing sovereign creditworthiness, evaluating fiscal strength, monetary policy flexibility, institutional quality, economic resilience, and external vulnerability. Sovereign ratings serve as ceilings for most domestic issuers.', '[{"name": "fiscalBalance", "type": "decimal", "description": "Government fiscal balance as % of GDP"}, {"name": "debtToGDP", "type": "decimal", "description": "Government debt as % of GDP"}, {"name": "institutionalScore", "type": "decimal", "description": "Institutional strength assessment score"}, {"name": "externalVulnerability", "type": "decimal", "description": "External vulnerability indicator"}, {"name": "countryCeiling", "type": "string", "description": "Maximum domestic issuer rating"}]'::jsonb, '[{"type": "related", "label": "Profiles Sovereign Entity", "targetId": "cr-8"}, {"type": "related", "label": "Follows Sovereign Methodology", "targetId": "cr-5"}, {"type": "related", "label": "Results in Sovereign Rating", "targetId": "cr-1"}]'::jsonb, 'credit-rating,sovereign,country-risk,fiscal,monetary-policy,institutional-strength'::text[], 'Sovereign analysis agents integrate macroeconomic data, political risk assessments, and institutional quality metrics to produce comprehensive sovereign credit profiles.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g-7 - Performance Statistics"}, {"name": "EU CRA Regulation Art. 8"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-2', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Rating Scale', 'Credit Rating Operations', 'A standardized ordinal scale used to express relative creditworthiness of issuers or obligations. Includes long-term scales (AAA to D), short-term scales (F1+ to D), and recovery ratings.', '[{"name": "scaleType", "type": "enum", "description": "Scale type: long-term, short-term, recovery, national"}, {"name": "investmentGradeCutoff", "type": "string", "description": "Lowest investment-grade symbol (e.g., BBB-)"}, {"name": "defaultCategory", "type": "string", "description": "Symbol denoting default (e.g., D, RD)"}, {"name": "notchCount", "type": "integer", "description": "Number of distinct rating levels in the scale"}]'::jsonb, '[{"type": "related", "label": "Applied in Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "Calibrated by Transition Matrix", "targetId": "cr-6"}]'::jsonb, 'credit-rating,rating-scale,investment-grade,speculative-grade,notch'::text[], 'Agents map quantitative model outputs to rating scale symbols and validate consistency across comparable issuers.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-3', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Rating Outlook', 'Credit Rating Operations', 'A forward-looking assessment indicating the likely direction of a rating over the medium term (typically 12-24 months). Outlooks signal potential rating changes to market participants.', '[{"name": "direction", "type": "enum", "description": "Outlook direction: positive, negative, stable, developing"}, {"name": "horizon", "type": "string", "description": "Time horizon for outlook assessment"}, {"name": "triggerFactors", "type": "array", "description": "Key factors that could trigger a rating change"}]'::jsonb, '[{"type": "related", "label": "Accompanies Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "May Transition to Watch", "targetId": "cr-4"}]'::jsonb, 'credit-rating,outlook,forward-looking,medium-term'::text[], 'Surveillance agents continuously evaluate outlook triggers and recommend outlook changes when thresholds are breached.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-4', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Rating Watch', 'Credit Rating Operations', 'A designation indicating a rating is under active review for potential change, typically within 90 days. Watch placement signals heightened probability of near-term rating action due to an identifiable event or trend.', '[{"name": "watchDirection", "type": "enum", "description": "Watch direction: positive, negative, evolving"}, {"name": "triggerEvent", "type": "string", "description": "Event triggering watch placement"}, {"name": "expectedResolutionDays", "type": "integer", "description": "Expected resolution timeframe in days"}, {"name": "resolutionOptions", "type": "array", "description": "Possible resolution outcomes"}]'::jsonb, '[{"type": "related", "label": "Resolves to Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "Escalated from Outlook", "targetId": "cr-3"}, {"type": "related", "label": "Triggered by Surveillance", "targetId": "cr-11"}]'::jsonb, 'credit-rating,watch-list,credit-watch,review,near-term'::text[], 'Surveillance agents detect watch-triggering events in real-time and initiate watch placement workflows with appropriate analyst notification.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "IOSCO Code of Conduct"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-5', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Rating Methodology', 'Rating Methodologies', 'A published, structured analytical framework defining the criteria, factors, weightings, and procedures used to assign credit ratings to a specific asset class or issuer type. Methodologies must be publicly disclosed and consistently applied.', '[{"name": "assetClass", "type": "string", "description": "Target asset class (sovereign, corporate, structured finance, etc.)"}, {"name": "versionNumber", "type": "string", "description": "Current methodology version"}, {"name": "effectiveDate", "type": "date", "description": "Date methodology became effective"}, {"name": "keyRatingFactors", "type": "array", "description": "Primary factors considered in the methodology"}]'::jsonb, '[{"type": "related", "label": "Applied in Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "Calibrated using Transition Data", "targetId": "cr-6"}, {"type": "related", "label": "Disclosed per SEC 17g-7", "targetId": "cr-10"}]'::jsonb, 'credit-rating,methodology,criteria,analytical-framework,asset-class'::text[], 'Methodology compliance agents validate that every rating action correctly applies the published methodology criteria and flags deviations for committee review.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g-7 - Methodology Disclosure"}, {"name": "EU CRA Regulation Art. 8"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-6', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Transition Matrix', 'Rating Methodologies', 'A statistical table showing the historical frequency of rating migrations between rating categories over a defined time period. Used for model validation, methodology calibration, and rating performance measurement.', '[{"name": "cohortPeriod", "type": "string", "description": "Time period for cohort analysis (1-year, 3-year, etc.)"}, {"name": "assetClass", "type": "string", "description": "Asset class scope of the matrix"}, {"name": "defaultRate", "type": "decimal", "description": "Observed default rate for the period"}, {"name": "stabilityRate", "type": "decimal", "description": "Percentage of ratings that remained unchanged"}]'::jsonb, '[{"type": "related", "label": "Validates Rating Scale", "targetId": "cr-2"}, {"type": "related", "label": "Feeds Default Probability Model", "targetId": "cr-7"}, {"type": "related", "label": "Published in Performance Statistics", "targetId": "cr-10"}]'::jsonb, 'credit-rating,transition-matrix,migration,default-rate,performance,cohort'::text[], 'Agents generate and analyze transition matrices to validate model accuracy and identify rating drift across portfolios.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g-7 - Performance Statistics"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-7', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Default Probability Model', 'Rating Methodologies', 'A quantitative model estimating the likelihood of issuer or obligation default within a specified time horizon. Includes point-in-time, through-the-cycle, and hybrid approaches calibrated to historical default data.', '[{"name": "modelType", "type": "enum", "description": "Model approach: point-in-time, through-the-cycle, hybrid"}, {"name": "timeHorizon", "type": "string", "description": "Default probability time horizon"}, {"name": "calibrationDate", "type": "date", "description": "Date of most recent model calibration"}, {"name": "discriminatoryPower", "type": "decimal", "description": "Model accuracy metric (e.g., Gini coefficient, AUC)"}]'::jsonb, '[{"type": "related", "label": "Component of Credit Risk Assessment", "targetId": "fibo-8"}, {"type": "related", "label": "Calibrated from Transition Matrix", "targetId": "cr-6"}, {"type": "related", "label": "Part of Rating Methodology", "targetId": "cr-5"}]'::jsonb, 'credit-rating,default-probability,PD,quantitative-model,calibration,Merton'::text[], 'Quantitative modeling agents execute default probability calculations and validate model discrimination power against historical benchmarks.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-8', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Issuer Profile', 'Rated Entities', 'A comprehensive profile of an entity whose creditworthiness is being rated, including financial metrics, industry classification, ownership structure, and rating history. Covers corporates, financial institutions, sovereigns, and sub-sovereign entities.', '[{"name": "issuerType", "type": "enum", "description": "Type: corporate, financial-institution, sovereign, sub-sovereign, supranational"}, {"name": "sectorClassification", "type": "string", "description": "Industry sector classification"}, {"name": "currentRating", "type": "string", "description": "Current long-term issuer rating"}, {"name": "ratingHistory", "type": "array", "description": "Historical rating actions for this issuer"}]'::jsonb, '[{"type": "related", "label": "Subject of Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "Monitored by Surveillance", "targetId": "cr-11"}, {"type": "related", "label": "Is a Counterparty", "targetId": "fibo-5"}]'::jsonb, 'credit-rating,issuer,rated-entity,corporate,sovereign,financial-institution'::text[], 'Agents maintain comprehensive issuer profiles with real-time financial data integration and automated peer group comparisons.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('cr-9', 'financial_services', 'FIBO (Financial Industry Business Ontology)', 'Rating Committee', 'Regulatory Compliance', 'A formal deliberative body of qualified analysts that reviews and approves all rating actions. Committee composition, quorum requirements, and voting procedures are governed by internal policies and regulatory requirements.', '[{"name": "committeeType", "type": "enum", "description": "Type: initial rating, surveillance, methodology, appeal"}, {"name": "quorumRequirement", "type": "integer", "description": "Minimum voting members required"}, {"name": "votingMethod", "type": "enum", "description": "Voting method: simple-majority, supermajority, consensus"}, {"name": "chairQualification", "type": "string", "description": "Required chair qualification level"}]'::jsonb, '[{"type": "related", "label": "Approves Rating Action", "targetId": "cr-1"}, {"type": "related", "label": "Subject to Conflict Screening", "targetId": "cr-15"}, {"type": "related", "label": "Validates Methodology Application", "targetId": "cr-5"}]'::jsonb, 'credit-rating,rating-committee,governance,approval,quorum,voting'::text[], 'Agents prepare committee packages with pre-computed analytics, peer comparisons, and methodology compliance checks to streamline committee deliberation.', '2026-02-15 10:19:29.067017', ''::text[], 'industry-standard', 0, '[{"name": "SEC Rule 17g - NRSRO Governance"}, {"name": "EU CRA Regulation Art. 7"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-c9eb0089-ba9c-44a9-b1c9-b7fd89375566', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Scale', 'Credit Rating Operations', 'A Rating Scale is an essential framework used by credit rating agencies to consistently express the relative creditworthiness of issuers (such as corporations, sovereigns, or financial instruments). The scale provides standardized categories (e.g., AAA, AA, A, BBB, down to D for default) that convey the likelihood of default or credit risk over a specified time horizon. Long-term scales assess risks over years, while short-term scales address obligations due within a year; recovery ratings offer insights into expected recoveries post-default. In financial operations, the rating scale supports risk management, regulatory reporting, investment decision-making, and product pricing. This concept ensures transparency and comparability across different entities and jurisdictions.', '[{"name": "scaleType", "type": "enum", "description": "Indicates whether the scale is for long-term, short-term, or recovery ratings."}, {"name": "scaleVersion", "type": "string", "description": "The version or release date of the rating scale definition."}, {"name": "ordinalLevels", "type": "integer", "description": "The number of discrete rating levels defined in the scale."}, {"name": "agencyProprietary", "type": "boolean", "description": "Specifies whether the scale is proprietary to a particular agency."}]'::jsonb, '[]'::jsonb, 'Risk Measurement,Reference Data,Regulatory Compliance,Credit Assessment'::text[], NULL, '2026-02-15 11:39:11.655301', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-a4071341-ebef-4153-b2a3-90a39379b129', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Outlook', 'Credit Rating Operations', 'A Rating Outlook provides a qualitative view of the anticipated direction for an entity''s credit rating over a medium-term horizon (usually 12–24 months). It captures the credit rating agency''s forward-looking opinion on whether a rating is likely to improve, deteriorate, or remain stable given current economic trends, financial performance, and market conditions. Market participants use this information to anticipate changes in creditworthiness before formal rating actions are taken. The Rating Outlook is a critical tool in risk management, portfolio monitoring, and regulatory notifications. Financial institutions rely on the outlook to adjust exposure and make more informed lending, investment, and counterparty risk decisions.', '[{"name": "outlookDirection", "type": "enum", "description": "Indicates whether the outlook is Positive, Negative, Stable, or Developing."}, {"name": "effectiveDate", "type": "date", "description": "Date on which the outlook became effective or was last updated."}, {"name": "agencyName", "type": "string", "description": "Name of the credit rating agency providing the outlook."}, {"name": "outlookPeriodMonths", "type": "integer", "description": "Number of months for which the outlook is intended (typically 12–24)."}]'::jsonb, '[{"type": "related", "label": "Precedes or informs potential credit rating actions", "targetId": "custom-b5eae9a9-2b3a-456b-be64-198c95c7508a"}]'::jsonb, 'Early Warning Indicator,Portfolio Monitoring,Counterparty Risk,Decision Support,Regulatory Reporting'::text[], NULL, '2026-02-16 03:04:35.339813', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-b5eae9a9-2b3a-456b-be64-198c95c7508a', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Credit Rating Action', 'Credit Rating Operations', 'A Credit Rating Action is a formal process in which a credit rating agency determines, adjusts, confirms, or removes a rating on a financial obligation, entity, or security. Ratings actions reflect the agency’s current assessment of default risks and are essential for transparent communication to investors, regulators, and market participants. The process is governed by established methodologies and necessitates approval from a committee, ensuring independence and mitigating analyst bias. In financial services operations, tracking and understanding each rating action is critical for effective risk management, portfolio analytics, and transparent client communications. Such actions have direct downstream effects on compliance, capital adequacy calculations, and customer relationship management.', '[{"name": "actionType", "type": "enum", "description": "Type of rating action (e.g., affirm, upgrade, downgrade, withdraw)."}, {"name": "effectiveDate", "type": "date", "description": "The date when the rating action becomes effective."}, {"name": "committeeDecisionReference", "type": "string", "description": "Reference or link to the approving committee’s decision documentation."}, {"name": "publicAnnouncementUrl", "type": "string", "description": "Link to the public announcement or press release regarding the action."}]'::jsonb, '[{"type": "related", "label": "Approval provided by Rating Committee", "targetId": "custom-4b88486c-0fee-41c6-bb17-e6f0dfbbd9fa"}]'::jsonb, 'regulatory-reporting,risk-management,decision-audit,rating-agency-compliance'::text[], NULL, '2026-02-16 04:36:47.265688', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-f9642ce5-09a0-4d4e-a5d7-ead500fa225a', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Watch', 'Credit Rating Operations', 'A ''Rating Watch'' is a specialized status assigned by credit rating agencies to indicate that a particular credit rating is currently under heightened scrutiny due to the emergence of a specific event or observable trend. This designation typically suggests that there is a significant chance that the rating may be upgraded, downgraded, or affirmed within a short period, generally not exceeding 90 days. The event or trigger prompting the watch could include pending mergers, regulatory actions, or significant financial developments. In the context of financial services operations, a Rating Watch directly impacts risk monitoring, pricing models, and regulatory reporting obligations. Institutions must actively track these alerts to adjust risk exposure and investor communications proactively.', '[{"name": "watchInitiationDate", "type": "date", "description": "The date on which the Rating Watch was initiated by the agency."}, {"name": "expectedResolutionPeriod", "type": "string", "description": "The anticipated timeframe for maintaining the Rating Watch before action is taken."}, {"name": "watchReason", "type": "string", "description": "The specific event, trend, or trigger that led to the placement of the rating on watch."}, {"name": "watchDirection", "type": "enum", "description": "Indicates if the watch is for upgrade, downgrade, or uncertain direction."}]'::jsonb, '[{"type": "related", "label": "Potential outcome of Rating Watch", "targetId": "custom-b5eae9a9-2b3a-456b-be64-198c95c7508a"}]'::jsonb, 'Credit Surveillance,Market Moving Event,Compliance Trigger,Credit Signal'::text[], NULL, '2026-02-16 07:15:04.464595', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-0c971ef6-837f-4857-8c11-00ccbfde6ad3', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Credit Surveillance Event', 'Credit Rating Operations', 'A Credit Surveillance Event represents a significant occurrence identified during ongoing credit monitoring that may affect a rated entity’s creditworthiness. Such events encompass instances like sharp declines in financial performance, major leadership changes, industry-wide disruptions, or regulatory interventions. These events act as triggers for credit analysts and automated surveillance systems to initiate deeper reviews of existing ratings or recommend actions. Early detection of credit surveillance events enables proactive risk management and supports timely updates to rating reports, ensuring stakeholders have the most accurate risk assessments. In the context of financial services operations, they are critical markers for both human and AI agents in the lifecycle of credit risk management.', '[{"name": "eventDate", "type": "date", "description": "The date when the credit surveillance event was detected."}, {"name": "eventSource", "type": "string", "description": "Originating source or channel where the event was identified (e.g., news, regulatory filing, internal alert)."}, {"name": "materialityLevel", "type": "enum", "description": "An assessment of the significance of the event (e.g., High, Medium, Low)."}, {"name": "requiresAction", "type": "boolean", "description": "Indicates whether the event necessitates a formal rating review or intervention."}]'::jsonb, '[]'::jsonb, 'Event Detection,Early Warning,Risk Monitoring,Material Event,Rating Trigger'::text[], NULL, '2026-02-16 08:29:55.050532', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-fd64f6e7-4a4b-4013-958a-f65f753887dd', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Default Probability Model', 'Rating Methodologies', 'A Default Probability Model is a quantitative analytical tool used within credit rating methodologies to assess the likelihood that a borrower or financial obligation will default within a given time period. It incorporates statistical and econometric methods to evaluate default risks based on historical performance, economic indicators, and issuer-specific attributes. These models can be point-in-time (responsive to current conditions), through-the-cycle (reflecting long-term average risk), or hybrid forms, and are calibrated using comprehensive historical default databases. In financial services operations, such models inform risk management decisions, capital allocation, loan pricing, and compliance reporting. Their accuracy and transparency are critical for both internal governance and regulatory scrutiny.', '[{"name": "modelType", "type": "enum", "description": "Specifies whether the model is point-in-time, through-the-cycle, or hybrid."}, {"name": "calibrationDate", "type": "date", "description": "The most recent date on which the model was calibrated."}, {"name": "historicalDataWindow", "type": "string", "description": "The time span of historical data used for model calibration (e.g., 2000-2023)."}, {"name": "validationStatus", "type": "enum", "description": "Current regulatory validation and approval state (e.g., pending, approved, rejected)."}]'::jsonb, '[{"type": "related", "label": "Used as an input in broader credit risk assessments", "targetId": "fibo-8"}]'::jsonb, 'Credit Risk Modeling,Model Risk Management,Regulatory Compliance,Risk Analytics,Quantitative Finance'::text[], NULL, '2026-02-16 08:32:47.778364', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-6c145521-673e-42e4-97b3-c26704c5a020', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Methodology', 'Rating Methodologies', 'The ''Rating Methodology'' concept refers to a detailed and standardized set of analytical procedures and criteria published by credit rating agencies to guide the assignment of credit ratings for different asset classes or issuer types, such as corporates, sovereigns, or structured finance instruments. It ensures transparency, consistency, and comparability across ratings by defining key factors, their relative importance (weightings), and the decision-making process involved in evaluating creditworthiness. In financial services operations, this framework is critical for risk assessment, regulatory reporting, and investment decision support. Compliance with disclosed methodologies also underpins market trust in the ratings produced. Rating methodologies must be updated as needed to reflect evolving market conditions, regulations, or new data insights.', '[{"name": "applicableAssetClass", "type": "string", "description": "The specific asset class for which the methodology is designed (e.g., sovereign debt, corporate bonds, structured products)."}, {"name": "lastRevisionDate", "type": "date", "description": "The most recent date on which the methodology was reviewed or updated."}, {"name": "methodologyVersion", "type": "string", "description": "A version identifier to track changes in methodology over time."}, {"name": "approvalStatus", "type": "enum", "description": "The approval state of the methodology (e.g., ''Draft'', ''Approved'', ''Under Review'')."}]'::jsonb, '[]'::jsonb, 'regulatory-compliance,model-interpretability,governance,auditability'::text[], NULL, '2026-02-16 08:34:26.639339', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-2490c875-41d0-4cd8-90f1-5f2fee6739ec', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Transition Matrix', 'Rating Methodologies', 'A Transition Matrix represents the probability distribution of credit rating changes for financial instruments or counterparties over a specified time horizon. It captures both upgrades, downgrades, and instances where ratings remain unchanged, based on historical data. In financial services, transition matrices are essential for stress testing, risk modeling, and validating credit assessment methodologies. Institutions use transition matrices to assess credit quality migration risk, model expected and unexpected credit losses, and refine internal rating systems. Their comprehensive statistical nature makes them vital for both internal risk management and external disclosures.', '[{"name": "timeHorizon", "type": "string", "description": "The defined period over which rating transitions are measured (e.g., one year, three years)."}, {"name": "sourceDataType", "type": "enum", "description": "The type of input data source used for the matrix (e.g., issuer ratings, instrument ratings, portfolio data)."}, {"name": "calibrationDate", "type": "date", "description": "The date when the transition matrix was last calibrated or updated."}]'::jsonb, '[]'::jsonb, 'credit-migration,risk-analytics,model-validation,statistical-methodology,portfolio-monitoring'::text[], NULL, '2026-02-16 08:35:57.565221', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-d5e1cb84-d3d3-442b-8e26-87fa24d009c3', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Sovereign Credit Analysis', 'Rating Methodologies', 'Sovereign Credit Analysis involves evaluating the creditworthiness of a nation, incorporating diverse factors such as fiscal strength (budgetary discipline, debt levels), monetary policy flexibility, institutional effectiveness, economic structure, and vulnerability to external shocks. This analysis is foundational in determining the sovereign’s ability and willingness to meet its financial obligations, which has downstream effects on the perceived credit quality of most other domestic entities. In financial services operations, accurate sovereign credit analysis informs risk limits, country exposure, pricing models, and investment decisions. It requires integration with real-time macroeconomic, political, and market data, leveraging sophisticated modeling approaches for forward-looking assessment. Sovereign ratings typically serve as credit ceilings for sub-sovereign and corporate issuers within the rated country.', '[{"name": "latestRating", "type": "enum", "description": "The most current credit rating assigned to the sovereign (e.g. AAA, AA, A)"}, {"name": "ratingOutlook", "type": "enum", "description": "The outlook associated with the rating (e.g. Stable, Positive, Negative, Watch)"}, {"name": "nextReviewDate", "type": "date", "description": "Scheduled date for the next sovereign credit assessment"}, {"name": "leadAnalyst", "type": "string", "description": "Name or identifier of the responsible sovereign analyst"}]'::jsonb, '[]'::jsonb, 'Sovereign Risk,Country Analysis,Risk Assessment,Macroeconomic Evaluation'::text[], NULL, '2026-02-16 08:37:34.877724', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-096764df-ee5a-4cef-a741-1c311641605e', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Issuer Profile', 'Rated Entities', 'An Issuer Profile is a centralized data construct that aggregates and maintains critical information about an entity (such as a corporation, financial institution, sovereign, or sub-sovereign) subject to creditworthiness evaluation. It encapsulates essential data points—financial performance indicators, industry codes, ownership and governance structures, prior and current credit ratings, and other salient attributes relevant to risk and regulatory assessment. This profile forms the foundation for credit rating analysis, investor disclosure, and regulatory reporting processes in financial services. As a living data representation, it is continuously updated to reflect changes that may impact the entity’s credit risk. Reliable Issuer Profiles enhance transparency, support due diligence, and facilitate comparability across rated entities for stakeholders including rating agencies, investment managers, and regulators.', '[{"name": "incorporationDate", "type": "date", "description": "The official date when the entity was legally incorporated or established."}, {"name": "primaryRegulator", "type": "string", "description": "The main regulatory body overseeing the entity."}, {"name": "entityStatus", "type": "enum", "description": "The current operational status of the entity (e.g., active, in liquidation, suspended)."}, {"name": "ultimateBeneficialOwner", "type": "string", "description": "The individual or entity that is the ultimate beneficial owner of the issuer."}]'::jsonb, '[{"type": "related", "label": "The Issuer Profile is a crucial component of the Issuer Engagement process, providing essential information about the issuer''s background and operations.", "targetId": "Issuer Engagement"}, {"type": "related", "label": "The Issuer Profile is related to KYC Verification as it contains information necessary for understanding the issuer''s legitimacy and compliance with regulations.", "targetId": "KYC Verification"}, {"type": "related", "label": "The Issuer Profile governs the content of the Regulatory Report by providing necessary issuer information required for compliance and reporting purposes.", "targetId": "Regulatory Report"}, {"type": "depends_on", "label": "The Issuer Profile depends on the Compliance Check to ensure that the issuer adheres to legal and regulatory requirements.", "targetId": "Compliance Check"}, {"type": "related", "label": "The Issuer Profile is measured by the Credit Risk Assessment, which evaluates the creditworthiness of the issuer based on the information contained in the profile.", "targetId": "Credit Risk Assessment"}, {"type": "related", "label": "The Issuer Profile is required in Transaction Monitoring to identify and assess risks associated with transactions involving the issuer.", "targetId": "Transaction Monitoring"}, {"type": "related", "label": "The Issuer Profile is related to the Sanctions List as it may include information about whether the issuer is subject to any sanctions or restrictions.", "targetId": "Sanctions List"}, {"type": "related", "label": "The Issuer Profile governs the issuerInformationDisclosure process by outlining what information about the issuer needs to be disclosed.", "targetId": "issuerInformationDisclosure"}]'::jsonb, 'KYC,Due Diligence,Client Onboarding,Counterparty Risk'::text[], NULL, '2026-02-16 08:39:48.597304', ''::text[], 'custom-extension', 0, '[]'::jsonb, 9, '[{"label": "Issuer Profile", "version": 1, "synonyms": [], "updatedAt": "2026-03-06T12:17:40.749Z", "properties": [{"name": "incorporationDate", "type": "date", 