 evaluation. It encapsulates essential data points—financial performance indicators, industry codes, ownership and governance structures, prior and current credit ratings, and other salient attributes relevant to risk and regulatory assessment. This profile forms the foundation for credit rating analysis, investor disclosure, and regulatory reporting processes in financial services. As a living data representation, it is continuously updated to reflect changes that may impact the entity’s credit risk. Reliable Issuer Profiles enhance transparency, support due diligence, and facilitate comparability across rated entities for stakeholders including rating agencies, investment managers, and regulators.", "relationships": [{"type": "related", "label": "The Issuer Profile is a crucial component of the Issuer Engagement process, providing essential information about the issuer''s background and operations.", "targetId": "Issuer Engagement"}, {"type": "related", "label": "The Issuer Profile is related to KYC Verification as it contains information necessary for understanding the issuer''s legitimacy and compliance with regulations.", "targetId": "KYC Verification"}, {"type": "related", "label": "The Issuer Profile governs the content of the Regulatory Report by providing necessary issuer information required for compliance and reporting purposes.", "targetId": "Regulatory Report"}, {"type": "depends_on", "label": "The Issuer Profile depends on the Compliance Check to ensure that the issuer adheres to legal and regulatory requirements.", "targetId": "Compliance Check"}, {"type": "related", "label": "The Issuer Profile is measured by the Credit Risk Assessment, which evaluates the creditworthiness of the issuer based on the information contained in the profile.", "targetId": "Credit Risk Assessment"}, {"type": "related", "label": "The Issuer Profile is required in Transaction Monitoring to identify and assess risks associated with transactions involving the issuer.", "targetId": "Transaction Monitoring"}], "linkedRegulations": []}, {"label": "Issuer Profile", "version": 8, "synonyms": [], "updatedAt": "2026-03-06T12:18:46.594Z", "properties": [{"name": "incorporationDate", "type": "date", "description": "The official date when the entity was legally incorporated or established."}, {"name": "primaryRegulator", "type": "string", "description": "The main regulatory body overseeing the entity."}, {"name": "entityStatus", "type": "enum", "description": "The current operational status of the entity (e.g., active, in liquidation, suspended)."}, {"name": "ultimateBeneficialOwner", "type": "string", "description": "The individual or entity that is the ultimate beneficial owner of the issuer."}], "description": "An Issuer Profile is a centralized data construct that aggregates and maintains critical information about an entity (such as a corporation, financial institution, sovereign, or sub-sovereign) subject to creditworthiness evaluation. It encapsulates essential data points—financial performance indicators, industry codes, ownership and governance structures, prior and current credit ratings, and other salient attributes relevant to risk and regulatory assessment. This profile forms the foundation for credit rating analysis, investor disclosure, and regulatory reporting processes in financial services. As a living data representation, it is continuously updated to reflect changes that may impact the entity’s credit risk. Reliable Issuer Profiles enhance transparency, support due diligence, and facilitate comparability across rated entities for stakeholders including rating agencies, investment managers, and regulators.", "relationships": [{"type": "related", "label": "The Issuer Profile is a crucial component of the Issuer Engagement process, providing essential information about the issuer''s background and operations.", "targetId": "Issuer Engagement"}, {"type": "related", "label": "The Issuer Profile is related to KYC Verification as it contains information necessary for understanding the issuer''s legitimacy and compliance with regulations.", "targetId": "KYC Verification"}, {"type": "related", "label": "The Issuer Profile governs the content of the Regulatory Report by providing necessary issuer information required for compliance and reporting purposes.", "targetId": "Regulatory Report"}, {"type": "depends_on", "label": "The Issuer Profile depends on the Compliance Check to ensure that the issuer adheres to legal and regulatory requirements.", "targetId": "Compliance Check"}, {"type": "related", "label": "The Issuer Profile is measured by the Credit Risk Assessment, which evaluates the creditworthiness of the issuer based on the information contained in the profile.", "targetId": "Credit Risk Assessment"}, {"type": "related", "label": "The Issuer Profile is required in Transaction Monitoring to identify and assess risks associated with transactions involving the issuer.", "targetId": "Transaction Monitoring"}, {"type": "related", "label": "The Issuer Profile is related to the Sanctions List as it may include information about whether the issuer is subject to any sanctions or restrictions.", "targetId": "Sanctions List"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-e2f2d12c-fe2b-46ac-b58f-dd0b08ac9e13', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Structured Finance Vehicle', 'Rated Entities', 'A Structured Finance Vehicle (SFV) is a specially created legal entity used in financial markets to aggregate underlying assets such as loans, mortgages, or receivables, and issue securities backed by these pools. SFVs facilitate risk transformation and investor diversification by structuring tranches with varying exposures and credit enhancements. They play a pivotal role in capital markets through asset-backed securities (ABS), mortgage-backed securities (MBS), collateralized debt obligations (CDO), collateralized loan obligations (CLO), and commercial mortgage-backed securities (CMBS). These vehicles are rated based on their underlying asset quality, structural features like waterfall mechanics, and risk mitigation strategies. SFVs must be carefully managed for transparency, reporting, and regulatory compliance as they directly influence market stability and investor protection.', '[{"name": "assetPoolComposition", "type": "string", "description": "Detailed description or classification of underlying asset types in the SFV."}, {"name": "structuralEnhancements", "type": "string", "description": "Summary of credit enhancement mechanisms such as subordination, reserve accounts, or overcollateralization."}, {"name": "ratingAgencyAssignments", "type": "string", "description": "List of credit rating agencies and the ratings assigned to each tranche."}, {"name": "legalJurisdiction", "type": "string", "description": "Jurisdiction under which the SFV is constituted and regulated."}]'::jsonb, '[]'::jsonb, 'Securitization,Asset-Backed Securities,Risk Tranching,Special Purpose Entity,Capital Markets Structure'::text[], NULL, '2026-02-16 08:41:50.947028', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-f6ca8b33-408a-406b-8b08-e48845020f1e', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Tranche Structure', 'Structured Products', 'The ''Tranche Structure'' concept represents the detailed configuration of layered financial instruments within a structured finance product such as asset-backed securities (ABS) or collateralized debt obligations (CDOs). Each tranche is defined by its order in the payment waterfall, loss allocation priority, and embedded credit enhancements, which directly impact investor risk and expected returns. Senior, mezzanine, and equity tranches are established to allocate cash flows and absorb losses according to predefined contractual rules. Understanding tranche structure is critical for parties involved in structuring, rating, and trading of these securities, as it directly figures into risk modeling and valuation. AI agents analyzing tranche structures can optimize portfolio construction, monitor risk, and support regulatory reporting requirements.', '[{"name": "trancheType", "type": "enum", "description": "The classification of the tranche (e.g., Senior, Mezzanine, Equity)."}, {"name": "creditEnhancementLevel", "type": "decimal", "description": "Quantitative value of credit support provided to the tranche (e.g., overcollateralization percentage)."}, {"name": "paymentPriority", "type": "integer", "description": "Ordinal ranking of this tranche''s rights to receive payments relative to others."}, {"name": "lossAllocationThreshold", "type": "decimal", "description": "The percentage or absolute threshold of losses that the tranche will absorb before others."}]'::jsonb, '[{"type": "parent", "label": "Belongs to the structured finance vehicle (e.g., CDO, ABS)", "targetId": "custom-e2f2d12c-fe2b-46ac-b58f-dd0b08ac9e13"}]'::jsonb, 'Risk Allocation,Payment Waterfall,Credit Enhancement,Hierarchical Structure,Investor Protection'::text[], NULL, '2026-02-16 15:02:38.938021', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-bcac5c10-36a5-4738-b617-4701e3ce04da', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Credit Enhancement', 'Structured Products', 'Credit enhancement refers to a set of techniques or mechanisms used in structured finance to raise the credit quality of specific tranches above the baseline level provided by the collateral pool. Common methods include subordination, overcollateralization, reserve accounts, excess spread, and the use of third-party guarantees. These mechanisms reduce the risk of default for senior tranches and make them more attractive to investors by providing additional layers of protection in case of losses. In financial services operations, credit enhancement is integral to structuring securitized products and accurately modeling their risk profiles. Properly managed credit enhancement increases confidence in structured products, facilitates regulatory compliance, and impacts how ratings agencies evaluate these securities.', '[{"name": "enhancementType", "type": "enum", "description": "Specifies the type of credit enhancement (e.g., subordination, overcollateralization, third-party guarantee)"}, {"name": "enhancementAmount", "type": "decimal", "description": "Quantifies the monetary value of the enhancement provided"}, {"name": "coverageRatio", "type": "decimal", "description": "Indicates the ratio of enhancement amount to underlying pool size"}, {"name": "providerName", "type": "string", "description": "Identifies the third-party provider of the guarantee or enhancement, if applicable"}]'::jsonb, '[]'::jsonb, 'Risk Mitigation,Investor Protection,Securitization Analytics,Rating Impact,Financial Innovation'::text[], NULL, '2026-02-16 15:04:46.471335', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-4b88486c-0fee-41c6-bb17-e6f0dfbbd9fa', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Committee', 'Regulatory Compliance', 'The Rating Committee plays a pivotal role in the credit rating process within financial institutions. It serves as an authoritative group responsible for the assessment, discussion, and approval of credit rating decisions, ensuring objectivity and the absence of conflicts of interest. The committee''s deliberations are central to maintaining transparency and demonstrating due diligence in the assignment of credit ratings. In financial_services operations, its mandated oversight and documented processes provide essential controls, especially for regulated products and jurisdictions. The composition and functioning of this committee are critical in upholding the credibility and regulatory acceptability of ratings issued.', '[{"name": "meetingDate", "type": "date", "description": "The scheduled date of the Rating Committee meeting."}, {"name": "quorumAchieved", "type": "boolean", "description": "Indicates whether the minimum required members were present."}, {"name": "decisionOutcome", "type": "enum", "description": "The result of the rating action (e.g., ''Approved'', ''Rejected'', ''Deferred'')."}, {"name": "independentMemberCount", "type": "integer", "description": "Number of independent members present in the committee meeting."}]'::jsonb, '[{"type": "depends_on", "label": "The committee reviews and approves credit rating actions.", "targetId": "custom-b5eae9a9-2b3a-456b-be64-198c95c7508a"}]'::jsonb, 'Governance,AuditTrail,ConflictOfInterest,DecisionMaking,CreditRatingProcess'::text[], NULL, '2026-02-16 15:06:29.463989', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-76629af2-f811-429c-b6a3-946988d387a4', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'SEC 17g-7 Disclosure', 'Regulatory Compliance', 'The SEC 17g-7 Disclosure is a crucial regulatory document required for every rating action conducted by a Nationally Recognized Statistical Rating Organization (NRSRO). It ensures that investors and regulators receive comprehensive and standardized information, including the underlying methodologies, data sources, quantitative inputs, and limitations associated with a credit rating. The disclosure facilitates transparency and comparability across ratings, helping stakeholders make better-informed decisions. In the context of financial services operations, this concept underpins risk management, due diligence, and compliance reporting processes where credit ratings play a vital role. AI agents can leverage structured 17g-7 Disclosures to automate compliance checks, validate rating methodologies, and monitor ongoing changes in rating assumptions.', '[{"name": "documentVersion", "type": "string", "description": "The version identifier or timestamp marking the specific disclosure iteration."}, {"name": "ratingActionDate", "type": "date", "description": "Date on which the associated rating action and disclosure was published."}, {"name": "nrsroIdentifier", "type": "string", "description": "Unique identifier for the NRSRO responsible for the rating action and disclosure."}, {"name": "publicAccessUrl", "type": "string", "description": "Web link or repository location where the disclosure is publicly accessible."}]'::jsonb, '[{"type": "parent", "label": "Disclosure is associated with a specific credit rating action", "targetId": "custom-b5eae9a9-2b3a-456b-be64-198c95c7508a"}, {"type": "depends_on", "label": "Disclosure depends on the formal rating methodology employed", "targetId": "custom-6c145521-673e-42e4-97b3-c26704c5a020"}]'::jsonb, 'Transparency,Due Diligence,Investor Protection,Documentation,Audit Trail'::text[], NULL, '2026-02-16 15:08:19.964253', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-113afd84-2e26-4d31-a2c9-6808c1b96313', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Conflict of Interest Declaration', 'Regulatory Compliance', 'The ''Conflict of Interest Declaration'' is a critical compliance requirement within the credit rating process, ensuring transparency by mandating the disclosure and evaluation of potential personal, organizational, and structural conflicts. This declaration encompasses mechanisms to identify and manage risks such as issuer-paid model conflicts, excessive revenue reliance on a single client, analyst personal financial interests, and provision of ancillary services. In financial services operations, such declarations are crucial to uphold the integrity of credit assessments and maintain stakeholder trust. Automated screening processes facilitate regular and objective assessments, flagging potential conflicts early in the lifecycle. Effective conflict of interest management reduces reputational risk and supports fair market practices.', '[{"name": "declarationDate", "type": "date", "description": "The date when the conflict of interest declaration was submitted."}, {"name": "reviewedBy", "type": "string", "description": "The name or identifier of the compliance officer or entity who reviewed the declaration."}, {"name": "conflictType", "type": "enum", "description": "Specifies the type of conflict identified, such as issuer-paid model, revenue concentration, personal interests, or ancillary services."}]'::jsonb, '[]'::jsonb, 'Ethics,Disclosure Management,Credit Rating Operations,Personal Account Dealing,Audit Readiness'::text[], NULL, '2026-02-16 15:12:32.30685', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-bc6bf6f8-5e40-42ca-baeb-4cb99aaabe12', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'NRSRO Registration', 'Regulatory Compliance', 'NRSRO (Nationally Recognized Statistical Rating Organization) Registration is a critical regulatory designation granted by the SEC to credit rating agencies that allows them to issue ratings used for regulatory purposes in the U.S. financial markets. This concept encompasses the initial registration process, including submission of Form NRSRO, as well as the ongoing compliance obligations such as annual certifications, maintaining examination readiness, and the regular publication of performance statistics. Within financial services operations, NRSRO Registration serves as an operational and reputational baseline, with non-compliance jeopardizing the validity of issued ratings and counterparties’ regulatory calculations. Maintaining proper registration status is essential for credit rating agencies to participate in key market functions, while also assuring market transparency and standardized risk assessments. The concept also implicates data governance processes due to reporting, disclosure, and audit requirements tied to SEC oversight.', '[{"name": "registrationNumber", "type": "string", "description": "Unique identifier assigned to the NRSRO by the SEC."}, {"name": "registrationDate", "type": "date", "description": "Date the NRSRO registration was granted by the SEC."}, {"name": "status", "type": "enum", "description": "Current regulatory status (e.g., Active, Suspended, Revoked, Pending Renewal)."}, {"name": "lastAnnualCertificationDate", "type": "date", "description": "Date of the most recent annual compliance certification filing."}]'::jsonb, '[]'::jsonb, 'SEC Compliance,Credit Rating Agency Operations,Regulatory Reporting,U.S. Financial Regulation'::text[], NULL, '2026-02-16 15:14:26.977395', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-management-incident', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Incident', 'Service Management', 'An unplanned interruption or reduction in quality of an IT service.', '[{"name": "incidentId", "type": "string", "description": "Unique identifier for the incident."}, {"name": "priority", "type": "enum", "description": "Level of urgency assigned to the incident."}]'::jsonb, '[{"type": "depends_on", "label": "Incidents are associated with specific services.", "targetId": "technology_saas-service-architecture-service"}]'::jsonb, 'management,event,resolution'::text[], 'Incident management is critical for restoring service operations quickly.', '2026-02-16 17:03:54.375603', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-management-request', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Request', 'Service Management', 'A formal user demand for information or service fulfillment.', '[{"name": "requestType", "type": "enum", "description": "Classification of the request."}, {"name": "requestStatus", "type": "string", "description": "Current state of the request."}]'::jsonb, '[{"type": "related", "label": "Requests pertain to available services.", "targetId": "technology_saas-service-architecture-service"}]'::jsonb, 'user,fulfillment,automation'::text[], 'Request management streamlines user access to IT services.', '2026-02-16 17:03:54.420084', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-management-change', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Change', 'Service Management', 'A modification to any aspect of a service or infrastructure managed via formal process.', '[{"name": "changeId", "type": "string", "description": "Unique ID for the change record."}, {"name": "changeType", "type": "enum", "description": "Category of the change process."}]'::jsonb, '[{"type": "parent", "label": "Changes are part of release planning.", "targetId": "technology_saas-service-architecture-release"}]'::jsonb, 'workflow,approval,deployment'::text[], 'Change management reduces risk and ensures consistent IT operations.', '2026-02-16 17:03:54.46434', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-reliability-sla', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'SLA', 'Service Reliability', 'Service Level Agreement governing performance and reliability targets.', '[{"name": "targetAvailability", "type": "decimal", "description": "Percentage uptime promised."}, {"name": "responseTime", "type": "decimal", "description": "Maximum response time allowed."}]'::jsonb, '[{"type": "depends_on", "label": "SLAs are defined for specific services.", "targetId": "technology_saas-service-architecture-service"}]'::jsonb, 'contract,performance,expectation'::text[], 'SLAs provide benchmarks for service reliability and customer satisfaction.', '2026-02-16 17:03:54.50896', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-reliability-error-budget', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Error Budget', 'Service Reliability', 'Allocated margin for service errors within agreed performance boundaries.', '[{"name": "remainingBudget", "type": "decimal", "description": "Percentage of error budget left."}, {"name": "resetDate", "type": "date", "description": "Date when error budget resets."}]'::jsonb, '[{"type": "related", "label": "Error budget is calculated from SLA targets.", "targetId": "technology_saas-service-reliability-sla"}]'::jsonb, 'threshold,risk,sre'::text[], 'Error budgets influence engineering priorities and release cadence.', '2026-02-16 17:03:54.553119', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-reliability-monitoring', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Monitoring', 'Service Reliability', 'Continuous observation of system metrics to ensure service health.', '[{"name": "metricType", "type": "enum", "description": "Type of data metric collected."}, {"name": "frequency", "type": "integer", "description": "How often monitoring is performed."}]'::jsonb, '[{"type": "depends_on", "label": "Monitoring is applied to managed services.", "targetId": "technology_saas-service-architecture-service"}]'::jsonb, 'analytics,automation,health'::text[], 'Monitoring is foundational for proactive service reliability operations.', '2026-02-16 17:03:54.597416', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-architecture-service', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Service', 'Service Architecture', 'A discrete application or orchestrated functionality delivered to users.', '[{"name": "serviceName", "type": "string", "description": "Name of the IT service."}, {"name": "serviceTier", "type": "enum", "description": "Classification of service criticality."}]'::jsonb, '[{"type": "parent", "label": "Services are composed of components.", "targetId": "technology_saas-service-architecture-component"}]'::jsonb, 'foundation,business,itil'::text[], 'Services are the core units of delivery for SaaS organizations.', '2026-02-16 17:03:54.641376', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('technology_saas-service-architecture-component', 'technology_saas', 'ITIL / SRE (IT Service Management & Site Reliability)', 'Component', 'Service Architecture', 'Logical or physical unit which forms part of a larger IT service.', '[{"name": "componentName", "type": "string", "description": "Name of the component."}, {"name": "status", "type": "enum", "description": "Current operational status."}]'::jsonb, '[{"type": "child", "label": "Components are part of services.", "targetId": "technology_saas-service-architecture-service"}]'::jsonb, 'microservice,infrastructure,dependency'::text[], 'Component management supports modularity and scalability.', '2026-02-16 17:03:54.68711', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
