INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-initial-rating-assignment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Initial Rating Assignment', 'Credit Rating Assignment', 'The process by which an issuer or debt instrument receives its first credit rating after thorough analysis of its financial and qualitative characteristics. It sets the base assessment that will be subject to future monitoring and review.', '[{"name": "ratingDate", "type": "date", "description": "Date the initial rating was assigned"}, {"name": "assignedRating", "type": "string", "description": "Credit rating given to the issuer or instrument"}, {"name": "analystLead", "type": "string", "description": "Lead analyst overseeing the rating assignment"}]'::jsonb, '[{"type": "parent", "label": "Rating is assigned to specific issuer type", "targetId": "financial_services-credit-rating-issuer-type"}, {"type": "related", "label": "Assignment guided by approved methodology", "targetId": "Rating Methodology"}]'::jsonb, 'assignment,initial,credit rating,process'::text[], 'Sets the foundation for all subsequent rating actions and market perceptions.', '2026-02-17 05:07:54.507495', 'Rating Initiation,First-Time Assignment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuer-rating-withdrawal', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Issuer Rating Withdrawal', 'Credit Rating Assignment', 'The formal removal of a credit rating assigned to an issuer or security, either at the request of the issuer, due to insufficient information, or following full repayment of obligations.', '[{"name": "withdrawalDate", "type": "date", "description": "Date rating was withdrawn"}, {"name": "withdrawalReason", "type": "string", "description": "Explanation for withdrawal"}, {"name": "publicAnnouncement", "type": "boolean", "description": "Whether withdrawal was publicly announced"}]'::jsonb, '[{"type": "depends_on", "label": "Withdrawal may follow surveillance event", "targetId": "Credit Surveillance Event"}]'::jsonb, 'withdrawal,status change,disclosure'::text[], 'Ensures transparency and accurate market information regarding rated entities.', '2026-02-17 05:07:54.542619', 'Rating Withdrawal,Termination of Rating'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-unsolicited-rating', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Unsolicited Rating', 'Credit Rating Assignment', 'A credit rating assigned without the issuer''s formal participation or request, relying on available public and private data. Unsolicited ratings are disclosed as such to distinguish them from solicited ratings.', '[{"name": "isSolicited", "type": "boolean", "description": "Indicates if rating is unsolicited"}, {"name": "dataSources", "type": "string", "description": "Summary of information sources used"}, {"name": "disclosureLevel", "type": "enum", "description": "Extent of disclosure provided"}]'::jsonb, '[{"type": "related", "label": "Assigned to various issuer types", "targetId": "financial_services-credit-rating-issuer-type"}]'::jsonb, 'unsolicited,public,rating process,disclosure'::text[], 'Provides independent risk assessments to markets even without issuer cooperation.', '2026-02-17 05:07:54.555109', 'Unprompted Rating,Non-Requested Rating'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuer-type', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Issuer Type', 'Issuer Classification', 'Categories defining the nature of the entity being rated, such as sovereign, financial institution, corporate, or public finance. Classification impacts the rating process, methodologies, and disclosures.', '[{"name": "typeName", "type": "string", "description": "Name of issuer type"}, {"name": "sectorCategory", "type": "string", "description": "Broad industry or sector grouping"}, {"name": "jurisdiction", "type": "string", "description": "Country or region of the issuer"}]'::jsonb, '[{"type": "child", "label": "Subtype of issuer information", "targetId": "Issuer Profile"}, {"type": "parent", "label": "Defines rating process", "targetId": "financial_services-credit-rating-initial-rating-assignment"}]'::jsonb, 'issuer,classification,sector,type'::text[], 'Issuer type impacts applicable rating methodologies and risk factors.', '2026-02-17 05:07:54.56669', 'Issuer Segment,Entity Category'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-credit-rating-region', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Credit Rating Region', 'Issuer Classification', 'Geographical categorization impacting ratings due to regional economic, regulatory, and market dynamics. Used to standardize and localize credit risk assessments.', '[{"name": "regionName", "type": "string", "description": "Name of the region"}, {"name": "regulatoryEnvironment", "type": "string", "description": "Overview of relevant regulations"}, {"name": "economicIndicatorSummary", "type": "string", "description": "Summary of regional credit drivers"}]'::jsonb, '[{"type": "related", "label": "Issuer assigned to geographic region", "targetId": "financial_services-credit-rating-issuer-type"}]'::jsonb, 'region,geography,classification,risk'::text[], 'Considers geographic risk factors that affect creditworthiness and rating comparability.', '2026-02-17 05:07:54.568716', 'Rating Geography,Risk Region'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-sector-exposure-assessment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Sector Exposure Assessment', 'Issuer Classification', 'Evaluation of an issuer''s concentration and vulnerability to economic sectors, which can significantly affect its credit risk profile. Factors into industry-specific risk analysis.', '[{"name": "sector", "type": "string", "description": "Industry or sector of assessment"}, {"name": "exposureLevel", "type": "decimal", "description": "Proportion of issuer exposure to sector"}, {"name": "concentrationAssessment", "type": "string", "description": "Summary of risk due to concentration"}]'::jsonb, '[{"type": "related", "label": "Sector exposure linked to issuer", "targetId": "financial_services-credit-rating-issuer-type"}, {"type": "depends_on", "label": "Inputs sector results", "targetId": "Credit Risk Assessment"}]'::jsonb, 'sector,exposure,industry,risk'::text[], 'Essential for understanding diversification and systemic risk in credit ratings.', '2026-02-17 05:07:54.571524', 'Industry Exposure,Sector Risk'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-payment-default-event', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Payment Default Event', 'Credit Event Monitoring', 'A documented event in which an issuer fails to make a scheduled principal or interest payment, triggering review and potential rating action. Central to credit risk evaluation.', '[{"name": "eventDate", "type": "date", "description": "Date default occurred"}, {"name": "missedPaymentAmount", "type": "decimal", "description": "Value of missed payment"}, {"name": "curePeriodEnd", "type": "date", "description": "Deadline for curing the default"}]'::jsonb, '[{"type": "depends_on", "label": "Reported through surveillance", "targetId": "Credit Surveillance Event"}]'::jsonb, 'default,credit event,payment,risk'::text[], 'Drives rating changes and informs market participants of credit deterioration.', '2026-02-17 05:07:54.573893', 'Missed Payment,Default Occurrence'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-restructuring-event', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Restructuring Event', 'Credit Event Monitoring', 'Significant modification of debt terms, such as maturity extension, interest reduction, or principal haircut, usually reflecting issuer distress and requiring rating review.', '[{"name": "eventType", "type": "string", "description": "Nature of restructuring"}, {"name": "announcementDate", "type": "date", "description": "Public disclosure date"}, {"name": "affectedInstruments", "type": "string", "description": "Securities impacted by restructuring"}]'::jsonb, '[{"type": "depends_on", "label": "Monitored as part of surveillance", "targetId": "Credit Surveillance Event"}]'::jsonb, 'restructuring,default,event,distress'::text[], 'Signals financial trouble and affects the rating outcome for issuers and instruments.', '2026-02-17 05:07:54.576808', 'Debt Restructuring,Work-Out Event'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-early-redemption-event', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Early Redemption Event', 'Credit Event Monitoring', 'Redemption or repayment of a debt instrument prior to its scheduled maturity, often altering credit risk calculations and surveillance processes.', '[{"name": "redemptionDate", "type": "date", "description": "Redemption effective date"}, {"name": "redemptionAmount", "type": "decimal", "description": "Total amount repaid early"}, {"name": "reason", "type": "string", "description": "Explanation for early redemption"}]'::jsonb, '[{"type": "related", "label": "Triggers surveillance update", "targetId": "Credit Surveillance Event"}]'::jsonb, 'redemption,credit event,prepayment'::text[], 'Early settlement affects ongoing credit obligations and rating stability.', '2026-02-17 05:07:54.579724', 'Prepayment,Early Repayment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-analyst-coverage-team', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Analyst Coverage Team', 'Rating Governance', 'A designated group of analysts responsible for conducting credit research, assigning and monitoring ratings for a particular set of issuers or sectors. Ensures analytical rigor and independence.', '[{"name": "teamLead", "type": "string", "description": "Lead analyst or manager"}, {"name": "coverageScope", "type": "string", "description": "Set of issuers or products covered"}, {"name": "teamSize", "type": "integer", "description": "Number of team members"}]'::jsonb, '[{"type": "related", "label": "Executes rating process", "targetId": "financial_services-credit-rating-initial-rating-assignment"}, {"type": "depends_on", "label": "Performs ongoing surveillance", "targetId": "Credit Surveillance Event"}]'::jsonb, 'analyst,team,governance,coverage'::text[], 'Provides expertise and independence, critical to rating credibility.', '2026-02-17 05:07:54.58214', 'Credit Analysis Team,Analytical Group'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-rating-policy-statement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Policy Statement', 'Rating Governance', 'Official document outlining principles, standards, and rules governing the rating process, including conflict management and disclosure practices. Anchors rating agency transparency and accountability.', '[{"name": "policyVersion", "type": "string", "description": "Current policy iteration"}, {"name": "effectiveDate", "type": "date", "description": "When the policy took effect"}, {"name": "publiclyDisclosed", "type": "boolean", "description": "Indicates if policy is public"}]'::jsonb, '[{"type": "depends_on", "label": "Built on regulatory requirements", "targetId": "Regulatory Framework"}]'::jsonb, 'policy,governance,disclosure,transparency'::text[], 'Promotes trust through clear, auditable rating practices.', '2026-02-17 05:07:54.584941', 'Rating Policy,Methodological Charter'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-analyst-rotation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Analyst Rotation', 'Rating Governance', 'An internal policy whereby analysts are periodically reassigned to avoid conflicts of interest and maintain objectivity in the ratings process.', '[{"name": "rotationFrequency", "type": "string", "description": "How often analysts are rotated"}, {"name": "rotationPolicy", "type": "string", "description": "Rules governing rotation"}, {"name": "lastRotationDate", "type": "date", "description": "Most recent analyst assignment change"}]'::jsonb, '[{"type": "related", "label": "Applies to analyst teams", "targetId": "financial_services-credit-rating-analyst-coverage-team"}]'::jsonb, 'rotation,analyst,governance,objectivity'::text[], 'Essential for upholding independence and mitigating long-term bias.', '2026-02-17 05:07:54.587813', 'Analyst Reassignment,Periodical Rotation'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-rating-rationale-summary', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Rationale Summary', 'Disclosure & Transparency', 'Concise, publicly-available explanation detailing the key drivers and considerations behind the credit rating, supporting transparency for investors and stakeholders.', '[{"name": "summaryText", "type": "string", "description": "Core rationale statement"}, {"name": "publicationDate", "type": "date", "description": "Date rationale was published"}, {"name": "language", "type": "string", "description": "Language of publication"}]'::jsonb, '[{"type": "depends_on", "label": "Explains the rating action decision", "targetId": "Rating Action"}]'::jsonb, 'disclosure,rationale,transparency,stakeholder'::text[], 'Mandatory for informed market decisions and regulatory compliance.', '2026-02-17 05:07:54.590361', 'Rating Justification,Rationale Note'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuer-participation-statement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Issuer Participation Statement', 'Disclosure & Transparency', 'A disclosure indicating whether the rated entity participated in the rating process, signifying the use of issuer-provided versus public information.', '[{"name": "participationConfirmed", "type": "boolean", "description": "Issuer''s involvement"}, {"name": "disclosureDate", "type": "date", "description": "When participation status was disclosed"}]'::jsonb, '[{"type": "related", "label": "Linked to rating participation type", "targetId": "financial_services-credit-rating-unsolicited-rating"}]'::jsonb, 'issuer,participation,disclosure'::text[], 'Indicates transparency and influences perceived rating reliability.', '2026-02-17 05:07:54.592717', 'Participation Disclosure,Issuer Involvement Statement'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-rating-action-publication', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rating Action Publication', 'Disclosure & Transparency', 'The formal publication and dissemination of a rating action (upgrade, downgrade, affirmation, or withdrawal) to the market and stakeholders.', '[{"name": "publicationDate", "type": "date", "description": "When the action was published"}, {"name": "communicationChannel", "type": "string", "description": "How the action was disclosed"}, {"name": "audience", "type": "string", "description": "Intended recipients of disclosure"}]'::jsonb, '[{"type": "parent", "label": "Publishes credit rating actions", "targetId": "Rating Action"}]'::jsonb, 'publication,disclosure,market communication'::text[], 'Ensures timely market access to official credit ratings and associated changes.', '2026-02-17 05:07:54.595211', 'Rating Release,Public Rating Announcement'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-key-financial-ratio-analysis', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Key Financial Ratio Analysis', 'Quantitative & Qualitative Analysis', 'Systematic evaluation of critical financial ratios (like leverage, coverage, and liquidity metrics) used to benchmark the credit quality of issuers during the rating process.', '[{"name": "analysisDate", "type": "date", "description": "Date ratios were evaluated"}, {"name": "ratiosAssessed", "type": "string", "description": "List of key ratios reviewed"}, {"name": "outcomeSummary", "type": "string", "description": "Credit impact assessment"}]'::jsonb, '[{"type": "depends_on", "label": "Provides core risk metrics", "targetId": "Credit Risk Assessment"}, {"type": "related", "label": "Examines issuer financials", "targetId": "Issuer Profile"}]'::jsonb, 'ratio,analysis,financials,quantitative'::text[], 'Supports rating decisions and comparisons across issuers.', '2026-02-17 05:07:54.597895', 'Ratio Benchmarking,Financial Ratio Review'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-peer-comparison-analysis', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Peer Comparison Analysis', 'Quantitative & Qualitative Analysis', 'Assessing an issuer''s financial and qualitative position relative to similar entities (peers), helping contextualize its credit strength within its sector.', '[{"name": "comparisonDate", "type": "date", "description": "Analysis as of this date"}, {"name": "peerGroupIdentified", "type": "string", "description": "Defined set of peer issuers"}, {"name": "relativePosition", "type": "string", "description": "Issuer standing among peers"}]'::jsonb, '[{"type": "related", "label": "Limited to specific issuer categories", "targetId": "financial_services-credit-rating-issuer-type"}]'::jsonb, 'peer,benchmark,sector,comparison'::text[], 'Ensures consistency and fairness in credit ratings within industry groups.', '2026-02-17 05:07:54.600801', 'Comparative Analysis,Sector Benchmarking'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-qualitative-factor-review', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Qualitative Factor Review', 'Quantitative & Qualitative Analysis', 'Critical review of non-quantifiable factors such as corporate governance, regulatory environment, and management quality, influencing the final credit rating.', '[{"name": "reviewDate", "type": "date", "description": "Date qualitative review was completed"}, {"name": "factorType", "type": "string", "description": "Nature of qualitative factor (e.g., governance)"}, {"name": "analystAssessment", "type": "string", "description": "Expert evaluation and notes"}]'::jsonb, '[{"type": "related", "label": "Assessment method informed by methodology", "targetId": "Rating Methodology"}]'::jsonb, 'qualitative,factor,evaluation,governance'::text[], 'Accounts for risks not captured by quantitative analysis alone.', '2026-02-17 05:07:54.612098', 'Qualitative Assessment,Non-Financial Review'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-checking-account-application', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Checking Account Application', 'Deposit Accounts', 'A Checking Account Application represents a critical point in the retail banking customer onboarding process. It captures all information required for due diligence, identity verification, and the product relationship initiation at a community bank. This concept involves collecting sensitive personal details, conducting risk assessments, and matching the applicant''s profile against available checking account products. Community banks use this application not only to facilitate regulatory compliance but also to enhance the customer experience by streamlining eligibility and approval steps. The success and efficiency of processing these applications impact customer satisfaction, operational risk, and regulatory reporting obligations.', '[{"name": "applicationId", "type": "string", "description": "Unique identifier for the application"}, {"name": "submittedDate", "type": "date", "description": "Date the application was submitted"}, {"name": "accountType", "type": "enum", "description": "Type of checking account requested"}, {"name": "applicationStatus", "type": "enum", "description": "Current processing status of the application (e.g., Pending, Approved, Declined, Needs More Info)"}, {"name": "channel", "type": "enum", "description": "Submission origin of the application (e.g., Online, Branch, Mobile App)"}, {"name": "applicantRiskScore", "type": "decimal", "description": "Calculated risk score based on identity and profile checks during application intake"}]'::jsonb, '[{"type": "depends_on", "label": "Links to the applicant''s profile", "targetId": "financial_services-retail-banking-customer-profile"}, {"type": "related", "label": "Application status outcome", "targetId": "financial_services-retail-banking-account-approval-decision"}]'::jsonb, 'onboarding,account,community bank,application,KYC,AML,identity verification,customer onboarding,fraud prevention'::text[], 'Critical for acquiring new retail banking customers and supporting local financial access.', '2026-02-18 04:31:08.144024', 'New Account Request,Checking Application'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-overdraft-protection-enrollment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Overdraft Protection Enrollment', 'Deposit Accounts', 'Overdraft Protection Enrollment is a critical banking operation that authorizes the automated transfer of funds from a linked account—such as a savings or line of credit—to a checking account when its balance is insufficient to cover a transaction. This service is designed to prevent declined payments, bounced checks, and the associated fees while enhancing customer satisfaction. The enrollment process involves explicit customer consent, verification and validation of the linked account, and the activation of protection on the specified checking account. Robust operational controls are essential to ensure seamless coverage, accurate real-time fund transfers, and proper notification of overdraft events. This concept plays a key role in both customer experience management and risk mitigation within a bank’s deposit account product suite.', '[{"name": "enrollmentId", "type": "string", "description": "Unique enrollment identifier"}, {"name": "linkedAccountNumber", "type": "string", "description": "Account number providing overdraft coverage"}, {"name": "enrollmentStatus", "type": "enum", "description": "Current status of enrollment"}, {"name": "enrollmentDate", "type": "date", "description": "Date when the customer completed overdraft protection enrollment"}, {"name": "consentMethod", "type": "enum", "description": "Method by which customer consent was obtained (e.g., online, in-branch, phone)"}, {"name": "protectionLimit", "type": "decimal", "description": "Maximum amount that can be covered by overdraft protection"}]'::jsonb, '[{"type": "depends_on", "label": "Requires an open checking account", "targetId": "financial_services-retail-banking-checking-account-application"}, {"type": "related", "label": "Documents customer authorization for overdraft protection", "targetId": "financial_services-retail-banking-customer-consent-record"}]'::jsonb, 'protection,services,deposit,retail,consent,consumer-protection,compliance,account-linkage'::text[], 'Helps banks manage risk and enhances the customer experience by reducing declined transactions.', '2026-02-18 04:31:08.215067', 'Overdraft Service Enrollment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-direct-deposit-setup', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Direct Deposit Setup', 'Deposit Accounts', 'Direct Deposit Setup refers to the orchestration of enabling automatic, electronic credits from entities such as employers, government agencies, or pension providers to a designated customer deposit account. This typically involves capturing, validating, and transmitting account details and payment instructions using secure networks like ACH. Financial institutions must ensure accurate routing, verification of account ownership, and ongoing monitoring for successful transaction execution. The setup supports operational efficiency, reduces paper check processing, and enhances customer experience by ensuring timely fund availability. In agent-driven environments, this process includes robust validation, exception handling, and seamless onboarding integrations.', '[{"name": "setupId", "type": "string", "description": "Direct deposit setup identifier"}, {"name": "employerName", "type": "string", "description": "Name of the depositing entity"}, {"name": "depositFrequency", "type": "enum", "description": "How often deposits are made"}, {"name": "customerConsentDate", "type": "date", "description": "Date when the customer provided explicit consent for direct deposit setup."}, {"name": "depositStartDate", "type": "date", "description": "Scheduled date for first deposit to be credited."}, {"name": "accountVerificationStatus", "type": "enum", "description": "Status indicating whether the deposit account has been verified."}]'::jsonb, '[{"type": "related", "label": "Associated with a checking account", "targetId": "financial_services-retail-banking-checking-account-application"}]'::jsonb, 'ACH,deposit,payroll,automation,KYC,compliance,automation_agent,account_verification'::text[], 'Essential for daily banking convenience and a key service feature for retail customers.', '2026-02-18 04:31:08.261388', 'Automated Deposit,ACH Deposit Setup'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-account-fee-schedule', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Account Fee Schedule', 'Deposit Accounts', 'The Account Fee Schedule enumerates the full set of charges that may be applied to a checking or savings account over its lifecycle. This schedule includes maintenance and service fees, overdraft charges, non-sufficient funds (NSF) fees, and stipulations around minimum balance requirements which could trigger additional fees. Clear and accurate fee schedules are crucial for transparency with account holders and are closely managed by compliance functions. In modern financial services operations, the Account Fee Schedule supports dynamic pricing, product differentiation, and client communication, with adjustments flowing directly from changes in internal policy or regulatory requirements. For AI agents, structured access to these schedules enables individualized fee calculations, automated compliance checks, and optimization of client communication strategies.', '[{"name": "feeScheduleId", "type": "string", "description": "Fee schedule identifier"}, {"name": "feeType", "type": "enum", "description": "Type of account fee"}, {"name": "feeAmount", "type": "decimal", "description": "Monetary value of the fee"}, {"name": "effectiveDate", "type": "date", "description": "The date on which the fee schedule comes into effect."}, {"name": "applicableAccountTypes", "type": "string", "description": "List or classification of account types to which this fee schedule applies."}, {"name": "waiverCriteria", "type": "string", "description": "Conditions under which certain fees may be waived for a customer."}, {"name": "scheduleVersion", "type": "string", "description": "Version identifier for tracking changes to the fee schedule."}]'::jsonb, '[{"type": "related", "label": "Determines applicable fees", "targetId": "financial_services-retail-banking-checking-account-application"}]'::jsonb, 'fees,disclosure,deposit,pricing,compliance,retail-banking,product-management'::text[], 'Transparency and clarity on fees are regulatory requirements and influence customer satisfaction.', '2026-02-18 04:31:08.308892', 'Account Fees,Schedule of Charges'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-customer-profile', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Customer Profile', 'Customer Profile & Interaction', 'A Customer Profile in financial services encapsulates a holistic view of a retail banking client, aggregating demographic data, detailed contact information, product preferences, service usage patterns, and the nature of account and product relationships. It forms the backbone for delivering personalized banking experiences, facilitating customer onboarding, KYC processes, risk assessment, and targeted marketing activities. Financial institutions rely on precise and updated Customer Profiles to optimize cross-selling opportunities, enhance customer lifetime value, and comply with regulatory requirements such as AML and GDPR. In AI agent ecosystems, the Customer Profile serves as a primary data source for adaptive interaction, tailored recommendations, and service fulfillment workflows. Ensuring data completeness and accuracy directly impacts customer satisfaction, retention, and risk mitigation.', '[{"name": "customerId", "type": "string", "description": "Unique ID for the customer"}, {"name": "primaryContactMethod", "type": "enum", "description": "Preferred way to contact the customer"}, {"name": "customerSegment", "type": "enum", "description": "Target segment for marketing/service"}, {"name": "dateOfBirth", "type": "date", "description": "The customer''s date of birth for identity verification and suitability checks."}, {"name": "riskRating", "type": "enum", "description": "Current risk classification of the customer (e.g., low, medium, high) for AML/KYC purposes."}, {"name": "consentStatus", "type": "enum", "description": "Current status of data usage consent provided by the customer (e.g., granted, revoked, pending)."}, {"name": "servicePreferences", "type": "string", "description": "Customer''s preferences for banking channels and services."}]'::jsonb, '[{"type": "parent", "label": "Customer submits application", "targetId": "financial_services-retail-banking-checking-account-application"}, {"type": "child", "label": "Captures data usage and communication consents for the customer", "targetId": "financial_services-retail-banking-customer-consent-record"}]'::jsonb, 'customer,profile,contact,engagement,KYC,PII,AML,risk,consent-management'::text[], 'Foundation for all banking engagements and supports tailored service offerings.', '2026-02-18 04:31:08.35585', 'Client Profile,Customer Record'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-branch-interaction-event', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Branch Interaction Event', 'Customer Profile & Interaction', 'A Branch Interaction Event represents a granular, time-stamped record of an engagement between a customer and community bank personnel, whether conducted in-person at a branch location or remotely via digital channels. This event provides operational insights into customer needs, preferences, and service execution, encompassing actions such as onboarding, transaction assistance, cross-selling, and issue resolution. Branch Interaction Events are critical touchpoints in the customer experience lifecycle and provide key data for analyzing service quality and branch performance. When systematically captured, these events enable the application of advanced analytics for improving operational efficiency and tailoring financial products. They also form an essential data source for continuous AI-led customer relationship management and regulatory reporting.', '[{"name": "interactionId", "type": "string", "description": "Unique interaction event ID"}, {"name": "interactionType", "type": "enum", "description": "Nature of the activity (e.g., inquiry, support)"}, {"name": "interactionDate", "type": "date", "description": "Date and time of interaction"}, {"name": "channel", "type": "enum", "description": "Indicates the channel used for the interaction (e.g., in-person, phone, video, chat)."}, {"name": "staffId", "type": "string", "description": "Identifier for the bank personnel involved in the interaction."}, {"name": "resolutionStatus", "type": "enum", "description": "Indicates if and how the interaction was resolved (e.g., resolved, escalated, follow-up required)."}]'::jsonb, '[{"type": "related", "label": "Interaction involving customer", "targetId": "financial_services-retail-banking-customer-profile"}]'::jsonb, 'interaction,branch,event,service,customer-experience,KYC,service-quality,compliance'::text[], 'Captures customer experiences and supports service quality improvement.', '2026-02-18 04:31:08.403396', 'Customer Service Event'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-customer-consent-record', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Customer Consent Record', 'Customer Profile & Interaction', 'A Customer Consent Record is a critical artifact in financial services, capturing a customer''s explicit agreement for how their personal and financial data may be used. This record underpins a range of operations, from executing product opt-ins to managing communication preferences, and ensures organizations adhere to legal requirements regarding customer privacy and consent. Beyond initial collection, it supports ongoing consent lifecycle management—tracking revocations and updates throughout the customer relationship. Proper management of these records enables transparent auditing, builds customer trust, and minimizes regulatory exposure. It is foundational for enabling automated, compliant interactions in digital channels.', '[{"name": "consentId", "type": "string", "description": "Unique identifier for the consent event"}, {"name": "consentType", "type": "enum", "description": "Nature of the consent (e.g., data sharing)"}, {"name": "consentTimestamp", "type": "date", "description": "Time when consent was given"}, {"name": "consentStatus", "type": "enum", "description": "Current status of the consent (e.g., Active, Withdrawn, Expired)."}, {"name": "expiryDate", "type": "date", "description": "The date on which the consent will expire or renew."}, {"name": "channelGiven", "type": "string", "description": "Medium through which consent was given (e.g., web, mobile, branch)."}, {"name": "purposeDescription", "type": "string", "description": "Detailed description of the purpose for which consent was obtained."}]'::jsonb, '[{"type": "related", "label": "Collected from the customer", "targetId": "financial_services-retail-banking-customer-profile"}]'::jsonb, 'compliance,privacy,data,consent,customer-rights,audit-trail,marketing-preference,user-preference'::text[], 'Essential for meeting data privacy laws and building customer trust.', '2026-02-18 04:31:08.450218', 'Privacy Consent,Opt-in Record'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-deposit-product-catalog', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Deposit Product Catalog', 'Product & Service Management', 'The Deposit Product Catalog serves as the authoritative repository for all consumer-oriented deposit offerings within a financial institution. It systematically organizes key information about each product, such as account types (e.g., Free Checking, Senior Accounts), features (interest rates, fees, minimum balances), and customer eligibility rules. In financial services operations, maintaining an up-to-date and accurate catalog is vital for supporting product discovery, onboarding workflows, and compliance reporting. AI agents use this catalog to match customer profiles to products, support suitability analysis, and automate channel-based promotions. The catalog''s structure enhances both operational efficiency and regulatory transparency.', '[{"name": "productId", "type": "string", "description": "Unique deposit product identifier"}, {"name": "productName", "type": "string", "description": "Name of the deposit product"}, {"name": "productCategory", "type": "enum", "description": "Product type (e.g., checking, savings)"}, {"name": "interestRate", "type": "decimal", "description": "Applicable interest rate for the deposit product."}, {"name": "eligibilityCriteria", "type": "string", "description": "Summary of customer attributes required for account opening."}, {"name": "feesAndCharges", "type": "string", "description": "Description of applicable fees and charges."}, {"name": "productEffectiveDate", "type": "date", "description": "Date when the deposit product became available."}]'::jsonb, '[{"type": "related", "label": "Selects product offering", "targetId": "financial_services-retail-banking-checking-account-application"}]'::jsonb, 'products,catalog,deposit,offering,compliance,eligibility,accountTypes,rates'::text[], 'Defines the bank''s value proposition and differentiates against competitors.', '2026-02-18 04:31:08.4985', 'Product List,Account Catalog'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-account-approval-decision', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Account Approval Decision', 'Product & Service Management', 'Account Approval Decision refers to the bank''s authoritative response to an individual''s or entity''s application for a new deposit account. This process involves a detailed review of the applicant''s identity, financial history, and risk profile—including anti-money laundering (AML) and know your customer (KYC) checks—before rendering a result. The outcome (approved, rejected, or pending) is critical, as it influences customer onboarding and downstream servicing processes, and must be justified and documented for auditability. In modern financial services, the speed and transparency of this decision process directly affect customer satisfaction and regulatory compliance. Additionally, decisions must be systematically recorded for reference in case of disputes or regulatory inquiries.', '[{"name": "decisionId", "type": "string", "description": "Unique approval decision ID"}, {"name": "decisionDate", "type": "date", "description": "Date of the decision"}, {"name": "decisionOutcome", "type": "enum", "description": "Outcome (approved, rejected, pending)"}, {"name": "reviewerId", "type": "string", "description": "Identifier of the human or agent who performed or authorized the decision."}, {"name": "decisionReason", "type": "string", "description": "Justification or reason for the decision outcome."}, {"name": "applicationChannel", "type": "enum", "description": "Channel through which the application was received (e.g., online, branch, mobile)."}, {"name": "reviewDuration", "type": "decimal", "description": "Elapsed time (in hours or days) between application receipt and approval decision."}]'::jsonb, '[{"type": "child", "label": "Decision on application", "targetId": "financial_services-retail-banking-checking-account-application"}]'::jsonb, 'approval,decision,onboarding,compliance,risk-assessment,fraud-detection,audit-trail,aml,kyc'::text[], 'Central compliance checkpoint in opening new banking relationships.', '2026-02-18 04:31:08.545404', 'Account Opening Decision,Application Decision'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-debit-card-issuance', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Debit Card Issuance', 'Product & Service Management', 'Debit Card Issuance is a fundamental service in retail banking that encompasses the end-to-end process of creating, personalizing, and delivering a debit card to a customer who holds a deposit account. This includes orchestrating background checks, card personalization for security and branding, and coordinating logistics for timely delivery and activation. The process must ensure that the card is correctly linked to the customer''s account, comply with anti-fraud requirements, and offer seamless activation upon receipt. In modern financial operations, digital channels may also be used to instantly provision virtual debit cards for immediate use. The orchestration of debit card issuance directly impacts customer satisfaction, fraud prevention, and regulatory compliance.', '[{"name": "cardId", "type": "string", "description": "Unique debit card identifier"}, {"name": "issueDate", "type": "date", "description": "Date card was issued"}, {"name": "cardStatus", "type": "enum", "description": "Card activation or delivery status"}, {"name": "deliveryMethod", "type": "enum", "description": "Mode of card delivery such as mail, branch pickup, or instant issuance"}, {"name": "activationDeadline", "type": "date", "description": "Expiry date by which the debit card must be activated"}, {"name": "cardType", "type": "string", "description": "Type of debit card issued, e.g., contactless, EMV chip, virtual"}, {"name": "issuerBankId", "type": "string", "description": "Identifier of the bank or financial institution issuing the card"}]'::jsonb, '[{"type": "related", "label": "For approved accounts", "targetId": "financial_services-retail-banking-checking-account-application"}]'::jsonb, 'debit card,issuance,payment,plastic,onboarding,KYC,fulfillment,security'::text[], 'Enables account holders to access funds and transacts efficiently.', '2026-02-18 04:31:08.592398', 'Debit Provision,Card Issuance'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-online-banking-enrollment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Online Banking Enrollment', 'Digital Banking & Access', 'Online Banking Enrollment refers to the secured onboarding process through which a retail customer registers for access to a community bank’s digital banking services. This process includes user identity verification, acceptance of terms and conditions, and the establishment of digital credentials, such as a username and authentication methods. In financial operations, this is a crucial step enabling customers to manage accounts, perform transactions, and receive account notifications online. Effective enrollment enhances customer convenience and helps banks reduce in-person branch visits while improving service accessibility. The quality and security of this process directly impact customer experience, fraud prevention, and compliance adherence.', '[{"name": "enrollmentId", "type": "string", "description": "Unique enrollment record ID"}, {"name": "username", "type": "string", "description": "Chosen online banking username"}, {"name": "enrollmentDate", "type": "date", "description": "Date of online banking registration"}, {"name": "verificationStatus", "type": "enum", "description": "Status indicating whether the user''s identity and information have been fully verified (e.g., Pending, Verified, Rejected)."}, {"name": "authenticationMethod", "type": "string", "description": "Primary authentication method selected during enrollment (e.g., password, biometric, OTP)."}, {"name": "customerConsentDate", "type": "date", "description": "Date and time the customer provided explicit consent to terms and conditions."}, {"name": "enrollmentChannel", "type": "string", "description": "Indicates the platform used for enrollment (e.g., mobile app, web portal, in-branch kiosk)."}]'::jsonb, '[{"type": "related", "label": "Enrollment by customer", "targetId": "financial_services-retail-banking-customer-profile"}]'::jsonb, 'digital,online,access,portal,onboarding,security,KYC,authentication'::text[], 'A core capability for customer engagement and competitive digital service delivery.', '2026-02-18 04:31:08.639077', 'Internet Banking Registration,eBanking Enrollment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-mobile-deposit-capture-event', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Mobile Deposit Capture Event', 'Digital Banking & Access', 'A Mobile Deposit Capture Event represents a customer-initiated transaction wherein check images are submitted for processing through a mobile banking application. This event streamlines the deposit process by eliminating the need for physical branch visits and enabling real-time crediting of funds, subject to validation and fraud checks. In financial services operations, this concept is integral to improving customer experience, increasing deposit velocity, and supporting digital transformation strategies. The event includes digitization of physical checks, secure transmission of images, and automated back-office handling for fund clearing and settlement. As such, it must interoperate seamlessly with digital identity management, fraud analytics, compliance monitoring, and core banking systems.', '[{"name": "eventId", "type": "string", "description": "Unique event identifier"}, {"name": "depositAmount", "type": "decimal", "description": "Amount deposited via mobile"}, {"name": "captureTimestamp", "type": "date", "description": "Timestamp of deposit submission"}, {"name": "deviceIdentifier", "type": "string", "description": "Unique identifier for the mobile device used to capture the deposit."}, {"name": "imageQualityScore", "type": "decimal", "description": "Score representing the quality of the submitted check images."}, {"name": "geoLocation", "type": "string", "description": "Geolocation data of the device at the time of the deposit capture event."}]'::jsonb, '[{"type": "depends_on", "label": "Requires digital access", "targetId": "financial_services-retail-banking-online-banking-enrollment"}]'::jsonb, 'mobile,remote deposit,digital,check,remote onboarding,AI automation,compliance monitoring,image processing'::text[], 'Drives convenience and reduces branch footfall, especially in community banking.', '2026-02-18 04:31:08.685727', 'RDC Event,Mobile Check Deposit'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-account-aggregation-consent', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Account Aggregation Consent', 'Digital Banking & Access', 'Account Aggregation Consent is a critical concept in digital banking enabling customers to authorize their bank or third-party providers to access and consolidate financial data from multiple external accounts. This consent serves as the legal and operational foundation for open banking services, allowing users to view and manage all their finances through a single interface. It ensures transparency, provides enhanced user experience, and promotes financial wellness by presenting comprehensive financial information. Proper management of this consent mitigates operational and reputational risks associated with data access and usage. Efficient handling of aggregation consents is paramount for delivering seamless and compliant digital banking solutions.', '[{"name": "consentId", "type": "string", "description": "Consent record identifier"}, {"name": "aggregationProvider", "type": "string", "description": "Name of the external data aggregator"}, {"name": "consentGivenDate", "type": "date", "description": "Date consent was provided"}, {"name": "consentExpiryDate", "type": "date", "description": "Date on which the consent expires and requires renewal."}, {"name": "consentRevoked", "type": "boolean", "description": "Indicates whether the customer has revoked the consent."}, {"name": "consentScope", "type": "string", "description": "Details on the types of data covered by the consent."}, {"name": "customerIdentifier", "type": "string", "description": "Unique customer ID associated with the aggregation consent."}]'::jsonb, '[{"type": "related", "label": "A specific form of consent", "targetId": "financial_services-retail-banking-customer-consent-record"}]'::jsonb, 'open banking,aggregation,consent,digital,privacy,data protection,regulatory compliance,customer experience'::text[], 'Supports open banking initiatives and digital innovation in retail banking.', '2026-02-18 04:31:08.731947', 'Financial Data Sharing Consent'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-personal-loan-application', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Personal Loan Application', 'Retail Lending', 'A Personal Loan Application represents an official request made by an individual retail banking customer to obtain an unsecured loan, typically used for personal financial needs such as debt consolidation, discretionary spending, or emergency expenses. The application includes detailed borrower information, requested loan amount, loan purpose, and supporting documents regarding income, employment, and creditworthiness. Within financial services operations, this concept supports automated credit decisioning, underwriting, and customer onboarding workflows. Lifecycle events—including submission, approval, rejection, and funding—must be meticulously tracked for operational, risk, and compliance purposes. Integration with credit bureaus, fraud detection systems, and customer profile data is essential for efficient AI-driven evaluation and execution.', '[{"name": "applicationId", "type": "string", "description": "Personal loan application identifier"}, {"name": "requestedAmount", "type": "decimal", "description": "Amount of the loan requested"}, {"name": "applicationStatus", "type": "enum", "description": "Current stage of the application"}, {"name": "loanPurpose", "type": "string", "description": "Declared reason for seeking the loan (e.g., debt consolidation, medical, education)."}, {"name": "applicantIncome", "type": "decimal", "description": "Stated or verified gross monthly or annual income of the applicant."}, {"name": "creditScoreAtApplication", "type": "integer", "description": "Credit score used for the initial application decision."}, {"name": "consentStatus", "type": "enum", "description": "Status indicating whether the applicant consented to data processing and credit checks."}]'::jsonb, '[{"type": "related", "label": "Submitted by customer", "targetId": "financial_services-retail-banking-customer-profile"}]'::jsonb, 'loan,credit,personal,application,retail-lending,KYC,decisioning,unsecured-loan'::text[], 'Major community bank product for customer financing and margin generation.', '2026-02-18 04:31:08.778453', 'Consumer Loan Application,Term Loan Request'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-secured-loan-collateral-detail', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Secured Loan Collateral Detail', 'Retail Lending', 'Secured Loan Collateral Detail represents the comprehensive data points describing the asset that a retail customer pledges to secure personal loans (such as auto or home improvement loans). It includes information such as asset type (e.g., automobile, savings, real estate), estimated value, and unique identifiers for tracking. These details help financial institutions accurately assess risk, determine loan-to-value ratios, and ensure enforceability in the event of default. Capturing precise collateral details is critical to both loan underwriting and ongoing credit risk monitoring. AI-driven systems can leverage this concept for faster credit decisions, collateral revaluation, and compliance processes.', '[{"name": "collateralId", "type": "string", "description": "Collateral detail record ID"}, {"name": "collateralType", "type": "string", "description": "Nature of collateral (auto, savings, etc.)"}, {"name": "estimatedValue", "type": "decimal", "description": "Estimated collateral value"}, {"name": "collateralRegistrationNumber", "type": "string", "description": "Official registration or VIN/serial number for the collateral asset."}, {"name": "ownershipVerified", "type": "boolean", "description": "Flag indicating whether asset ownership has been independently verified."}, {"name": "latestAppraisalDate", "type": "date", "description": "Date of the most recent collateral valuation or appraisal."}]'::jsonb, '[{"type": "related", "label": "Secures loan approval", "targetId": "financial_services-retail-banking-personal-loan-application"}]'::jsonb, 'collateral,loan,security,retail,asset_verification,risk_assessment,valuation,compliance'::text[], 'Reduces lending risk and enables responsible credit expansion.', '2026-02-18 04:31:08.824521', 'Collateral Detail,Pledged Asset'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-loan-repayment-schedule', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Loan Repayment Schedule', 'Retail Lending', 'The Loan Repayment Schedule is a foundational artifact within retail lending, detailing the structured timeline of repayments for a specific loan, including installment amounts, due dates, and how each payment impacts the remaining principal. It serves as an operational guide for both the lender and borrower, ensuring clarity around obligations and expectations throughout the life of the loan. Lenders rely on this schedule to automate payment processing, assess delinquencies, and project cash flows, while borrowers use it to plan personal finances and avoid missed payments. AI agents interfacing with such schedules enable efficient monitoring, proactive collections, and personalized client communications. Accurate schedule data also underpins compliance, reporting, and customer service operations in retail banking environments.', '[{"name": "scheduleId", "type": "string", "description": "Unique repayment schedule identifier"}, {"name": "paymentFrequency", "type": "enum", "description": "Payment interval (monthly, biweekly)"}, {"name": "finalPaymentDate", "type": "date", "description": "Last payment date"}, {"name": "paymentAmount", "type": "decimal", "description": "The fixed or variable amount due for each scheduled payment."}, {"name": "outstandingPrincipal", "type": "decimal", "description": "Remaining loan balance after each scheduled payment."}, {"name": "interestRateType", "type": "enum", "description": "The type of interest applied (e.g., fixed, variable, tiered) to the schedule."}]'::jsonb, '[{"type": "depends_on", "label": "Set for each approved loan", "targetId": "financial_services-retail-banking-personal-loan-application"}]'::jsonb, 'loan,repayment,schedule,credit,cashflow,installment,payment_processing,consumer_protection'::text[], 'Transparency into debt obligations benefits both bank and customer.', '2026-02-18 04:31:08.871466', 'Amortization Schedule,Payment Plan'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-dispute-resolution-case', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Dispute Resolution Case', 'Customer Assistance & Compliance', 'A Dispute Resolution Case in financial services represents a structured process initiated when a customer raises a concern regarding unauthorized transactions, erroneous fees, or similar service issues. This workflow typically involves intake, investigation, evidence gathering, remediation proposal, communication with stakeholders, and case closure. Seamless management ensures timely resolution, maintains customer trust, and upholds service quality. Dispute cases are often subject to strict record-keeping and documentation requirements to comply with audits. Integration with transaction records, call logs, and compliance systems is key for holistic operation.', '[{"name": "caseId", "type": "string", "description": "Unique case identifier"}, {"name": "caseStatus", "type": "enum", "description": "Current stage of resolution"}, {"name": "disputeType", "type": "enum", "description": "Nature of dispute (transaction, fee, etc.)"}, {"name": "initiatedDate", "type": "date", "description": "The date the dispute resolution case was opened."}, {"name": "resolutionDate", "type": "date", "description": "The date on which the dispute was resolved or closed."}, {"name": "customerId", "type": "string", "description": "Unique identifier for the customer initiating the dispute."}, {"name": "resolutionOutcome", "type": "enum", "description": "Final outcome of the dispute (e.g., approved, denied, partial remediation)."}]'::jsonb, '[{"type": "depends_on", "label": "Case may originate from branch event", "targetId": "financial_services-retail-banking-branch-interaction-event"}]'::jsonb, 'dispute,case,compliance,resolution,customer-service,remediation,audit,transaction-monitoring'::text[], 'Maintains service quality, ensures customer retention, and fulfills regulatory requirements.', '2026-02-18 04:31:08.917627', 'Customer Dispute,Dispute Case'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-fraud-alert-notification', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Fraud Alert Notification', 'Customer Assistance & Compliance', 'Fraud Alert Notification is a critical mechanism in financial services, providing immediate communication to customers when potential fraudulent activity is detected. Its primary function allows customers to quickly confirm or deny suspicious transactions, thus minimizing financial loss and enabling rapid response measures. This concept supports business continuity by ensuring both customer trust and compliance with anti-fraud regulations. AI agents can utilize Fraud Alert Notification to analyze transaction patterns, automate alert dispatch, and orchestrate customer responses in near-real time. A robust implementation must integrate with transaction monitoring systems to ensure comprehensive coverage and detailed auditability.', '[{"name": "alertId", "type": "string", "description": "Identifier for the fraud alert"}, {"name": "alertChannel", "type": "enum", "description": "Medium used (SMS, email, phone)"}, {"name": "responseStatus", "type": "enum", "description": "Customer response status"}, {"name": "suspectedTransactionId", "type": "string", "description": "Identifier for the specific transaction under suspicion"}, {"name": "alertPriority", "type": "enum", "description": "Urgency or severity level of the fraud alert"}, {"name": "notificationTimestamp", "type": "date", "description": "Date and time when the alert was sent"}]'::jsonb, '[{"type": "related", "label": "Notification sent to customer", "targetId": "financial_services-retail-banking-customer-profile"}]'::jsonb, 'fraud,alert,security,risk,customer-experience,regtech,incident-management,real-time-notification'::text[], 'Protects customers and limits liability for community banks.', '2026-02-18 04:31:08.963464', 'Suspicious Activity Alert'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-retail-banking-account-closure-request', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Account Closure Request', 'Customer Assistance & Compliance', 'An Account Closure Request is a structured, auditable instruction initiated by a client, typically transmitted through digital or in-person channels, to terminate a deposit account relationship. It encapsulates the customer''s stated reason for closure, validates fulfillment of outstanding obligations (such as fee settlements or loan payoffs), and initiates downstream workflows including balance disbursement, legal checks, and reporting updates. In modern financial operations, this request triggers automated tasks for verification, risk assessment, and regulatory reporting, ensuring both customer protection and institutional compliance. Integral to customer lifecycle management, the concept supports trend analysis on churn, AML surveillance, and service quality evaluations.', '[{"name": "closureRequestId", "type": "string", "description": "Unique closure request identifier"}, {"name": "closureReason", "type": "string", "description": "Customer-provided reason for closure"}, {"name": "requestedClosureDate", "type": "date", "description": "Requested date for account closure"}, {"name": "closureStatus", "type": "enum", "description": "Indicates the current processing state of the request (e.g., ''Pending'', ''In Review'', ''Completed'')."}, {"name": "finalSettlementAmount", "type": "decimal", "description": "The closing balance or amount to be settled at the time of closure."}, {"name": "processedBy", "type": "string", "description": "Identifier for the agent, employee, or system that processed the closure request."}, {"name": "regulatoryHoldFlag", "type": "boolean", "description": "Indicates if closure is subject to a regulatory or legal hold."}]'::jsonb, '[{"type": "related", "label": "Submitted by customer", "targetId": "financial_services-retail-banking-customer-profile"}]'::jsonb, 'account closure,request,deposit,workflow,customer churn,data retention,regulatory compliance,customer experience'::text[], 'Facilitates life cycle management of accounts while supporting compliance and retention analytics.', '2026-02-18 04:31:09.010135', 'Closure Request,Account Termination Request'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-920c9162-397b-4f76-9c9e-9a8912070ddd', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Personal Checking', 'Deposit Accounts', 'A Personal Checking Account is a deposit account typically held by individuals for managing day-to-day financial transactions, including receiving deposits, making payments, and accessing funds via checks, debit cards, or digital banking. These accounts are foundational to personal finance operations, facilitating salary deposits, bill payments, and money transfers. In the context of financial services operations, personal checking accounts serve as primary onboarding points for retail banking customers and play a critical role in customer relationship management. They often interface with ancillary banking services, such as overdraft protection and fraud detection, requiring sophisticated data and workflow integration. AI-driven automation is increasingly leveraged to support onboarding, transaction categorization, compliance monitoring, and personalized customer service for these accounts.', '[{"name": "accountStatus", "type": "enum", "description": "The current operational status of the account (e.g., Active, Dormant, Locked, Closed)."}, {"name": "overdraftProtectionEnabled", "type": "boolean", "description": "Indicates whether overdraft protection is active for this account."}, {"name": "accountTenure", "type": "integer", "description": "The length of time (in months or years) the checking account has been open."}, {"name": "minimumBalanceRequirement", "type": "decimal", "description": "Specifies the minimum balance that must be maintained to avoid fees."}]'::jsonb, '[]'::jsonb, 'Retail Banking,Payments,Transaction Monitoring,AML Compliance,Customer Onboarding'::text[], NULL, '2026-02-18 04:42:52.231315', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-initialratingassessment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'initialRatingAssessment', 'Credit Rating Assignment', 'The initialRatingAssessment is a critical juncture in the credit rating lifecycle, where an entity, security, or financial instrument receives its first formal opinion of creditworthiness. This process synthesizes quantitative and qualitative data—such as financial statements, market trends, and management practices—using standardized methodologies. The outcome establishes a reference point for ongoing credit monitoring, investor communications, and regulatory disclosures. The initial assessment also sets the foundation for rating actions like upgrades, downgrades, and reviews that may occur throughout the life of the rated instrument. In financial operations, a robust initial assessment underpins portfolio risk management and compliance benchmarking.', '[{"name": "assessmentDate", "type": "date", "description": "Date when the initial rating was completed"}, {"name": "assignedRating", "type": "string", "description": "Rating assigned in the initial assessment"}, {"name": "assessorId", "type": "string", "description": "Identifier for the analyst or team responsible"}, {"name": "methodologyVersion", "type": "string", "description": "The version or reference to the specific rating methodology applied during the assessment."}, {"name": "dataSnapshotReference", "type": "string", "description": "Reference to the set of financial and qualitative data used at the time of rating."}, {"name": "externalDataSourcesUsed", "type": "string", "description": "A list or description of third-party data sources leveraged during the assessment process."}]'::jsonb, '[{"type": "depends_on", "label": "Relies on committee approval", "targetId": "financial_services-credit-rating-ratingcommitteedecision"}]'::jsonb, 'assignment,process,rating,assessment,creditworthiness,initial-assignment,regulatory-compliance,audit-trail'::text[], 'Foundation for all subsequent rating activities and disclosures.', '2026-02-20 03:42:36.626227', 'first time rating,initial opinion'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-unsolicitedrating', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'unsolicitedRating', 'Credit Rating Assignment', 'An unsolicited rating is a credit rating issued by a credit rating agency without a formal request or input from the organization or issuer being rated, or their agents. In financial services operations, unsolicited ratings commonly serve as reference points for investors and market participants when requested ratings are unavailable or withheld. The lack of issuer participation means these ratings may not benefit from full disclosure or direct, entity-supplied information, sometimes resulting in increased reliance on publicly available data and industry signals. Asset managers, regulators, and market surveillance functions often monitor unsolicited ratings for early warning signals, issuer due diligence, or benchmarking purposes. In the AI agent lifecycle, correctly distinguishing between solicited and unsolicited ratings is critical for risk assessment and reporting integrity.', '[{"name": "publicationDate", "type": "date", "description": "Date the unsolicited rating was published"}, {"name": "reasonCode", "type": "string", "description": "Reason for assigning unsolicited rating"}, {"name": "notificationSent", "type": "boolean", "description": "Whether the issuer was notified"}, {"name": "ratingSource", "type": "string", "description": "Identifies the credit rating agency that issued the unsolicited rating."}, {"name": "ratingConfidenceLevel", "type": "decimal", "description": "Quantitative confidence or reliability score assigned by the agency for the unsolicited rating."}, {"name": "informationSourcesUsed", "type": "string", "description": "Summary or references to public or third-party sources used in the rating."}]'::jsonb, '[{"type": "related", "label": "Indicates lack of engagement", "targetId": "financial_services-credit-rating-issuerengagement"}]'::jsonb, 'unsolicited,issuer,assessment,independent,public-data,rating-agency,transparency,regulation'::text[], 'Enables broader market coverage in line with regulatory recommendations.', '2026-02-20 03:42:36.698561', 'unrequested rating,independent rating'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingreaffirmation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ratingReaffirmation', 'Credit Rating Assignment', 'The ''ratingReaffirmation'' concept represents a decision made by a credit rating agency or committee to maintain an existing credit rating after thorough periodic surveillance or analysis of material events. This outcome occurs when the review finds no significant changes in the creditworthiness of the entity or instrument, justifying the continued validity of the current rating. Such reaffirmations are critical for investor confidence and market stability, as they signal ongoing monitoring and due diligence by rating providers. In financial operations, documenting and communicating reaffirmations enhances transparency and trust between issuers, investors, and regulators. AI agents can automate and streamline surveillance processes, enabling accurate tracking and timely notifications of reaffirmation outcomes.', '[{"name": "reaffirmationDate", "type": "date", "description": "Date when the rating was reaffirmed"}, {"name": "rationaleText", "type": "string", "description": "Explanation for reaffirmation decision"}, {"name": "associatedRatingEntity", "type": "string", "description": "Name or identifier of the entity or instrument whose rating is reaffirmed."}, {"name": "reaffirmationType", "type": "enum", "description": "Categorization of reaffirmation, such as periodic review, event-driven, or ad hoc."}, {"name": "committeeMembers", "type": "string", "description": "List of individuals participating in the reaffirmation decision."}]'::jsonb, '[{"type": "parent", "label": "Output of committee review", "targetId": "financial_services-credit-rating-ratingcommitteedecision"}]'::jsonb, 'reaffirmation,surveillance,confirmation,rating,auditTrail,periodicReview,regulatoryCompliance,stakeholderNotification'::text[], 'Maintains market confidence and transparency regarding rating stability.', '2026-02-20 03:42:36.765061', 'maintained rating,rating review outcome'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingcommitteedecision', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ratingCommitteeDecision', 'Rating Process Governance', 'The ''ratingCommitteeDecision'' represents the formal outcome of deliberations by a credit rating committee, which is responsible for independent and collective evaluation of creditworthiness of financial instruments or entities. This decision forms the authoritative record for changes in credit ratings, underlying the transparency and accountability of rating actions within financial services. It serves as the foundation for rating publications, client notifications, and regulatory disclosures. Committee decisions ensure consistency and rigor by aggregating expert opinions and applying governance standards to maintain integrity in the rating process. These formal rulings are often audited and referenced in risk management, investor communications, and compliance workflows.', '[{"name": "decisionDate", "type": "date", "description": "Date the committee reached the decision"}, {"name": "decisionType", "type": "enum", "description": "Type (e.g., assign, upgrade, downgrade, withdraw)"}, {"name": "committeeChairId", "type": "string", "description": "Identifier for the committee chair"}, {"name": "decisionJustification", "type": "string", "description": "Explanation or rationale provided by the committee for the decision."}, {"name": "affectedEntities", "type": "string", "description": "Identifiers or names of entities/instruments impacted by the committee decision."}, {"name": "decisionOutcomeStatus", "type": "enum", "description": "Final status (e.g., implemented, on hold, escalated) of the committee''s decision."}]'::jsonb, '[{"type": "child", "label": "Made by committee members", "targetId": "financial_services-credit-rating-ratingcommitteemember"}]'::jsonb, 'governance,committee,decision,rating,auditability,regulation,confidentiality,notification,riskAssessment'::text[], 'Ensures independent and objective rating decisions, an IOSCO Code core requirement.', '2026-02-20 03:42:36.836597', 'committee resolution,rating approval'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingcommitteemember', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ratingCommitteeMember', 'Rating Process Governance', 'A ratingCommitteeMember is an individual who actively participates in the governance structure of a credit rating agency or financial institution''s rating process. These members contribute to the collaborative review and determination of credit ratings for issuers or instruments, ensuring the process is conducted impartially and in accordance with organizational and regulatory requirements. Their involvement directly impacts how ratings are discussed, approved, and communicated, with a strong emphasis on ethical considerations, independence, and transparency. Members are commonly subject to rigorous qualification and conduct standards due to the sensitive nature of rating decisions and their direct influence on market participants. The documentation and activity of each member are audited and retained to ensure traceability and accountability in high-stakes financial services environments.', '[{"name": "memberId", "type": "string", "description": "Unique identifier for the committee member"}, {"name": "role", "type": "string", "description": "E.g., chair, member, secretary"}, {"name": "tenureStart", "type": "date", "description": "Start date of membership"}, {"name": "expertiseArea", "type": "string", "description": "Primary sector or asset class expertise of the committee member."}, {"name": "votingWeight", "type": "decimal", "description": "Weight assigned to the member''s vote in rating decisions, if applicable."}, {"name": "isIndependent", "type": "boolean", "description": "Indicates whether the member is independent from the rated entity."}, {"name": "trainingLastCompleted", "type": "date", "description": "Date when the member last completed mandatory rating or compliance training."}]'::jsonb, '[{"type": "parent", "label": "Participates in making decisions", "targetId": "financial_services-credit-rating-ratingcommitteedecision"}]'::jsonb, 'governance,committee,personnel,rating,audit,compliance,expertise,regulatory,conflict-management'::text[], 'Mitigates bias and enforces checks-and-balances within rating agencies.', '2026-02-20 03:42:36.905039', 'committee participant,rating panelist'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingactionrationale', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ratingActionRationale', 'Rating Process Governance', 'The ''ratingActionRationale'' provides a comprehensive, auditable narrative detailing the justification, evaluation criteria, and data that underpin a specific credit rating action by a rating agency. It ensures transparency of decision-making, documenting both quantitative analysis (e.g., financial metrics, macroeconomic forecasts) and qualitative assessments (e.g., management quality, sector outlook). In financial services operations, this rationale establishes trust with stakeholders, enables peer or regulatory review, and supports the continuous improvement of rating models. AI agent integration can streamline rationale generation, consistency checks, and cross-referencing with underlying data sources. Maintaining and tracking robust rationales is fundamental for internal governance, dispute resolution, and responding to regulatory requests.', '[{"name": "rationaleId", "type": "string", "description": "Identifier for rationale record"}, {"name": "rationaleText", "type": "string", "description": "Full rationale explanation"}, {"name": "linkedRatingAction", "type": "string", "description": "Reference to related rating action"}, {"name": "approvalStatus", "type": "enum", "description": "The review and approval status of the rationale, e.g., Draft, Reviewed, Approved, Rejected."}, {"name": "rationalePreparedBy", "type": "string", "description": "Identifier or name of the analyst or agent who prepared the rationale."}, {"name": "rationaleDate", "type": "date", "description": "The date on which the rationale was created or last updated."}]'::jsonb, '[]'::jsonb, 'documentation,rationale,compliance,rating,audit-trail,transparency,explainability,decision-support'::text[], 'Required for regulatory transparency and issuer/market trust.', '2026-02-20 03:42:36.971791', 'rationale statement,action justification'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingdatavalidation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ratingDataValidation', 'Data Integrity and Controls', 'Rating data validation is a critical process in financial services for ensuring that all data used in credit rating assignments meets stringent accuracy, consistency, and completeness criteria. This validation step protects the integrity of credit ratings, which are widely relied upon for risk management, capital allocation, regulatory reporting, and investor decision-making. The process often involves automated and manual checks against multiple data sources, including market, issuer, and historical performance data. Effective rating data validation can prevent costly errors, improve transparency, and increase stakeholder confidence in credit rating outcomes. As data volumes and complexity grow, AI agents are increasingly used to perform high-frequency, multi-dimensional validations to maintain timeliness and reliability.', '[{"name": "validationDate", "type": "date", "description": "When validation was performed"}, {"name": "validationStatus", "type": "enum", "description": "Pass/Fail or specific validation result"}, {"name": "checkedBy", "type": "string", "description": "Validator identity"}, {"name": "validationMethod", "type": "string", "description": "Specifies the approach or algorithm used during data validation (e.g., manual review, statistical checks, machine learning)."}, {"name": "validationScope", "type": "string", "description": "Describes the subset of data or fields covered by the specific validation instance."}, {"name": "validationOutcomeNotes", "type": "string", "description": "Provides detailed notes or rationale for the validation outcome, especially in cases of failure."}, {"name": "validationSeverity", "type": "enum", "description": "Indicates the criticality or impact level of detected issues (e.g., low, medium, high)."}]'::jsonb, '[]'::jsonb, 'validation,data,controls,quality,auditability,financialServices,regulatoryCompliance,creditRisk,traceability'::text[], 'Critical for rating credibility and regulatory compliance.', '2026-02-20 03:42:37.039025', 'data check,input validation'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuerinformationdisclosure', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'issuerInformationDisclosure', 'Data Integrity and Controls', 'IssuerInformationDisclosure captures the ongoing obligation of an issuer to provide relevant, timely, and accurate material information to credit rating agencies. This process is crucial for enabling agencies to maintain up-to-date assessments of creditworthiness, reflecting both financial and non-financial developments. Disclosures may occur periodically, such as annual reports, or be triggered by significant corporate events, mergers, or regulatory actions. Ensuring the integrity, completeness, and compliance of these disclosures is foundational for accurate credit ratings and transparent financial markets. In financial services operations, precise issuer information disclosure supports risk analytics, counterparty assessment, and decision-making within trading, lending, and investment domains.', '[{"name": "disclosureDate", "type": "date", "description": "Date of disclosure"}, {"name": "disclosureType", "type": "string", "description": "Nature of disclosure (annual report, event-driven, etc.)"}, {"name": "isCompliant", "type": "boolean", "description": "Whether the disclosure meets regulatory requirements"}, {"name": "materialityAssessment", "type": "string", "description": "Assessment of whether disclosed information is considered material for rating decisions."}, {"name": "disclosureChannel", "type": "string", "description": "Method by which issuer provides disclosure (e.g., regulatory portal, press release, direct submission)."}, {"name": "documentReference", "type": "string", "description": "Link or reference to the actual disclosed document or dataset."}]'::jsonb, '[{"type": "parent", "label": "Data inputs may be validated", "targetId": "financial_services-credit-rating-ratingdatavalidation"}]'::jsonb, 'disclosure,issuer,data,compliance,data-integrity,audit-trail,materiality,event-driven,timeliness'::text[], 'Required for informed, fair, and transparent credit ratings.', '2026-02-20 03:42:37.105917', 'issuer report,information submission'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-publicratingreport', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'publicRatingReport', 'Credit Rating Publication & Surveillance', 'A publicRatingReport is a formal document published by a credit rating agency to communicate a specific entity’s or instrument’s credit rating. It encompasses not only the assigned rating but also an in-depth rationale, key risk factors, and economic or sectoral considerations influencing the rating decision. This report is disseminated broadly to issuers, investors, regulators, and the general market to ensure transparency. The use of publicRatingReport facilitates informed investment decisions, regulatory oversight, and market surveillance. Its structure and content must adhere to industry standards to support auditability and comparability across ratings.', '[{"name": "reportId", "type": "string", "description": "Unique report identifier"}, {"name": "publishedDate", "type": "date", "description": "Date report became public"}, {"name": "language", "type": "string", "description": "Language of report"}, {"name": "issuerName", "type": "string", "description": "Name of the entity or instrument being rated."}, {"name": "coverageRegion", "type": "string", "description": "Geographic region or market covered by the report."}, {"name": "reportVersion", "type": "integer", "description": "Sequential version identifier for updates or amendments to the report."}, {"name": "confidentialInformationExcluded", "type": "boolean", "description": "Indicates if confidential information has been omitted from the public report as per regulatory requirements."}]'::jsonb, '[{"type": "depends_on", "label": "Includes full rationale", "targetId": "financial_services-credit-rating-ratingactionrationale"}, {"type": "depends_on", "label": "Incorporates market conditions data at publication time", "targetId": "fibo-9"}]'::jsonb, 'publication,report,market,transparency,regulatoryDisclosure,investorRelations,creditRisk,marketIntelligence'::text[], 'Central channel for sharing credit opinions with investors and regulators.', '2026-02-20 03:42:37.172907', 'rating announcement,credit report'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuerfeedbackprocess', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'issuerFeedbackProcess', 'Credit Rating Publication & Surveillance', 'The issuerFeedbackProcess serves as a structured mechanism within credit rating agencies for rated entities to provide input on their preliminary credit ratings, methodologies, and rationales prior to official publication. This channel promotes transparency and ensures the issuer has an opportunity to address factual inaccuracies, clarify data points, or dispute interpretations. Issuer feedback may result in revisions to the draft rating report, strengthening the accuracy and credibility of the published rating. The process is vital for maintaining robust governance in credit rating operations and fosters trust between issuers and rating organizations. Efficient management of issuer feedback is critical to timely rating disclosure and to upholding regulatory mandates.', '[{"name": "feedbackRequestDate", "type": "date", "description": "When feedback was solicited"}, {"name": "issuerResponseDeadline", "type": "date", "description": "Deadline for issuer feedback"}, {"name": "feedbackReceived", "type": "boolean", "description": "Whether issuer provided feedback"}, {"name": "feedbackSummary", "type": "string", "description": "Summary of key points or issues raised in issuer feedback."}, {"name": "feedbackResolved", "type": "boolean", "description": "Indicates whether the issuer''s feedback was addressed prior to publication."}, {"name": "feedbackDocumentUrl", "type": "string", "description": "Link or location of the full issuer feedback document for reference."}, {"name": "revisionImpactLevel", "type": "enum", "description": "Level of report revision prompted by issuer feedback (e.g., minor, moderate, significant)."}]'::jsonb, '[{"type": "parent", "label": "Feedback may impact the report", "targetId": "financial_services-credit-rating-publicratingreport"}]'::jsonb, 'issuer,feedback,process,engagement,compliance,transparency,auditability,corporate-governance,stakeholder-engagement'::text[], 'Ensures fairness, accuracy, and gives issuers opportunity to correct factual errors.', '2026-02-20 03:42:37.23949', 'issuer response,comments process'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingwithdrawal', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ratingWithdrawal', 'Credit Rating Publication & Surveillance', 'Rating withdrawal is a critical process within credit rating surveillance, involving the formal cessation of an agency''s opinion on an entity or financial instrument. This procedure typically arises when sufficient information is unavailable, securities are redeemed, or other operational factors prevent ongoing monitoring. A rating withdrawal must be meticulously documented and communicated, as it directly affects market transparency and investor decision-making. In financial services operations, managing rating withdrawals ensures compliance with industry practices for disclosure and upholds the integrity of published rating histories.', '[{"name": "withdrawalDate", "type": "date", "description": "Date when rating was withdrawn"}, {"name": "withdrawalReason", "type": "string", "description": "Explanation for withdrawal"}, {"name": "notificationSent", "type": "boolean", "description": "Whether market/issuer was notified"}, {"name": "issuerContactDetails", "type": "string", "description": "Contact information for the relevant issuer, facilitating withdrawal communication"}, {"name": "publicDisclosureUrl", "type": "string", "description": "URL linking to public disclosure or press release regarding the withdrawal"}, {"name": "regulatoryReference", "type": "string", "description": "Citation of applicable regulatory frameworks governing the withdrawal decision"}]'::jsonb, '[{"type": "related", "label": "May be explained in a report", "targetId": "financial_services-credit-rating-publicratingreport"}]'::jsonb, 'withdrawal,termination,disclosure,rating,regulatoryCompliance,notification,auditTrail,issuerCommunication,instrumentLifecycle'::text[], 'Maintains integrity by ensuring ratings only exist when current, relevant, and sufficiently informed.', '2026-02-20 03:42:37.306686', 'rating removal,opinion withdrawal'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuerdefaultevent', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'issuerDefaultEvent', 'Credit Event & Incident Tracking', 'An issuerDefaultEvent represents the formal identification and documentation of a debt default by a rated issuer. Such an event signals a significant risk occurrence and is a pivotal trigger for credit rating agencies to reassess and possibly adjust the issuer''s credit rating. In financial_services operations, issuer default events initiate cascades of responses, including notification of counterparties, activation of contractual provisions, and initiation of recovery or restructuring strategies. This concept is crucial for accurate credit risk modeling, historical event analysis, and meeting auditing requirements. It also influences capital adequacy, stress testing, and disclosure obligations under different regulatory regimes.', '[{"name": "defaultDate", "type": "date", "description": "When the default event occurred"}, {"name": "impactSeverity", "type": "string", "description": "Magnitude or context of default"}, {"name": "remediationStatus", "type": "string", "description": "Current state of attempted remedies"}, {"name": "defaultType", "type": "enum", "description": "Classification of default (e.g., missed payment, bankruptcy filing, technical default)."}, {"name": "notifiedParties", "type": "string", "description": "List of stakeholders or regulatory bodies notified of the default."}, {"name": "recoveryEstimate", "type": "decimal", "description": "Estimated percentage of principal expected to be recovered post-default."}, {"name": "sourceConfirmationDate", "type": "date", "description": "Date when the default event was independently confirmed by an authoritative source."}]'::jsonb, '[]'::jsonb, 'default,event,issuer,impact,creditRisk,materialEvent,regulatoryReporting,restructuring'::text[], 'Significantly affects the ongoing validity and perception of credit ratings.', '2026-02-20 03:42:37.373577', 'issuer default,credit event'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-materialeventnotification', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'materialEventNotification', 'Credit Event & Incident Tracking', 'A materialEventNotification is a formal notice or alert that communicates the occurrence of a significant event which could materially impact the risk profile or creditworthiness of a rated entity, instrument, or facility. Examples include mergers and acquisitions, regulatory actions, significant litigation, or senior management turnover. In financial services operations, these notifications are critical for timely credit risk assessment, stakeholder awareness, and triggering downstream processes such as surveillance or ratings review. Such notifications help ensure that all relevant parties—credit analysts, counterparties, regulators, and rating subscribers—are informed of developments that may influence existing ratings. They are frequently automated using AI-driven monitoring solutions for timely detection and dissemination.', '[{"name": "eventDate", "type": "date", "description": "When event occurred or was disclosed"}, {"name": "eventType", "type": "string", "description": "Nature of the event"}, {"name": "notifiedTo", "type": "string", "description": "Party or platform notified"}, {"name": "eventSeverity", "type": "enum", "description": "Categorization of the material impact (e.g., High, Medium, Low) to facilitate prioritization."}, {"name": "sourceReference", "type": "string", "description": "Reference or citation for where the material event was first identified."}, {"name": "actionRequired", "type": "string", "description": "Specifies whether specific follow-up actions are mandated by the notification."}]'::jsonb, '[{"type": "related", "label": "May require public disclosure", "targetId": "financial_services-credit-rating-publicratingreport"}, {"type": "child", "label": "May result in a credit rating action", "targetId": "custom-b5eae9a9-2b3a-456b-be64-198c95c7508a"}, {"type": "related", "label": "Can be linked to relevant market news sources", "targetId": "fibo-9"}]'::jsonb, 'materiality,notification,disclosure,event,corporate-actions,market-sensitivity,regulatory-reporting,risk-management'::text[], 'Timely notification is key for responsible credit risk monitoring.', '2026-02-20 03:42:37.440128', 'significant event alert,material development'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuersectorclassification', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'issuerSectorClassification', 'Issuer and Instrument Classification', 'The issuerSectorClassification concept provides a standardized way to categorize financial instrument issuers across recognized economic sectors, such as sovereign, financial, corporate, and public finance. This classification is a cornerstone for risk assessment, performance benchmarking, and portfolio analysis within financial institutions. It supports analytical uniformity and comparability across diverse asset classes, facilitating sector-specific credit risk modeling and trend identification. In both regulatory and reporting contexts, sector classification underpins stress testing, capital allocation, and sectoral exposure disclosures. Accurate and consistent sector assignments enable financial institutions and their agents to navigate regulatory mandates and market practices efficiently.', '[{"name": "classificationDate", "type": "date", "description": "Date of sector assignment"}, {"name": "sectorType", "type": "string", "description": "E.g., sovereign, utility, corporate"}, {"name": "assignedBy", "type": "string", "description": "Who assigned the classification"}, {"name": "sectorDefinitionSource", "type": "string", "description": "Reference source or taxonomy used for the sector classification."}, {"name": "isRegulatoryClassification", "type": "boolean", "description": "Indicates if the classification is aligned with regulatory definitions."}, {"name": "classificationConfidenceScore", "type": "decimal", "description": "Quantitative score representing the confidence level of the sector assignment."}, {"name": "lastReviewedDate", "type": "date", "description": "Date the sector classification was last reviewed or validated."}]'::jsonb, '[]'::jsonb, 'issuer,sector,classification,taxonomy,regulatory-reporting,risk-aggregation,portfolio-monitoring,exposure-management,data-quality'::text[], 'Enables appropriate methodology selection and enhances rating comparability.', '2026-02-20 03:42:37.513362', 'sector tagging,industry classification'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-securitysubordinationlevel', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'securitySubordinationLevel', 'Issuer and Instrument Classification', 'The ''securitySubordinationLevel'' concept delineates the relative repayment priority of a security in the event of issuer default or restructuring. This hierarchy—ranging from senior to subordinated—affects the risk profile, investor protection, and yield expectations for the affected security. In capital structure analytics, this classification is fundamental for assessing loss exposure and expected recovery rates for stakeholders. Accurate classification of subordination levels facilitates consistent credit rating outcomes and influences decision-making in portfolio management and risk mitigation strategies. It is also integral to structured finance models where waterfall mechanisms dictate payment flows based on security ranking.', '[{"name": "subordinationLevel", "type": "string", "description": "Position (senior, subordinated, mezzanine, etc.)"}, {"name": "assignedDate", "type": "date", "description": "Date the level was determined"}, {"name": "isSecured", "type": "boolean", "description": "Indicates presence of collateral"}, {"name": "priorityRanking", "type": "integer", "description": "Numerical value representing the exact precedence in the capital structure."}, {"name": "lossAbsorptionCapacity", "type": "decimal", "description": "Amount or percentage of losses that can be absorbed by this security level."}, {"name": "isCallable", "type": "boolean", "description": "Indicates whether the security can be called or retired before maturity."}, {"name": "legalReference", "type": "string", "description": "Citation of legal documentation or contract specifying subordination terms."}]'::jsonb, '[]'::jsonb, 'security,subordination,ranking,credit risk,structured finance,priority,waterfall,loss severity,capital structure'::text[], 'Crucial for determining loss severity and recovery prospects in credit ratings.', '2026-02-20 03:42:37.579902', 'seniority level,security rank'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingpressrelease', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'RatingPressRelease', 'External Communications & Disclosures', 'A RatingPressRelease is an official, time-bound statement disseminated by a rating agency to the market, stakeholders, and the public, announcing changes to an entity''s credit rating, as well as the supporting analysis and future outlook. This communication is critical for transparency, influencing market sentiment, and informing investment and risk management decisions across the financial ecosystem. It often contains not only the rating action but also justifications, trends, and factors influencing the change. RatingPressReleases are distributed through multiple regulated and public channels to ensure broad and equal access to material information. Their timeliness and accuracy are paramount in maintaining market integrity, fair disclosure, and regulatory compliance.', '[{"name": "releaseDate", "type": "date", "description": "Date of publication."}, {"name": "distributionChannels", "type": "string", "description": "Newswires, websites, email blasts, etc."}, {"name": "headline", "type": "string", "description": "A concise title summarizing the main rating action."}, {"name": "impactedEntities", "type": "string", "description": "List of entities and instruments affected by the rating action."}, {"name": "embargoLiftTime", "type": "date", "description": "Timestamp when the press release may be publicly disclosed."}, {"name": "rationaleSummary", "type": "string", "description": "Concise explanation of the reasons for the rating action."}]'::jsonb, '[{"type": "depends_on", "label": "Aligns the timing with real-time financial market data events.", "targetId": "fibo-9"}]'::jsonb, 'press,disclosure,announcement,regulatory,public-information,embargoed,market-sensitive,timeliness'::text[], 'Ensures fair disclosure to market participants and compliance with regulatory transparency requirements.', '2026-02-24 17:06:08.778777', 'RatingAnnouncement,CreditRelease'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuerengagement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'IssuerEngagement', 'External Communications & Disclosures', 'IssuerEngagement represents the formal interactions and information exchanges between credit rating agencies and issuers, typically focused on clarifying analytical findings, obtaining issuer feedback, and discussing potential rating actions. These sessions are crucial to ensure transparency, accuracy, and mutual understanding in the credit rating process, allowing issuers to address queries or concerns before finalizing ratings. IssuerEngagement activities help identify material risks, validate assumptions, and facilitate constructive dialogue, often leading to enhanced ratings quality and issuer trust. In financial services operations, this concept ensures that credit ratings are based on comprehensive and verified issuer input, supporting robust decision-making for investors and regulators. Such engagements are also recorded and monitored for compliance and audit purposes within rating agency workflows.', '[{"name": "engagementDate", "type": "date", "description": "Date of the engagement meeting."}, {"name": "engagementType", "type": "string", "description": "Nature of interaction, e.g., management meeting, feedback."}, {"name": "engagementDuration", "type": "decimal", "description": "Length of the engagement session in hours or minutes."}, {"name": "issuerRepresentative", "type": "string", "description": "Name or identifier of the issuer''s representative involved in the engagement."}, {"name": "actionItemsAgreed", "type": "string", "description": "List of follow-up actions or deliverables agreed upon during the session."}]'::jsonb, '[]'::jsonb, 'communication,issuer,feedback,outreach,regulatory_audit,issuer_confidentiality,meeting_minutes,compliance_monitoring'::text[], 'Key for obtaining issuer perspectives and ensuring analytical transparency and completeness.', '2026-02-24 17:06:08.852782', 'IssuerDialogue,IssuerMeeting'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-confidentialinformationdisclosure', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ConfidentialInformationDisclosure', 'External Communications & Disclosures', 'ConfidentialInformationDisclosure is a critical control process within financial services, governing how sensitive and non-public information is managed during external communications, especially in credit rating activities. This process involves identifying confidential data, monitoring its flow, and ensuring disclosures occur only in compliance with internal controls and regulatory mandates. It is fundamental to maintaining trust with clients, upholding market integrity, and preventing inadvertent information leaks that could influence financial markets or breach contractual obligations. In rating agency contexts, it spans handling issuer-provided documents, internal analysis, and regulated disclosure channels. Proper execution of this process safeguards reputation and supports legal defense against potential misuse claims.', '[{"name": "disclosureDate", "type": "date", "description": "Date on which confidential info is handled/disclosed."}, {"name": "recipientType", "type": "string", "description": "Who received the confidential information."}, {"name": "informationType", "type": "string", "description": "Classification or category of the confidential information disclosed (e.g., MNPI, PII, business secrets)."}, {"name": "disclosureMethod", "type": "enum", "description": "Channel or mechanism through which the confidential information was disclosed (e.g., email, portal, verbal)."}, {"name": "authorizedBy", "type": "string", "description": "Identity or role of the person/entity authorizing the disclosure."}]'::jsonb, '[{"type": "related", "label": "May occur in context of issuer engagement.", "targetId": "financial_services-credit-rating-issuerengagement"}]'::jsonb, 'confidentiality,regulatory,disclosure,policy,information-control,audit,issuer-communications,security'::text[], 'Protects both the rating agency and issuer against misuse of material non-public information.', '2026-02-24 17:06:08.905727', 'SensitiveInfoDisclosure,NonPublicInfoHandling'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-creditratinghistory', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'CreditRatingHistory', 'Credit Rating Data & Publication', 'CreditRatingHistory captures the chronological evolution of credit ratings assigned to a financial entity or instrument. This comprehensive dataset includes every rating event (upgrade, downgrade, affirmation, or withdrawal), offering transparency into the risk profile''s changes over time. In financial services operations, maintaining an accurate credit rating history is essential for risk modeling, regulatory reporting, and investment analysis. Such histories also support portfolio stress testing and counterparty risk assessment, ensuring that all rating actions are auditable and traceable. Integration of this data allows firms to benchmark credit performance and anticipate potential rating transitions.', '[{"name": "historyStartDate", "type": "date", "description": "First recorded rating date."}, {"name": "historyEntries", "type": "integer", "description": "Total number of rating actions recorded."}, {"name": "mostRecentActionDate", "type": "date", "description": "Date of the most recent credit rating action."}, {"name": "ratingTransitionFrequency", "type": "decimal", "description": "Frequency or rate at which rating actions occur over the recorded period."}, {"name": "averageRatingScore", "type": "decimal", "description": "Average rating value over the historical period, useful for trend analysis."}]'::jsonb, '[]'::jsonb, 'history,record,timelines,publication,compliance,trend-analysis,risk-monitoring,auditing'::text[], 'Enables performance tracking, transparency, and regulatory reporting for rated entities.', '2026-02-24 17:06:08.954841', 'RatingTrackRecord,RatingTimeline'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-ratingrationalepublication', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'RatingRationalePublication', 'Credit Rating Data & Publication', 'A RatingRationalePublication is a formal disclosure, such as a document, press release, or web page, that transparently communicates the detailed reasoning and supporting facts behind an agency’s or lender’s credit rating decision. It provides stakeholders—such as investors, regulators, and counterparties—with insights into the methodologies, financial data, and qualitative judgments underpinning a rating change or affirmation. This publication is integral to sustaining market trust, supporting transparency, and reducing information asymmetry in capital markets. In financial_services operations, these rationales feed into credit risk assessment workflows, inform downstream investment decisions, and enable external stakeholder review and regulatory audits. AI agents use these documents for sentiment analysis, trend monitoring, and verification of rating consistency.', '[{"name": "publicationDate", "type": "date", "description": "When the rationale was published."}, {"name": "publicURL", "type": "string", "description": "Location of the published rationale."}, {"name": "ratingAction", "type": "enum", "description": "Type of rating action this rationale supports (e.g., upgrade, downgrade, affirmation, withdrawal)."}, {"name": "subjectEntity", "type": "string", "description": "The specific entity, instrument, or program that this publication refers to."}, {"name": "methodologyReference", "type": "string", "description": "Link or identifier to the rating methodology used in the analysis."}]'::jsonb, '[]'::jsonb, 'publication,rationale,analysis,disclosure,transparency,audit,compliance'::text[], 'Facilitates informed decision-making by investors, issuers, and market regulators.', '2026-02-24 17:06:09.001181', 'RatingJustification,CreditReport'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-peercomparisonsummary', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'PeerComparisonSummary', 'Credit Rating Data & Publication', 'A PeerComparisonSummary provides an evaluative snapshot that compares the credit profile of an issuer with a selected group of peers. This comparative summary is pivotal in illuminating relative strengths and weaknesses, helping stakeholders understand an issuer''s standing within its industry or sector. Credit rating committees use this analysis to substantiate rating decisions and provide transparency to market participants. In financial services operations, such summaries aid in risk management, pricing strategies, and regulatory disclosures. PeerComparisonSummary can also be leveraged to monitor competitive positioning over time, especially during market shifts.', '[{"name": "peerGroupName", "type": "string", "description": "Name of the comparison group."}, {"name": "comparisonDate", "type": "date", "description": "Date the comparison was compiled."}, {"name": "keyComparativeMetric", "type": "string", "description": "The primary metric or set of metrics used for peer benchmarking (e.g., leverage ratio, profitability)."}, {"name": "issuerRelativeRank", "type": "integer", "description": "Issuer''s rank within the peer group based on selected metrics."}, {"name": "analysisType", "type": "enum", "description": "Specifies the type of comparative analysis (e.g., quantitative, qualitative, blended)."}]'::jsonb, '[]'::jsonb, 'comparison,peer,benchmarking,credit-assessment,rating-transparency,regulatory-disclosure,risk-benchmarking'::text[], 'Provides market context for rating users and helps benchmark creditworthiness.', '2026-02-24 17:06:09.047132', 'PeerBenchmark,RelativeAnalysis'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-d45be08e-b628-4663-a169-df0f4b0bf8e9', 'custom', 'Cross-Industry Ontology', 'Order to Cash', 'Business Processes', 'End-to-end process from order receipt to payment collection', '[]'::jsonb, '[]'::jsonb, ''::text[], NULL, '2026-02-28 02:12:00.261093', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-entity-management-businessentity', 'custom', 'Cross-Industry Ontology', 'BusinessEntity', 'Entity Management', 'A BusinessEntity represents a distinct unit that may have legal, functional, or operational roles within an organization or across corporate boundaries. In the context of custom AI agent operations, this concept is crucial for delineating the scope of authority, operational processes, and regulatory obligations associated with each unit. AI agents must recognize and manage unique entity attributes, such as geographic jurisdiction, business function, and reporting structure. Properly modeling BusinessEntity enables agents to execute entity-specific tasks, ensure regulatory compliance, and tailor workflows to organizational requirements. Accurate entity distinction is fundamental for interoperability, risk management, and supporting audits across complex enterprise ecosystems.', '[{"name": "entityId", "type": "string", "description": "Unique identifier for the business entity."}, {"name": "entityType", "type": "enum", "description": "Type of entity, e.g., legal, operational, subsidiary."}, {"name": "jurisdiction", "type": "string", "description": "Primary legal or regulatory jurisdiction where the entity operates."}, {"name": "registrationDate", "type": "date", "description": "Official registration date of the business entity."}, {"name": "status", "type": "enum", "description": "Current operational status (e.g., active, dissolved, suspended)."}, {"name": "legalIdentifier", "type": "string", "description": "Globally recognized legal identifier, such as an LEI code."}]'::jsonb, '[{"type": "parent", "label": "Managed or owned by an organizational unit.", "targetId": "custom-entity-management-organizationalunit"}, {"type": "child", "label": "Holds or operates business accounts.", "targetId": "BusinessAccount"}, {"type": "related", "label": "Subject to specific data privacy policies.", "targetId": "Data Privacy Policy"}, {"type": "depends_on", "label": "Dependent on relevant regulatory licenses for operations.", "targetId": "Regulatory License"}]'::jsonb, 'governance,identity,compliance,jurisdictional,data-sovereignty,risk-segmentation,entity-resolution'::text[], 'Applicable to all industries for structuring corporate hierarchies.', '2026-02-28 02:46:21.299681', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-entity-management-organizationalunit', 'custom', 'Cross-Industry Ontology', 'OrganizationalUnit', 'Entity Management', 'An OrganizationalUnit represents a formal subsection within a broader business entity, typically defined by function (such as HR, IT, or Sales), geography (e.g., regional branches), or operational focus. In the context of custom operations and AI agent management, OrganizationalUnit is crucial for delineating accountabilities, managing workflows, and ensuring operational efficiency and segregation of duties. It enables granular tracing of activities and performance attribution in cross-functional processes. AI agents can use OrganizationalUnit metadata to customize actions, enforce policy boundaries, and tailor reporting based on internal structures. This concept supports granular access controls and localized compliance automation across enterprise operations.', '[{"name": "unitCode", "type": "string", "description": "Code identifying the organizational unit."}, {"name": "unitName", "type": "string", "description": "Full name of the unit."}, {"name": "unitType", "type": "enum", "description": "Defines whether the unit is functional, regional, or project-based."}, {"name": "parentUnitCode", "type": "string", "description": "Code of the parent organizational unit, enabling hierarchical tracing."}, {"name": "managerName", "type": "string", "description": "Name of the person responsible for the unit."}]'::jsonb, '[{"type": "child", "label": "Belongs to a business entity.", "targetId": "custom-entity-management-businessentity"}, {"type": "related", "label": "Organizational unit staffed by these employees.", "targetId": "Employee"}, {"type": "depends_on", "label": "Organizational unit operates within a specific regulatory jurisdiction.", "targetId": "Jurisdiction"}]'::jsonb, 'structure,location,responsibility,hierarchy,compliance,operations,governance'::text[], 'Foundational for mapping enterprise structure in any sector.', '2026-02-28 02:46:21.347255', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-entity-management-externalpartner', 'custom', 'Cross-Industry Ontology', 'ExternalPartner', 'Entity Management', 'The ''ExternalPartner'' concept refers to any organization or individual entity operating outside a company''s legal boundary but involved in ongoing business relationships with it. In the context of custom operations, these entities are critical for enabling supply chains, co-developing products or services, distributing outputs, or providing specialized expertise. Efficient management and oversight of external partners ensure optimized collaboration, streamlined workflows, and reduced operational risks. AI agents can automate onboarding, performance monitoring, and compliance checks for external partners, enhancing operational transparency and responsiveness. This concept plays an essential role in enterprise risk management and workflow automation.', '[{"name": "partnerType", "type": "enum", "description": "Nature of partnership (e.g., supplier, distributor, client)."}, {"name": "contractId", "type": "string", "description": "Identifier for contractual agreement."}, {"name": "partnershipStartDate", "type": "date", "description": "Date when the partnership with the external entity commenced."}, {"name": "riskRating", "type": "string", "description": "Risk assessment score or level for the external partner."}, {"name": "jurisdiction", "type": "string", "description": "Primary legal or operational jurisdiction of the external partner."}]'::jsonb, '[{"type": "related", "label": "Has business relationships with entities.", "targetId": "custom-entity-management-businessentity"}, {"type": "depends_on", "label": "Is governed by one or more contractual agreements", "targetId": "Contractual Agreement"}, {"type": "related", "label": "Is subject to compliance and regulatory requirements", "targetId": "Compliance Obligation"}]'::jsonb, 'relationship,supply-chain,collaboration,third-party,risk-management,outsourcing,vendor,partner-evaluation'::text[], 'Critical for cross-industry supply chain and stakeholder management.', '2026-02-28 02:46:21.39157', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-product-service-product', 'custom', 'Cross-Industry Ontology', 'Product', 'Product & Service', 'In custom AI agent operations, the ''Product'' concept represents any organizational output, whether physical or digital, intended for sale or broader distribution. AI agents can use detailed product ontologies for lifecycle management, pricing optimization, or ensuring regulatory labeling and compliance. Understanding a product as both a data entity and a business object is critical for orchestrating inventory, order fulfillment, and customer personalization processes. Agents managing ''Product'' data must handle complex attributes, dependencies, and nested service relationships, especially in modular or configurable offerings. This foundational concept underpins a wide variety of cross-industry automation and analytics scenarios.', '[{"name": "sku", "type": "string", "description": "Stock Keeping Unit or product code."}, {"name": "productCategory", "type": "enum", "description": "Classification, e.g., electronics, software, service."}, {"name": "releaseDate", "type": "date", "description": "The official date when the product is made available to the market."}, {"name": "regulatoryComplianceStatus", "type": "enum", "description": "Indicates whether the product meets all relevant regulatory requirements."}, {"name": "warrantyPeriod", "type": "string", "description": "Duration for which the product is covered by warranty terms."}]'::jsonb, '[{"type": "depends_on", "label": "May require bundled services.", "targetId": "custom-product-service-service"}, {"type": "related", "label": "Supplied by specific organization or vendor", "targetId": "Supplier"}, {"type": "child", "label": "Has variants or specific released versions", "targetId": "Product Version"}]'::jsonb, 'goods,inventory,offering,SKUManagement,compliance-sensitive,digital-assets'::text[], 'Universal for product lifecycle management across domains.', '2026-02-28 02:46:21.43583', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-product-service-service', 'custom', 'Cross-Industry Ontology', 'Service', 'Product & Service', 'A service, as defined in the Cross-Industry Ontology, represents an intangible value proposition delivered by an organization to address specific customer needs. In custom operations, services can include technical support, maintenance, consulting, data processing, or other non-physical deliverables tailored to client requirements. AI agents managing service lifecycles typically facilitate service provisioning, ensure compliance with service level agreements, and monitor service delivery metrics. This concept is critical for mapping how clients interact with an organization beyond tangible products, creating opportunities for differentiation and added-value. Effectively capturing service metadata within an ontology also supports automation in contract management and performance analytics.', '[{"name": "serviceLevel", "type": "string", "description": "Definition of service quality (e.g., SLA details)."}, {"name": "serviceType", "type": "enum", "description": "Nature of service provided."}, {"name": "serviceAvailability", "type": "string", "description": "Indicates scheduled uptime and any maintenance windows applicable to the service."}, {"name": "serviceOwner", "type": "string", "description": "The individual or department accountable for the service''s delivery and performance."}, {"name": "complianceRequirement", "type": "string", "description": "Summarizes any external standards or regulations the service must comply with."}]'::jsonb, '[{"type": "related", "label": "Often complimented by products.", "targetId": "custom-product-service-product"}, {"type": "depends_on", "label": "Depends on underlying systems for service delivery", "targetId": "IT Infrastructure Component"}, {"type": "related", "label": "Defined by contractual service agreement terms", "targetId": "Service Agreement"}]'::jsonb, 'offering,intangible,delivery,SLA,provisioning,customer-experience,support,automated-monitoring'::text[], 'Relevant for IT, manufacturing, logistics, and more.', '2026-02-28 02:46:21.480176', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-product-service-productlifecyclestage', 'custom', 'Cross-Industry Ontology', 'ProductLifecycleStage', 'Product & Service', 'ProductLifecycleStage represents a distinct phase in the evolution of a product or service, delineating transitions such as introduction, growth, maturity, and retirement. In custom operations, tracking the lifecycle stage is crucial for AI agents to determine which operational and compliance policies apply, trigger stage-specific workflows, or automate customer notifications (e.g., for end-of-support). Lifecycle stage management underpins activities such as upgrades, feature deprecation, and migration planning, informing resource allocation and marketing strategies. AI agents use these stages to synchronize processes between engineering, compliance, sales, and support functions, ensuring consistency and traceability. Accurate staging enhances reporting and supports adaptive decision-making for continued product viability.', '[{"name": "stageName", "type": "string", "description": "Name of the lifecycle stage."}, {"name": "effectiveDate", "type": "date", "description": "When this stage becomes active."}, {"name": "previousStage", "type": "string", "description": "Identifies the immediately preceding lifecycle stage."}, {"name": "nextStage", "type": "string", "description": "Identifies the immediately succeeding lifecycle stage."}, {"name": "stageDescription", "type": "string", "description": "Detailed description of activities, objectives, and controls relevant to this stage."}]'::jsonb, '[{"type": "parent", "label": "Determines the current status of a product.", "targetId": "custom-product-service-product"}, {"type": "depends_on", "label": "Must adhere to stage-specific regulatory mandates.", "targetId": "RegulatoryComplianceRequirement"}, {"type": "related", "label": "Informs SLA terms based on product lifecycle stage.", "targetId": "ServiceLevelAgreement"}]'::jsonb, 'innovation,maintenance,obsolescence,upgrade,release,support,deprecation'::text[], 'Essential for product portfolio and compliance management.', '2026-02-28 02:46:21.524428', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-process-workflow-businessprocess', 'custom', 'Cross-Industry Ontology', 'BusinessProcess', 'Process & Workflow', 'A BusinessProcess represents a structured set of coordinated activities or tasks designed to deliver a specific outcome in line with business goals. In the context of custom operations, BusinessProcesses provide the execution blueprint for AI agents to operationalize rules, handle handoffs, and ensure compliance within complex environments. Effective definition and management of BusinessProcesses enable organizations to standardize operations, dynamically adapt to changes, and continuously optimize performance. AI agents can orchestrate, monitor, and improve BusinessProcesses, directly impacting productivity, compliance, and operational resilience. Clear visibility and control over BusinessProcesses facilitate responsive automation and enhanced exception management.', '[{"name": "processId", "type": "string", "description": "Unique process identifier."}, {"name": "processOwner", "type": "string", "description": "Responsible party or role."}, {"name": "processType", "type": "enum", "description": "Categorizes the process, e.g., ''Operational'', ''Compliance'', ''Customer-Facing''."}, {"name": "processStatus", "type": "string", "description": "Current status of the process (e.g., Active, Suspended, Completed, In Review)."}, {"name": "startDate", "type": "date", "description": "The initiation date of the business process."}]'::jsonb, '[{"type": "depends_on", "label": "Implemented using workflows.", "targetId": "custom-process-workflow-workflow"}, {"type": "child", "label": "Composed of specific process steps", "targetId": "ProcessStep"}, {"type": "depends_on", "label": "Execution governed by business rules", "targetId": "BusinessRule"}]'::jsonb, 'operations,optimization,automation,compliance,workflow,auditability,traceability'::text[], 'Core foundation in all operational and enterprise architectures.', '2026-02-28 02:46:21.568325', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-process-workflow-workflow', 'custom', 'Cross-Industry Ontology', 'Workflow', 'Process & Workflow', 'A workflow represents an orchestrated sequence of tasks, either manual or automated, that collectively achieve defined business outcomes within an organization. In custom operations, workflows are pivotal for codifying operational knowledge, standardizing execution, and providing traceable paths for auditing. AI agents leverage workflows to dynamically manage task allocations, optimize resource utilization, and enable adaptive responses to changing operational conditions. Workflows also facilitate integration across digital and human systems, ensuring consistency and compliance in complex multi-domain environments. Properly managed workflows accelerate time-to-value and support continuous improvement initiatives.', '[{"name": "workflowName", "type": "string", "description": "Human-readable workflow name."}, {"name": "workflowType", "type": "enum", "description": "Manual, semi-automated, or automated workflow."}, {"name": "workflowStatus", "type": "enum", "description": "Current status such as Draft, Active, Paused, or Completed."}, {"name": "lastExecuted", "type": "date", "description": "Timestamp of the last execution of this workflow."}, {"name": "owner", "type": "string", "description": "Person or team responsible for the workflow''s maintenance."}]'::jsonb, '[{"type": "child", "label": "Executes steps within a business process.", "targetId": "custom-process-workflow-businessprocess"}, {"type": "related", "label": "Includes specific approval or validation steps", "targetId": "Approval Step"}, {"type": "depends_on", "label": "Requires reference data for execution", "targetId": "Reference Data Source"}]'::jsonb, 'tasks,coordination,execution,process-automation,business-process,compliance,auditability'::text[], 'Frequently leveraged in digital transformation initiatives.', '2026-02-28 02:46:21.613071', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-process-workflow-processmetric', 'custom', 'Cross-Industry Ontology', 'ProcessMetric', 'Process & Workflow', 'A ProcessMetric provides objective, quantitative insights into how a process performs against set goals, such as speed, accuracy, cost efficiency, or compliance rates. By consistently measuring and tracking these metrics, organizations can identify bottlenecks and inefficiencies for targeted improvements. In custom operations, AI agents use process metrics to trigger alerts, automate corrective actions, and inform optimization routines. Comprehensive process metrics are also vital for ensuring that workflows remain aligned with organizational objectives and service level agreements. Ultimately, robust process metrics support evidence-based decision-making and continuous improvement initiatives.', '[{"name": "metricName", "type": "string", "description": "Name of the process metric."}, {"name": "metricValue", "type": "decimal", "description": "Current or historical value for the metric."}, {"name": "targetThreshold", "type": "decimal", "description": "The expected or regulatory threshold value for this metric."}, {"name": "lastUpdated", "type": "date", "description": "Timestamp of the most recent metric update."}, {"name": "measurementFrequency", "type": "string", "description": "The interval at which the metric is measured (e.g., daily, weekly, real-time)."}]'::jsonb, '[{"type": "related", "label": "Assesses efficiency and quality of processes.", "targetId": "custom-process-workflow-businessprocess"}, {"type": "child", "label": "Can trigger alerts based on threshold breaches", "targetId": "ProcessMetricAlert"}, {"type": "depends_on", "label": "Requires accurate data input from defined data sources", "targetId": "DataSource"}]'::jsonb, 'KPI,benchmarking,monitoring,operational-risk,trend-analysis,compliance-reporting,continuous-improvement'::text[], 'Critical for business performance management and regulatory requirements.', '2026-02-28 02:46:21.657273', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-data-information-dataasset', 'custom', 'Cross-Industry Ontology', 'DataAsset', 'Data & Information', 'A DataAsset is a fundamental unit representing either a logical or physical aggregation of data, identified for its intrinsic or strategic business value within an organization. Custom operations involving DataAssets focus on their creation, transformation, sharing, and management throughout their lifecycle, ensuring alignment with business objectives and compliance obligations. AI agents interacting with DataAssets must account for the varying forms (structured, unstructured, semi-structured), and track their provenance, quality, and lineage for operational transparency. In custom operations environments, DataAssets are central to enabling automated data governance, federated data sharing, and advanced analytics workflows. Effective DataAsset management underpins secure data utilization, value extraction, and compliant external sharing.', '[{"name": "assetId", "type": "string", "description": "Data asset identifier."}, {"name": "assetType", "type": "enum", "description": "Type: structured, unstructured, semi-structured."}, {"name": "owner", "type": "string", "description": "Responsible individual or organizational unit for the DataAsset."}, {"name": "creationDate", "type": "date", "description": "Date the DataAsset was created."}, {"name": "sensitivityLevel", "type": "enum", "description": "Classification of the DataAsset''s sensitivity (e.g., public, confidential, restricted)."}, {"name": "retentionPolicy", "type": "string", "description": "Policy defining the lifespan and deletion criteria for the DataAsset."}]'::jsonb, '[{"type": "parent", "label": "Evaluated based on classification rules.", "targetId": "custom-data-information-dataclassification"}, {"type": "related", "label": "Tracks derivation and transformation history of the DataAsset.", "targetId": "Data Lineage"}, {"type": "child", "label": "Subject to specific quality metrics and validation rules.", "targetId": "Data Quality Rule"}]'::jsonb, 'information,value,management,governance,cataloging,data-lifecycle,security,compliance'::text[], 'Key for data governance across regulated and non-regulated industries.', '2026-02-28 02:46:21.702407', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-data-information-dataclassification', 'custom', 'Cross-Industry Ontology', 'DataClassification', 'Data & Information', 'DataClassification is a formal process that assigns a sensitivity and access level to data assets, ensuring that each piece of information is appropriately handled within custom operations. This allows AI agents and systems to enforce security policies, automate data governance, and ensure proper access control. It assists in managing data lifecycles by dictating handling practices, retention periods, and permissible usage. Accurate data classification is crucial for risk management and regulatory reporting, as it underpins safeguards for sensitive and regulated information. In custom AI deployments, DataClassification determines how agents may interact with, transmit, or process different data subsets, reducing the risk of data leakage.', '[{"name": "classificationLevel", "type": "enum", "description": "Level: public, internal, confidential, restricted."}, {"name": "validityPeriod", "type": "date", "description": "Expiry or review date."}, {"name": "classificationAuthority", "type": "string", "description": "The individual or system responsible for assigning the classification."}, {"name": "reviewFrequency", "type": "string", "description": "How often the classification should be reviewed or audited."}, {"name": "applicableRegulations", "type": "string", "description": "Specific regulations tied to the classified data asset."}]'::jsonb, '[{"type": "child", "label": "Classifies the sensitivity of assigned data assets.", "targetId": "custom-data-information-dataasset"}, {"type": "depends_on", "label": "Classification relies on the policies that govern data access", "targetId": "Data Access Policy"}, {"type": "related", "label": "Classification informs applicable data retention guidelines", "targetId": "Data Retention Rule"}]'::jsonb, 'security,compliance,policy,data-governance,risk-management,privacy,data-lifecycle'::text[], 'Relevant for privacy, GDPR, and industrial confidentiality.', '2026-02-28 02:46:21.746908', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-data-information-masterdata', 'custom', 'Cross-Industry Ontology', 'MasterData', 'Data & Information', 'MasterData represents the foundational, authoritative set of core organizational entities such as customers, products, and suppliers, ensuring data consistency and integrity across business processes. In the context of custom operations, MasterData serves as the backbone that enables AI agents to reconcile disparate data sources, orchestrate business workflows, and reduce duplication or conflicting records. AI agents interacting with MasterData can automate validation, support regulatory audits, and streamline data integration within enterprise systems. Maintaining up-to-date, accurate MasterData significantly reduces operational risk and facilitates seamless cross-domain analytics and reporting.', '[{"name": "domain", "type": "enum", "description": "Domain e.g., customer, product, supplier."}, {"name": "version", "type": "string", "description": "Master data versioning info."}, {"name": "lastUpdated", "type": "date", "description": "Timestamp of the most recent update to this master data record."}, {"name": "status", "type": "enum", "description": "Current lifecycle status such as active, deprecated, or archived."}, {"name": "authoritySource", "type": "string", "description": "Original authoritative source for this master data record."}]'::jsonb, '[{"type": "related", "label": "Sourced from or synchronized with data assets.", "targetId": "custom-data-information-dataasset"}, {"type": "parent", "label": "Is consolidated within a broader reference data set", "targetId": "Reference Data Set"}, {"type": "depends_on", "label": "Is managed in accordance with", "targetId": "Data Governance Policy"}]'::jsonb, 'reference,consistency,integration,authoritative,lineage,validation,PII,auditability'::text[], 'Fundamental for enterprise data architecture and integration.', '2026-02-28 02:46:21.791212', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-risk-compliance-risk', 'custom', 'Cross-Industry Ontology', 'Risk', 'Risk & Compliance', 'In the context of custom AI agent operations, ''Risk'' represents a potential threat, vulnerability, or uncertainty that may disrupt desired business outcomes or system objectives. AI agents can play a significant role in continuously monitoring, identifying, and assessing risks across operational, financial, and regulatory domains. Risk is not merely a static condition; its context and impact can change in real time, requiring adaptive AI-driven controls and remediation. By treating risk as a structured ontology concept, organizations ensure traceability of how risks are identified, prioritized, and responded to throughout the AI agent lifecycle. This enables proactive mitigation strategies, scalable risk governance, and auditable decision-making.', '[{"name": "riskCategory", "type": "enum", "description": "Type: operational, financial, regulatory."}, {"name": "riskScore", "type": "decimal", "description": "Quantitative risk rating or assessment."}, {"name": "riskLikelihood", "type": "decimal", "description": "Probability of the risk materializing within a defined time frame."}, {"name": "riskOwner", "type": "string", "description": "Responsible party or role accountable for managing the risk."}, {"name": "riskReviewDate", "type": "date", "description": "Most recent date when the risk was assessed or reviewed."}]'::jsonb, '[{"type": "depends_on", "label": "Mitigated through implementation of controls.", "targetId": "custom-risk-compliance-control"}, {"type": "related", "label": "May materialize as an incident if unmitigated", "targetId": "Incident"}, {"type": "depends_on", "label": "Assessed using defined indicators and metrics", "targetId": "Risk Indicator"}]'::jsonb, 'assessment,probability,impact,alerting,remediation,governance,continuous-monitoring'::text[], 'Vital for ERM systems across all regulated industries.', '2026-02-28 02:46:21.835183', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-risk-compliance-control', 'custom', 'Cross-Industry Ontology', 'Control', 'Risk & Compliance', 'In custom AI agent operations, a ''Control'' refers to a formally defined measure, technical safeguard, or procedural action constructed and executed to manage, reduce, or eliminate identified risks. These controls are crucial in sustaining operational resilience and maintaining integrity across automated or human-in-the-loop workflows. Controls may encompass automated application checks, manual approvals, authorization gates, or monitoring thresholds, specifically architected to handle threats identified in the AI agent''s operational environment. Their implementation helps ensure compliance with prescribed policy mandates, bolster cyber defenses, and facilitate dynamic remediation in the event of control failures. For AI agents, having granular visibility and interaction with these controls is vital for adaptive risk responses and compliance automation.', '[{"name": "controlType", "type": "enum", "description": "Type: preventive, detective, corrective."}, {"name": "controlOwner", "type": "string", "description": "Responsible party for the control."}, {"name": "controlFrequency", "type": "enum", "description": "How often the control is tested or executed (e.g., continuous, daily, monthly)."}, {"name": "controlStatus", "type": "enum", "description": "Current operational status of the control (e.g., effective, ineffective, needs review)."}, {"name": "lastTestedDate", "type": "date", "description": "The most recent date this control was tested or reviewed."}]'::jsonb, '[{"type": "related", "label": "Implements mitigation strategies for risks.", "targetId": "custom-risk-compliance-risk"}, {"type": "parent", "label": "Is a component of the overall mitigation strategy for risks.", "targetId": "Risk Mitigation Strategy"}, {"type": "depends_on", "label": "Enforced or triggered by regulatory requirements.", "targetId": "Regulatory Requirement"}]'::jsonb, 'mitigation,audit,policy,internal-controls,compliance-assurance,security,control-testing'::text[], 'Required for internal controls in finance, healthcare, manufacturing, and more.', '2026-02-28 02:46:21.878718', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-risk-compliance-compliancerequirement', 'custom', 'Cross-Industry Ontology', 'ComplianceRequirement', 'Risk & Compliance', 'A ComplianceRequirement defines the specific legal, regulatory, or internal policy conditions that must be satisfied by organizational processes and operations. In the context of custom AI agent operations, these requirements serve as critical guardrails for automating business decisions, ensuring agents enforce rules and respond appropriately to governance changes. Compliance requirements often span jurisdictions and may involve ongoing obligations such as monitoring, reporting, and adapting operational controls. For AI agents, accurate mapping and real-time evaluation of these requirements are essential for mitigating compliance risk without impeding business agility. Proactive handling of these requirements allows organizations to innovate while maintaining legal defensibility.', '[{"name": "requirementId", "type": "string", "description": "Unique identifier for the requirement."}, {"name": "jurisdiction", "type": "string", "description": "Applicable legal or regulatory domain."}, {"name": "requirementType", "type": "enum", "description": "Specifies whether the requirement is legal, regulatory, policy, or contractual."}, {"name": "effectiveDate", "type": "date", "description": "The date from which the requirement becomes enforceable."}, {"name": "penaltyDescription", "type": "string", "description": "Details of penalties or consequences for non-compliance."}, {"name": "lastReviewedDate", "type": "date", "description": "The most recent date this requirement was reviewed for currency and accuracy."}]'::jsonb, '[{"type": "parent", "label": "Defines controls necessary for compliance.", "targetId": "custom-risk-compliance-control"}, {"type": "depends_on", "label": "Is mandated or authored by", "targetId": "Regulatory Body"}, {"type": "related", "label": "Is cited or verified by", "targetId": "Audit Finding"}]'::jsonb, 'regulation,policy,governance,oversight,monitoring,audit-ready,jurisdictional,obligation'::text[], 'Indispensable for regulatory compliance in all major sectors.', '2026-02-28 02:46:21.923077', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-performance-analytics-keyperformanceindicator', 'custom', 'Cross-Industry Ontology', 'KeyPerformanceIndicator', 'Performance & Analytics', 'A Key Performance Indicator (KPI) is a critical metric used within custom operations to objectively evaluate progression towards targeted business outcomes and strategic goals. In AI agent lifecycle management, KPIs are essential for monitoring agent effectiveness, optimizing behavioral adaptations, and benchmarking operational improvements. They enable ongoing performance assessment, support automated decision-making, and drive alignment with overall organizational objectives. KPIs are often integrated into dashboards for continual oversight and trigger interventions if thresholds are breached. Integration of AI with KPIs allows for real-time analytics, anomaly detection, and proactive optimization of operational workflows.', '[{"name": "indicatorName", "type": "string", "description": "Name of the KPI."}, {"name": "targetValue", "type": "decimal", "description": "Planned or expected value for the metric."}, {"name": "actualValue", "type": "decimal", "description": "Measured value of the KPI over a specific period."}, {"name": "measurementFrequency", "type": "string", "description": "How often the KPI is measured (e.g., daily, weekly, monthly)."}, {"name": "status", "type": "enum", "description": "Current state of the KPI relative to its target (e.g., on track, at risk, off track)."}]'::jsonb, '[{"type": "related", "label": "May be derived from process metrics.", "targetId": "custom-process-workflow-processmetric"}, {"type": "depends_on", "label": "KPI relies on data from source systems.", "targetId": "Data Source System"}, {"type": "related", "label": "KPI is used to measure progress towards a business objective.", "targetId": "Business Objective"}]'::jsonb, 'measurement,strategy,dashboard,performance-management,reporting,compliance,automation'::text[], 'Central for management and operational reporting across industries.', '2026-02-28 02:46:21.967362', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-performance-analytics-analyticsmodel', 'custom', 'Cross-Industry Ontology', 'AnalyticsModel', 'Performance & Analytics', 'An AnalyticsModel represents a core computational asset within custom operations, serving as a statistical or machine learning model designed to uncover actionable insights from organizational data. These models may range from simple regressions to complex neural networks, depending on the analytical requirements and data types. In the context of AI agent lifecycle management, the AnalyticsModel is pivotal for enabling data-driven decision-making and automating predictive or prescriptive functionalities. Effective management of AnalyticsModels encompasses not only initial development, but also ongoing retraining, monitoring, and governance to ensure relevancy and accuracy. Their lifecycle is tightly integrated with business objectives, data governance policies, and operational workflows in modern enterprises.', '[{"name": "modelType", "type": "enum", "description": "Type of model: regression, classification, clustering, etc."}, {"name": "accuracy", "type": "decimal", "description": "Most recent accuracy or performance metric."}, {"name": "lastTrainedDate", "type": "date", "description": "Timestamp when the AnalyticsModel was most recently trained or updated."}, {"name": "explainabilityScore", "type": "decimal", "description": "Score indicating how interpretable or explainable the model outputs are."}, {"name": "inputFeatureList", "type": "string", "description": "Delimited list of input features or variables utilized by the model."}]'::jsonb, '[{"type": "depends_on", "label": "Trained and evaluated using data assets.", "targetId": "custom-data-information-dataasset"}, {"type": "related", "label": "Assessed by risk evaluation procedures for model governance", "targetId": "ModelRiskAssessment"}, {"type": "child", "label": "Composed of one or more versioned model instances", "targetId": "ModelVersion"}]'::jsonb, 'prediction,insight,data-science,model-governance,machine-learning,explainability,automated-decisioning'::text[], 'Used for advanced analytics and AI across sectors.', '2026-02-28 02:46:22.011964', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-performance-analytics-benchmark', 'custom', 'Cross-Industry Ontology', 'Benchmark', 'Performance & Analytics', 'A Benchmark serves as a reference point, often established using industry standards, regulatory guidance, or internal best practices, to measure performance and outcomes for processes, agents, or the organization. In custom operations, it enables objective assessment, comparison, and continuous improvement by specifying clear targets or standards for analytics and reporting. AI agents can dynamically update benchmarks based on evolving data sets, apply them for automated anomaly detection, and trigger workflows when deviations occur. Benchmarks are also integral to scenario analysis and operational risk assessment. Integrating benchmarks helps ensure consistency and transparency in performance management across domains.', '[{"name": "benchmarkType", "type": "enum", "description": "Type: internal, industry, regulatory."}, {"name": "benchmarkValue", "type": "decimal", "description": "Value used to compare against actuals."}, {"name": "sourceAuthority", "type": "string", "description": "Name or reference of the authority or entity that provided or validated the benchmark."}, {"name": "effectiveDate", "type": "date", "description": "The date from which the benchmark becomes applicable."}, {"name": "applicabilityScope", "type": "string", "description": "The domain, process, or entity to which the benchmark applies."}]'::jsonb, '[{"type": "related", "label": "Establishes threshold for KPI evaluation.", "targetId": "custom-performance-analytics-keyperformanceindicator"}, {"type": "parent", "label": "Is a subset of standardized performance references.", "targetId": "Performance Standard"}, {"type": "depends_on", "label": "Requires authoritative data sources for benchmark creation and validation.", "targetId": "Reference Data Source"}]'::jsonb, 'comparison,target,performance,standardization,regulatory-compliance,analytics,baseline'::text[], 'Supports performance improvement and competitive analysis in all domains.', '2026-02-28 02:46:22.055707', ''::text[], 'industry-standard', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-89de0b36-59bd-4481-b39d-18907166e877', 'custom', 'Cross-Industry Ontology', 'SKU', 'Product & Service', 'A Stock Keeping Unit (SKU) is a unique identifier used to track individual products or services within an inventory management system. In custom operations, SKUs enable AI agents to differentiate, monitor, and optimize the handling of products, including stock allocation, shelf placement, and dynamic pricing. SKUs form the backbone of product-level analytics and are essential for automating supply chain tasks such as replenishment and order fulfillment. By associating operational data with SKUs, organizations increase accuracy and efficiency in inventory processing. AI agents leveraging SKUs can enhance responsiveness to demand fluctuations and product recalls.', '[{"name": "skuCode", "type": "string", "description": "Unique alphanumeric SKU identifier assigned to the product or service."}, {"name": "isActive", "type": "boolean", "description": "Indicates if the SKU is currently in use or has been retired."}, {"name": "dateAssigned", "type": "date", "description": "Date when the SKU was assigned to the product or service."}, {"name": "skuType", "type": "enum", "description": "Type classification for the SKU, such as physical product, digital service, or bundle."}]'::jsonb, '[{"type": "related", "label": "SKU is tracked at specific inventory locations", "targetId": "Inventory Location"}, {"type": "parent", "label": "SKU is an attribute of a Product", "targetId": "Product"}, {"type": "depends_on", "label": "SKU is tied to pricing and discount information", "targetId": "Pricing Information"}]'::jsonb, 'inventory-management,product-identification,supply-chain,retail-operations'::text[], NULL, '2026-02-28 02:59:59.421404', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-fd146b87-02bc-4d0f-b227-c4be8ad151e9', 'custom', 'Cross-Industry Ontology', 'Product Family', 'Product & Service', 'A Product Family is a high-level grouping of related products that share common features, design, or intended market segment. In the context of custom operations, classifying products into families enables AI agents to streamline product management, automate portfolio categorization, and deliver targeted enhancements or compliance checks across similar offerings. Product Families support efficient change management by allowing updates or controls to be applied collectively, reducing redundancy in process execution. Moreover, AI agents can use this grouping to track lifecycle events, analyze aggregated performance, and ensure consistent regulatory adherence across all products within a family.', '[{"name": "familyCode", "type": "string", "description": "A unique identifier for the product family to facilitate reference and integration."}, {"name": "familyDescription", "type": "string", "description": "Detailed narrative describing the shared characteristics of products in this family."}, {"name": "marketSegment", "type": "string", "description": "Target customer group or industry segment for the product family."}]'::jsonb, '[{"type": "parent", "label": "Belongs to overarching Product Entity", "targetId": "Product Entity"}, {"type": "child", "label": "Comprises multiple Product Variants", "targetId": "Product Variant"}]'::jsonb, 'Product Classification,Lifecycle Management,Portfolio Grouping,Regulatory Reporting'::text[], NULL, '2026-02-28 07:02:57.954007', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-747ff513-09c7-47ef-92a7-777b0526297d', 'custom', 'Cross-Industry Ontology', 'Configuration Rules', 'Product & Service', 'Configuration Rules define the customizable parameters and governance which dictate how a product or service is instantiated, modified, or managed throughout its operational lifecycle. Within custom operations, these rules ensure products are deployed in compliance with business logic and technical constraints, supporting variability without compromising standardization. Configuration Rules are critical in enabling AI agents to autonomously adapt offerings to specific client or regulatory requirements. They play a central role in orchestrating complex workflows, especially where dynamic composition or automated provisioning is needed. Clear definition and management of these rules enhance the reliability and repeatability of custom product/service operations.', '[{"name": "applicableScope", "type": "string", "description": "The business domain, product line, or service area where the rule applies."}, {"name": "effectiveDate", "type": "date", "description": "The date on which the configuration rule becomes active."}, {"name": "ruleVersion", "type": "string", "description": "Identifier for the specific version of the rule to support audits and rollback."}, {"name": "isRegulatoryRequired", "type": "boolean", "description": "Indicates if the configuration rule is mandated by a regulatory authority."}]'::jsonb, '[{"type": "related", "label": "Configuration Rules referenced by Compliance Policy", "targetId": "Compliance Policy"}, {"type": "depends_on", "label": "Configuration Rule activates based on Product Lifecycle Event", "targetId": "Product Lifecycle Event"}]'::jsonb, 'Rule Management,Product Customization,Business Logic,Compliance Automation'::text[], NULL, '2026-02-28 10:59:04.929404', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-578980df-7123-44b3-b9e2-ff0d608bbff0', 'custom', 'Cross-Industry Ontology', 'BOM (Bill of Materials)', 'Product & Service', 'The Bill of Materials (BOM) is a comprehensive listing of all components, subassemblies, raw materials, and precise quantities required to manufacture a product or deliver a service. In the context of custom operations, a BOM is crucial for accurate production planning, inventory management, and supply chain optimization. AI agents can leverage BOMs to automate procurement, ensure compliance with design specifications, and optimize costs. Furthermore, BOMs play a key role when configuring variants of complex products and coordinating engineering changes. Properly managed BOM data enables traceability, efficient resource allocation, and seamless product lifecycle management.', '[{"name": "versionNumber", "type": "string", "description": "Identifies the BOM version to track changes and revisions."}, {"name": "effectiveDate", "type": "date", "description": "The date when the BOM becomes active for production use."}, {"name": "bomType", "type": "enum", "description": "Specifies whether it is an engineering, manufacturing, or as-built BOM."}, {"name": "status", "type": "enum", "description": "Indicates the current state of the BOM (e.g., draft, approved, obsolete)."}]'::jsonb, '[{"type": "depends_on", "label": "BOM details all Components required for the product", "targetId": "Component"}, {"type": "related", "label": "BOM specifies the relationship with Suppliers for sourcing parts", "targetId": "Supplier"}, {"type": "child", "label": "BOM instances are updated by Engineering Change Orders", "targetId": "Engineering Change Order"}]'::jsonb, 'Product Configuration,Supply Chain,Manufacturing Process,Traceability,Regulatory Compliance'::text[], NULL, '2026-02-28 13:17:13.377664', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-f661aa43-413f-4dff-99f1-a76c78c0965a', 'custom', 'Cross-Industry Ontology', 'Base Price', 'Price List', 'In the context of custom operations, ''Base Price'' serves as the initial or standard price assigned to a product, service, or asset in a price list before discounts, taxes, or other modifiers are applied. For AI agents, the base price provides a critical reference point for pricing computations, margin analysis, and the application of dynamic pricing strategies. The accuracy and governance of the base price strongly influence downstream financial calculations and reporting. Establishing a reliable base price enables automated agents to ensure pricing consistency and support efficient price list modifications during negotiation or promotional campaigns. Proper handling of this concept is also essential for audit trails and transparent pricing practices.', '[{"name": "currencyCode", "type": "string", "description": "The ISO currency code in which the base price is denominated."}, {"name": "effectiveDate", "type": "date", "description": "The start date when this base price becomes valid."}, {"name": "validThrough", "type": "date", "description": "The end date through which the base price remains effective."}, {"name": "priceType", "type": "enum", "description": "Categorization of the base price, e.g., wholesale, retail, or negotiated."}]'::jsonb, '[{"type": "parent", "label": "Base Price is a primary attribute of the Price List entity", "targetId": "Price List"}, {"type": "related", "label": "Base Price may be modified according to applicable Discount Policy", "targetId": "Discount Policy"}, {"type": "depends_on", "label": "Base Price determination depends on the underlying Cost Basis", "targetId": "Cost Basis"}]'::jsonb, 'Pricing Operations,Audit Trail,Regulatory Reporting,Business Sensitive,Dynamic Pricing'::text[], NULL, '2026-02-28 16:10:48.876526', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-72399b58-301c-46bf-a7f4-c56274ec8b4d', 'custom', 'Cross-Industry Ontology', 'Tier Pricing', 'Price List', 'Tier Pricing refers to a pricing strategy where the unit price of goods or services varies based on quantity purchased, customer segment, or transaction volume. In the context of custom operations, AI agents utilize tier pricing models to dynamically calculate final prices, offering discounts or incentives as thresholds are met. Tier pricing is especially relevant for businesses managing complex sales agreements, bulk ordering, or loyalty programs. Robust handling of tier pricing enables more granular revenue forecasting, enhances customer personalization, and supports compliance with fair pricing practices. Integrating tier pricing into price lists ensures accurate and adaptable quoting during the sales or procurement process.', '[{"name": "tierThreshold", "type": "decimal", "description": "The minimum quantity or value required to qualify for a specific tier."}, {"name": "tierUnitPrice", "type": "decimal", "description": "The price per unit applicable when the corresponding tier threshold is met."}, {"name": "tierEffectiveDate", "type": "date", "description": "The date when a particular tier price becomes effective."}, {"name": "customerSegmentEligibility", "type": "string", "description": "Specific customer segments or groups eligible for this tier pricing."}]'::jsonb, '[{"type": "parent", "label": "Is a detailed structure within the Price List", "targetId": "Price List"}, {"type": "related", "label": "Linked to contractual agreements specifying tier pricing terms", "targetId": "Sales Contract"}]'::jsonb, 'Discount Management,Volume Pricing,Customer Segmentation,Dynamic Pricing'::text[], NULL, '2026-02-28 16:38:26.182449', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-d80f398d-7678-48af-8b6e-fb6d2a9d1355', 'custom', 'Cross-Industry Ontology', 'Volume breaks', 'Price List', 'In the context of custom operations, ''Volume breaks'' refer to the predefined quantity thresholds within a price list that determine price differentials based on the volume of goods or services purchased. These breaks allow dynamic pricing strategies, enabling organizations to offer tiered discounts or incentives as order volumes increase. AI agents can leverage volume breaks to optimize purchasing recommendations, automate pricing updates, and ensure contract compliance with negotiated terms. Proper handling and interpretation of volume breaks are crucial for maintaining pricing integrity, calculating accurate invoicing, and supporting complex sales agreements. Integrating volume breaks into agent workflows enhances transparency and agility in price list management.', '[{"name": "breakThresholdQuantity", "type": "decimal", "description": "The quantity of goods or services at which a new price tier is activated."}, {"name": "breakPrice", "type": "decimal", "description": "The price applicable for the specified volume tier."}, {"name": "effectiveDate", "type": "date", "description": "The date from which the volume break is considered valid."}]'::jsonb, '[{"type": "parent", "label": "Belongs to this price list", "targetId": "Price List"}, {"type": "related", "label": "Referenced in these sales contracts", "targetId": "Sales Agreement"}]'::jsonb, 'Dynamic Pricing,Tiered Discounting,Contractual Terms,Wholesale Pricing'::text[], NULL, '2026-02-28 17:49:58.702224', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-8a9105a0-b786-46b4-82e2-be254d4465ba', 'custom', 'Cross-Industry Ontology', 'Currency', 'Price List', 'Currency represents the specific national or supranational unit of exchange associated with items or services in a price list. In custom operations, associating price values with a clearly defined currency ensures accuracy in multi-jurisdictional billing, financial reconciliation, and reporting. For AI agent lifecycle management, correct handling and mapping of currency information is crucial for operations such as automated pricing, cross-border transactions, and currency conversion processes. Proper currency attribution supports downstream functions like auditing, analytics, financial forecasting, and compliance reporting. This concept further enables precise aggregation and comparison of financial data across diverse organizational geographies.', '[{"name": "isoCode", "type": "string", "description": "The three-letter standardized ISO 4217 currency code (e.g., ''USD'', ''EUR'')."}, {"name": "symbol", "type": "string", "description": "The character or symbol representing the currency (e.g., ''$'', ''€'')."}, {"name": "decimalPlaces", "type": "integer", "description": "The number of decimal places used for this currency."}, {"name": "effectiveDate", "type": "date", "description": "The date when the currency became effective for use in the price list."}]'::jsonb, '[{"type": "related", "label": "Linkage to exchange rates for conversion operations", "targetId": "Exchange Rate"}, {"type": "parent", "label": "Currency contextualizes the value represented as a monetary amount", "targetId": "Monetary Amount"}, {"type": "depends_on", "label": "Validity or applicability of a currency is jurisdiction-dependent", "targetId": "Jurisdiction"}]'::jsonb, 'Financial Attribute,Internationalization,Data Standardization,Currency Compliance'::text[], NULL, '2026-02-28 18:30:00.532216', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-de2e5e24-f712-478d-aab2-a760e557fa4f', 'custom', 'Cross-Industry Ontology', 'Effective Dates', 'Price List', 'In the context of custom operations, ''Effective Dates'' define the time period during which a particular Price List is valid and enforceable. This period determines when specific prices, discounts, or contractual terms can be offered to customers, partners, or internal stakeholders. Accurate management of Effective Dates is crucial for synchronizing system updates, price transitions, and for ensuring business rules are applied appropriately over time. AI agents must carefully track, compare, and audit these dates to avoid unauthorized pricing or out-of-policy transactions. In dynamic markets or regulatory environments, precise application of Effective Dates supports auditability and compliance and enables seamless pricing rollouts.', '[{"name": "startDate", "type": "date", "description": "The date and time when the Price List becomes effective."}, {"name": "endDate", "type": "date", "description": "The date and time when the Price List ceases to be effective."}, {"name": "timezone", "type": "string", "description": "The time zone in which the Effective Dates are set, crucial for global operations."}, {"name": "status", "type": "enum", "description": "Indicates if the Effective Dates are current, pending, or expired."}]'::jsonb, '[{"type": "parent", "label": "Is Effective Date for the Price List", "targetId": "Price List"}, {"type": "related", "label": "Governs application of contract terms", "targetId": "Contractual Terms"}]'::jsonb, 'Temporal Control,Pricing Governance,Contract Lifecycle Management,Validity Periods'::text[], NULL, '2026-02-28 18:36:11.105259', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-009cfbbf-f2a2-4214-831f-bfa3239321a3', 'custom', 'Cross-Industry Ontology', 'Discount type (%, fixed, promotional)', 'Discount', 'The ''Discount type'' concept specifies the nature of a discount applied within a business operation or transaction, such as percentage-based, fixed amount, or promotional offers. In the context of custom operations, explicitly defining the discount type ensures that AI agents can correctly calculate, validate, and apply the appropriate discount rules according to business policy. This distinction is critical for dynamic pricing models, targeted customer incentives, and complex transaction reconciliations. An AI agent managing discounts must accurately interpret and implement discount types in real time to maximize business outcomes, maintain auditability, and minimize errors. Consistency in discount type classification also supports downstream analytics and reporting.', '[{"name": "discountTypeCode", "type": "enum", "description": "Enumerated code defining the type of discount (e.g., percentage, fixed amount, promotional)."}, {"name": "applicabilityRule", "type": "string", "description": "Rule or condition specifying when the discount type is applicable."}, {"name": "validityPeriod", "type": "string", "description": "Timeframe or date range during which the discount type is valid."}]'::jsonb, '[{"type": "parent", "label": "Is a defining attribute of Discount", "targetId": "Discount"}, {"type": "depends_on", "label": "Discount type selection depends on Transaction context", "targetId": "Transaction"}, {"type": "related", "label": "Discount type is governed by Pricing Policy rules", "targetId": "Pricing Policy"}]'::jsonb, 'Pricing,Transactional Integrity,Campaign Management,Revenue Recognition'::text[], NULL, '2026-02-28 18:41:09.910058', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-4f4393dd-52d9-4d9b-bff8-9c23f942cc0c', 'custom', 'Cross-Industry Ontology', 'Approval Matrix', 'Discount', 'An Approval Matrix under the Discount category is a structured framework used to define which individuals or roles have the authority to approve specific types or levels of discounts within an organization. In the context of custom operations, this ensures that discounting decisions are properly governed, preventing unauthorized or excessive discounts that could impact financial performance. The matrix typically specifies approval thresholds and escalation paths, supporting consistent and auditable operations. For AI agent lifecycles, integrating the approval matrix enables autonomous agents to route discount approvals, verify compliance, and streamline the approval process. It also provides transparency and traceability in discount management workflows, ensuring that every decision is recorded and justified.', '[{"name": "approvalLevel", "type": "decimal", "description": "The monetary threshold at which a specific approver is required."}, {"name": "roleDesignation", "type": "string", "description": "The title or role authorized to approve discounts at a particular level."}, {"name": "escalationPath", "type": "string", "description": "The defined process for escalating discount requests that exceed approval thresholds."}]'::jsonb, '[{"type": "related", "label": "Approval Matrix is based on Discount Policy", "targetId": "Discount Policy"}, {"type": "depends_on", "label": "Approval Matrix assignments depend on Employee Role", "targetId": "Employee Role"}]'::jsonb, 'Workflow Automation,Risk Management,Access Control,Auditability'::text[], NULL, '2026-02-28 18:50:27.07452', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-041fb8e4-4c36-4e0f-addc-89aff4a48749', 'custom', 'Cross-Industry Ontology', 'Stacking rules', 'Discount', 'Stacking rules define the logic and constraints governing how multiple discounts can be applied together within a transaction, such as whether they can be combined, the order of application, or exclusivity requirements. In custom operations, these rules ensure accurate calculation of final prices and prevent conflicts or over-discounting, which is critical for revenue assurance. AI agents leveraging stacking rules can automate and validate discount applications, audit compliance with business policies, and recommend optimal discount strategies. By making stacking rules explicit, organizations reduce risk, enhance transparency, and enable adaptive pricing strategies. Stacking rules are essential in retail, e-commerce, and financial service operations where multiple, sometimes overlapping, promotions or offers are present.', '[{"name": "ruleType", "type": "enum", "description": "Specifies if the rule is combinable, exclusive, or conditional."}, {"name": "priorityLevel", "type": "integer", "description": "Indicates the priority order in which this rule should be applied."}, {"name": "effectiveDate", "type": "date", "description": "Date when this stacking rule comes into effect."}]'::jsonb, '[{"type": "related", "label": "Adheres to overarching promotion policies", "targetId": "Promotion Policy"}, {"type": "depends_on", "label": "Defines application behavior for associated Discount Entity", "targetId": "Discount Entity"}, {"type": "related", "label": "Recorded in discount rule change audit log", "targetId": "Audit Log"}]'::jsonb, 'Promotion Management,Revenue Assurance,Pricing Compliance,Retail Operations'::text[], NULL, '2026-02-28 18:53:03.711368', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-78387fb3-966e-403a-b6c1-c7b5b2fe1979', 'custom', 'Cross-Industry Ontology', 'Quote ID', 'Quote', 'The Quote ID is a unique identifier assigned to each individual quote within a pricing or quoting system. In the context of custom operations, it plays a critical role in tracking, referencing, and managing quotes throughout their lifecycle, enabling agents to distinguish between quotes, link related data, and support automated decision making. The Quote ID allows for seamless retrieval and updates, facilitates the audit trail for all transactional quote activities, and ensures consistency when integrating across multiple systems or platforms. It is foundational for orchestrating workflows that involve quote submission, revision, approval, and fulfillment. For AI-driven processes, the Quote ID serves as the anchor point to unite contextual data during analytics and compliance checks.', '[{"name": "issueDate", "type": "date", "description": "The date and time the Quote ID was generated."}, {"name": "sourceSystem", "type": "string", "description": "The originating system or platform that issued the Quote ID."}, {"name": "quoteStatus", "type": "enum", "description": "The current status of the quote (e.g., active, expired, amended, cancelled)."}]'::jsonb, '[{"type": "parent", "label": "Is assigned to Quote", "targetId": "Quote"}, {"type": "depends_on", "label": "Generated using Reference Data Source", "targetId": "Reference Data Source"}]'::jsonb, 'Identifier,LifecycleManagement,AuditTrail,WorkflowOrchestration'::text[], NULL, '2026-02-28 19:00:52.919128', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-0befde9d-dd83-45d1-8f89-f5bab1c306ac', 'custom', 'Cross-Industry Ontology', 'Line Items', 'Quote', 'Line Items within a Quote represent the individual goods or services, each with its own attributes such as description, quantity, unit price, and applicable conditions. In custom operations, accurate representation of Line Items enables granular tracking of quoted offerings, facilitates automated negotiations, and ensures comprehensive auditability of transactions. AI agents processing Quote entities depend on detailed Line Item data for tasks like price optimization and customized proposal generation. Additionally, maintaining structured Line Items allows for clearer contract terms and better alignment with downstream order or invoice systems. Ultimately, Line Items provide the foundation for precise and modular business processes in quotation workflows.', '[{"name": "lineItemId", "type": "string", "description": "A unique identifier for this line item within the quote for traceability."}, {"name": "description", "type": "string", "description": "A detailed description of the product or service for this line item."}, {"name": "quantity", "type": "decimal", "description": "The amount or number of units for this line item."}, {"name": "unitPrice", "type": "decimal", "description": "The quoted price per unit for this line item."}]'::jsonb, '[{"type": "parent", "label": "Is part of the parent Quote entity", "targetId": "Quote"}, {"type": "related", "label": "References an entry in the master catalog", "targetId": "Product or Service Catalog Entry"}, {"type": "related", "label": "Correlates with an order''s line item for fulfillment", "targetId": "Order Line Item"}]'::jsonb, 'itemization,pricing,quote-management,audit-trail'::text[], NULL, '2026-03-01 05:25:04.14576', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-671f9d3e-1f81-4d04-b25a-bbd5afdf0d43', 'custom', 'Cross-Industry Ontology', 'Total', 'Quote', 'In the context of custom operations, ''Total'' as an attribute of the Quote entity represents the aggregated value resulting from the underlying items, services, or products included within a quote. This value often incorporates line item costs, discounts, surcharges, and may factor in applicable taxes or fees depending on industry conventions. Accurate calculation and representation of the ''Total'' are critical for ensuring customer transparency, financial consistency, and downstream process automation. AI agents interacting with this concept must handle real-time recalculation, validation, and dynamic updates in response to changes within the Quote. Ensuring completeness and reliability of the ''Total'' supports business operations such as offer generation, contract lifecycle management, and order fulfillment.', '[{"name": "currencyCode", "type": "string", "description": "Three-letter ISO code representing the currency of the quoted total"}, {"name": "calculationBasis", "type": "string", "description": "Description or reference to the method or set of rules used to compute the total"}, {"name": "isTaxInclusive", "type": "boolean", "description": "Indicates whether the total includes applicable taxes"}, {"name": "lastCalculatedDate", "type": "date", "description": "Timestamp when this total was last computed or updated"}]'::jsonb, '[{"type": "depends_on", "label": "Total is calculated as the sum or aggregation of line item values", "targetId": "Line Item"}, {"type": "related", "label": "Total reflects adjustments from related discounts", "targetId": "Discount"}, {"type": "related", "label": "Total may include or exclude calculated tax amounts depending on context", "targetId": "Tax"}]'::jsonb, 'financial-aggregation,pricing,audit-trail,compliance,quote-processing'::text[], NULL, '2026-03-01 06:44:56.905221', ''::text[], 'custom-extension', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-5dc7da55-6f4d-4adb-851f-21ab38bd3d3a', 'custom', 'Cross-Industry Ontology', 'Validity', 'Quote', 'Validity, as an attribute of the Quote entity, refers to the period and set of conditions under which a particular quote is considered accurate, actionable, and binding for a transaction. In custom AI agent operations, managing quote validity ensures that agents act only on current, relevant market or product information, reducing the risks of executing against outdated or retracted quotes. Validity parameters often include start and end timestamps, market events that can void the quote, and any contextual qualifications. Properly maintaining quote validity enables agents to optimize transaction timing, ensure compliance, and deliver high-quality automated negotiations or trades. It also supports automated quote expiration and renewal processes that are crucial in fast-moving digital marketplaces.', '[{"name": "validFrom", "type": "date", "description": "The date and time from which the quote becomes valid."}, {"name": "validUntil", "type": "date", "description": "The expiry date and time after which the quote is no longer valid."}, {"name": "validityConditions", "type": "string", "description": "Specific business or legal conditions under which this validity is applicable."}, {"name": "isRenewable", "type": "boolean", "description": "Indicates whether the quote validity can be renewed automatically or requires new authorization."}]'::jsonb, '[{"type": "related", "label": "Terminates upon occurrence of the expiration event", "targetId": "Expiration Event"}, {"type": "depends_on", "label": "Validity may depend on live market data updates", "targetId": "Market Data Feed"}, {"type": "parent", "label": "Validity is an attribute of the Quote entity", "targetId": "Quote"}]'::jsonb, 'Time-Sensitivity,Compliance,Transactional Integrity,Lifecycle Management'::text[], NULL, '2026-03-01 09:39:48.026792', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Validity", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T09:40:24.622Z", "properties": [], "description": "Attribute of Quote Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-b7f69a65-6e71-4f58-b80b-cda87cf8fe1b', 'custom', 'Cross-Industry Ontology', 'Status', 'Quote', 'The ''Status'' attribute in the context of a Quote represents the current state of a quotation through its lifecycle. This can include stages such as Created, Sent, Accepted, Rejected, Expired, or Cancelled, and is vital for orchestrating workflow automation, auditing, and transaction routing in custom operations. For AI agents, this attribute acts as a decision gateway, determining the next actions, notifications, and compliance checks required for a particular Quote instance. Enriching the Status attribute allows for precise tracking and context-aware automation, reducing manual oversight and streamlining business processes. Accurate status management is essential for interoperability with external systems and maintaining data integrity in end-to-end quote management.', '[{"name": "previousStatus", "type": "string", "description": "The immediate past status value for traceability of changes"}, {"name": "statusTimestamp", "type": "date", "description": "The precise datetime when the status was last updated"}, {"name": "statusChangedBy", "type": "string", "description": "Identifier for the user or agent that performed the last status update"}]'::jsonb, '[{"type": "depends_on", "label": "Status changes triggered by specific lifecycle events", "targetId": "Quote Lifecycle Event"}, {"type": "related", "label": "Mapped to workflow state management for process orchestration", "targetId": "Workflow State"}]'::jsonb, 'Lifecycle,AuditTrail,Workflow,Governance'::text[], NULL, '2026-03-01 10:14:06.008272', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Status", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T10:14:32.669Z", "properties": [], "description": "Attribute of Quote Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-2a9f5033-8135-45e2-b44a-9e04f69da90b', 'custom', 'Cross-Industry Ontology', 'Version history', 'Quote', 'Version history in the context of a Quote entity captures all changes, edits, and updates made to a given quote throughout its lifecycle, providing a chronological record of modifications. This is essential in custom operations to ensure traceability, transparency, and auditability of pricing and offer information, especially when multiple stakeholders modify the same quote over time. In AI agent lifecycle management, version history enables agents to compare revisions, detect anomalies, automate approval flows, and ensure compliance with internal and external requirements. For organizations handling complex quoting processes, version history supports collaborative editing, rollback capabilities, and automated documentation. This fosters trust and accountability, particularly in regulated or high-value transaction environments.', '[{"name": "modifiedBy", "type": "string", "description": "Identifier for the user or system responsible for the change"}, {"name": "changeTimestamp", "type": "date", "description": "Date and time when the change to the quote was made"}, {"name": "changeReason", "type": "string", "description": "Free-text or enumerated explanation of why the change was made"}, {"name": "previousVersionReference", "type": "string", "description": "Unique reference to the immediately preceding version of the quote"}]'::jsonb, '[{"type": "parent", "label": "Version history is maintained for the Quote entity", "targetId": "Quote"}, {"type": "related", "label": "Version history contributes to the overall audit trail", "targetId": "Audit Trail"}, {"type": "depends_on", "label": "Version history entries are linked to the acting user or agent", "targetId": "User Profile"}]'::jsonb, 'Auditability,Change Management,Data Lineage,Regulatory Reporting,Quote Governance'::text[], NULL, '2026-03-01 10:34:07.41401', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Version history", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T10:34:30.870Z", "properties": [], "description": "Attribute of Quote Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-51fd4a9a-6f2c-4ee5-b7de-aabd25c3af59', 'custom', 'Cross-Industry Ontology', 'Account ID', 'Customer', 'The Account ID is a unique alphanumeric identifier assigned to a customer’s account within an organization''s systems. In the context of custom operations, it serves as a critical key for associating all account-related transactions, user permissions, and activity logs with a specific customer entity. AI agents managing customer lifecycles depend on the Account ID to accurately track activities such as onboarding, authentication, transaction processing, and account closure. Integrating Account ID into operations ensures precision in operations like fraud detection, personalized service delivery, and compliance monitoring. Persistent and secure management of Account ID is essential for system interoperability, reporting, and customer experience optimization.', '[{"name": "accountIdType", "type": "enum", "description": "Specifies the format or type of Account ID (e.g., internal, external, legacy, API)."}, {"name": "issueDate", "type": "date", "description": "Date the Account ID was generated or assigned."}, {"name": "status", "type": "enum", "description": "Indicates the current validity of the Account ID (e.g., active, suspended, closed, archived)."}, {"name": "issuerSystem", "type": "string", "description": "Identifies the IT system or authority that created or manages the Account ID."}]'::jsonb, '[{"type": "parent", "label": "Account ID belongs to Customer entity", "targetId": "Customer"}, {"type": "depends_on", "label": "Account ID linked to authentication credentials for system access", "targetId": "Authentication Credential"}, {"type": "related", "label": "Current state or status of the Account ID", "targetId": "Account Status"}]'::jsonb, 'PII,Identifier,Access Management,Audit Trail'::text[], NULL, '2026-03-01 11:07:06.146001', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Account ID", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T11:07:38.146Z", "properties": [], "description": "Attribute of Customer Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-be176848-ea61-411b-aa51-d41d8431d4bb', 'custom', 'Cross-Industry Ontology', 'Segment', 'Customer', 'The ''Segment'' concept represents the categorization of customers into distinct groups based on shared characteristics, behaviors, or value to the organization. Within custom operations, customer segments enable targeted service personalization, marketing strategies, and differentiated risk management workflows. AI agents use segmentation to automate routing, tailor interaction strategies, and optimize resource allocation across business processes. Effective segment management underpins scalable growth by aligning offerings and operations with customer needs. Integrating robust segmentation ensures that customer-centric AI solutions remain adaptive and compliant in dynamic regulatory environments.', '[{"name": "segmentName", "type": "string", "description": "A unique, human-readable name describing the customer segment."}, {"name": "segmentCriteria", "type": "string", "description": "The explicit criteria or rules defining membership in this segment."}, {"name": "segmentRiskLevel", "type": "enum", "description": "A classification indicating the risk profile associated with the segment (e.g., Low, Medium, High)."}]'::jsonb, '[{"type": "parent", "label": "Derived from specific customer entity data", "targetId": "Customer Entity"}, {"type": "depends_on", "label": "Segmentation is dependent on underlying customer attributes", "targetId": "Customer Attribute"}]'::jsonb, 'profiling,targeting,customer-analytics,risk-segmentation'::text[], NULL, '2026-03-01 11:58:08.1658', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Segment", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T11:58:36.546Z", "properties": [], "description": "Attribute of Customer Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-b1daeba3-4b44-4faf-9ecb-243a666f2913', 'custom', 'Cross-Industry Ontology', 'Contract ID', 'Customer', 'A Contract ID is a unique identifier assigned to a specific contract held or entered into by a customer entity. Within custom operations, this identifier allows AI agents to accurately reference and manage contractual obligations, entitlements, and activities tied to an individual customer. It is fundamental for associating transactions, renewal events, and compliance checkpoints with the correct contract instance. This enables granular tracking of contract life cycles, ensures operational fidelity, and streamlines exception management in automated workflows.', '[{"name": "contractStatus", "type": "enum", "description": "The current lifecycle state of the contract (e.g., active, expired, pending, terminated)."}, {"name": "effectiveDate", "type": "date", "description": "The date on which the contract entered into force."}, {"name": "expirationDate", "type": "date", "description": "The scheduled date on which the contract will expire or be eligible for renewal."}]'::jsonb, '[{"type": "related", "label": "Identifies the customer associated with this contract", "targetId": "Customer Entity"}, {"type": "child", "label": "Links to the full legal documentation supporting this Contract ID", "targetId": "Contract Document"}, {"type": "depends_on", "label": "Contract ID is meaningful only with reference to its lifecycle status", "targetId": "Contract Status"}]'::jsonb, 'Unique Identifier,Lifecycle Management,Regulatory Audit,Contractual Data,Customer Association'::text[], NULL, '2026-03-01 12:22:04.884245', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Contract ID", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T12:22:42.487Z", "properties": [], "description": "Attribute of Customer Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-52c09439-df14-4cb7-a489-cb6e032e6001', 'custom', 'Cross-Industry Ontology', 'Credit Tier', 'Customer', 'Credit Tier refers to the classification of a customer based on their creditworthiness, typically derived from credit scoring models and underwriting criteria. In the context of custom operations, the Credit Tier plays a crucial role in automating eligibility, pricing, and risk management decisions for various financial products and services. AI agents utilizing the Credit Tier can streamline customer segmentation, personalize product offerings, and trigger dynamic workflow adjustments based on risk profile. Integration of this concept enables real-time credit assessment, supports portfolio analytics, and enhances compliance monitoring. Dealing with Credit Tier requires strict adherence to data privacy, explainability, and fairness requirements due to its direct impact on customer outcomes and regulatory scrutiny.', '[{"name": "creditTierLevel", "type": "string", "description": "The specific level or grade assigned to a customer (e.g., Premium, Standard, Subprime)."}, {"name": "creditScoreSource", "type": "string", "description": "The originating source or system used to determine the credit tier."}, {"name": "tierEffectiveDate", "type": "date", "description": "The date when the credit tier was assigned or last updated."}, {"name": "tierReviewFrequency", "type": "string", "description": "Indicates how often the credit tier is reviewed or reassessed."}]'::jsonb, '[{"type": "parent", "label": "Credit Tier is an attribute of Customer Entity", "targetId": "Customer Entity"}, {"type": "related", "label": "Credit Tier is determined by Credit Assessment", "targetId": "Credit Assessment"}, {"type": "depends_on", "label": "Credit Tier is derived from Credit Score", "targetId": "Credit Score"}]'::jsonb, 'Risk Segmentation,Eligibility Assessment,Customer Classification,Automated Underwriting,Financial Inclusion'::text[], NULL, '2026-03-01 13:05:26.429616', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Credit Tier", "version": 1, "synonyms": [], "updatedAt": "2026-03-01T13:06:10.261Z", "properties": [], "description": "Attribute pf Customer Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-31959d47-0b40-4e7a-a869-00bd67a94643', 'custom', 'Cross-Industry Ontology', 'Preferred Channel', 'Customer', 'Preferred Channel refers to the communication or service medium a customer most frequently chooses or has indicated as their favorite for interacting with an organization. In the context of custom operations, this attribute is critical for tailoring automated communications, support, and service delivery to maximize engagement and satisfaction. Recognizing and leveraging the Preferred Channel can enhance operational efficiency and personalize customer experience by directing AI agent actions to the customer''s chosen platforms (e.g., email, SMS, app, phone). Agents must dynamically adapt workflows according to this attribute, ensuring compliance with customer preferences. Tracking changes in Preferred Channel usage can also provide insights into shifting customer behavior for proactive operations management.', '[{"name": "channelType", "type": "enum", "description": "The specific channel chosen by the customer (e.g., email, SMS, voice, social media)."}, {"name": "lastUpdatedDate", "type": "date", "description": "Timestamp of when the customer''s preferred channel was last modified."}, {"name": "consentStatus", "type": "enum", "description": "Indicates whether the customer has provided active consent for communications through their preferred channel."}]'::jsonb, '[{"type": "related", "label": "Indicates consent status or history for the preferred communication channel", "targetId": "Customer Consent"}, {"type": "depends_on", "label": "Requires real-time availability and operability of the selected channel", "targetId": "Channel Availability"}]'::jsonb, 'ChannelPreferences,CustomerPersonalization,ConsentManagement,CommunicationRouting'::text[], NULL, '2026-03-02 03:18:32.005605', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Preferred Channel", "version": 1, "synonyms": [], "updatedAt": "2026-03-02T03:18:56.817Z", "properties": [], "description": "Attribute of Customer Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-85db580e-1273-40a7-bab6-a7a494a3c426', 'custom', 'Cross-Industry Ontology', 'Threshold', 'Approval', 'In the context of custom AI agent operations, the ''Threshold'' concept under ''Approval'' acts as a boundary value that determines whether a specific approval process is triggered. This parameter is crucial in workflow automations where financial, operational, or security-related decisions depend on pre-defined quantitative or qualitative limits. Common implementations involve setting monetary, risk, compliance, or transaction volume limits that serve as gates within multi-level approval hierarchies. Proper configuration of thresholds can balance operational agility with control and oversight, reducing manual intervention while maintaining compliance. In dynamic environments, thresholds may adapt in real time based on contextual data and past outcomes, making them essential for intelligent, responsive agent-driven operations.', '[{"name": "thresholdValue", "type": "decimal", "description": "The numeric value that defines the threshold limit for approval triggering."}, {"name": "thresholdType", "type": "string", "description": "The category of threshold (e.g. financial, operational, risk, security)."}, {"name": "currency", "type": "string", "description": "The currency code for financial thresholds, if applicable."}, {"name": "effectiveDate", "type": "date", "description": "The date the threshold becomes active."}]'::jsonb, '[{"type": "related", "label": "Applied within approval workflows", "targetId": "Approval Workflow"}, {"type": "depends_on", "label": "Defined according to specific approval policy", "targetId": "Approval Policy"}, {"type": "related", "label": "Thresholds vary based on user roles", "targetId": "User Role"}]'::jsonb, 'Limits,Controls,Approval Automation,Escalation,Risk Management'::text[], NULL, '2026-03-02 05:21:26.873969', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Threshold", "version": 1, "synonyms": [], "updatedAt": "2026-03-02T05:21:54.002Z", "properties": [], "description": "Attributes for Approval Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-6ed5ca74-59a5-4db7-87b9-c80e1a0ca559', 'custom', 'Cross-Industry Ontology', 'Approver Role', 'Approval', 'The Approver Role represents an entity or individual who is authorized to review and grant approval for processes, requests, or transactions within an organization. In custom operations, this role is critical for enforcing segregation of duties, chain-of-command validations, and workflow checkpoints. AI agents configured to interact with this concept must accurately understand contextual constraints, assignment logic, and escalation protocols. The Approver Role is often embedded in operational workflows such as financial transactions, access management, and change control processes. Accurate modeling of this role enables robust automation of authorization and compliance verification steps.', '[{"name": "approverLevel", "type": "enum", "description": "Indicates the hierarchical or authority level of the approver (e.g., line manager, executive, specialist)"}, {"name": "approvalScope", "type": "string", "description": "Defines the scope or range of actions and requests this role is permitted to approve"}, {"name": "delegationAllowed", "type": "boolean", "description": "Specifies whether the approver can delegate their approval authority to others"}]'::jsonb, '[{"type": "depends_on", "label": "Is governed by", "targetId": "Approval Policy"}, {"type": "related", "label": "Is subject to", "targetId": "Segregation of Duties Control"}]'::jsonb, 'Workflow Control,Auditability,SegregationOfDuties,NonRepudiation'::text[], NULL, '2026-03-02 05:39:18.770338', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Approver Role", "version": 1, "synonyms": [], "updatedAt": "2026-03-02T05:39:45.674Z", "properties": [], "description": "Attributes for Approval Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-0dc3e97d-0beb-451d-b3c7-2d0952479a81', 'custom', 'Cross-Industry Ontology', 'Escalation Path', 'Approval', 'In the context of custom operations, the ''Escalation Path'' defines a predefined sequence of roles or entities that must be notified or must act when an approval request cannot be processed at a certain level due to issues such as lack of authority, expertise, or extended delays. This path acts as a safety net within an approval workflow, ensuring that critical processes are not stalled indefinitely by automatically routing exceptions or unresolved requests to higher authorities. AI agents leverage escalation paths to maintain business continuity, enforce organizational policies, and ensure that priority matters receive timely attention. Automated management of escalation paths reduces manual intervention in exception handling, supporting scalable and efficient operations. Moreover, an explicit escalation path allows auditability and traceability of all decision points in approval processes.', '[{"name": "escalationLevel", "type": "integer", "description": "The ordinal position in the escalation sequence, indicating the level of authority."}, {"name": "escalationTriggerCondition", "type": "string", "description": "The specific condition or rule that initiates the escalation process."}, {"name": "maximumAllowedEscalationTime", "type": "decimal", "description": "Maximum time (in hours or days) before an escalation must be executed."}]'::jsonb, '[{"type": "depends_on", "label": "Escalation Path is configured based on the Approval Entity context", "targetId": "Approval Entity"}, {"type": "related", "label": "Escalation Path is governed by the organization''s Approval Policy", "targetId": "Approval Policy"}]'::jsonb, 'WorkflowManagement,ExceptionHandling,OperationalResilience,ProcessAutomation'::text[], NULL, '2026-03-02 07:21:52.54523', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "Escalation Path", "version": 1, "synonyms": [], "updatedAt": "2026-03-02T07:26:32.064Z", "properties": [], "description": "Attribute of Approval Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-f184dbc3-df74-4713-afa7-d5971d53e7ef', 'custom', 'Cross-Industry Ontology', 'SLA', 'Approval', 'A Service Level Agreement (SLA) within the context of custom operations defines the agreed performance and quality parameters between service providers and consumers, often governing critical operational processes and approvals. It details key metrics such as response times, resolution targets, and escalation procedures essential for compliance and service delivery. For AI agent lifecycle management, SLAs operationalize thresholds and governance for machine decision-making, ensuring automated actions and approvals adhere to defined standards and respond proactively to SLA breaches. SLAs can be dynamically monitored and enforced by AI agents, enabling real-time compliance oversight and incident management. This concept is fundamental in ensuring transparent accountability and operational consistency within automated workflows.', '[{"name": "slaTargetTime", "type": "decimal", "description": "The agreed-upon timeframe for approval completion, typically measured in hours or days."}, {"name": "slaBreachAction", "type": "string", "description": "The pre-defined action or escalation path if SLA is breached."}, {"name": "slaMetricType", "type": "enum", "description": "The categorization of the SLA, such as Response Time, Resolution Time, or Quality Metric."}, {"name": "effectiveDate", "type": "date", "description": "The date when the SLA becomes effective for the Approval Entity."}]'::jsonb, '[{"type": "depends_on", "label": "Depends on defined approval process steps to calculate SLA adherence", "targetId": "Approval Workflow"}, {"type": "related", "label": "Related to incident events triggered when SLA is breached", "targetId": "Incident Management Event"}, {"type": "parent", "label": "SLA is a specific instance of a broader contractual obligation", "targetId": "Contractual Obligation"}]'::jsonb, 'Operational Risk,Performance Management,Compliance Monitoring,Escalation,Auditability'::text[], NULL, '2026-03-02 08:18:00.347761', ''::text[], 'custom-extension', 0, '[]'::jsonb, 2, '[{"label": "SLA", "version": 1, "synonyms": [], "updatedAt": "2026-03-02T08:18:29.597Z", "properties": [], "description": "Attribute of Approval Entity", "relationships": [], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-strategic-asset-allocation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Strategic Asset Allocation', 'Asset Allocation', 'Strategic Asset Allocation is the disciplined process by which investment professionals set target allocations for various asset classes within a portfolio, aligning these weights with the investor’s risk tolerance, return objectives, and anticipated investment horizon. In financial services operations, this concept serves as the foundation for implementing and automating long-term investment policies, portfolio construction, and consistent rebalancing routines. It guides which asset types to include and at what proportions, considering prevailing market conditions, regulatory constraints, and future cash flow requirements. As a rule-based approach, it provides transparency in aligning investment management and fiduciary responsibilities and acts as a benchmark for ongoing portfolio performance evaluation. This ensures portfolios systematically adhere to the stated investment principles, removing reliance on short-term market movements or behavioral biases.', '[{"name": "targetAllocation", "type": "decimal", "description": "Percentage of portfolio assigned to each asset class."}, {"name": "reviewFrequency", "type": "enum", "description": "How often allocation is reviewed (annual, quarterly, monthly)."}, {"name": "riskLevel", "type": "enum", "description": "Overall risk associated with the allocation."}, {"name": "expectedReturn", "type": "decimal", "description": "Anticipated average return of the strategic allocation over a specified period."}, {"name": "investmentHorizon", "type": "integer", "description": "Number of years the allocation strategy is intended to cover."}, {"name": "liquidityConstraint", "type": "string", "description": "Limitations regarding how quickly assets within the allocation can be converted to cash."}]'::jsonb, '[{"type": "depends_on", "label": "Allocation is designed to meet portfolio objectives.", "targetId": "financial_services-asset-management-portfolio-objective"}, {"type": "related", "label": "Contrasts with tactical approaches.", "targetId": "financial_services-asset-management-tactical-asset-allocation"}, {"type": "depends_on", "label": "Allocation construction utilizes market data inputs.", "targetId": "fibo-9"}]'::jsonb, 'strategy,investment,long-term,risk-management,portfolio-construction,governance,compliance,asset-classification'::text[], 'Establishes foundation for risk/return profile in asset management.', '2026-03-06 04:36:37.086547', 'SAA,Strategic Allocation'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Strategic Asset Allocation", "version": 1, "synonyms": ["SAA", "Strategic Allocation"], "updatedAt": "2026-03-06T04:39:23.100Z", "properties": [{"name": "targetAllocation", "type": "decimal", "description": "Percentage of portfolio assigned to each asset class."}, {"name": "reviewFrequency", "type": "enum", "description": "How often allocation is reviewed (annual, quarterly, monthly)."}, {"name": "riskLevel", "type": "enum", "description": "Overall risk associated with the allocation."}], "description": "A long-term investment strategy that determines the optimal combination of asset classes for a portfolio based on risk tolerance, investment objectives, and time horizon.", "relationships": [{"type": "depends_on", "label": "Allocation is designed to meet portfolio objectives.", "targetId": "financial_services-asset-management-portfolio-objective"}, {"type": "related", "label": "Contrasts with tactical approaches.", "targetId": "financial_services-asset-management-tactical-asset-allocation"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-tactical-asset-allocation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Tactical Asset Allocation', 'Asset Allocation', 'Tactical Asset Allocation (TAA) is a strategy within portfolio management that involves actively shifting the portfolio''s asset mix to exploit short-term investment opportunities or to respond swiftly to significant changes in market conditions. This approach distinguishes itself from strategic allocation by its frequent adjustments based on quantitative models, fundamental analysis, or market signals. In a financial services operation, TAA requires rapid and informed decision-making, leveraging real-time data analytics, sentiment analysis, and often advanced forecasting methods. TAA plays a vital role in generating alpha, enhancing risk-adjusted returns, and managing portfolio drawdowns. Its operational execution demands robust risk monitoring and strict adherence to policy constraints to avoid unintended exposures.', '[{"name": "deviationFromBaseline", "type": "decimal", "description": "Percentage shift from strategic allocation."}, {"name": "triggerCondition", "type": "string", "description": "Market or economic event that initiates adjustment."}, {"name": "duration", "type": "integer", "description": "Length of time tactical allocation is maintained (days/months)."}, {"name": "riskBudgetUtilization", "type": "decimal", "description": "Percentage of allowable risk budget consumed by tactical moves."}, {"name": "performanceAttribution", "type": "string", "description": "Description or quantitative breakdown of returns from tactical decisions."}, {"name": "approvalStatus", "type": "enum", "description": "Indicates compliance or investment officer''s signoff on the tactical shift."}, {"name": "affectedAssetClasses", "type": "string", "description": "Asset classes adjusted within the tactical allocation."}]'::jsonb, '[{"type": "parent", "label": "Tactical allocation is a short-term variation.", "targetId": "financial_services-asset-management-strategic-asset-allocation"}, {"type": "depends_on", "label": "Tactical shifts are signaled by real-time market data inputs.", "targetId": "fibo-9"}]'::jsonb, 'active-management,market-timing,flexibility,short-term,portfolio-optimization,client-focused,risk-adjusted-performance,market-adaptivity'::text[], 'Allows asset managers to enhance returns beyond strategic allocation.', '2026-03-06 04:36:37.138608', 'TAA,Tactical Allocation'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Tactical Asset Allocation", "version": 1, "synonyms": ["TAA", "Tactical Allocation"], "updatedAt": "2026-03-06T04:46:24.205Z", "properties": [{"name": "deviationFromBaseline", "type": "decimal", "description": "Percentage shift from strategic allocation."}, {"name": "triggerCondition", "type": "string", "description": "Market or economic event that initiates adjustment."}, {"name": "duration", "type": "integer", "description": "Length of time tactical allocation is maintained (days/months)."}], "description": "A dynamic investment process that actively adjusts the asset mix to capitalize on short-term market opportunities or respond to changing market conditions.", "relationships": [{"type": "parent", "label": "Tactical allocation is a short-term variation.", "targetId": "financial_services-asset-management-strategic-asset-allocation"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-asset-class-exposure', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Asset Class Exposure', 'Asset Allocation', 'Asset Class Exposure refers to the measurement, management, and reporting of the allocation proportions across specific asset classes within an investment portfolio. This concept is fundamental in financial services operations, as it directly impacts portfolio risk, return characteristics, and compliance with investment mandates or regulatory guidelines. Both institutional and retail investors utilize asset class exposure information to optimize diversification, achieve investment objectives, and align with risk tolerance levels. Detailed tracking of asset class exposures enables portfolio managers to rebalance holdings proactively in response to market changes or evolving client needs. AI agents can play a crucial role in automating exposure monitoring, generating insights, and ensuring that portfolios adhere to defined asset allocation strategies.', '[{"name": "exposureType", "type": "enum", "description": "Type of asset class (e.g., equity, bond, real estate)."}, {"name": "exposurePercentage", "type": "decimal", "description": "Portfolio percentage allocated to this asset class."}, {"name": "exposureTimestamp", "type": "date", "description": "Date and time when asset class exposure was calculated or recorded."}, {"name": "benchmarkExposure", "type": "decimal", "description": "Benchmark portfolio''s exposure to this asset class for comparative analysis."}, {"name": "riskContribution", "type": "decimal", "description": "Estimated contribution of this asset class exposure to the overall portfolio risk."}]'::jsonb, '[{"type": "child", "label": "Derived from strategic allocation decisions.", "targetId": "financial_services-asset-management-strategic-asset-allocation"}, {"type": "depends_on", "label": "Exposure calculations depend on real-time market data inputs.", "targetId": "fibo-9"}]'::jsonb, 'risk,diversification,composition,allocation,portfolio-monitoring,regulatory-reporting,investment-strategy,risk-assessment'::text[], 'Defines risk, diversification, and potential returns for portfolios.', '2026-03-06 04:36:37.1834', 'Asset Exposure,Class Weighting'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Asset Class Exposure", "version": 1, "synonyms": ["Asset Exposure", "Class Weighting"], "updatedAt": "2026-03-06T04:46:52.998Z", "properties": [{"name": "exposureType", "type": "enum", "description": "Type of asset class (e.g., equity, bond, real estate)."}, {"name": "exposurePercentage", "type": "decimal", "description": "Portfolio percentage allocated to this asset class."}], "description": "Represents the proportion and type of underlying asset classes (e.g., equities, fixed income, real estate) within a portfolio.", "relationships": [{"type": "child", "label": "Derived from strategic allocation decisions.", "targetId": "financial_services-asset-management-strategic-asset-allocation"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-rebalancing-schedule', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Rebalancing Schedule', 'Portfolio Management Processes', 'A Rebalancing Schedule defines the systematic timetable or conditional triggers for adjusting portfolio holdings, ensuring adherence to the investor''s desired asset allocation and risk parameters. In financial services, it supports disciplined portfolio management, minimizing the impact of market drift and behavioral biases. Rebalancing can be performed at fixed intervals (calendar-based), when asset allocations deviate beyond set thresholds, or via hybrid approaches. This process is critical for maintaining portfolio objectives, complying with mandate constraints, and optimizing client investment outcomes. Effective scheduling aligns operational activities, trading logistics, and client communications.', '[{"name": "frequency", "type": "enum", "description": "Interval of rebalancing (quarterly, annually, triggered)."}, {"name": "rebalanceMethod", "type": "enum", "description": "Method used (threshold, calendar, hybrid)."}, {"name": "nextRebalanceDate", "type": "date", "description": "The planned next execution date for the rebalancing event."}, {"name": "toleranceBand", "type": "decimal", "description": "Permitted deviation from target allocation before triggering a rebalance."}, {"name": "lastRebalanced", "type": "date", "description": "Date when the last rebalancing action was executed."}]'::jsonb, '[{"type": "depends_on", "label": "Schedule acts on asset class exposures.", "targetId": "financial_services-asset-management-asset-class-exposure"}]'::jsonb, 'maintenance,risk-control,operations,timing,governance,compliance,automation,client-communication'::text[], 'Ensures portfolio stays aligned with target strategy and regulatory objectives.', '2026-03-06 04:36:37.227706', 'Portfolio Rebalancing,Schedule Rebalance'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Rebalancing Schedule", "version": 1, "synonyms": ["Portfolio Rebalancing", "Schedule Rebalance"], "updatedAt": "2026-03-06T04:47:28.910Z", "properties": [{"name": "frequency", "type": "enum", "description": "Interval of rebalancing (quarterly, annually, triggered)."}, {"name": "rebalanceMethod", "type": "enum", "description": "Method used (threshold, calendar, hybrid)."}], "description": "A predefined calendar or rule set for adjusting portfolio holdings to maintain target asset allocation and risk levels.", "relationships": [{"type": "depends_on", "label": "Schedule acts on asset class exposures.", "targetId": "financial_services-asset-management-asset-class-exposure"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-investment-mandate', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Investment Mandate', 'Portfolio Management Processes', 'An Investment Mandate is a critical governance document in the portfolio management process, defining how assets within a fund or account are to be managed. It outlines the investment objectives, permissible asset classes, allocation ranges, risk tolerances, and specific constraints that must be adhered to by portfolio managers. The mandate ensures the portfolio remains aligned with client objectives, regulatory requirements, and risk management framework. It plays a fundamental role in operational accountability and performance measurement. AI agents must be able to interpret, monitor, and enforce these rules across complex investment landscapes.', '[{"name": "mandateType", "type": "enum", "description": "Type (discretionary, advisory, customized)."}, {"name": "constraints", "type": "string", "description": "Specific rules or restrictions imposed."}, {"name": "objective", "type": "string", "description": "Stated investment objective of the mandate."}, {"name": "effectiveDate", "type": "date", "description": "The date on which the investment mandate becomes effective."}, {"name": "reviewFrequency", "type": "string", "description": "Expected time interval for mandate review (e.g., quarterly, annually)."}, {"name": "mandateOwner", "type": "string", "description": "Person or entity with ultimate responsibility for the mandate."}]'::jsonb, '[{"type": "parent", "label": "Mandate defines objectives for portfolio.", "targetId": "financial_services-asset-management-portfolio-objective"}]'::jsonb, 'governance,legal,risk,policy,client-specific,fiduciary,compliance-automation,portfolio-constraints'::text[], 'Guides asset managers to comply with investor expectations and legal frameworks.', '2026-03-06 04:36:37.272586', 'Mandate,Fund Mandate'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Investment Mandate", "version": 1, "synonyms": ["Mandate", "Fund Mandate"], "updatedAt": "2026-03-06T04:47:53.002Z", "properties": [{"name": "mandateType", "type": "enum", "description": "Type (discretionary, advisory, customized)."}, {"name": "constraints", "type": "string", "description": "Specific rules or restrictions imposed."}, {"name": "objective", "type": "string", "description": "Stated investment objective of the mandate."}], "description": "A formal document specifying the investment guidelines, limits, objectives, and constraints for managing a portfolio or fund.", "relationships": [{"type": "parent", "label": "Mandate defines objectives for portfolio.", "targetId": "financial_services-asset-management-portfolio-objective"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-performance-attribution', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Performance Attribution', 'Portfolio Management Processes', 'Performance Attribution is a critical analytical process within portfolio management aimed at precisely determining the sources of a portfolio’s returns. It decomposes performance into components such as asset allocation, security selection, and the impact of other portfolio management decisions. Understanding these factors empowers investment teams to evaluate strategies'' effectiveness, optimize decision-making, and communicate results to stakeholders. In financial services operations, Performance Attribution supports transparency, fuels iterative improvement, and is often pivotal in client reporting and regulatory disclosures. Its complexity necessitates robust data aggregation and clear methodology alignment with industry standards.', '[{"name": "allocationEffect", "type": "decimal", "description": "Return attributable to asset allocation decisions."}, {"name": "selectionEffect", "type": "decimal", "description": "Impact of security selection on performance."}, {"name": "timingEffect", "type": "decimal", "description": "Impact of timing decisions (e.g., entry/exit points) on portfolio performance."}, {"name": "interactionEffect", "type": "decimal", "description": "Combined effect of allocation and selection decisions on performance."}, {"name": "benchmarkReference", "type": "string", "description": "Identifier or description of the benchmark used for attribution comparison."}]'::jsonb, '[{"type": "related", "label": "Attribution measures objective achievement.", "targetId": "financial_services-asset-management-portfolio-objective"}, {"type": "depends_on", "label": "Requires market pricing and benchmark data for calculation.", "targetId": "fibo-9"}]'::jsonb, 'analytics,reporting,performance,decision-making,risk-management,portfolio-analysis,compliance,client-communication'::text[], 'Empowers managers to optimize strategies and demonstrate value to clients.', '2026-03-06 04:36:37.31691', 'Attribution Analysis,Performance Decomposition'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Performance Attribution", "version": 1, "synonyms": ["Attribution Analysis", "Performance Decomposition"], "updatedAt": "2026-03-06T04:38:20.715Z", "properties": [{"name": "allocationEffect", "type": "decimal", "description": "Return attributable to asset allocation decisions."}, {"name": "selectionEffect", "type": "decimal", "description": "Impact of security selection on performance."}], "description": "Analytical process of determining sources of portfolio performance, distinguishing returns from asset allocation, security selection, and other factors.", "relationships": [{"type": "related", "label": "Attribution measures objective achievement.", "targetId": "financial_services-asset-management-portfolio-objective"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-mutual-fund', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Mutual Fund', 'Fund Types and Vehicles', 'A Mutual Fund is an open-ended investment vehicle that aggregates capital from multiple investors and allocates it across a diversified portfolio of assets, such as equities, bonds, and money market instruments. The fund is managed by professional managers who follow defined objectives and limitations set forth in the fund''s prospectus. Its open-ended structure allows for continuous creation and redemption of shares at NAV, providing investors with liquidity and flexibility. Mutual funds serve both retail and institutional investors, offering access to diversified investments and professional management. They play a significant role in capital formation, wealth management, and retail investor participation in the capital markets.', '[{"name": "fundSize", "type": "decimal", "description": "Total assets under management for the fund."}, {"name": "shareClass", "type": "enum", "description": "Specific class of shares (A, B, C, Institutional)."}, {"name": "inceptionDate", "type": "date", "description": "The date on which the mutual fund was launched."}, {"name": "expenseRatio", "type": "decimal", "description": "The ratio of fund operating expenses to average assets under management."}, {"name": "distributionFrequency", "type": "enum", "description": "Frequency of dividend or interest distribution (e.g., monthly, quarterly, yearly)."}, {"name": "benchmarkIndex", "type": "string", "description": "The reference index or blend of indices used to measure the fund’s performance."}]'::jsonb, '[{"type": "depends_on", "label": "Operates based on mandate limitations.", "targetId": "financial_services-asset-management-investment-mandate"}]'::jsonb, 'pooled-investment,liquidity,regulation,retail,net-asset-valuation,fund-governance,market-disclosure,institutional-investing'::text[], 'Primary vehicle for retail investors and critical to AUM growth.', '2026-03-06 04:36:37.362191', 'Open-End Fund,Mutual Trust'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Mutual Fund", "version": 1, "synonyms": ["Open-End Fund", "Mutual Trust"], "updatedAt": "2026-03-06T04:49:19.247Z", "properties": [{"name": "fundSize", "type": "decimal", "description": "Total assets under management for the fund."}, {"name": "shareClass", "type": "enum", "description": "Specific class of shares (A, B, C, Institutional)."}], "description": "An open-ended investment vehicle pooling resources from multiple investors to invest in diversified assets, managed according to defined objectives and prospectus.", "relationships": [{"type": "depends_on", "label": "Operates based on mandate limitations.", "targetId": "financial_services-asset-management-investment-mandate"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-exchange-traded-fund', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Exchange-Traded Fund', 'Fund Types and Vehicles', 'An Exchange-Traded Fund (ETF) is an investment fund that pools money from many investors and invests in a diversified selection of assets such as equities, bonds, or commodities. ETFs are listed and traded throughout the day on regulated public exchanges, providing investors with liquidity and price transparency similar to individual stocks. Their structure facilitates efficient intraday trading, allows for frequent portfolio rebalancing, and typically results in lower management fees due to passive management strategies. ETFs are widely used in portfolio construction, asset allocation strategies, and risk diversification by institutions and retail investors. Operationally, ETFs require seamless integration with market data, custody, and settlement infrastructure.', '[{"name": "nav", "type": "decimal", "description": "Net asset value per share."}, {"name": "exchange", "type": "string", "description": "Trading venue for the ETF."}, {"name": "aum", "type": "decimal", "description": "Assets under management of the ETF."}, {"name": "expenseRatio", "type": "decimal", "description": "Annual operating expenses of the ETF as a percentage of average net assets."}, {"name": "creationRedemptionFrequency", "type": "enum", "description": "Frequency with which ETF shares may be created or redeemed (e.g., daily, weekly)."}, {"name": "benchmarkIndex", "type": "string", "description": "Reference index or strategy the ETF seeks to track."}]'::jsonb, '[{"type": "related", "label": "Provides diversified exposure.", "targetId": "financial_services-asset-management-asset-class-exposure"}]'::jsonb, 'etf,passive,liquidity,market-access,benchmark-tracking,index-fund,transferability,regulatory-disclosure'::text[], 'Offers cost-efficient diversification and is a major business line for asset managers.', '2026-03-06 04:36:37.407776', 'ETF,Exchange Fund'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Exchange-Traded Fund", "version": 1, "synonyms": ["ETF", "Exchange Fund"], "updatedAt": "2026-03-06T04:49:51.565Z", "properties": [{"name": "nav", "type": "decimal", "description": "Net asset value per share."}, {"name": "exchange", "type": "string", "description": "Trading venue for the ETF."}], "description": "A fund traded on public exchanges, offering diversified exposure to asset classes, with intraday liquidity and generally lower costs.", "relationships": [{"type": "related", "label": "Provides diversified exposure.", "targetId": "financial_services-asset-management-asset-class-exposure"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-private-equity-fund', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Private Equity Fund', 'Fund Types and Vehicles', 'A Private Equity Fund is a financial vehicle typically structured as a limited partnership, pooling capital from institutional and accredited investors to acquire and manage private companies. These funds emphasize long-term investment horizons, focusing on operational improvements and strategic value creation to realize capital gains upon eventual exit events such as IPOs or acquisitions. Fund management involves rigorous selection, ongoing oversight, and periodic reporting to limited partners regarding portfolio progress. The fund cycles, including capital calls, distributions, and performance measurement, are central in operational execution. AI agents interacting with Private Equity Funds must understand multi-layered entities, investor relations, and investment lifecycle tracking.', '[{"name": "commitmentAmount", "type": "decimal", "description": "Amount pledged by investors."}, {"name": "holdingPeriod", "type": "integer", "description": "Average duration of investment in years."}, {"name": "investmentStrategy", "type": "string", "description": "Details the fund’s target sectors, deal types, and value creation approach."}, {"name": "distributionSchedule", "type": "string", "description": "Defines when and how distributions are paid to investors."}, {"name": "fundVintage", "type": "date", "description": "Specifies the year in which the fund commenced operations."}]'::jsonb, '[{"type": "related", "label": "Fund operates per specific private equity mandates.", "targetId": "financial_services-asset-management-investment-mandate"}]'::jsonb, 'alternative,illiquid,partnership,private-market,institutional-investors,capital-call,exit-strategy,portfolio-management,performance-reporting'::text[], 'Supports diversification and higher returns beyond public markets.', '2026-03-06 04:36:37.452152', 'PE Fund,Private Equity Vehicle'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Private Equity Fund", "version": 1, "synonyms": ["PE Fund", "Private Equity Vehicle"], "updatedAt": "2026-03-06T04:50:26.189Z", "properties": [{"name": "commitmentAmount", "type": "decimal", "description": "Amount pledged by investors."}, {"name": "holdingPeriod", "type": "integer", "description": "Average duration of investment in years."}], "description": "A limited partnership vehicle invests in private companies, often with longer holding periods, aiming for capital appreciation through operational improvements and exits.", "relationships": [{"type": "related", "label": "Fund operates per specific private equity mandates.", "targetId": "financial_services-asset-management-investment-mandate"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-client-investment-policy-statement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Client Investment Policy Statement', 'Client & Investor Engagement', 'A Client Investment Policy Statement (IPS) is a foundational legal and strategic document in wealth and asset management, providing a structured articulation of the client''s investment objectives, constraints, and preferences. It serves as the primary reference for portfolio construction, asset allocation, and ongoing investment decisions, ensuring both compliance with client expectations and consistent application of fiduciary duty. The IPS typically covers goals, performance benchmarks, liquidity needs, time horizon, and any ethical or sector exclusions demanded by the client. In operational terms, it acts as a contract that must be adhered to during all stages of portfolio management and client engagement workflows. The IPS also plays a central role in periodic reviews and is critical for demonstrating due diligence during audits or dispute resolution.', '[{"name": "policyScope", "type": "string", "description": "Coverage (individual, institutional, endowment)."}, {"name": "riskTolerance", "type": "enum", "description": "Risk level defined by the client (low, moderate, high)."}, {"name": "liquidityRequirements", "type": "string", "description": "Details the client’s need for readily accessible funds or cash equivalents."}, {"name": "ethicalRestrictions", "type": "string", "description": "Specifies any sectors or asset classes to be excluded for ethical, religious, or policy reasons."}, {"name": "reviewFrequency", "type": "enum", "description": "Describes how often the IPS is scheduled for review (e.g., annual, semi-annual, event-driven)."}]'::jsonb, '[{"type": "depends_on", "label": "Defines the guiding objectives for the portfolio.", "targetId": "financial_services-asset-management-portfolio-objective"}]'::jsonb, 'client-document,goals,risk,policy,suitability,fiduciary-duty,compliance,document-management'::text[], 'Aligns asset management activities with client expectations and fiduciary duties.', '2026-03-06 04:36:37.497096', 'IPS,Investment Statement'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Client Investment Policy Statement", "version": 1, "synonyms": ["IPS", "Investment Statement"], "updatedAt": "2026-03-06T04:51:10.362Z", "properties": [{"name": "policyScope", "type": "string", "description": "Coverage (individual, institutional, endowment)."}, {"name": "riskTolerance", "type": "enum", "description": "Risk level defined by the client (low, moderate, high)."}], "description": "A formal agreement outlining the investment goals, strategies, risk tolerance, and specific requirements for an individual or institutional client portfolio.", "relationships": [{"type": "depends_on", "label": "Defines the guiding objectives for the portfolio.", "targetId": "financial_services-asset-management-portfolio-objective"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-client-reporting-schedule', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Client Reporting Schedule', 'Client & Investor Engagement', 'The ''Client Reporting Schedule'' defines the official timetable and protocol for distributing essential information, including performance statements, portfolio holdings, and regulatory disclosures to clients. This schedule is paramount for maintaining trust, supporting investment decision-making, and fulfilling contractual obligations. It accommodates client preferences, regulatory demands, and operational resource planning, ensuring timely and accurate reporting. In financial services operations, adherence to the reporting schedule is essential for SLA compliance and effective communication. Automation of these schedules via AI agents supports personalization, error reduction, and scalability.', '[{"name": "reportFrequency", "type": "enum", "description": "Reporting interval (monthly, quarterly, annually)."}, {"name": "reportFormat", "type": "enum", "description": "Medium used (electronic, paper, portal)."}, {"name": "nextScheduledDelivery", "type": "date", "description": "The date of the next planned report delivery for the client."}, {"name": "clientPreferredLanguage", "type": "enum", "description": "Language in which the client prefers to receive their reports."}, {"name": "notificationChannel", "type": "enum", "description": "Primary method of notifying clients about report availability (e.g., email, SMS, portal alert)."}, {"name": "reportComplianceStatus", "type": "enum", "description": "Current compliance status with regulatory and SLA guidelines for the reporting schedule."}]'::jsonb, '[{"type": "related", "label": "Reports include attribution findings.", "targetId": "financial_services-asset-management-performance-attribution"}]'::jsonb, 'communication,transparency,client,reporting,automation,compliance,SLAs,investor-relations,service-level'::text[], 'Supports transparency, client satisfaction, and regulatory compliance.', '2026-03-06 04:36:37.541079', 'Reporting Calendar,Client Deliverable Schedule'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Client Reporting Schedule", "version": 1, "synonyms": ["Reporting Calendar", "Client Deliverable Schedule"], "updatedAt": "2026-03-06T04:51:47.269Z", "properties": [{"name": "reportFrequency", "type": "enum", "description": "Reporting interval (monthly, quarterly, annually)."}, {"name": "reportFormat", "type": "enum", "description": "Medium used (electronic, paper, portal)."}], "description": "A structured plan for delivering performance reports, holdings, and other relevant updates to clients at defined intervals.", "relationships": [{"type": "related", "label": "Reports include attribution findings.", "targetId": "financial_services-asset-management-performance-attribution"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-investor-suitability-assessment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Investor Suitability Assessment', 'Client & Investor Engagement', 'Investor Suitability Assessment is a critical due diligence activity conducted by financial institutions to ensure investment recommendations or executions align with each investor''s risk appetite, investment goals, knowledge, and financial situation. The process involves gathering relevant personal and financial data, analyzing experience levels, and matching these profiles to the risk-return characteristics of various products. This not only helps optimize investment outcomes for clients but also prevents mis-selling and potential financial harm. In day-to-day financial services operations, AI agents can automate and standardize these assessments to ensure continuous, objective, and regulatory-compliant decision-making, especially as investor profiles or product offerings evolve.', '[{"name": "suitabilityScore", "type": "decimal", "description": "Quantified suitability metric."}, {"name": "assessmentDate", "type": "date", "description": "Date of the suitability assessment."}, {"name": "investorProfileId", "type": "string", "description": "Unique identifier for the associated investor profile."}, {"name": "assessmentMethod", "type": "enum", "description": "The methodology or standard used for the suitability assessment (e.g., ''MiFID II'', ''FINRA'')."}, {"name": "assessmentOutcome", "type": "string", "description": "Summary of the suitability assessment findings (e.g., ''suitable'', ''partially suitable'', ''not suitable'')."}]'::jsonb, '[{"type": "depends_on", "label": "Assessment ensures mandate compliance.", "targetId": "financial_services-asset-management-investment-mandate"}]'::jsonb, 'compliance,assessment,client,product-fit,investor-protection,KYC,risk-assessment,product-recommendation'::text[], 'Crucial for regulatory compliance and appropriate product recommendations.', '2026-03-06 04:36:37.584871', 'Suitability Check,Investor Profile Assessment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Investor Suitability Assessment", "version": 1, "synonyms": ["Suitability Check", "Investor Profile Assessment"], "updatedAt": "2026-03-06T04:52:17.281Z", "properties": [{"name": "suitabilityScore", "type": "decimal", "description": "Quantified suitability metric."}, {"name": "assessmentDate", "type": "date", "description": "Date of the suitability assessment."}], "description": "An evaluation process to determine if an investor’s financial profile, experience, and objectives match the risk and characteristics of investment products.", "relationships": [{"type": "depends_on", "label": "Assessment ensures mandate compliance.", "targetId": "financial_services-asset-management-investment-mandate"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-esg-scoring-model', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'ESG Scoring Model', 'Risk & ESG Integration', 'An ESG Scoring Model is a systematic framework used by financial institutions to assess and assign quantitative ratings to companies and assets based on their Environmental, Social, and Governance (ESG) performance. These models integrate a wide spectrum of sustainability factors into financial analysis, enabling standardized and comparable evaluations for risk management, portfolio construction, and stakeholder reporting. ESG Scoring Models often aggregate data from diverse sources, apply custom weighting methodologies, and are calibrated to comply with evolving market and regulatory norms. In investment operations, such models support ESG integration across product lifecycles and are pivotal for constructing responsible investment strategies. Their outputs are increasingly demanded by clients, regulators, and rating agencies to validate sustainable investing practices.', '[{"name": "esgScore", "type": "decimal", "description": "Composite ESG rating."}, {"name": "lastUpdated", "type": "date", "description": "Date of most recent ESG score update."}, {"name": "scoringMethodology", "type": "string", "description": "Description or reference to the methodology/algorithm used to generate the ESG score."}, {"name": "dataSources", "type": "string", "description": "Enumerates internal and external sources used for the ESG evaluation."}, {"name": "scoreConfidenceLevel", "type": "decimal", "description": "Quantitative measure of confidence or reliability assigned to the ESG score."}]'::jsonb, '[{"type": "related", "label": "Can attribute returns to ESG performance.", "targetId": "financial_services-asset-management-performance-attribution"}]'::jsonb, 'esg,sustainability,analysis,scoring,regulatory-compliance,portfolio-management,data-integration,risk-management'::text[], 'Supports sustainable investing, enhances reputation, and meets client demand.', '2026-03-06 04:36:37.629212', 'ESG Model,Sustainability Score'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "ESG Scoring Model", "version": 1, "synonyms": ["ESG Model", "Sustainability Score"], "updatedAt": "2026-03-06T04:52:46.968Z", "properties": [{"name": "esgScore", "type": "decimal", "description": "Composite ESG rating."}, {"name": "lastUpdated", "type": "date", "description": "Date of most recent ESG score update."}], "description": "A framework for quantitatively rating companies and assets on Environmental, Social, and Governance factors for integration into investment analysis.", "relationships": [{"type": "related", "label": "Can attribute returns to ESG performance.", "targetId": "financial_services-asset-management-performance-attribution"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-risk-budgeting-process', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Risk Budgeting Process', 'Risk & ESG Integration', 'The Risk Budgeting Process refers to the systematic allocation and ongoing management of risk within a portfolio to achieve desired risk-adjusted returns. In financial services operations, this process involves assigning risk limits to various asset classes or portfolio components, ensuring that risk-taking is intentional and aligns with organizational objectives or client mandates. Effective risk budgeting enables more robust portfolio construction, facilitates the integration of risk and ESG factors, and improves performance monitoring. AI agents supporting this process can dynamically rebalance risk allocations, perform scenario analysis, and optimize portfolios based on evolving market and regulatory environments. Ultimately, this process is critical for institutions seeking to maintain adherence to internal policies and external regulations while maximizing value for stakeholders.', '[{"name": "riskBudget", "type": "decimal", "description": "Assigned risk limit for given portfolio segment."}, {"name": "budgetMethodology", "type": "string", "description": "Method used to allocate risk (e.g., Value at Risk, risk parity)."}, {"name": "adjustmentFrequency", "type": "string", "description": "How often risk budgets are reviewed and adjusted (e.g., daily, monthly, quarterly)."}, {"name": "esgIntegrationLevel", "type": "enum", "description": "Degree of ESG factor integration (e.g., none, partial, full) within the risk budgeting process."}, {"name": "historicalPerformance", "type": "decimal", "description": "Historical returns achieved based on previous risk budgets."}, {"name": "riskBudgetBreaches", "type": "integer", "description": "Number of times risk budget limits were exceeded within a reporting period."}]'::jsonb, '[{"type": "related", "label": "Risk budgets applied per asset class.", "targetId": "financial_services-asset-management-asset-class-exposure"}, {"type": "depends_on", "label": "Risk budgeting calculations require input from current market data feeds.", "targetId": "fibo-9"}]'::jsonb, 'risk,allocation,optimization,management,portfolio-construction,regulatory-compliance,ESG-integration,risk-limits,stress-testing'::text[], 'Vital for balancing risk and enhancing long-term performance for portfolios.', '2026-03-06 04:36:37.673676', 'Risk Allocation,Risk Distribution'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Risk Budgeting Process", "version": 1, "synonyms": ["Risk Allocation", "Risk Distribution"], "updatedAt": "2026-03-06T04:53:33.996Z", "properties": [{"name": "riskBudget", "type": "decimal", "description": "Assigned risk limit for given portfolio segment."}, {"name": "budgetMethodology", "type": "string", "description": "Method used to allocate risk (e.g., Value at Risk, risk parity)."}], "description": "Practice of allocating and managing risk across portfolio components to maximize returns and optimize risk-adjusted performance.", "relationships": [{"type": "related", "label": "Risk budgets applied per asset class.", "targetId": "financial_services-asset-management-asset-class-exposure"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-engagement-activity-log', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Engagement Activity Log', 'Risk & ESG Integration', 'The Engagement Activity Log is a structured record capturing all interactions between asset managers and investee companies centered around ESG (Environmental, Social, Governance) concerns, stewardship duties, and proxy voting activities. This log is crucial for evidencing the manager''s influence on investee behavior, and for demonstrating active stewardship in alignment with institutional mandates and client expectations. The Engagement Activity Log supports transparent reporting, compliance, and ongoing assessment of portfolio-level ESG integration strategies. Maintaining detailed logs enables asset managers to track engagement effectiveness, address escalating issues, and systematically review stewardship outcomes. In the broader context of financial operations, it facilitates accountability and data-driven decision-making for enhanced ESG performance.', '[{"name": "activityType", "type": "enum", "description": "Nature of engagement (proxy vote, meeting, letter)."}, {"name": "activityDate", "type": "date", "description": "Date of engagement event."}, {"name": "engagedParty", "type": "string", "description": "Name or identifier of the investee company or individual engaged."}, {"name": "engagementOutcome", "type": "enum", "description": "Result or status of the engagement action (e.g., ''Resolved'', ''Ongoing'', ''Escalated'')."}, {"name": "stewardshipOfficer", "type": "string", "description": "Name or ID of the asset manager or stewardship officer responsible for the activity."}, {"name": "esgIssueCategory", "type": "enum", "description": "The category of ESG issue addressed (e.g., climate, diversity, governance practice)."}]'::jsonb, '[{"type": "related", "label": "Engagement may influence future ESG scores.", "targetId": "financial_services-asset-management-esg-scoring-model"}]'::jsonb, 'engagement,esg,stewardship,record,compliance,proxy_voting,audit_trail,engagement_outcome'::text[], 'Shows active ownership and influence on ESG outcomes for invested assets.', '2026-03-06 04:36:37.718497', 'Stewardship Log,ESG Engagement Tracker'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Engagement Activity Log", "version": 1, "synonyms": ["Stewardship Log", "ESG Engagement Tracker"], "updatedAt": "2026-03-06T04:54:01.646Z", "properties": [{"name": "activityType", "type": "enum", "description": "Nature of engagement (proxy vote, meeting, letter)."}, {"name": "activityDate", "type": "date", "description": "Date of engagement event."}], "description": "A record of interactions between asset managers and investee companies specifically focused on ESG issues, proxy voting, and stewardship.", "relationships": [{"type": "related", "label": "Engagement may influence future ESG scores.", "targetId": "financial_services-asset-management-esg-scoring-model"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-portfolio-objective', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Portfolio Objective', 'Portfolio Objectives & Benchmarks', 'A Portfolio Objective articulates the foundational purpose behind a portfolio''s management, dictating investment strategy, asset allocation, and risk appetite. It serves as the guiding constraint for fund managers, informing the selection of asset classes, investment styles, and benchmarks. In financial services operations, the objective is defined in alignment with client requirements, regulatory mandates, and organizational strategies. AI agents use these objectives to automate compliance checks, support suitability assessment, and customize portfolio monitoring or rebalancing. Proper definition and management of Portfolio Objectives is essential to ensure that the portfolio delivers outcomes consistent with client expectations and regulatory constraints.', '[{"name": "objectiveType", "type": "enum", "description": "Nature (growth, income, balanced, preservation)."}, {"name": "targetReturn", "type": "decimal", "description": "Expected annual return target."}, {"name": "riskTolerance", "type": "enum", "description": "Client’s acceptable risk level for the portfolio (e.g., low, medium, high)."}, {"name": "investmentHorizon", "type": "integer", "description": "Duration in years the portfolio is expected to be managed toward the objective."}, {"name": "performanceBenchmark", "type": "string", "description": "The index or metric used to measure portfolio performance against the objective."}]'::jsonb, '[{"type": "parent", "label": "Objective forms part of mandate.", "targetId": "financial_services-asset-management-investment-mandate"}, {"type": "related", "label": "Objective tracking depends on reliable market performance data.", "targetId": "fibo-9"}]'::jsonb, 'goal,strategy,management,objective,client-preference,mandate-compliance,investment-policy,benchmarking,risk-management'::text[], 'Fundamental anchor for all asset management decisions and strategies.', '2026-03-06 04:36:37.763002', 'Investment Objective,Portfolio Goal'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Portfolio Objective", "version": 1, "synonyms": ["Investment Objective", "Portfolio Goal"], "updatedAt": "2026-03-06T04:54:26.454Z", "properties": [{"name": "objectiveType", "type": "enum", "description": "Nature (growth, income, balanced, preservation)."}, {"name": "targetReturn", "type": "decimal", "description": "Expected annual return target."}], "description": "The primary goal for a portfolio, such as capital preservation, income generation, or capital appreciation, defined by the client or mandate.", "relationships": [{"type": "parent", "label": "Objective forms part of mandate.", "targetId": "financial_services-asset-management-investment-mandate"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-benchmark-index', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Benchmark Index', 'Portfolio Objectives & Benchmarks', 'A Benchmark Index serves as a transparent and standardized reference point, facilitating objective measurement of portfolio or fund performance against market or sector-specific movements. Its utilization allows portfolio managers, investment committees, and clients to evaluate whether investment returns are attributable to skill or broader market trends. For institutional investing, selecting an appropriate benchmark is integral for setting portfolio strategies and performance agreements. The choice of a benchmark directly affects performance attribution, risk assessment, and reporting consistency. Accurate and timely integration of benchmark data is essential for analytics, ALM (Asset-Liability Management), and compliance reporting in financial operations.', '[{"name": "indexName", "type": "string", "description": "Official benchmark index name."}, {"name": "indexProvider", "type": "string", "description": "Organization providing the index."}, {"name": "currency", "type": "string", "description": "The base currency in which the benchmark index is calculated."}, {"name": "indexType", "type": "enum", "description": "Classification describing whether the index is equity, fixed income, multi-asset, commodity, etc."}, {"name": "rebalancingFrequency", "type": "string", "description": "How frequently the index constituents are reviewed and rebalanced (e.g., quarterly, monthly)."}, {"name": "inceptionDate", "type": "date", "description": "Date when the benchmark index was established."}]'::jsonb, '[{"type": "depends_on", "label": "Benchmark is selected to match portfolio objectives.", "targetId": "financial_services-asset-management-portfolio-objective"}, {"type": "related", "label": "Benchmark performance depends on timely and accurate market data feeds.", "targetId": "fibo-9"}]'::jsonb, 'performance,reference,comparison,index,benchmarking,regulatory-disclosure,asset-management,investment-strategy'::text[], 'Enables objective measurement of portfolio success and manager performance.', '2026-03-06 04:36:37.80735', 'Index Benchmark,Reference Index'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Benchmark Index", "version": 1, "synonyms": ["Index Benchmark", "Reference Index"], "updatedAt": "2026-03-06T04:54:44.394Z", "properties": [{"name": "indexName", "type": "string", "description": "Official benchmark index name."}, {"name": "indexProvider", "type": "string", "description": "Organization providing the index."}], "description": "A standard reference index used to compare and evaluate the performance of a portfolio or fund, such as the S&P 500 or MSCI World.", "relationships": [{"type": "depends_on", "label": "Benchmark is selected to match portfolio objectives.", "targetId": "financial_services-asset-management-portfolio-objective"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-asset-management-tracking-error-measurement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Tracking Error Measurement', 'Portfolio Objectives & Benchmarks', 'Tracking error measurement quantifies the deviation or volatility of a portfolio’s returns relative to a specified benchmark, serving as a key metric for evaluating the risk taken via active management strategies in financial services. It provides asset managers, regulators, and clients with clear insight into how closely a portfolio tracks its intended benchmark and whether excess risk is being assumed for potential outperformance. The measurement typically involves statistical analysis over a defined period, using historical return data from both the portfolio and its benchmark. Effective tracking error management is crucial for investment funds targeting specific tracking objectives, such as index funds or ETFs, and is instrumental in performance attribution and investor reporting. In AI-driven financial operations, this metric informs risk analytics, portfolio optimization, and compliance monitoring automations.', '[{"name": "trackingError", "type": "decimal", "description": "Numeric value of tracking error."}, {"name": "measurementPeriod", "type": "string", "description": "Timeframe for tracking error calculation."}, {"name": "benchmarkReturn", "type": "decimal", "description": "Return value of the selected benchmark over the measurement period."}, {"name": "portfolioReturn", "type": "decimal", "description": "Return value of the portfolio over the measurement period."}, {"name": "calculationMethodology", "type": "string", "description": "Description or reference to the statistical method used for tracking error computation."}, {"name": "lastCalculatedDate", "type": "date", "description": "Timestamp when tracking error was most recently computed."}]'::jsonb, '[{"type": "depends_on", "label": "Tracking error is computed relative to benchmark.", "targetId": "financial_services-asset-management-benchmark-index"}]'::jsonb, 'risk,performance,active-management,deviation,quantitative-analysis,performance-attribution,index-funds,compliance-reporting'::text[], 'Quantifies risk introduced by deviating from standard benchmarks.', '2026-03-06 04:36:37.851245', 'Active Risk,TE'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "Tracking Error Measurement", "version": 1, "synonyms": ["Active Risk", "TE"], "updatedAt": "2026-03-06T04:55:30.312Z", "properties": [{"name": "trackingError", "type": "decimal", "description": "Numeric value of tracking error."}, {"name": "measurementPeriod", "type": "string", "description": "Timeframe for tracking error calculation."}], "description": "Calculation of the volatility or deviation between portfolio returns and its chosen benchmark, used to gauge active management risk.", "relationships": [{"type": "depends_on", "label": "Tracking error is computed relative to benchmark.", "targetId": "financial_services-asset-management-benchmark-index"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-mnpievent', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'mnpiEvent', 'Material Non-Public Information (MNPI) Management', 'An mnpiEvent represents the occurrence or development of material non-public information (MNPI) related to securities, issuers, or corporate transactions within the financial services domain. These events, such as pending mergers, earnings figures, or major restructurings, necessitate immediate escalation and the activation of internal controls to restrict and monitor access to such sensitive information. The identification and registration of mnpiEvent instances are critical for compliance, as they trigger controls over who can access and act upon this information, thus preventing insider trading and information leakage. The mnpiEvent serves as a linchpin for various compliance procedures, including the creation of restricted lists and enforcement of information barriers. Effective management of these events is essential to protect market integrity, uphold legal mandates, and safeguard organizational reputation.', '[{"name": "eventType", "type": "enum", "description": "Type of MNPI event, such as M&A, earnings, restructuring"}, {"name": "eventDate", "type": "date", "description": "Date the MNPI event arose"}, {"name": "relatedIssuer", "type": "string", "description": "Issuer or company to which the MNPI pertains"}, {"name": "eventStatus", "type": "enum", "description": "Current status of the MNPI event, such as open, under review, closed."}, {"name": "originator", "type": "string", "description": "Individual or department responsible for identifying and reporting the MNPI event."}, {"name": "sensitivityLevel", "type": "enum", "description": "Classification of event sensitivity, such as confidential, highly confidential, or top secret."}, {"name": "expirationDate", "type": "date", "description": "Date on which the MNPI event ceases to be considered material or non-public."}]'::jsonb, '[{"type": "related", "label": "Triggers creation of restricted list entry", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "depends_on", "label": "Requires compliance with information barriers", "targetId": "financial_services-capital-markets-chinesewall"}, {"type": "related", "label": "Causes addition to insider list for event participants", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "child", "label": "May result in generation of surveillance alert", "targetId": "financial_services-capital-markets-surveillancealert"}, {"type": "related", "label": "Triggers mandatory MNPI training for affected staff", "targetId": "financial_services-capital-markets-mnpitrainingsession"}]'::jsonb, 'mnpi,informationControl,event,risk,insiderTradingPrevention,accessControl,marketAbuseRisk,issuerSensitive,regulatoryFlag'::text[], 'Proper management of MNPI is essential to prevent insider trading and market manipulation.', '2026-03-06 07:56:21.042272', 'materialEvent,non-publicDisclosure'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "mnpiEvent", "version": 1, "synonyms": ["materialEvent", "non-publicDisclosure"], "updatedAt": "2026-03-06T07:58:22.025Z", "properties": [{"name": "eventType", "type": "enum", "description": "Type of MNPI event, such as M&A, earnings, restructuring"}, {"name": "eventDate", "type": "date", "description": "Date the MNPI event arose"}, {"name": "relatedIssuer", "type": "string", "description": "Issuer or company to which the MNPI pertains"}], "description": "An occurrence or development containing material information about securities, issuers, or transactions that is not public, triggering internal controls and procedures to manage access and usage.", "relationships": [{"type": "related", "label": "Triggers creation of restricted list entry", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "depends_on", "label": "Requires compliance with information barriers", "targetId": "financial_services-capital-markets-chinesewall"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-restrictedlistentry', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'restrictedListEntry', 'Material Non-Public Information (MNPI) Management', 'A restrictedListEntry is a pivotal mechanism in financial services operations for controlling exposure to Material Non-Public Information (MNPI). When an organization possesses sensitive information about a security, issuer, or account—such as merger details or earnings not yet released—these entities are listed to prohibit trading or advisory actions by employees to prevent potential market abuse or conflicts of interest. The restricted list aids compliance and risk management teams in monitoring adherence to regulatory mandates, especially during periods where the risk of unlawful trading or tipping is heightened. AI agents can leverage the structured information maintained in restricted list entries to automate pre-trade checks, enhance surveillance, and trigger alerts in real time. This concept helps preserve market integrity while supporting rigorous compliance procedures.', '[{"name": "securityIdentifier", "type": "string", "description": "Unique identifier of restricted security or issuer"}, {"name": "restrictionStartDate", "type": "date", "description": "Date restriction begins"}, {"name": "restrictionReason", "type": "string", "description": "Summary of the MNPI or event causing restriction"}, {"name": "restrictionEndDate", "type": "date", "description": "Date when the restriction is scheduled to end or be reviewed."}, {"name": "affectedEmployeeCount", "type": "integer", "description": "Number of employees impacted by the restriction."}, {"name": "restrictionType", "type": "enum", "description": "Type of restriction, such as trading, advisory, or both."}]'::jsonb, '[{"type": "child", "label": "Placed in response to MNPI event", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Monitored via surveillance alerts", "targetId": "financial_services-capital-markets-surveillancealert"}, {"type": "related", "label": "Can be validated by compliance check agent", "targetId": "fibo-17"}, {"type": "related", "label": "May overlap with insider monitoring", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "child", "label": "Triggered by confidential information disclosure event", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}]'::jsonb, 'compliance,restriction,mnpi,list,surveillance,insider-trading-prevention,employee-monitoring,audit-trail'::text[], 'The restricted list prevents unauthorized trading and provides an auditable control over potential MNPI misuse.', '2026-03-06 07:56:21.094264', 'restrictedSecurity,blockListEntry'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "restrictedListEntry", "version": 1, "synonyms": ["restrictedSecurity", "blockListEntry"], "updatedAt": "2026-03-06T11:56:20.633Z", "properties": [{"name": "securityIdentifier", "type": "string", "description": "Unique identifier of restricted security or issuer"}, {"name": "restrictionStartDate", "type": "date", "description": "Date restriction begins"}, {"name": "restrictionReason", "type": "string", "description": "Summary of the MNPI or event causing restriction"}], "description": "A security, issuer, or account placed on a restricted list due to possession of MNPI, prohibiting employees from trading or advising on affected instruments.", "relationships": [{"type": "child", "label": "Placed in response to MNPI event", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Monitored via surveillance alerts", "targetId": "financial_services-capital-markets-surveillancealert"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-chinesewall', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'chineseWall', 'Material Non-Public Information (MNPI) Management', 'The concept of a ''chineseWall'' in financial services refers to the implementation of internal controls and structural barriers between distinct business units—such as investment banking, research, and trading—to mitigate the risk of material non-public information (MNPI) being improperly disseminated or used for unfair advantage. These walls are critical for maintaining market integrity and protecting client confidentiality, especially in complex organizations handling sensitive transactions. Mechanisms include physical separation, technological system access controls, and formalized policy frameworks. Effective chineseWall structures are crucial in contexts like mergers and acquisitions, client advisory, and proprietary trading desks. They also play a vital role in upholding organizational reputation and fostering trust with regulatory bodies.', '[{"name": "wallType", "type": "enum", "description": "Type of information barrier (physical, technological, policy-based)"}, {"name": "businessUnitA", "type": "string", "description": "First business unit separated"}, {"name": "businessUnitB", "type": "string", "description": "Second business unit separated"}, {"name": "implementationDate", "type": "date", "description": "Date when this chineseWall was established or last updated"}, {"name": "reviewFrequency", "type": "string", "description": "How often the effectiveness and configuration of the wall are reviewed"}, {"name": "complianceOwner", "type": "string", "description": "Person or role responsible for oversight of this wall"}]'::jsonb, '[{"type": "parent", "label": "Protects against misuse in MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Defines scope for insider list entries", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "related", "label": "Supports management of declared conflicts of interest", "targetId": "custom-113afd84-2e26-4d31-a2c9-6808c1b96313"}, {"type": "related", "label": "Triggers compliance checks for wall effectiveness", "targetId": "fibo-17"}, {"type": "related", "label": "Restricts disclosure of confidential information", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}]'::jsonb, 'barrier,compliance,mnpi,risk,information-barrier,insider-trading-prevention,employee-monitoring,access-control'::text[], 'Chinese walls are critical controls to mitigate regulatory risk and maintain market integrity.', '2026-03-06 07:56:21.140395', 'informationBarrier,ethicsWall'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "chineseWall", "version": 1, "synonyms": ["informationBarrier", "ethicsWall"], "updatedAt": "2026-03-06T11:57:06.094Z", "properties": [{"name": "wallType", "type": "enum", "description": "Type of information barrier (physical, technological, policy-based)"}, {"name": "businessUnitA", "type": "string", "description": "First business unit separated"}, {"name": "businessUnitB", "type": "string", "description": "Second business unit separated"}], "description": "An internal information barrier that separates different business units (such as investment banking and trading) to prevent the improper flow of MNPI.", "relationships": [{"type": "parent", "label": "Protects against misuse in MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Defines scope for insider list entries", "targetId": "financial_services-capital-markets-insiderlistentry"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-insiderlistentry', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'insiderListEntry', 'Material Non-Public Information (MNPI) Management', 'An insiderListEntry serves as an auditable record of individuals granted access to material non-public information (MNPI) related to a specific event, deal, or issuer. This register plays a central role in MNPI management by documenting who is privy to sensitive information during critical events such as mergers, acquisitions, or major issuances. Maintaining accuracy and traceability in this list is essential for effective monitoring of potential market abuse and inappropriate information dissemination. In operations, the insiderListEntry enables timely identification of possible insider trading and strengthens overall information barrier controls. The list needs to be promptly updated as access circumstances change and is a focal point for internal controls, audits, and regulatory inquiries.', '[{"name": "personName", "type": "string", "description": "Employee or contractor name"}, {"name": "accessGrantedDate", "type": "date", "description": "Date MNPI access was granted"}, {"name": "mnpiEventReference", "type": "string", "description": "Reference to triggering MNPI event"}, {"name": "accessRevokedDate", "type": "date", "description": "Date MNPI access was revoked for the individual"}, {"name": "department", "type": "string", "description": "Organizational department or unit of the individual"}, {"name": "roleType", "type": "string", "description": "Nature of access (e.g., legal, compliance, deal team)"}]'::jsonb, '[{"type": "related", "label": "Created in connection with MNPI event", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Monitored for risky activities", "targetId": "financial_services-capital-markets-surveillancealert"}, {"type": "related", "label": "Links to disclosures involving the individual", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}, {"type": "related", "label": "Tied to certification of training and responsibilities", "targetId": "financial_services-capital-markets-employeecertificationstatement"}, {"type": "related", "label": "Reference to required MNPI training enrollment", "targetId": "financial_services-capital-markets-mnpitrainingsession"}]'::jsonb, 'insider,mnpi,access,record,surveillance,regulatory-reporting,trading-controls,compliance-monitoring,dataprivacy'::text[], 'Insider lists enable monitoring and reporting for regulatory investigations and compliance.', '2026-03-06 07:56:21.185707', 'insiderRecord,mnpiAccessList'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "insiderListEntry", "version": 1, "synonyms": ["insiderRecord", "mnpiAccessList"], "updatedAt": "2026-03-06T11:57:41.304Z", "properties": [{"name": "personName", "type": "string", "description": "Employee or contractor name"}, {"name": "accessGrantedDate", "type": "date", "description": "Date MNPI access was granted"}, {"name": "mnpiEventReference", "type": "string", "description": "Reference to triggering MNPI event"}], "description": "A record of individuals who have access to MNPI for a specific event, deal, or issuer, maintained for regulatory and surveillance purposes.", "relationships": [{"type": "related", "label": "Created in connection with MNPI event", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Monitored for risky activities", "targetId": "financial_services-capital-markets-surveillancealert"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-surveillancealert', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'surveillanceAlert', 'Material Non-Public Information (MNPI) Management', 'A surveillanceAlert is an automated or manual notification generated when compliance systems detect potential misuse of Material Non-Public Information (MNPI). These alerts help monitor activities such as suspicious trading, abnormal communication patterns, or improper access to sensitive information by individuals with privileged access. In financial services operations, surveillance alerts are essential for timely identification, investigation, and escalation of possible regulatory violations. Their prompt handling supports proactive compliance management and mitigates the risk of insider trading incidents. Integration with related data sources and compliance workflows boosts their operational relevance and coverage.', '[{"name": "alertType", "type": "enum", "description": "Type of surveillance alert (trade, communication, access)"}, {"name": "alertDate", "type": "date", "description": "When alert was generated"}, {"name": "alertSeverity", "type": "enum", "description": "Severity rating of alert"}, {"name": "investigationStatus", "type": "enum", "description": "Current status of alert investigation (e.g. open, under review, closed)"}, {"name": "assignedTo", "type": "string", "description": "Identifier or name of compliance staff or team assigned to handle alert"}, {"name": "resolutionDate", "type": "date", "description": "Date the alert was resolved or closed"}, {"name": "sourceSystem", "type": "string", "description": "Name or identifier of the surveillance or detection system that produced the alert"}]'::jsonb, '[{"type": "depends_on", "label": "Monitors restricted securities", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "related", "label": "Focuses on individuals with MNPI access", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "related", "label": "SurveillanceAlert triggers or links to Compliance Checks", "targetId": "fibo-17"}, {"type": "related", "label": "Connects to Transaction Monitoring events for risk correlation", "targetId": "fibo-24"}, {"type": "related", "label": "Associated with disclosures of confidential information", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}]'::jsonb, 'surveillance,alert,mnpi,compliance,escalation,mnpi-surveillance,insider-trading,regulatory-alert,data-privacy'::text[], 'Surveillance alerts are essential for early detection and mitigation of MNPI-related risk.', '2026-03-06 07:56:21.230842', 'complianceAlert,mnpiAlert'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "surveillanceAlert", "version": 1, "synonyms": ["complianceAlert", "mnpiAlert"], "updatedAt": "2026-03-06T11:58:46.936Z", "properties": [{"name": "alertType", "type": "enum", "description": "Type of surveillance alert (trade, communication, access)"}, {"name": "alertDate", "type": "date", "description": "When alert was generated"}, {"name": "alertSeverity", "type": "enum", "description": "Severity rating of alert"}], "description": "Automated or manual signal indicating possible misuse of MNPI, such as suspicious trading, communications, or access patterns detected by compliance systems.", "relationships": [{"type": "depends_on", "label": "Monitors restricted securities", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "related", "label": "Focuses on individuals with MNPI access", "targetId": "financial_services-capital-markets-insiderlistentry"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-pretradeapproval', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'preTradeApproval', 'Trading & Execution Controls', 'The preTradeApproval process is a critical control in financial services operations, designed to ensure that any trade flagged for compliance concerns receives explicit review and authorization prior to execution. This step serves as a crucial gatekeeper, particularly for trades involving securities on restricted or watch lists, or those presenting potential conflicts of interest or non-public information risks. The workflow involves collecting trade details, conducting a thorough compliance check—including regulatory, firm-specific, and market rules—and obtaining sign-off from an authorized compliance officer. Audit trails are maintained, supporting accountability and transparency, and exceptions or denials are routed for escalation or remediation. By embedding preTradeApproval, firms mitigate regulatory penalties and reputational damage related to inadvertent or intentional rule breaches.', '[{"name": "tradeId", "type": "string", "description": "Unique trade identifier"}, {"name": "approvalStatus", "type": "enum", "description": "Status of approval (pending, approved, rejected)"}, {"name": "approver", "type": "string", "description": "Name of approving compliance officer"}, {"name": "approvalTimestamp", "type": "date", "description": "The precise date and time the pre-trade approval decision was made"}, {"name": "complianceCheckType", "type": "enum", "description": "Specifies the type of compliance review performed (e.g., MNPI, restricted, conflict of interest)"}, {"name": "escalationRequired", "type": "boolean", "description": "Indicates if this approval required escalation to higher compliance authority"}]'::jsonb, '[{"type": "depends_on", "label": "Triggered by security on restricted list", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "related", "label": "Can be flagged for further surveillance", "targetId": "financial_services-capital-markets-surveillancealert"}, {"type": "depends_on", "label": "Requires successful compliance screening", "targetId": "fibo-17"}, {"type": "related", "label": "Linked to the originating trade order", "targetId": "fibo-16"}, {"type": "related", "label": "Cross-references with individuals on insider list", "targetId": "financial_services-capital-markets-insiderlistentry"}]'::jsonb, 'trade,approval,compliance,mnpi,surveillance,restricted-list,authorization,escalation,internal-controls'::text[], 'Pre-trade approvals mitigate risks of unauthorized or illegal trading, especially under MNPI exposure.', '2026-03-06 07:56:21.277362', 'tradeApproval,preClearance'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "preTradeApproval", "version": 1, "synonyms": ["tradeApproval", "preClearance"], "updatedAt": "2026-03-06T12:00:18.898Z", "properties": [{"name": "tradeId", "type": "string", "description": "Unique trade identifier"}, {"name": "approvalStatus", "type": "enum", "description": "Status of approval (pending, approved, rejected)"}, {"name": "approver", "type": "string", "description": "Name of approving compliance officer"}], "description": "A mandatory authorization process for trades in securities flagged for compliance concerns, ensuring no regulatory or internal rules are breached before execution.", "relationships": [{"type": "depends_on", "label": "Triggered by security on restricted list", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "related", "label": "Can be flagged for further surveillance", "targetId": "financial_services-capital-markets-surveillancealert"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-bestexecutionpolicy', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'bestExecutionPolicy', 'Trading & Execution Controls', 'The bestExecutionPolicy is a formalized set of guidelines and protocols established by financial institutions to ensure every client trade order is executed under the most beneficial terms available. This policy mandates systematic evaluation of competing market venues and order-routing strategies, incorporating criteria such as price, speed, likelihood of execution, and settlement. It serves as an operational safeguard for clients, ensuring their interests are prioritized in an ever-changing market environment characterized by fragmented liquidity. In modern trading operations, maintaining a robust bestExecutionPolicy is vital for transparency, trust, and ongoing competitiveness amidst increased regulatory scrutiny. This policy also necessitates ongoing review and adaptation to keep pace with evolving markets and regulatory expectations.', '[{"name": "policyVersion", "type": "string", "description": "Policy version identifier"}, {"name": "effectiveDate", "type": "date", "description": "Policy start date"}, {"name": "assetClass", "type": "string", "description": "Asset class covered by the policy"}, {"name": "reviewFrequency", "type": "string", "description": "How often the policy is reviewed and updated (e.g., quarterly, annually)."}, {"name": "policyOwner", "type": "string", "description": "Designated individual or role responsible for the maintenance and oversight of the policy."}, {"name": "lastReviewDate", "type": "date", "description": "Date on which the policy was last reviewed."}]'::jsonb, '[{"type": "related", "label": "Conforms to the applicable regulatory framework", "targetId": "fibo-15"}, {"type": "depends_on", "label": "Informed by execution cost analysis", "targetId": "financial_services-capital-markets-executioncostanalysis"}, {"type": "related", "label": "Coordinated with trade surveillance controls", "targetId": "financial_services-capital-markets-tradesurveillancerule"}]'::jsonb, 'execution,policy,trade,regulation,MiFIDII,preTrade,postTradeAnalysis,orderRouting,compliance'::text[], 'Ensures fiduciary duty and regulatory compliance in executing client and proprietary trades.', '2026-03-06 07:56:21.322789', 'executionPolicy,tradingStandard'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "bestExecutionPolicy", "version": 1, "synonyms": ["executionPolicy", "tradingStandard"], "updatedAt": "2026-03-06T12:00:44.625Z", "properties": [{"name": "policyVersion", "type": "string", "description": "Policy version identifier"}, {"name": "effectiveDate", "type": "date", "description": "Policy start date"}, {"name": "assetClass", "type": "string", "description": "Asset class covered by the policy"}], "description": "A formal policy outlining procedures to ensure all client trades achieve the most advantageous terms given prevailing market conditions and regulatory requirements.", "relationships": [{"type": "depends_on", "label": "Relies on real-time market conditions", "targetId": "marketDataFeed"}, {"type": "related", "label": "Governs execution of trade orders", "targetId": "tradeOrder"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-tradesurveillancerule', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'tradeSurveillanceRule', 'Trading & Execution Controls', 'A tradeSurveillanceRule is a core compliance and risk control mechanism embedded within trading and execution platforms to detect and mitigate forms of unlawful or unethical trading activity. These automated rules continuously analyze live and historical trading data to identify patterns such as market manipulation, insider trading, or misuse of material non-public information (MNPI). They operate by applying configurable thresholds and logic across trade orders, executions, and market data. Well-parameterized surveillance rules help institutions promptly flag suspicious activity for human review, reducing exposure to regulatory fines and reputational damage. In the context of multi-asset and high-frequency trading, such rules are critical to maintaining market integrity and operational transparency.', '[{"name": "ruleName", "type": "string", "description": "Rule identifier"}, {"name": "ruleThreshold", "type": "decimal", "description": "Thresholds for triggering the rule"}, {"name": "ruleType", "type": "enum", "description": "Type of rule (volume, price movement, cross-asset) "}, {"name": "creationDate", "type": "date", "description": "The date when the surveillance rule was created or last updated."}, {"name": "activeStatus", "type": "boolean", "description": "Indicates if the rule is currently active and enforced."}, {"name": "alertSeverityLevel", "type": "enum", "description": "Severity level designated for alerts triggered by this rule (e.g., Low, Medium, High)."}]'::jsonb, '[{"type": "related", "label": "Generates surveillance alerts", "targetId": "financial_services-capital-markets-surveillancealert"}, {"type": "depends_on", "label": "Utilizes market data feed for price and volume information", "targetId": "fibo-9"}, {"type": "related", "label": "Cross-references employees or accounts on the insider list", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "depends_on", "label": "Incorporates timing and details of MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}]'::jsonb, 'trading,surveillance,rule,mnpi,compliance,market-abuse,surveillance-automation,regtech'::text[], 'Trade surveillance rules are key for detecting suspicious activity and meeting regulatory expectations.', '2026-03-06 07:56:21.368735', 'tradeComplianceRule,marketSurveillanceRule'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "tradeSurveillanceRule", "version": 1, "synonyms": ["tradeComplianceRule", "marketSurveillanceRule"], "updatedAt": "2026-03-06T12:01:20.669Z", "properties": [{"name": "ruleName", "type": "string", "description": "Rule identifier"}, {"name": "ruleThreshold", "type": "decimal", "description": "Thresholds for triggering the rule"}, {"name": "ruleType", "type": "enum", "description": "Type of rule (volume, price movement, cross-asset) "}], "description": "A compliance logic or automated rule set used to monitor trading activities for patterns indicative of market manipulation, insider trading, or MNPI misuse.", "relationships": [{"type": "related", "label": "Generates surveillance alerts", "targetId": "financial_services-capital-markets-surveillancealert"}, {"type": "depends_on", "label": "Monitors order activity for compliance", "targetId": "tradeOrder"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-dealmandate', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'dealMandate', 'Deal & Transaction Lifecycle', 'The ''dealMandate'' represents a formal contract through which a client authorizes an investment bank or financial institution to act as an advisor or executor for complex capital markets transactions, such as IPOs, M&A deals, or debt offerings. This mandate is a critical starting point in the deal & transaction lifecycle, codifying responsibilities, confidentiality, and scope for executing high-value, often market-sensitive, corporate actions. It frequently involves the generation and handling of Material Non-Public Information (MNPI), requiring stringent controls throughout the process. The issuance of a deal mandate triggers multiple downstream operational, regulatory, and information control processes. Effective management of deal mandates underpins both operational execution and regulatory compliance in financial services.', '[{"name": "mandateType", "type": "enum", "description": "Type of deal (IPO, M&A, debt)"}, {"name": "mandateDate", "type": "date", "description": "Date mandate was signed"}, {"name": "clientName", "type": "string", "description": "Name of client instructing the deal"}, {"name": "mandateStatus", "type": "enum", "description": "Current status of the mandate (e.g., pending, approved, executed, terminated)."}, {"name": "dealSize", "type": "decimal", "description": "Estimated size or value of the capital markets transaction."}, {"name": "executionDeadline", "type": "date", "description": "Target date by which the mandated deal must be executed."}]'::jsonb, '[{"type": "related", "label": "Deal mandates often generate MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "depends_on", "label": "Deal mandate requires associated conflict of interest check", "targetId": "custom-113afd84-2e26-4d31-a2c9-6808c1b96313"}, {"type": "related", "label": "Deal mandate submitted for committee review and authorization", "targetId": "financial_services-capital-markets-dealexecutioncommittee"}, {"type": "related", "label": "Mandate classified according to transaction confidentiality standards", "targetId": "financial_services-capital-markets-transactionconfidentialitylevel"}]'::jsonb, 'deal,mandate,transaction,investmentBanking,MNPI,capitalMarkets,confidentiality,regulatoryCompliance,corporateFinance'::text[], 'Deal mandates drive the start of capital markets transactions and require strict MNPI controls.', '2026-03-06 07:56:21.414247', 'transactionMandate,dealInstruction'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "dealMandate", "version": 1, "synonyms": ["transactionMandate", "dealInstruction"], "updatedAt": "2026-03-06T12:08:57.410Z", "properties": [{"name": "mandateType", "type": "enum", "description": "Type of deal (IPO, M&A, debt)"}, {"name": "mandateDate", "type": "date", "description": "Date mandate was signed"}, {"name": "clientName", "type": "string", "description": "Name of client instructing the deal"}], "description": "A formal instruction or contract authorizing an investment bank to advise or execute a capital markets transaction, such as IPO, M&A, or debt issuance, which may involve MNPI.", "relationships": [{"type": "related", "label": "Deal mandates often generate MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "parent", "label": "Mandate relates to issuer profile", "targetId": "issuerProfile"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-dealexecutioncommittee', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'dealExecutionCommittee', 'Deal & Transaction Lifecycle', 'The dealExecutionCommittee serves as a central governance body within financial institutions, tasked with the responsibility of reviewing, authorizing, and monitoring high-value capital markets transactions. This committee ensures that deals align with organizational strategy and risk appetite, enforcing information barriers and internal control policies. Their oversight covers compliance with evolving regulatory obligations, including due diligence, disclosure protocols, and conduct surveillance. They play a pivotal role in safeguarding the integrity of deal processes and mitigating reputational or legal risks. The committee''s activities are documented and auditable, forming part of essential corporate governance and regulatory submissions.', '[{"name": "committeeName", "type": "string", "description": "Execution committee identifier"}, {"name": "formationDate", "type": "date", "description": "Committee formation date"}, {"name": "chairperson", "type": "string", "description": "Committee chair name"}, {"name": "meetingFrequency", "type": "enum", "description": "Indicates how often the committee convenes (e.g., ad hoc, weekly, monthly)."}, {"name": "mandateScope", "type": "string", "description": "Defines the breadth of transactions or deals under the committee''s jurisdiction."}, {"name": "memberCount", "type": "integer", "description": "Total number of committee members."}]'::jsonb, '[{"type": "child", "label": "Oversees deal mandates", "targetId": "financial_services-capital-markets-dealmandate"}, {"type": "related", "label": "May appear on insider lists for information control", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "related", "label": "Must review conflict of interest declarations for all members", "targetId": "custom-113afd84-2e26-4d31-a2c9-6808c1b96313"}, {"type": "depends_on", "label": "Requires compliance checks to be completed before deal approval", "targetId": "fibo-17"}, {"type": "related", "label": "Monitors disclosures of confidential information relevant to deals", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}]'::jsonb, 'committee,deal,governance,compliance,transaction-oversight,mnpi-control,authorization,board-committee,risk-management'::text[], 'Deal execution committees oversee critical capital markets transactions and manage MNPI exposure.', '2026-03-06 07:56:21.460079', 'dealCommittee,executionCommittee'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "dealExecutionCommittee", "version": 1, "synonyms": ["dealCommittee", "executionCommittee"], "updatedAt": "2026-03-06T12:09:29.836Z", "properties": [{"name": "committeeName", "type": "string", "description": "Execution committee identifier"}, {"name": "formationDate", "type": "date", "description": "Committee formation date"}, {"name": "chairperson", "type": "string", "description": "Committee chair name"}], "description": "A governance body responsible for reviewing, authorizing, and monitoring the progress of capital markets deals, ensuring regulatory compliance and information control.", "relationships": [{"type": "child", "label": "Oversees deal mandates", "targetId": "financial_services-capital-markets-dealmandate"}, {"type": "related", "label": "May appear on insider lists for information control", "targetId": "financial_services-capital-markets-insiderlistentry"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-transactionconfidentialitylevel', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'transactionConfidentialityLevel', 'Deal & Transaction Lifecycle', 'The transactionConfidentialityLevel concept captures the classification status that dictates who has authorized access to sensitive information about capital markets transactions. It is a critical indicator throughout the deal and transaction lifecycle, ensuring that regulatory and internal policies regarding confidential, restricted, or public information are adhered to. This level of classification typically responds to events such as material non-public information (MNPI) events and determines both internal operational controls and external disclosure obligations. In financial services, managing this designation is essential for controlling the flow of information between deal teams, insider lists, and public stakeholders. Proper governance of transactionConfidentialityLevel protects both the organization and its clients from misconduct, reputational harm, and regulatory breaches.', '[{"name": "confidentialityLevel", "type": "enum", "description": "Level of confidentiality (public, restricted, confidential)"}, {"name": "assignedDate", "type": "date", "description": "Date confidentiality was set"}, {"name": "dealReference", "type": "string", "description": "Reference to the deal or transaction"}, {"name": "confidentialityExpiryDate", "type": "date", "description": "The date when the assigned confidentiality level is scheduled for review or expiration"}, {"name": "reviewedBy", "type": "string", "description": "Identifier of the compliance officer or reviewer who last confirmed the confidentiality status"}, {"name": "changeReason", "type": "string", "description": "Narrative or code indicating why the confidentiality classification was set or changed"}]'::jsonb, '[{"type": "depends_on", "label": "Classified based on MNPI status", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Controls access for insiders", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "related", "label": "Can trigger confidential information disclosure obligations", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}, {"type": "related", "label": "Enforced by related information barrier arrangements", "targetId": "financial_services-capital-markets-chinesewall"}]'::jsonb, 'confidentiality,deal,mnpi,classification,access-control,insider-trading-prevention,information-barrier,audit-trail'::text[], 'Transaction confidentiality levels affect who can access deal information and safeguard MNPI.', '2026-03-06 07:56:21.505285', 'transactionClassification,dealConfidentiality'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "transactionConfidentialityLevel", "version": 1, "synonyms": ["transactionClassification", "dealConfidentiality"], "updatedAt": "2026-03-06T12:09:58.364Z", "properties": [{"name": "confidentialityLevel", "type": "enum", "description": "Level of confidentiality (public, restricted, confidential)"}, {"name": "assignedDate", "type": "date", "description": "Date confidentiality was set"}, {"name": "dealReference", "type": "string", "description": "Reference to the deal or transaction"}], "description": "Classification level determining who can access details about a capital markets transaction, ranging from public, restricted, to strictly confidential.", "relationships": [{"type": "depends_on", "label": "Classified based on MNPI status", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Controls access for insiders", "targetId": "financial_services-capital-markets-insiderlistentry"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-issuertype', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'issuerType', 'Issuer & Security Analysis', 'The ''issuerType'' concept categorizes the nature of an entity issuing securities—such as sovereign, corporate, financial institution, or municipal sources. This classification is critical in capital markets as it directly influences the entity''s risk, regulatory, and compliance requirements. AI-enabled financial services must leverage issuerType for tailored due diligence, credit risk assessment, and investor suitability analysis. For structured finance and credit ratings, correctly identifying and classifying issuerType impacts factors like default probability modeling and disclosure protocols. An accurate, detailed issuerType assignment ensures transparency, consistency, and comparability for agents modeling exposure and managing regulatory submissions.', '[{"name": "issuerTypeName", "type": "enum", "description": "Type of issuer (corporate, sovereign, financial, municipal)"}, {"name": "issuerCountry", "type": "string", "description": "Country of issuer incorporation"}, {"name": "listedStatus", "type": "boolean", "description": "Is issuer listed on an exchange"}, {"name": "industrySector", "type": "string", "description": "The primary industry sector of the issuer, enabling more granular analysis."}, {"name": "regulatoryJurisdiction", "type": "string", "description": "Governing regulatory body or jurisdiction applicable to the issuer."}, {"name": "parentGroupName", "type": "string", "description": "Name of issuer''s parent entity, if applicable."}]'::jsonb, '[{"type": "related", "label": "Impacts deal mandates and structure", "targetId": "financial_services-capital-markets-dealmandate"}, {"type": "related", "label": "Guides the analysis process for sovereign issuer types", "targetId": "custom-d5e1cb84-d3d3-442b-8e26-87fa24d009c3"}, {"type": "related", "label": "Provides detailed industry sector breakdown for the issuerType", "targetId": "financial_services-credit-rating-issuersectorclassification"}, {"type": "depends_on", "label": "Requires verification of issuer''s identity during classification", "targetId": "fibo-6"}]'::jsonb, 'issuer,classification,capitalMarkets,risk,referenceData,disclosure,portfolioRisk,issuerDueDiligence'::text[], 'Issuer type affects risk assessment, compliance, and deal structuring in capital markets.', '2026-03-06 07:56:21.551098', 'issuerCategory,issuerClass'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "issuerType", "version": 1, "synonyms": ["issuerCategory", "issuerClass"], "updatedAt": "2026-03-06T12:11:14.085Z", "properties": [{"name": "issuerTypeName", "type": "enum", "description": "Type of issuer (corporate, sovereign, financial, municipal)"}, {"name": "issuerCountry", "type": "string", "description": "Country of issuer incorporation"}, {"name": "listedStatus", "type": "boolean", "description": "Is issuer listed on an exchange"}], "description": "Classification of an entity issuing securities in capital markets, such as sovereign, corporate, financial institution, or municipal, impacting risk and compliance profiles.", "relationships": [{"type": "parent", "label": "Used for categorizing issuer profiles", "targetId": "issuerProfile"}, {"type": "related", "label": "Impacts deal mandates and structure", "targetId": "financial_services-capital-markets-dealmandate"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-securityissuancecalendar', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'securityIssuanceCalendar', 'Issuer & Security Analysis', 'The securityIssuanceCalendar provides a comprehensive schedule of upcoming and historical placements of securities, such as IPOs, bond issues, or secondaries, within the capital markets. This calendar is used extensively by underwriters, issuers, and market participants to coordinate trading activity, plan deals, anticipate liquidity events, and manage risk exposures. Accurate and timely maintenance of the issuance calendar is crucial for aligning deal mandates, preventing conflicts of interest, and minimizing disruptions caused by market-sensitive disclosures. In financial services AI operations, it serves as a key reference for analytics, workflow automation, and regulatory disclosures. The calendar is also integral to decision-making for portfolio managers and compliance teams, guiding pre-trade approval and surveillance protocols.', '[{"name": "issuanceDate", "type": "date", "description": "Scheduled date for issuance"}, {"name": "securityType", "type": "enum", "description": "Type of security being issued"}, {"name": "issuerName", "type": "string", "description": "Name of issuing entity"}, {"name": "distributionMethod", "type": "enum", "description": "Means by which securities are offered (e.g., public offering, private placement)."}, {"name": "estimatedDealSize", "type": "decimal", "description": "Projected value of the issuance, supporting liquidity planning and market forecasting."}, {"name": "underwritingSyndicate", "type": "string", "description": "Name(s) of institutions underwriting or managing the issuance."}, {"name": "mnpiFlag", "type": "boolean", "description": "Indicates whether the issuance contains or generates material non-public information."}]'::jsonb, '[{"type": "related", "label": "Planned in accordance with deal mandates", "targetId": "financial_services-capital-markets-dealmandate"}, {"type": "depends_on", "label": "Timing may create MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "depends_on", "label": "Issuance may initiate corporate actions affecting securities holders.", "targetId": "fibo-22"}, {"type": "related", "label": "Broadcasts issuance schedule via live market data feeds for participant awareness.", "targetId": "fibo-9"}]'::jsonb, 'calendar,issuance,security,deal,mnpi,primaryMarket,compliance,underwriting,tradeExecution'::text[], 'Issuance calendars drive capital flow and must be managed for MNPI timing and compliance.', '2026-03-06 07:56:21.596761', 'dealCalendar,offeringSchedule'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "securityIssuanceCalendar", "version": 1, "synonyms": ["dealCalendar", "offeringSchedule"], "updatedAt": "2026-03-06T12:11:36.918Z", "properties": [{"name": "issuanceDate", "type": "date", "description": "Scheduled date for issuance"}, {"name": "securityType", "type": "enum", "description": "Type of security being issued"}, {"name": "issuerName", "type": "string", "description": "Name of issuing entity"}], "description": "Schedule of planned or actual placements of securities in the capital markets, including IPOs, bond issues, and secondary offerings, guiding trading and deal activity.", "relationships": [{"type": "related", "label": "Planned in accordance with deal mandates", "targetId": "financial_services-capital-markets-dealmandate"}, {"type": "depends_on", "label": "Timing may create MNPI events", "targetId": "financial_services-capital-markets-mnpievent"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-initialpricerange', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'initialPriceRange', 'Issuer & Security Analysis', 'The ''initialPriceRange'' represents the preliminary spectrum of potential offering prices for a new security, established before the actual issuance process concludes. This range is crucial in guiding investor expectations and bookbuilding activities, providing a starting point for negotiations and subscription interest. During the offering process, syndicate managers and underwriters adjust this range based on real-time market, investor input, and demand levels, ensuring optimal price discovery. Accurate and transparent handling of the initialPriceRange increases the efficiency of capital formation and helps prevent mispricing, which is critical for both issuers and investors. In modern issuance processes, this concept underpins digital workflows and automated pricing engines.', '[{"name": "minPrice", "type": "decimal", "description": "Lowest price in range"}, {"name": "maxPrice", "type": "decimal", "description": "Highest price in range"}, {"name": "securityId", "type": "string", "description": "Identifier for the security"}, {"name": "currency", "type": "string", "description": "The currency in which the initial price range is denominated"}, {"name": "dateAnnounced", "type": "date", "description": "The official date when the initial price range is disclosed"}, {"name": "bookrunnerId", "type": "string", "description": "Unique identifier for the lead bookrunner responsible for setting the price range"}]'::jsonb, '[{"type": "related", "label": "Defined as part of issuance schedule", "targetId": "financial_services-capital-markets-securityissuancecalendar"}, {"type": "related", "label": "Used as input for assessing price impact during issuance", "targetId": "financial_services-capital-markets-priceimpactmodel"}, {"type": "related", "label": "Refined based on order book depth analysis", "targetId": "financial_services-capital-markets-orderbookdepthsnapshot"}]'::jsonb, 'pricing,issuance,security,market,bookbuilding,primaryMarket,disclosure,syndication'::text[], 'Initial price ranges are critical for managing investor expectations and market risk.', '2026-03-06 07:56:21.642595', 'priceRange,bookbuildingRange'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "initialPriceRange", "version": 1, "synonyms": ["priceRange", "bookbuildingRange"], "updatedAt": "2026-03-06T12:12:20.245Z", "properties": [{"name": "minPrice", "type": "decimal", "description": "Lowest price in range"}, {"name": "maxPrice", "type": "decimal", "description": "Highest price in range"}, {"name": "securityId", "type": "string", "description": "Identifier for the security"}], "description": "The preliminary range of prices at which a security is expected to be offered during issuance, often subject to change based on bookbuilding and market feedback.", "relationships": [{"type": "related", "label": "Defined as part of issuance schedule", "targetId": "financial_services-capital-markets-securityissuancecalendar"}, {"type": "depends_on", "label": "Informed by market data", "targetId": "marketDataFeed"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-mnpitrainingsession', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'mnpiTrainingSession', 'Capital Markets Compliance & Risk Controls', 'The ''mnpiTrainingSession'' concept embodies the formal educational process within capital markets aimed at ensuring employees understand the identification, proper handling, and regulatory risks associated with Material Non-Public Information (MNPI). These sessions play a foundational role in mitigating market abuse and insider trading risks, supporting a firm''s internal control framework and legal defense in regulatory actions. Training covers practical scenarios, legal definitions, compliance protocols, and integrates case studies reflecting recent enforcement trends. Institutions often record and audit these sessions to demonstrate proactive compliance to regulators and strengthen their risk management posture. Effective MNPI training is key to cultivating ethical behavior and reducing operational exposures tied to sensitive information.', '[{"name": "sessionDate", "type": "date", "description": "Date training was held"}, {"name": "trainerName", "type": "string", "description": "Name of trainer or training firm"}, {"name": "attendeeCount", "type": "integer", "description": "Number of attendees"}, {"name": "trainingCompletionStatus", "type": "enum", "description": "Indicates whether the attendee completed, failed, or did not attend the session"}, {"name": "sessionDuration", "type": "decimal", "description": "Length of the training session in hours"}, {"name": "trainingType", "type": "string", "description": "Specifies the format (e.g., in-person, online, self-paced) of the training session"}, {"name": "sessionLocation", "type": "string", "description": "Physical or virtual location where the training session was conducted"}]'::jsonb, '[{"type": "related", "label": "May reference attendees with MNPI access", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "parent", "label": "Training linked to event relevance", "targetId": "financial_services-capital-markets-mnpievent"}, {"type": "related", "label": "Links training completion with employee certification of MNPI awareness", "targetId": "financial_services-capital-markets-employeecertificationstatement"}, {"type": "related", "label": "References the policy guidelines covered during the training session", "targetId": "financial_services-capital-markets-mnpipolicydocument"}]'::jsonb, 'training,compliance,mnpi,education,marketAbuse,internalControls,employeeConduct,informationSecurity'::text[], 'Training sessions foster awareness and compliance culture around MNPI management.', '2026-03-06 07:56:21.688236', 'mnpiTraining,insiderTraining'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "mnpiTrainingSession", "version": 1, "synonyms": ["mnpiTraining", "insiderTraining"], "updatedAt": "2026-03-06T12:13:16.937Z", "properties": [{"name": "sessionDate", "type": "date", "description": "Date training was held"}, {"name": "trainerName", "type": "string", "description": "Name of trainer or training firm"}, {"name": "attendeeCount", "type": "integer", "description": "Number of attendees"}], "description": "An official session or course provided to employees, covering the identification, handling, and regulatory risks of MNPI in capital markets operations.", "relationships": [{"type": "related", "label": "May reference attendees with MNPI access", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "parent", "label": "Training linked to event relevance", "targetId": "financial_services-capital-markets-mnpievent"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-employeecertificationstatement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'employeeCertificationStatement', 'Capital Markets Compliance & Risk Controls', 'The employeeCertificationStatement is a foundational compliance artifact in capital markets operations. It represents a signed affirmation by an employee, verifying their understanding of policies regarding Material Nonpublic Information (MNPI), Chinese walls, and related internal controls. These statements are issued periodically, such as during onboarding, annually, or after significant compliance training events, and serve as proof of employee commitment to upholding strict market conduct standards. The document is essential in evidencing adherence to regulatory expectations around information barriers and insider trading prevention. Automated and auditable tracking of these statements demonstrates a firm''s robust compliance framework to regulators and internal auditors.', '[{"name": "employeeName", "type": "string", "description": "Name of certifying employee"}, {"name": "certificationDate", "type": "date", "description": "Certification date"}, {"name": "certificationType", "type": "enum", "description": "Type (annual, event-driven, onboarding)"}, {"name": "employeeId", "type": "string", "description": "Unique identifier for the certifying employee."}, {"name": "certificationStatus", "type": "enum", "description": "Current status of the certification (e.g., pending, completed, expired, revoked)."}, {"name": "reviewedBy", "type": "string", "description": "Name of the compliance officer or manager who reviewed the certification statement."}]'::jsonb, '[{"type": "related", "label": "Often follows mandatory MNPI training", "targetId": "financial_services-capital-markets-mnpitrainingsession"}, {"type": "related", "label": "Applicable for MNPI insiders", "targetId": "financial_services-capital-markets-insiderlistentry"}, {"type": "related", "label": "May supplement the conflict of interest declaration for complete employee compliance attestation", "targetId": "custom-113afd84-2e26-4d31-a2c9-6808c1b96313"}, {"type": "depends_on", "label": "Certification validity checked during compliance assessments", "targetId": "fibo-17"}, {"type": "related", "label": "Linked with confidential information disclosures requiring certification coverage", "targetId": "financial_services-credit-rating-confidentialinformationdisclosure"}]'::jsonb, 'certification,employee,compliance,mnpi,attestation,insider-trading-prevention,information-barriers,regulatory-proof'::text[], 'Certification statements form part of regulatory audit trails for MNPI controls.', '2026-03-06 07:56:21.734153', 'mnpiCertification,employeeStatement'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "employeeCertificationStatement", "version": 1, "synonyms": ["mnpiCertification", "employeeStatement"], "updatedAt": "2026-03-06T12:13:38.948Z", "properties": [{"name": "employeeName", "type": "string", "description": "Name of certifying employee"}, {"name": "certificationDate", "type": "date", "description": "Certification date"}, {"name": "certificationType", "type": "enum", "description": "Type (annual, event-driven, onboarding)"}], "description": "A formal statement signed by employees affirming their understanding of MNPI policy, Chinese walls, and compliance obligations within capital markets activities.", "relationships": [{"type": "related", "label": "Often follows mandatory MNPI training", "targetId": "financial_services-capital-markets-mnpitrainingsession"}, {"type": "related", "label": "Applicable for MNPI insiders", "targetId": "financial_services-capital-markets-insiderlistentry"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-mnpipolicydocument', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'mnpiPolicyDocument', 'Capital Markets Compliance & Risk Controls', 'The mnpiPolicyDocument is a foundational compliance artifact in capital markets, detailing how an organization identifies, manages, and controls access to Material Non-Public Information (MNPI). It outlines procedures for handling sensitive information, the governance processes to ensure continuous compliance, and references to regulatory frameworks such as SEC Rule 10b5-1. This document is critical in minimizing the risk of insider trading and ensuring fair market practices among employees and related parties. In modern financial institutions, the mnpiPolicyDocument is frequently referenced during audits, staff training, and the deployment of surveillance technologies within the firm''s compliance ecosystem.', '[{"name": "documentVersion", "type": "string", "description": "Policy document version"}, {"name": "publicationDate", "type": "date", "description": "Date document was issued"}, {"name": "documentStatus", "type": "enum", "description": "Status (active, draft, archived)"}, {"name": "lastReviewedDate", "type": "date", "description": "The most recent date the policy was formally reviewed or updated."}, {"name": "regulatoryReference", "type": "string", "description": "Citation of underlying regulations or laws referenced in the policy."}, {"name": "applicabilityScope", "type": "string", "description": "Description of which departments, jurisdictions, or employee classes the policy applies to."}]'::jsonb, '[{"type": "parent", "label": "Defines procedures for restricted list management", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "related", "label": "Employees certify against policy guidance", "targetId": "financial_services-capital-markets-employeecertificationstatement"}, {"type": "related", "label": "Describes information barrier protocols complementary to MNPI policy", "targetId": "financial_services-capital-markets-chinesewall"}, {"type": "related", "label": "Mandates staff participation in MNPI training programs", "targetId": "financial_services-capital-markets-mnpitrainingsession"}]'::jsonb, 'policy,mnpi,documentation,compliance,insider-trading-prevention,information-barriers,policy-attestation,staff-training'::text[], 'MNPI policies are central for establishing firm-wide standards and regulatory compliance.', '2026-03-06 07:56:21.780461', 'mnpiPolicy,insiderTradingPolicy'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "mnpiPolicyDocument", "version": 1, "synonyms": ["mnpiPolicy", "insiderTradingPolicy"], "updatedAt": "2026-03-06T12:14:06.419Z", "properties": [{"name": "documentVersion", "type": "string", "description": "Policy document version"}, {"name": "publicationDate", "type": "date", "description": "Date document was issued"}, {"name": "documentStatus", "type": "enum", "description": "Status (active, draft, archived)"}], "description": "Official documentation detailing procedures, controls, and regulatory guidance for the identification and management of MNPI in capital markets environments.", "relationships": [{"type": "parent", "label": "Defines procedures for restricted list management", "targetId": "financial_services-capital-markets-restrictedlistentry"}, {"type": "related", "label": "Employees certify against policy guidance", "targetId": "financial_services-capital-markets-employeecertificationstatement"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-priceimpactmodel', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'priceImpactModel', 'Capital Markets Analytics & Modeling', 'The priceImpactModel is a specialized quantitative framework used in capital markets to predict how large trades, issuances, or market-moving events (including the release of material non-public information, MNPI) affect the price of securities. This model is essential for structuring deals, assessing market liquidity, and evaluating the risk of price slippage associated with trading or issuance activities. By analyzing historical market data, trade volumes, and event-driven volatility, the model informs both pricing strategy and regulatory compliance, ensuring market fairness and transparency. Financial institutions utilize the priceImpactModel during syndicate processes, issuance planning, and proprietary trading to optimize execution, minimize systemic risk, and maintain regulatory integrity.', '[{"name": "modelName", "type": "string", "description": "Price impact model identifier"}, {"name": "lastCalibrationDate", "type": "date", "description": "Date model calibration last occurred"}, {"name": "assetClass", "type": "string", "description": "Asset class for which model is used"}, {"name": "calibrationFrequency", "type": "string", "description": "How often the model is recalibrated, e.g., daily, weekly, monthly."}, {"name": "modelVersion", "type": "string", "description": "Current version identifier for the price impact model."}, {"name": "mnpiSensitivity", "type": "decimal", "description": "Indicates how sensitive the model is to material non-public information events."}, {"name": "regulatoryComplianceStatus", "type": "enum", "description": "Status indicating whether the model complies with relevant regulatory requirements."}]'::jsonb, '[{"type": "related", "label": "Informs price range setting during issuance", "targetId": "financial_services-capital-markets-initialpricerange"}, {"type": "depends_on", "label": "Price impact model utilizes inputs from market risk modeling", "targetId": "fibo-19"}, {"type": "related", "label": "Price impact model adjusts for special events involving material non-public information", "targetId": "financial_services-capital-markets-mnpievent"}]'::jsonb, 'analytics,model,pricing,capitalMarkets,quantitativeModel,liquidityAnalysis,eventRisk,tradeExecution,regulatoryCompliance'::text[], 'Price impact models inform deal structuring and trading strategies while considering compliance risks.', '2026-03-06 07:56:21.826304', 'impactModel,marketImpactModel'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "priceImpactModel", "version": 1, "synonyms": ["impactModel", "marketImpactModel"], "updatedAt": "2026-03-06T12:14:45.948Z", "properties": [{"name": "modelName", "type": "string", "description": "Price impact model identifier"}, {"name": "lastCalibrationDate", "type": "date", "description": "Date model calibration last occurred"}, {"name": "assetClass", "type": "string", "description": "Asset class for which model is used"}], "description": "Quantitative model used to estimate the effect of large trades, issuance, or events (including MNPI) on the security’s market price, critical to deal structuring and compliance assessments.", "relationships": [{"type": "depends_on", "label": "Requires market data inputs", "targetId": "marketDataFeed"}, {"type": "related", "label": "Informs price range setting during issuance", "targetId": "financial_services-capital-markets-initialpricerange"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-executioncostanalysis', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'executionCostAnalysis', 'Capital Markets Analytics & Modeling', 'ExecutionCostAnalysis is a focused analytical process in capital markets that quantifies both implicit (e.g., market impact, slippage) and explicit (e.g., commissions, fees) costs realized during the execution of trades. This analysis helps trading desks, compliance teams, and portfolio managers assess the effectiveness of trade execution strategies in achieving best execution for clients. By providing transparency into cost drivers, execution cost analysis improves decision-making and trading performance. Its output is often referenced in regulatory audits and performance reviews, supporting ongoing optimization. When integrated with real-time data sources, it enables responsive adjustments and ongoing compliance monitoring.', '[{"name": "analysisDate", "type": "date", "description": "Date analysis was run"}, {"name": "tradeVolume", "type": "decimal", "description": "Volume of trade analyzed"}, {"name": "costType", "type": "enum", "description": "Type of cost (implicit, explicit)"}, {"name": "benchmarkedCost", "type": "decimal", "description": "Cost compared to industry benchmarks for similar trade types."}, {"name": "marketImpactEstimate", "type": "decimal", "description": "Quantitative estimate of the trade''s impact on market prices."}, {"name": "executionStrategy", "type": "enum", "description": "Type of trading strategy used (e.g., algorithmic, manual, VWAP, TWAP)."}, {"name": "currency", "type": "string", "description": "Currency denomination for the execution costs analyzed."}]'::jsonb, '[{"type": "related", "label": "Supports compliance with execution policy", "targetId": "financial_services-capital-markets-bestexecutionpolicy"}, {"type": "related", "label": "References price impact modeling for implicit costs", "targetId": "financial_services-capital-markets-priceimpactmodel"}, {"type": "related", "label": "Utilizes market depth data for slippage analysis", "targetId": "financial_services-capital-markets-orderbookdepthsnapshot"}, {"type": "related", "label": "Benchmarks execution cost analysis against market standards", "targetId": "financial_services-asset-management-benchmark-index"}]'::jsonb, 'cost,execution,analysis,trading,transactioncost,bestexecution,slippage,marketimpact,performance'::text[], 'Execution cost analysis supports compliance, risk monitoring, and client reporting.', '2026-03-06 07:56:21.871761', 'tradeCostAnalysis,executionAnalysis'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "executionCostAnalysis", "version": 1, "synonyms": ["tradeCostAnalysis", "executionAnalysis"], "updatedAt": "2026-03-06T12:15:03.565Z", "properties": [{"name": "analysisDate", "type": "date", "description": "Date analysis was run"}, {"name": "tradeVolume", "type": "decimal", "description": "Volume of trade analyzed"}, {"name": "costType", "type": "enum", "description": "Type of cost (implicit, explicit)"}], "description": "Analytical process to determine the implicit and explicit costs incurred during trade execution, including market impact, spreads, and slippage, relevant for best execution compliance.", "relationships": [{"type": "related", "label": "Supports compliance with execution policy", "targetId": "financial_services-capital-markets-bestexecutionpolicy"}, {"type": "depends_on", "label": "Analyzes specific trades", "targetId": "tradeOrder"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-capital-markets-orderbookdepthsnapshot', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'orderBookDepthSnapshot', 'Capital Markets Analytics & Modeling', 'The ''orderBookDepthSnapshot'' provides a detailed record of buy and sell orders at multiple price levels for a particular security at a specific instance. This snapshot serves as a foundational analytic for assessing liquidity and potential execution costs, assisting traders and risk managers in understanding order concentration and market depth. It is instrumental in identifying price slippage risks, supports compliance with Best Execution requirements, and helps safeguard against misuse of material non-public information (MNPI). In high-frequency and algorithmic trading environments, such snapshots are vital for microstructure analysis and optimizing trade strategies. The captured data also supports surveillance functions by making anomalous order placements or spoofing detection possible.', '[{"name": "snapshotDateTime", "type": "date", "description": "Time of snapshot"}, {"name": "securityId", "type": "string", "description": "Security for which order book was analyzed"}, {"name": "depthLevels", "type": "integer", "description": "Number of price levels captured"}, {"name": "exchangeVenue", "type": "string", "description": "The trading venue or exchange from which the order book was sourced."}, {"name": "bidAskSpread", "type": "decimal", "description": "The spread between the best bid and the best ask at the snapshot time."}, {"name": "notionalDepth", "type": "decimal", "description": "Aggregate monetary value available across all captured order book levels."}]'::jsonb, '[{"type": "related", "label": "Feeds into price impact modeling", "targetId": "financial_services-capital-markets-priceimpactmodel"}, {"type": "related", "label": "Used to monitor short-term liquidity risk", "targetId": "fibo-23"}, {"type": "related", "label": "Supports trade order execution strategies", "targetId": "fibo-16"}, {"type": "depends_on", "label": "Triggers surveillance alerts for market abuse", "targetId": "financial_services-capital-markets-surveillancealert"}]'::jsonb, 'orderBook,liquidity,market,analytics,executionMonitoring,tradingSurveillance,microstructure,mnpiSurveillance'::text[], 'Order book depth analysis is essential for understanding liquidity and monitoring for MNPI-driven anomalies.', '2026-03-06 07:56:21.917459', 'orderBookSnapshot,depthSnapshot'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "orderBookDepthSnapshot", "version": 1, "synonyms": ["orderBookSnapshot", "depthSnapshot"], "updatedAt": "2026-03-06T12:15:27.426Z", "properties": [{"name": "snapshotDateTime", "type": "date", "description": "Time of snapshot"}, {"name": "securityId", "type": "string", "description": "Security for which order book was analyzed"}, {"name": "depthLevels", "type": "integer", "description": "Number of price levels captured"}], "description": "A record of the buy and sell orders at different price levels for a security at a specific point in time, analyzed for liquidity, execution, and MNPI risk.", "relationships": [{"type": "depends_on", "label": "Obtained from market data feeds", "targetId": "marketDataFeed"}, {"type": "related", "label": "Feeds into price impact modeling", "targetId": "financial_services-capital-markets-priceimpactmodel"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-74f3726d-99ba-473e-9ece-ffe480039e6f', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'SoD', 'Risk & Compliance', 'SoD, or Segregation of Duties, is a fundamental risk management and internal control principle designed to prevent fraud, errors, and conflicts of interest in financial services operations. By ensuring that no single individual has full control over critical financial transactions or processes, SoD reduces the likelihood of unauthorized activities and improves accountability. In the context of financial services, typical SoD implementations include separating roles for transaction initiation, review, and approval, such as ensuring that the person who sets up a payment isn''t the one to authorize it. It also applies in trading, settlement, custody, and compliance functions where independent checks are required. Proper SoD implementation is essential for effective oversight and safeguarding of assets.', '[{"name": "policyVersion", "type": "string", "description": "Version identifier for the applied SoD policy or rule set."}, {"name": "lastAuditDate", "type": "date", "description": "Date of the most recent audit or review of SoD compliance."}, {"name": "violationAlertLevel", "type": "enum", "description": "Severity or priority of alerts triggered by SoD violations (e.g., Low, Medium, High)."}]'::jsonb, '[{"type": "depends_on", "label": "SoD enforcement relies on compliance check outcomes", "targetId": "fibo-17"}, {"type": "related", "label": "SoD is applied to distinct roles in the trade settlement process", "targetId": "fibo-10"}, {"type": "related", "label": "SoD is critical in payment instruction approval workflows", "targetId": "fibo-12"}, {"type": "related", "label": "Segregation of Duties (SoD) is a critical component in compliance checks to ensure that no individual has control over conflicting duties.", "targetId": "Compliance Check"}, {"type": "related", "label": "SoD principles help to enhance transaction monitoring by ensuring that no single individual is responsible for all aspects of a transaction.", "targetId": "Transaction Monitoring"}, {"type": "related", "label": "SoD governs the processes that trigger fraud alert notifications by distributing responsibilities among different individuals.", "targetId": "Fraud Alert Notification"}, {"type": "depends_on", "label": "Effective implementation of SoD depends on thorough KYC verification to ensure that roles and responsibilities are clearly defined.", "targetId": "KYC Verification"}, {"type": "related", "label": "SoD is a fundamental part of the regulatory framework aimed at preventing fraud and ensuring compliance in financial services.", "targetId": "Regulatory Framework"}, {"type": "related", "label": "SoD relates to AML screening by ensuring that different individuals handle transaction approvals and monitoring to prevent money laundering.", "targetId": "AML Screening"}, {"type": "related", "label": "The effectiveness of SoD measures can be evaluated through conflict of interest declarations to ensure transparency and accountability.", "targetId": "Conflict of Interest Declaration"}, {"type": "related", "label": "SoD is required in the preparation of regulatory reports to ensure that data integrity and compliance are maintained.", "targetId": "Regulatory Report"}]'::jsonb, 'Internal Control,Fraud Prevention,Operational Risk,Role Governance,Auditability'::text[], NULL, '2026-03-06 12:26:05.69646', ''::text[], 'custom-extension', 0, '[]'::jsonb, 10, E'[{"label": "SoD", "version": 1, "synonyms": [], "updatedAt": "2026-03-06T12:26:35.716Z", "properties": [], "description": "- It’s a risk management and internal control principle that ensures no single individual has control over all aspects of a critical transaction or process.\\n- Example: In financial services, one person should not both initiate and approve a payment, or both trade and settle securities.", "relationships": [], "linkedRegulations": []}, {"label": "SoD", "version": 2, "synonyms": [], "updatedAt": "2026-03-06T12:26:56.337Z", "properties": [{"name": "policyVersion", "type": "string", "description": "Version identifier for the applied SoD policy or rule set."}, {"name": "lastAuditDate", "type": "date", "description": "Date of the most recent audit or review of SoD compliance."}, {"name": "violationAlertLevel", "type": "enum", "description": "Severity or priority of alerts triggered by SoD violations (e.g., Low, Medium, High)."}], "description": "SoD, or Segregation of Duties, is a fundamental risk management and internal control principle designed to prevent fraud, errors, and conflicts of interest in financial services operations. By ensuring that no single individual has full control over critical financial transactions or processes, SoD reduces the likelihood of unauthorized activities and improves accountability. In the context of financial services, typical SoD implementations include separating roles for transaction initiation, review, and approval, such as ensuring that the person who sets up a payment isn''t the one to authorize it. It also applies in trading, settlement, custody, and compliance functions where independent checks are required. Proper SoD implementation is essential for effective oversight and safeguarding of assets.", "relationships": [{"type": "depends_on", "label": "SoD enforcement relies on compliance check outcomes", "targetId": "fibo-17"}, {"type": "related", "label": "SoD is applied to distinct roles in the trade settlement process", "targetId": "fibo-10"}, {"type": "related", "label": "SoD is critical in payment instruction approval workflows", "targetId": "fibo-12"}], "linkedRegulations": []}, {"label