INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-vindecoding', 'custom', 'Cross-Industry Ontology', 'vinDecoding', 'Vehicle Specification', 'vinDecoding is a critical process in the automotive ecosystem where the unique Vehicle Identification Number (VIN) is algorithmically decoded to retrieve a vehicle''s standardized specifications, manufacturing details, and build equipment data. This process is integral for use cases requiring precise vehicle identification, such as valuation, regulatory checks, and detailed analytics. In custom operations with AI agents, vinDecoding enables the automation of fleet audits, real-time inventory verifications, and dynamic insurance underwriting by providing consistent and structured vehicle data. Effective vinDecoding ensures downstream systems receive accurate and rich datasets for operational decisioning. The dependability and repeatability of vinDecoding directly impact the quality of analytics and business operations that rely on granular vehicle-level detail.', '[{"name": "vin", "type": "string", "description": "17-character Vehicle Identification Number"}, {"name": "decodeDate", "type": "date", "description": "Date when decoding occurred"}, {"name": "decodeSource", "type": "string", "description": "Origin data provider for decoding"}, {"name": "decodingConfidenceScore", "type": "decimal", "description": "A measure of the system''s confidence in the accuracy of the decoded data."}, {"name": "countryOfOrigin", "type": "string", "description": "Country where the vehicle was manufactured as derived from VIN."}, {"name": "vehicleModelYear", "type": "integer", "description": "The model year of the vehicle as decoded from its VIN."}]'::jsonb, '[{"type": "related", "label": "Provides details for option identification", "targetId": "custom-vehicle-valuation-and-analytics-vehicleoption"}, {"type": "related", "label": "Enables grade assignment based on build data", "targetId": "custom-vehicle-valuation-and-analytics-vehicleconditiongrade"}, {"type": "depends_on", "label": "Requires reference data source for VIN decoding logic", "targetId": "custom-data-information-dataasset"}, {"type": "related", "label": "Links decoded VIN to ownership events", "targetId": "custom-vehicle-valuation-and-analytics-ownershiphistory"}]'::jsonb, 'vehicledetails,vin,builddata,identification,regulatorycompliance,datavalidation,automotiveanalytics,assettracking'::text[], 'Accurate VIN decoding enables granular and VIN-specific valuation crucial for industry pricing accuracy.', '2026-03-11 14:46:26.325305', 'VIN Parsing,VIN Lookup'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "vinDecoding", "version": 1, "synonyms": ["VIN Parsing", "VIN Lookup"], "updatedAt": "2026-03-11T14:50:57.814Z", "properties": [{"name": "vin", "type": "string", "description": "17-character Vehicle Identification Number"}, {"name": "decodeDate", "type": "date", "description": "Date when decoding occurred"}, {"name": "decodeSource", "type": "string", "description": "Origin data provider for decoding"}], "description": "The process of extracting standardized vehicle information from the Vehicle Identification Number, providing detailed build and equipment data essential for precise valuation.", "relationships": [{"type": "related", "label": "Provides details for option identification", "targetId": "custom-vehicle-valuation-and-analytics-vehicleoption"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-vehicleoption', 'custom', 'Cross-Industry Ontology', 'vehicleOption', 'Vehicle Specification', 'The ''vehicleOption'' concept represents any feature, package, or add-on that can be configured or retrofitted into a vehicle, from advanced safety systems or luxury interior trims to technology upgrades and exclusive appearance packages. In custom AI agent operations, this concept is critical for precisely parsing, interpreting, and valuing the individual specifications that differentiate otherwise similar vehicles. AI agents leverage detailed vehicleOption data to power granular price evaluations, option-based market comparisons, residual value forecasts, and to identify trends in option popularity. Each option may have a direct or cascading effect on the vehicle’s value, insurability, and compliance with regulatory emissions or safety requirements. Effective handling of vehicleOption data allows AI agents to offer enriched, tailored, and regulatory-aligned valuation analytics.', '[{"name": "optionCode", "type": "string", "description": "Manufacturer’s code for the option"}, {"name": "optionDescription", "type": "string", "description": "Detailed description of the option"}, {"name": "msrpAdjustment", "type": "decimal", "description": "Price influence on MSRP"}, {"name": "optionCategory", "type": "string", "description": "Classifies the option type (e.g., safety, luxury, technology, performance)."}, {"name": "factoryInstalled", "type": "boolean", "description": "Indicates if the option was factory installed or added aftermarket."}, {"name": "optionEffectiveDate", "type": "date", "description": "Date when option became available for this vehicle model."}]'::jsonb, '[{"type": "parent", "label": "Sourced via VIN decoding", "targetId": "custom-vehicle-valuation-and-analytics-vindecoding"}, {"type": "depends_on", "label": "Adjusts the base price according to the vehicleOption", "targetId": "custom-f661aa43-413f-4dff-99f1-a76c78c0965a"}, {"type": "related", "label": "Drives adjustment factors in vehicle valuation", "targetId": "custom-vehicle-valuation-and-analytics-adjustmentfactor"}]'::jsonb, 'features,equipment,specs,optioncode,optiontype,installed,package,retrofit'::text[], 'Options materially affect valuation, insurance, and resale value across all automotive transactions.', '2026-03-11 14:46:26.375102', 'Factory Option,Feature Package'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "vehicleOption", "version": 1, "synonyms": ["Factory Option", "Feature Package"], "updatedAt": "2026-03-11T14:52:30.250Z", "properties": [{"name": "optionCode", "type": "string", "description": "Manufacturer’s code for the option"}, {"name": "optionDescription", "type": "string", "description": "Detailed description of the option"}, {"name": "msrpAdjustment", "type": "decimal", "description": "Price influence on MSRP"}], "description": "Represents specific features, packages, or add-ons present on a vehicle, which can impact its valuation significantly.", "relationships": [{"type": "parent", "label": "Sourced via VIN decoding", "targetId": "custom-vehicle-valuation-and-analytics-vindecoding"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-vehicleconditiongrade', 'custom', 'Cross-Industry Ontology', 'vehicleConditionGrade', 'Vehicle Specification', 'The ''vehicleConditionGrade'' is a critical standardized metric used to quantify the overall state of a vehicle, encompassing physical, mechanical, and aesthetic factors. In custom operations, this grade directly informs downstream processes such as automated valuation modeling, risk assessment, and decisioning for buy/sell recommendations. Use of a well-calibrated condition grade allows AI agents to uniformly compare vehicles, supporting consistent pricing and inventory classification across portfolios. Notably, the vehicleConditionGrade serves as a reference anchor when reconciling discrepancies between inspection data, historical usage, and market value projections. Integrating real-time updates to this grade enables proactive management of portfolio risk and operational efficiency.', '[{"name": "gradeValue", "type": "string", "description": "Assigned condition grade (e.g., 1.0-5.0)"}, {"name": "assessmentDate", "type": "date", "description": "Date of the grading assessment"}, {"name": "gradingAuthority", "type": "string", "description": "Name of the organization or individual responsible for assigning the grade"}, {"name": "gradeScaleUsed", "type": "string", "description": "The specific grading scale or methodology (e.g., NADA, Black Book, proprietary)"}, {"name": "previousGradeValue", "type": "string", "description": "The prior assigned grade before the latest assessment, if applicable"}]'::jsonb, '[{"type": "depends_on", "label": "Grading is determined by inspection results", "targetId": "inspectionReport"}, {"type": "related", "label": "Grade may be adjusted based on accident history", "targetId": "custom-vehicle-valuation-and-analytics-accidenthistoryadjustment"}, {"type": "related", "label": "Grade may reference odometer usage patterns", "targetId": "custom-vehicle-valuation-and-analytics-odometerhistory"}, {"type": "depends_on", "label": "For EVs, battery health may modify condition grade", "targetId": "custom-vehicle-valuation-and-analytics-batteryhealthscore"}]'::jsonb, 'condition,assessment,inspection,grading,valuation,risk-analysis,compliance,quality-control'::text[], 'Condition is pivotal for determining vehicle value in remarketing, lending, and resale scenarios.', '2026-03-11 14:46:26.421209', 'Condition Score,Inspection Grade'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "vehicleConditionGrade", "version": 1, "synonyms": ["Condition Score", "Inspection Grade"], "updatedAt": "2026-03-11T14:53:25.749Z", "properties": [{"name": "gradeValue", "type": "string", "description": "Assigned condition grade (e.g., 1.0-5.0)"}, {"name": "assessmentDate", "type": "date", "description": "Date of the grading assessment"}], "description": "Standardized rating representing the physical, mechanical, and aesthetic condition of a vehicle for use in valuation models.", "relationships": [{"type": "depends_on", "label": "Grading is determined by inspection results", "targetId": "inspectionReport"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-wholesalevalue', 'custom', 'Cross-Industry Ontology', 'wholesaleValue', 'Market Valuation', 'The ''wholesaleValue'' concept captures the real-time estimated price a dealer would pay to acquire a vehicle from another trusted source, such as another dealer or at auction. This metric is vital for market valuation strategies, providing a rapidly adjustable reference based on supply-demand dynamics, vehicle provenance, and physical attributes. In custom AI agent operations, this enables agents to automate pricing recommendations, dynamically monitor inventory valuation, and inform remarketing strategies based on near real-time analytics. Continuous integration with external market data feeds and internal vehicle history is essential for accurate wholesale valuation. This value serves as a benchmark for trade-in, auction-house listing, and dealer transfer pricing.', '[{"name": "value", "type": "decimal", "description": "Calculated wholesale value"}, {"name": "valuationDate", "type": "date", "description": "Date when value was estimated"}, {"name": "valuationMethod", "type": "string", "description": "The methodology or analytic model used for calculating the wholesale value"}, {"name": "marketRegion", "type": "string", "description": "Geographical region or market segment for which the value was estimated"}, {"name": "confidenceScore", "type": "decimal", "description": "Statistical confidence in the accuracy of the wholesale value estimate"}]'::jsonb, '[{"type": "depends_on", "label": "Impacted by market trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}, {"type": "depends_on", "label": "Determined by physical condition grading of the vehicle", "targetId": "custom-vehicle-valuation-and-analytics-vehicleconditiongrade"}, {"type": "depends_on", "label": "Calculation attributed to a specific data or analytics source", "targetId": "custom-vehicle-valuation-and-analytics-valuationsource"}, {"type": "related", "label": "Benchmarks against expected retail transaction values", "targetId": "custom-vehicle-valuation-and-analytics-retailvalue"}]'::jsonb, 'pricing,dealer,remarketing,auction,risk-insight,automation,valuation-model,market-data'::text[], 'Used by dealers, lenders, and fleet operators in trade, financing, and risk management.', '2026-03-11 14:46:26.466601', 'Trade Value,Auction Value'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "wholesaleValue", "version": 1, "synonyms": ["Trade Value", "Auction Value"], "updatedAt": "2026-03-11T14:54:47.299Z", "properties": [{"name": "value", "type": "decimal", "description": "Calculated wholesale value"}, {"name": "valuationDate", "type": "date", "description": "Date when value was estimated"}], "description": "The estimated price a dealer would pay to acquire a vehicle from another dealer or at auction, influenced by real-time supply, demand, and vehicle characteristics.", "relationships": [{"type": "depends_on", "label": "Impacted by market trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-retailvalue', 'custom', 'Cross-Industry Ontology', 'retailValue', 'Market Valuation', 'The ''retailValue'' concept specifies the typical market price at which a vehicle is publicly listed for sale, serving as a critical reference point for price benchmarking, negotiation, and valuation risk assessment. In custom operations, it enables AI agents to dynamically inform decision support systems, align pricing strategies with market realities, and perform competitor analysis. Accurate retail value determination is essential for both transparent customer interactions and internal financial reporting within the automotive market landscape. The concept further provides agents with a baseline to detect market anomalies and to adjust offers based on real-time supply and demand. Integrating this value into automated workflows ensures consistency in how vehicles are priced and presented to end-users.', '[{"name": "value", "type": "decimal", "description": "Calculated retail value"}, {"name": "valuationDate", "type": "date", "description": "Calculation date for retail value"}, {"name": "currencyCode", "type": "string", "description": "The ISO code for the currency in which the retail value is expressed"}, {"name": "confidenceScore", "type": "decimal", "description": "Quantitative confidence in the calculated retail value"}, {"name": "valuationSource", "type": "string", "description": "The system, entity, or data supplier that generated the retail value"}]'::jsonb, '[{"type": "related", "label": "Derived from market listings", "targetId": "listingData"}, {"type": "related", "label": "Influenced by prevailing market trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}, {"type": "related", "label": "Benchmarked against similar vehicles in a competitive set", "targetId": "custom-vehicle-valuation-and-analytics-competitiveset"}, {"type": "depends_on", "label": "Calculation depends on adjustment factors", "targetId": "custom-vehicle-valuation-and-analytics-adjustmentfactor"}]'::jsonb, 'retail,pricing,marketvalue,listings,transparency,benchmarking,vehiclepricing,auditability'::text[], 'Critical benchmark for consumers, dealers, and lenders setting pricing and making investment decisions.', '2026-03-11 14:46:26.512584', 'Retail Asking Price,Market Price'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "retailValue", "version": 1, "synonyms": ["Retail Asking Price", "Market Price"], "updatedAt": "2026-03-11T14:55:20.096Z", "properties": [{"name": "value", "type": "decimal", "description": "Calculated retail value"}, {"name": "valuationDate", "type": "date", "description": "Calculation date for retail value"}], "description": "The average market price at which a vehicle is listed for sale to consumers, reflecting current retail conditions and competitive landscape.", "relationships": [{"type": "related", "label": "Derived from market listings", "targetId": "listingData"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-residualvalueforecast', 'custom', 'Cross-Industry Ontology', 'residualValueForecast', 'Market Valuation', 'The ''residualValueForecast'' concept refers to the predictive estimation of a vehicle''s value at a specified future date, typically after a lease term or at the end of a fleet management contract. Accurate forecasting is crucial for setting lease payments, evaluating the Total Cost of Ownership, and managing risk exposure in vehicle portfolios. Custom operations integrating this concept may leverage machine learning models to refine estimates based on market trends, vehicle condition, and historical depreciation. This process ensures both lessors and lessees can make informed financial decisions and minimize unexpected losses. Integration into enterprise workflows improves the transparency and traceability of valuation assumptions.', '[{"name": "forecastValue", "type": "decimal", "description": "Projected future value"}, {"name": "forecastDate", "type": "date", "description": "Date of the forecast"}, {"name": "termMonths", "type": "integer", "description": "Number of months out for forecast"}, {"name": "confidenceInterval", "type": "decimal", "description": "Degree of statistical confidence in the forecasted value"}, {"name": "forecastSource", "type": "string", "description": "Reference or description of the data/model provider used for the forecast"}, {"name": "valuationCurrency", "type": "string", "description": "Currency in which the forecast value is expressed"}]'::jsonb, '[{"type": "depends_on", "label": "Forecast is calculated from depreciation model", "targetId": "depreciationCurve"}, {"type": "related", "label": "Forecast sensitivity to prevailing market trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}, {"type": "related", "label": "Forecast relies on external or authoritative valuation sources", "targetId": "custom-vehicle-valuation-and-analytics-valuationsource"}, {"type": "related", "label": "Forecast incorporates specific market or asset adjustment factors", "targetId": "custom-vehicle-valuation-and-analytics-adjustmentfactor"}]'::jsonb, 'leasing,fleet,projection,futurevalue,predictiveanalytics,riskmanagement,auditability,dataclassification'::text[], 'Essential for leasing, financing, and portfolio risk modeling across the auto industry.', '2026-03-11 14:46:26.558107', 'Projected Value,Lease-End Value'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "residualValueForecast", "version": 1, "synonyms": ["Projected Value", "Lease-End Value"], "updatedAt": "2026-03-11T14:55:52.380Z", "properties": [{"name": "forecastValue", "type": "decimal", "description": "Projected future value"}, {"name": "forecastDate", "type": "date", "description": "Date of the forecast"}, {"name": "termMonths", "type": "integer", "description": "Number of months out for forecast"}], "description": "Predictive estimate of a vehicle’s future value at a specified point in time, extensively used in lease and fleet planning.", "relationships": [{"type": "depends_on", "label": "Forecast is calculated from depreciation model", "targetId": "depreciationCurve"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-accidenthistoryadjustment', 'custom', 'Cross-Industry Ontology', 'accidentHistoryAdjustment', 'Vehicle History Analytics', 'The ''accidentHistoryAdjustment'' concept quantifies the reduction applied to a vehicle''s baseline valuation based on the record of past accidents, integrating objective damage assessments and market perception of diminished value. In custom AI agent operations, this adjustment is pivotal for ensuring precise, transparent, and real-time vehicle appraisals—especially in used car markets, insurance evaluations, and fleet management. Accurate representation of accident devaluation directly influences price negotiations, insurance premiums, and residual forecasting models. By standardizing how accident impacts are adjusted, organizations can eliminate subjectivity, reduce fraud, and enhance consumer trust. AI agents leveraging this concept can rapidly synthesize history data and calculate consistent adjustments across portfolios.', '[{"name": "adjustmentAmount", "type": "decimal", "description": "Dollar deduction due to accident history"}, {"name": "incidentDate", "type": "date", "description": "Date of the relevant accident"}, {"name": "adjustmentReason", "type": "string", "description": "Textual reason or code specifying what aspect of the accident most influenced the adjustment (e.g., frame damage, airbag deployment)."}, {"name": "valuationMethodology", "type": "string", "description": "Description or identifier of the methodology/model used to calculate the adjustment."}]'::jsonb, '[{"type": "depends_on", "label": "Derived from detailed history report", "targetId": "vehicleHistoryReport"}, {"type": "depends_on", "label": "Adjustment is influenced by overall vehicle condition grade", "targetId": "custom-vehicle-valuation-and-analytics-vehicleconditiongrade"}, {"type": "related", "label": "Adjustment impacts the residual value forecasting process", "targetId": "custom-vehicle-valuation-and-analytics-residualvalueforecast"}, {"type": "related", "label": "Uses standardized adjustment factors in calculation", "targetId": "custom-vehicle-valuation-and-analytics-adjustmentfactor"}]'::jsonb, 'diminishedvalue,history,damage,adjustment,valuation,compliance,insurance,transparency'::text[], 'Accident history significantly affects vehicle marketability and insurance, requiring accurate valuation adjustments.', '2026-03-11 14:46:26.603557', 'Damage Deduction,Condition Adjustment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "accidentHistoryAdjustment", "version": 1, "synonyms": ["Damage Deduction", "Condition Adjustment"], "updatedAt": "2026-03-11T14:58:23.164Z", "properties": [{"name": "adjustmentAmount", "type": "decimal", "description": "Dollar deduction due to accident history"}, {"name": "incidentDate", "type": "date", "description": "Date of the relevant accident"}], "description": "Adjustment applied to baseline vehicle valuation in recognition of past accidents, reflecting diminished value from damage history.", "relationships": [{"type": "depends_on", "label": "Derived from detailed history report", "targetId": "vehicleHistoryReport"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-ownershiphistory', 'custom', 'Cross-Industry Ontology', 'ownershipHistory', 'Vehicle History Analytics', 'The ownershipHistory concept catalogs all previous owners of a vehicle, noting whether their usage was personal, commercial, or rental, and summarizing patterns of title transfer. In custom AI agent operations, analyzing ownership history helps assess risk, depreciation, and expected maintenance by detecting high-frequency transfers, periods of intensive commercial use, or irregular ownership sequences. Ownership history is critical for determining how past owners’ behaviors influenced mechanical wear and for detecting potential odometer fraud by correlating with other vehicle events. Accurate ownershipHistory data enables more precise residual value forecasting, customized insurance products, and targeted marketing. In resale, it can also inform consumer trust and compliance with disclosure regulations.', '[{"name": "ownerCount", "type": "integer", "description": "Number of previous owners"}, {"name": "useCategory", "type": "enum", "description": "Nature of prior use (e.g., fleet, personal)"}, {"name": "ownerTypeDetail", "type": "string", "description": "Additional detail on each owner''s business area or personal status (e.g., government, corporation, individual)."}, {"name": "ownershipTransitionDates", "type": "string", "description": "List or range of dates corresponding to each change in ownership."}, {"name": "geographicalRegion", "type": "string", "description": "Region or country associated with each period of ownership, providing geo-context for market or regulatory analysis."}]'::jsonb, '[{"type": "related", "label": "Ownership period linked to mileage readings", "targetId": "custom-vehicle-valuation-and-analytics-odometerhistory"}, {"type": "related", "label": "Correlates historical ownership periods to accident events for risk profiling", "targetId": "custom-vehicle-valuation-and-analytics-accidenthistoryadjustment"}, {"type": "parent", "label": "Ownership history is managed as a governed data asset in enterprise catalogs", "targetId": "custom-data-information-dataasset"}]'::jsonb, 'owners,usehistory,provenance,history,titleTraceability,usageIntensity,compliance,vehicleAppraisal'::text[], 'Ownership profile influences trust, safety, and price for resale or purchase.', '2026-03-11 14:46:26.648771', 'Owner Chain,Previous Owners'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "ownershipHistory", "version": 1, "synonyms": ["Owner Chain", "Previous Owners"], "updatedAt": "2026-03-11T14:59:19.163Z", "properties": [{"name": "ownerCount", "type": "integer", "description": "Number of previous owners"}, {"name": "useCategory", "type": "enum", "description": "Nature of prior use (e.g., fleet, personal)"}], "description": "Summary of prior owners, including commercial, rental, or personal use, impacting value through wear, mileage, and maintenance patterns.", "relationships": [{"type": "related", "label": "Ownership period linked to mileage readings", "targetId": "custom-vehicle-valuation-and-analytics-odometerhistory"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-odometerhistory', 'custom', 'Cross-Industry Ontology', 'odometerHistory', 'Vehicle History Analytics', 'The odometerHistory concept provides a chronological record of mileage readings captured throughout a vehicle''s operational life. For custom operations, this data stream is integral to detecting mileage fraud, supporting reliable valuation, and analyzing wear-and-tear patterns. AI agents can automate anomaly detection, validate mileage claims in real time, and correlate mileage with maintenance schedules for predictive analytics. This log offers granular lifecycle insight, serving insurance, fleet management, and resale valuation scenarios. Ensuring the integrity and authenticity of this history is critical for operational trust across industry participants.', '[{"name": "mileageReading", "type": "integer", "description": "Mileage at recorded point"}, {"name": "readingDate", "type": "date", "description": "Date of odometer reading"}, {"name": "recordedBy", "type": "string", "description": "Indicates the entity or system responsible for capturing the odometer reading"}, {"name": "readingSource", "type": "enum", "description": "Specifies the method or device used for the odometer reading (e.g., dealer inspection, telematics, self-report)"}, {"name": "isVerified", "type": "boolean", "description": "Denotes whether the specific odometer reading has been independently verified"}]'::jsonb, '[{"type": "parent", "label": "Odometer readings by ownership segments", "targetId": "custom-vehicle-valuation-and-analytics-ownershiphistory"}, {"type": "related", "label": "Correlates vehicle mileage with battery health events for EV analytics", "targetId": "custom-vehicle-valuation-and-analytics-batteryhealthscore"}, {"type": "related", "label": "Feeds odometer readings into vehicle value prediction models", "targetId": "custom-vehicle-valuation-and-analytics-residualvalueforecast"}, {"type": "depends_on", "label": "Odometer readings depend on confirmed ownership transitions", "targetId": "custom-vehicle-valuation-and-analytics-ownershiphistory"}]'::jsonb, 'mileage,fraud,usage,historicaldata,tamperdetection,telematics,valueassessment,compliance,fleetanalytics'::text[], 'Ensures mileage integrity, supporting fraud prevention and accurate depreciation assessment.', '2026-03-11 14:46:26.694969', 'Mileage Log,Odo Reading'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "odometerHistory", "version": 1, "synonyms": ["Mileage Log", "Odo Reading"], "updatedAt": "2026-03-11T14:59:55.045Z", "properties": [{"name": "mileageReading", "type": "integer", "description": "Mileage at recorded point"}, {"name": "readingDate", "type": "date", "description": "Date of odometer reading"}], "description": "Chronological log of recorded mileage readings, essential for fraud detection, value estimation, and lifetime usage analytics.", "relationships": [{"type": "parent", "label": "Odometer readings by ownership segments", "targetId": "custom-vehicle-valuation-and-analytics-ownershiphistory"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-batteryhealthscore', 'custom', 'Cross-Industry Ontology', 'batteryHealthScore', 'Electric Vehicle (EV) Analytics', 'The batteryHealthScore provides a granular measurement of an EV’s battery state, incorporating parameters such as remaining capacity, number of charging cycles, efficiency, and results from diagnostic tests. This score enables transparent evaluation of battery performance and is crucial for resale valuation, warranty management, and predictive maintenance. AI agents can leverage this metric to forecast residual value, trigger battery service events, and inform consumers or fleet managers about necessary interventions. In the context of custom operations, integrating batteryHealthScore into analytics pipelines facilitates streamlining of fleet operations and enhances user trust in battery longevity estimates. It serves as an essential data point in end-to-end EV lifecycle management.', '[{"name": "score", "type": "decimal", "description": "Battery health on a normalized scale (e.g., 0-100)"}, {"name": "assessmentDate", "type": "date", "description": "Date battery was evaluated"}, {"name": "evaluationMethod", "type": "string", "description": "Description or identifier of the algorithm or process used to calculate the battery health score."}, {"name": "sourceSystem", "type": "string", "description": "Originating system or device that supplied the battery data for the assessment."}, {"name": "diagnosticFlags", "type": "string", "description": "List of diagnostic warnings or anomalies detected during the battery evaluation."}]'::jsonb, '[{"type": "related", "label": "Battery health impacts range", "targetId": "custom-vehicle-valuation-and-analytics-evrangeestimation"}, {"type": "child", "label": "Triggers battery replacement when healthScore falls below threshold", "targetId": "custom-vehicle-valuation-and-analytics-batteryreplacementevent"}, {"type": "related", "label": "Informs overall vehicle condition via battery health", "targetId": "custom-vehicle-valuation-and-analytics-vehicleconditiongrade"}, {"type": "depends_on", "label": "Battery health may degrade with increased mileage", "targetId": "custom-vehicle-valuation-and-analytics-odometerhistory"}]'::jsonb, 'ev,battery,healthcheck,capacity,diagnostics,maintenance,predictive,valuation,lifecycle'::text[], 'Battery performance is critical for EV residual values, lender risk, and buyer confidence.', '2026-03-11 14:46:26.740826', 'Battery Condition,State of Health (SoH)'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "batteryHealthScore", "version": 1, "synonyms": ["Battery Condition", "State of Health (SoH)"], "updatedAt": "2026-03-11T15:00:54.474Z", "properties": [{"name": "score", "type": "decimal", "description": "Battery health on a normalized scale (e.g., 0-100)"}, {"name": "assessmentDate", "type": "date", "description": "Date battery was evaluated"}], "description": "Quantitative assessment of an EV’s battery performance and longevity relative to new, factoring in capacity, charging cycles, and diagnostics.", "relationships": [{"type": "related", "label": "Battery health impacts range", "targetId": "custom-vehicle-valuation-and-analytics-evrangeestimation"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-evrangeestimation', 'custom', 'Cross-Industry Ontology', 'evRangeEstimation', 'Electric Vehicle (EV) Analytics', 'evRangeEstimation refers to the process of calculating a data-driven forecast of how far an electric vehicle (EV) can travel on a single charge, considering not only current battery health but also environmental variables such as temperature, terrain, and driver behavior captured from historic usage data. In custom operations, this concept enables dynamic range prediction for fleet optimization, resale valuation accuracy, and personalized range alerts to enhance user experience. AI agents can refine these estimates with real-time sensor data, delivering granular insights per individual vehicle or aggregated fleet. This concept is particularly crucial for designing EV-specific business processes around lease, resale, and usage-based insurance offerings. Accurate evRangeEstimation supports operational decisions such as charging, routing, and vehicle maintenance scheduling.', '[{"name": "estimatedRange", "type": "integer", "description": "Estimated miles/kilometers per full charge"}, {"name": "estimationMethod", "type": "string", "description": "Method or algorithm used"}, {"name": "rangeConfidenceInterval", "type": "decimal", "description": "Confidence interval expressing estimation uncertainty"}, {"name": "timestamp", "type": "date", "description": "Date and time when the range estimation was performed"}, {"name": "environmentalConditions", "type": "string", "description": "Key environmental parameters (e.g., temperature, terrain) factored into estimation"}]'::jsonb, '[{"type": "depends_on", "label": "Range is a function of battery health", "targetId": "custom-vehicle-valuation-and-analytics-batteryhealthscore"}, {"type": "depends_on", "label": "Historic usage data informs range estimation", "targetId": "custom-vehicle-valuation-and-analytics-odometerhistory"}, {"type": "depends_on", "label": "Range estimation accuracy may depend on battery replacement history", "targetId": "custom-vehicle-valuation-and-analytics-batteryreplacementevent"}, {"type": "depends_on", "label": "Estimation powered by advanced analytics models", "targetId": "custom-performance-analytics-analyticsmodel"}]'::jsonb, 'ev,range,distance,estimation,telematics,batteryanalytics,predictivemaintenance,fleetmanagement'::text[], 'Range is key for purchase decisions, lease valuations, and warranty claims in the EV sector.', '2026-03-11 14:46:26.786402', 'Range Prediction,Battery Range'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "evRangeEstimation", "version": 1, "synonyms": ["Range Prediction", "Battery Range"], "updatedAt": "2026-03-11T15:01:33.978Z", "properties": [{"name": "estimatedRange", "type": "integer", "description": "Estimated miles/kilometers per full charge"}, {"name": "estimationMethod", "type": "string", "description": "Method or algorithm used"}], "description": "Data-driven estimate of an electric vehicle’s usable driving range based on battery health, environmental, and historic usage data.", "relationships": [{"type": "depends_on", "label": "Range is a function of battery health", "targetId": "custom-vehicle-valuation-and-analytics-batteryhealthscore"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-batteryreplacementevent', 'custom', 'Cross-Industry Ontology', 'batteryReplacementEvent', 'Electric Vehicle (EV) Analytics', 'A batteryReplacementEvent captures the specifics of an EV battery replacement, specifying whether the replacement was full or partial and on what date it occurred. This event directly impacts vehicle value, warranty status, and projected future performance or range, making it vital for analytics, resale evaluation, and operational maintenance planning. Tracking these events helps custom AI agents to provide more accurate vehicle valuations, maintenance predictions, and warranty eligibility assessments. In addition, linking battery replacements to shifts in battery health metrics supports the diagnosis of anomalies or patterns across fleets. Such granular historical data enhances transparency for buyers, regulators, and fleet managers.', '[{"name": "replacementDate", "type": "date", "description": "When the battery was replaced"}, {"name": "replacementType", "type": "enum", "description": "Full vs partial replacement"}, {"name": "serviceProvider", "type": "string", "description": "Entity or service center that performed the battery replacement."}, {"name": "replacedBatterySerialNumber", "type": "string", "description": "Unique identifier of the battery removed during the replacement event."}, {"name": "replacementReason", "type": "enum", "description": "Specifies why the battery was replaced (e.g. degradation, defect, upgrade, recall)."}]'::jsonb, '[{"type": "related", "label": "Replacement resets battery health", "targetId": "custom-vehicle-valuation-and-analytics-batteryhealthscore"}, {"type": "depends_on", "label": "Links to odometer history at time of replacement", "targetId": "custom-vehicle-valuation-and-analytics-odometerhistory"}, {"type": "related", "label": "Relevant to ownership chain and disclosures", "targetId": "custom-vehicle-valuation-and-analytics-ownershiphistory"}, {"type": "related", "label": "Directly influences future value estimation", "targetId": "custom-vehicle-valuation-and-analytics-residualvalueforecast"}]'::jsonb, 'ev,maintenance,battery,history,lifecycle,serviceRecord,warranty,compliance'::text[], 'Battery replacements can restore EV value and are a key consideration in market and insurance analytics.', '2026-03-11 14:46:26.832028', 'Battery Swap,BatteryServiceEvent'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "batteryReplacementEvent", "version": 1, "synonyms": ["Battery Swap", "BatteryServiceEvent"], "updatedAt": "2026-03-11T15:03:23.601Z", "properties": [{"name": "replacementDate", "type": "date", "description": "When the battery was replaced"}, {"name": "replacementType", "type": "enum", "description": "Full vs partial replacement"}], "description": "Historical record detailing complete or partial EV battery replacement, directly influencing vehicle value and warranty.", "relationships": [{"type": "related", "label": "Replacement resets battery health", "targetId": "custom-vehicle-valuation-and-analytics-batteryhealthscore"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-markettrend', 'custom', 'Cross-Industry Ontology', 'marketTrend', 'Market Trend Intelligence', 'The ''marketTrend'' concept in the context of custom operations involves the systematic identification and interpretation of significant changes in supply, demand, and pricing metrics across various vehicle segments, models, or geographical regions. This concept helps organizations anticipate market fluctuations and tailor strategies in real-time, optimizing inventory levels, pricing schemes, and marketing initiatives to stay ahead of competitors. Leveraging advanced analytics and AI, marketTrend enables dynamic scenario analysis and forecasting, directly supporting operational decision-making. Its granular, data-driven insights are crucial for maximizing revenue and mitigating risks associated with volatile market conditions. Ultimately, marketTrend forms the backbone of market intelligence by transforming raw data into actionable strategic knowledge for stakeholders.', '[{"name": "trendType", "type": "string", "description": "E.g., price increase, supply shortage"}, {"name": "trendPeriod", "type": "string", "description": "Relevant time window (e.g., Q1 2024)"}, {"name": "confidenceScore", "type": "decimal", "description": "Degree of confidence or reliability associated with the detected trend"}, {"name": "dataSource", "type": "string", "description": "Primary source(s) used for deriving the market trend"}, {"name": "impactLevel", "type": "enum", "description": "Estimated impact of the trend (e.g., high, medium, low) on business outcomes"}]'::jsonb, '[{"type": "related", "label": "Trends influenced by market events", "targetId": "custom-vehicle-valuation-and-analytics-marketevent"}, {"type": "depends_on", "label": "Derived using analytics models", "targetId": "custom-performance-analytics-analyticsmodel"}, {"type": "related", "label": "Benchmarked against competitive set", "targetId": "custom-vehicle-valuation-and-analytics-competitiveset"}, {"type": "child", "label": "Impacts residual value forecasts", "targetId": "custom-vehicle-valuation-and-analytics-residualvalueforecast"}]'::jsonb, 'marketintelligence,trend,analytics,forecast,marketdynamics,pricingintelligence,demandforecast,supplychain,competitivemonitoring'::text[], 'Drives strategic pricing, stocking, and investment decisions for all automotive market stakeholders.', '2026-03-11 14:46:26.877423', 'Market Shift,Pricing Trend'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "marketTrend", "version": 1, "synonyms": ["Market Shift", "Pricing Trend"], "updatedAt": "2026-03-11T15:05:33.647Z", "properties": [{"name": "trendType", "type": "string", "description": "E.g., price increase, supply shortage"}, {"name": "trendPeriod", "type": "string", "description": "Relevant time window (e.g., Q1 2024)"}], "description": "Analysis of shifts in supply, demand, and pricing at vehicle segment, model, or region level, supporting forecasting and strategic decisions.", "relationships": [{"type": "related", "label": "Trends influenced by market events", "targetId": "custom-vehicle-valuation-and-analytics-marketevent"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-marketevent', 'custom', 'Cross-Industry Ontology', 'marketEvent', 'Market Trend Intelligence', 'A marketEvent represents any significant occurrence that can influence vehicle pricing and valuation, such as regulatory changes, supply-chain disruptions, or product recalls. In the context of custom operations, tracking market events is critical for robust pricing analytics, as these events often signal anticipated or real-time impacts to market behavior. Accurate and timely detection and classification of such events can provide competitive advantages by supporting instant model adjustments or responsive operational decision-making. Market events also drive the generation of market trends, supporting proactive scenario analyses. Ensuring this concept is well-integrated within AI agents is essential for automating the assessment of event-driven risks and opportunities within the automotive domain.', '[{"name": "eventType", "type": "string", "description": "Nature of event (e.g., recall, tariff)"}, {"name": "eventDate", "type": "date", "description": "Date event occurred"}, {"name": "eventImpactLevel", "type": "enum", "description": "Severity or expected business impact of the event (e.g., high, medium, low)"}, {"name": "sourceSystem", "type": "string", "description": "System or authority where the event data originated"}, {"name": "affectedMarkets", "type": "string", "description": "List of geographic or market segments directly impacted by the event"}]'::jsonb, '[{"type": "child", "label": "Market events drive trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}, {"type": "child", "label": "This event introduces or modifies a business risk", "targetId": "custom-risk-compliance-risk"}, {"type": "depends_on", "label": "This market event triggers compliance requirement reviews", "targetId": "custom-risk-compliance-compliancerequirement"}]'::jsonb, 'event,impact,trenddriver,market,regulatory,valuation-impact,supplychain,recalibration,event-detection'::text[], 'Timely market event data strengthens risk modeling, forecasting, and pricing agility.', '2026-03-11 14:46:26.923119', 'Market Disruption,External Event'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "marketEvent", "version": 1, "synonyms": ["Market Disruption", "External Event"], "updatedAt": "2026-03-11T15:06:03.975Z", "properties": [{"name": "eventType", "type": "string", "description": "Nature of event (e.g., recall, tariff)"}, {"name": "eventDate", "type": "date", "description": "Date event occurred"}], "description": "Discrete occurrences (e.g., regulatory changes, supply chain interruptions) that impact vehicle pricing and valuation analytics.", "relationships": [{"type": "child", "label": "Market events drive trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-competitiveset', 'custom', 'Cross-Industry Ontology', 'competitiveSet', 'Market Trend Intelligence', 'The ''competitiveSet'' concept represents a curated group of vehicles that are considered each other''s direct competitors in the marketplace. In custom operations, it is vital for benchmarking individual model valuations, pricing strategies, and assessing the impact of market movements on relative performance. Accurate definition and maintenance of competitive sets enable AI-driven comparative analytics, trend detection, and automated reporting for pricing or marketing strategies. Agents can dynamically adjust competitive sets based on new entrants, exits, or significant model changes to ensure contemporaneous market relevance. This automated, granular benchmarking is essential for improving decision quality and responding rapidly to market forces.', '[{"name": "setName", "type": "string", "description": "Name for the competitive group"}, {"name": "modelCount", "type": "integer", "description": "Number of models in the competitive set"}, {"name": "lastUpdatedDate", "type": "date", "description": "Timestamp of the last update to the competitive set composition"}, {"name": "compositionCriteria", "type": "string", "description": "Rules or logic used to define or update competitive set membership"}, {"name": "marketSegment", "type": "string", "description": "Market segment or category addressed by this competitive set"}]'::jsonb, '[{"type": "related", "label": "Benchmarks value against peer group", "targetId": "custom-vehicle-valuation-and-analytics-retailvalue"}, {"type": "depends_on", "label": "Competitive set definition influenced by market trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}, {"type": "related", "label": "Competitive set serves as a benchmarking basis", "targetId": "custom-performance-analytics-benchmark"}]'::jsonb, 'benchmark,marketcomparison,competition,vehiclegroup,pricingintelligence,auditing,dynamicsegmentation,marketentry,peeranalysis'::text[], 'Comparison with competitive sets informs pricing, positioning, and residuals forecasting.', '2026-03-11 14:46:26.968854', 'Comp Set,Peer Group'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "competitiveSet", "version": 1, "synonyms": ["Comp Set", "Peer Group"], "updatedAt": "2026-03-11T15:07:12.639Z", "properties": [{"name": "setName", "type": "string", "description": "Name for the competitive group"}, {"name": "modelCount", "type": "integer", "description": "Number of models in the competitive set"}], "description": "Group of vehicles considered direct competitors, used to benchmark valuations and analyze relative market performance.", "relationships": [{"type": "related", "label": "Benchmarks value against peer group", "targetId": "custom-vehicle-valuation-and-analytics-retailvalue"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-valuationsource', 'custom', 'Cross-Industry Ontology', 'valuationSource', 'Valuation Methodology & Governance', 'The concept of ''valuationSource'' specifies the precise origin from which a vehicle’s valuation estimate is derived, such as a proprietary pricing algorithm, expert appraiser, or extensive market survey. In the context of custom operations, this concept enables traceability and justifies valuation outcomes for both internal governance and client reporting. It is critical for ensuring transparency in valuation workflows and for selecting or benchmarking amongst competing sources. Accurately referencing a valuationSource also aids in validating AI-driven valuations against regulatory or industry standards. For AI agents, this concept allows the systematic comparison, documentation, and audibility of vehicle valuations, fostering trust in automated processes.', '[{"name": "sourceType", "type": "string", "description": "Nature of source (e.g., algorithm, expert)"}, {"name": "sourceName", "type": "string", "description": "Name of methodology or provider"}, {"name": "lastValidationDate", "type": "date", "description": "Date when the valuation source was last validated or reviewed for accuracy."}, {"name": "regulatoryApprovalStatus", "type": "enum", "description": "Indicates whether the valuation source is approved by relevant governance bodies."}, {"name": "confidenceScore", "type": "decimal", "description": "A quantitative measure representing the confidence or reliability of this valuation source."}]'::jsonb, '[{"type": "parent", "label": "Provides value estimates", "targetId": "custom-vehicle-valuation-and-analytics-wholesalevalue"}, {"type": "related", "label": "Utilizes the analytics model for estimating values", "targetId": "custom-performance-analytics-analyticsmodel"}, {"type": "depends_on", "label": "Benchmarked against standard reference values", "targetId": "custom-performance-analytics-benchmark"}, {"type": "parent", "label": "Records provenance as a documented data asset", "targetId": "custom-data-information-dataasset"}]'::jsonb, 'methodology,source,provenance,valuation,traceability,audit,model risk,external data'::text[], 'Transparency in source boosts confidence in valuation accuracy for all market actors.', '2026-03-11 14:46:27.014303', 'Valuation Method,Pricing Source'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "valuationSource", "version": 1, "synonyms": ["Valuation Method", "Pricing Source"], "updatedAt": "2026-03-11T15:08:03.123Z", "properties": [{"name": "sourceType", "type": "string", "description": "Nature of source (e.g., algorithm, expert)"}, {"name": "sourceName", "type": "string", "description": "Name of methodology or provider"}], "description": "Identifies the origin or method of a vehicle’s valuation estimate, including proprietary algorithms, market surveys, or expert appraisals.", "relationships": [{"type": "parent", "label": "Provides value estimates", "targetId": "custom-vehicle-valuation-and-analytics-wholesalevalue"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-adjustmentfactor', 'custom', 'Cross-Industry Ontology', 'adjustmentFactor', 'Valuation Methodology & Governance', 'The adjustmentFactor represents a quantitative adjustment applied to the base value of a vehicle to account for regional, seasonal, mileage, or condition-specific variations. It ensures that vehicle valuations reflect localized market dynamics and asset characteristics, supporting fair and accurate pricing. In custom operations, this concept allows AI agents to finely tune valuations in near real-time, adapting to new information or regulatory requirements. Accurate tracking and application of adjustment factors are critical both for end-consumer fairness and for enterprise risk management. Consistency in applying these factors underpins auditability and regulatory scrutiny.', '[{"name": "factorType", "type": "string", "description": "E.g., regional, mileage, seasonal"}, {"name": "factorValue", "type": "decimal", "description": "Multiplier or dollar value to apply"}, {"name": "effectiveDate", "type": "date", "description": "The date when the adjustment factor becomes applicable."}, {"name": "sourceReference", "type": "string", "description": "Citation or link to the source data or authority for the adjustment factor."}, {"name": "justification", "type": "string", "description": "Rationale or business rule behind this factor''s derivation."}]'::jsonb, '[{"type": "depends_on", "label": "Adjusts value based on conditional grade", "targetId": "custom-vehicle-valuation-and-analytics-vehicleconditiongrade"}, {"type": "depends_on", "label": "Adjustment factor calculation based on prevailing market trends", "targetId": "custom-vehicle-valuation-and-analytics-markettrend"}, {"type": "related", "label": "Directly modifies computed wholesale vehicle value", "targetId": "custom-vehicle-valuation-and-analytics-wholesalevalue"}, {"type": "related", "label": "Directly impacts computed retail vehicle value", "targetId": "custom-vehicle-valuation-and-analytics-retailvalue"}]'::jsonb, 'adjustment,modifier,localization,factor,priceAdjustment,valuationCorrection,compliance,auditability'::text[], 'Essential for tailoring vehicle valuations to local, conditional, or special factors.', '2026-03-11 14:46:27.060224', 'Adjustment Multiplier,Value Modifier'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "adjustmentFactor", "version": 1, "synonyms": ["Adjustment Multiplier", "Value Modifier"], "updatedAt": "2026-03-11T15:08:40.070Z", "properties": [{"name": "factorType", "type": "string", "description": "E.g., regional, mileage, seasonal"}, {"name": "factorValue", "type": "decimal", "description": "Multiplier or dollar value to apply"}], "description": "Published multiplier or deduction applied to base vehicle value for region, seasonality, mileage, or condition, supporting accurate localization.", "relationships": [{"type": "depends_on", "label": "Adjusts value based on conditional grade", "targetId": "custom-vehicle-valuation-and-analytics-vehicleconditiongrade"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-vehicle-valuation-and-analytics-governancecommittee', 'custom', 'Cross-Industry Ontology', 'governanceCommittee', 'Valuation Methodology & Governance', 'A governanceCommittee plays a pivotal role in the oversight of valuation methodologies within an organization. This committee is tasked with establishing, reviewing, and approving policies and models to ensure consistency, transparency, and accuracy in valuations. It acts as a safeguard for aligning methodologies with best practices and ongoing regulatory requirements, often serving as the final arbiter before valuation approaches are adopted or modified. Custom AI agents can assist the committee by automating document tracking, performing regulatory checks, and providing audit trails of valuation methodology changes. Effective governance enhances organizational accountability and fosters stakeholder trust in valuation outcomes.', '[{"name": "committeeName", "type": "string", "description": "Official name of the committee"}, {"name": "lastReviewDate", "type": "date", "description": "Last date of policy or model review"}, {"name": "memberCount", "type": "integer", "description": "Number of members currently serving on the committee"}, {"name": "committeeCharterURL", "type": "string", "description": "Reference link to the official committee charter or terms of reference"}, {"name": "reviewFrequency", "type": "string", "description": "Planned frequency for conducting reviews (e.g., quarterly, annually)"}]'::jsonb, '[{"type": "related", "label": "Oversees the use of valuation sources", "targetId": "custom-vehicle-valuation-and-analytics-valuationsource"}, {"type": "related", "label": "Utilizes defined escalation path for unresolved valuation disputes", "targetId": "custom-0dc3e97d-0beb-451d-b3c7-2d0952479a81"}, {"type": "parent", "label": "Reports to relevant organizational unit", "targetId": "custom-entity-management-organizationalunit"}, {"type": "related", "label": "Ensures adherence to specified compliance requirements", "targetId": "custom-risk-compliance-compliancerequirement"}]'::jsonb, 'oversight,methodology,compliance,governance,riskManagement,audit,transparency,valuationOversight'::text[], 'Institutes procedural rigor and market trust in valuation data and analytics processes.', '2026-03-11 14:46:27.105644', 'Valuation Board,Pricing Review Committee'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "governanceCommittee", "version": 1, "synonyms": ["Valuation Board", "Pricing Review Committee"], "updatedAt": "2026-03-11T15:09:11.491Z", "properties": [{"name": "committeeName", "type": "string", "description": "Official name of the committee"}, {"name": "lastReviewDate", "type": "date", "description": "Last date of policy or model review"}], "description": "Established group responsible for overseeing valuation methodologies, ensuring quality, transparency, and regulatory compliance.", "relationships": [{"type": "related", "label": "Oversees the use of valuation sources", "targetId": "custom-vehicle-valuation-and-analytics-valuationsource"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-partnumber', 'custom', 'Cross-Industry Ontology', 'partNumber', 'Component Identification', 'The ''partNumber'' concept refers to a manufacturer- or distributor-assigned code that uniquely identifies a specific automotive part. In custom AI-driven operations, this identifier is essential for automating precise part lookup, streamlining cross-market interchange, and validating parts in complex repair scenarios. AI agents leverage part numbers to reconcile supply chain records, integrate inventory across disparate channels, and standardize part references, reducing risks of misidentification. Automated workflows use the partNumber for compatibility checks, maintenance scheduling, and supporting warranty claims management. The robust assignment and handling of part numbers underpin traceable, interoperable custom operations across the automotive supply chain.', '[{"name": "number", "type": "string", "description": "Alphanumeric identifier assigned to the part"}, {"name": "issuingOrganization", "type": "string", "description": "Entity who issued or maintains the part number"}, {"name": "partType", "type": "string", "description": "General type/category of the part"}, {"name": "dateAssigned", "type": "date", "description": "Date the partNumber was assigned to the part."}, {"name": "version", "type": "string", "description": "Revision or version of the partNumber for tracking updates or supersessions."}, {"name": "superseded", "type": "boolean", "description": "Indicates whether this partNumber has been replaced by a newer identifier."}]'::jsonb, '[{"type": "depends_on", "label": "Part number is assigned according to OEM coverage", "targetId": "custom-automotive-parts-and-repair-data-oemcoverage"}, {"type": "related", "label": "Maps to equivalent part numbers in interchange catalogues", "targetId": "custom-automotive-parts-and-repair-data-interchangenumber"}, {"type": "parent", "label": "Part of a defined product entity", "targetId": "custom-product-service-product"}, {"type": "related", "label": "Included in the Bill of Materials for assemblies", "targetId": "custom-578980df-7123-44b3-b9e2-ff0d608bbff0"}]'::jsonb, 'classification,identification,lookup,catalog,traceability,recall-management,supply-chain,inventory-control'::text[], 'Part numbers are foundational to parts cataloging, interchange, ordering, and warranty tracking in all automotive domains.', '2026-03-11 15:12:06.223809', 'catalogNumber,OE number,PN'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "partNumber", "version": 1, "synonyms": ["catalogNumber", "OE number", "PN"], "updatedAt": "2026-03-11T15:14:12.711Z", "properties": [{"name": "number", "type": "string", "description": "Alphanumeric identifier assigned to the part"}, {"name": "issuingOrganization", "type": "string", "description": "Entity who issued or maintains the part number"}, {"name": "partType", "type": "string", "description": "General type/category of the part"}], "description": "A unique identifier assigned to a specific automotive part by the manufacturer or distributor for cataloguing, ordering, and inventory management. Essential for accurate part lookup and interchange across markets.", "relationships": [{"type": "depends_on", "label": "Part number is assigned according to OEM coverage", "targetId": "custom-automotive-parts-and-repair-data-oemcoverage"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-interchangenumber', 'custom', 'Cross-Industry Ontology', 'interchangeNumber', 'Component Identification', 'The interchangeNumber serves as a critical cross-reference identifier, enabling seamless mapping between equivalent or superseded part numbers among different manufacturers, suppliers, or standards in complex parts ecosystems. In custom operations, AI agents use interchangeNumbers to ensure accurate part selection, replacement compatibility, and inventory synchronization across varying catalogs, significantly enhancing supply chain efficiency. Lack of proper interchange management can cause costly delays, part mismatches, and customer dissatisfaction due to incompatible replacements. Smart agents automating parts sourcing and replacement workflows rely on interchangeNumbers for instant equivalence checks and dynamic sourcing. This process supports lifecycle management, enabling traceability of parts throughout maintenance, repair, and replacement scenarios.', '[{"name": "interchangeId", "type": "string", "description": "Interchange reference code or identifier"}, {"name": "sourceSystem", "type": "string", "description": "Catalog or interchange database source"}, {"name": "validityPeriod", "type": "date", "description": "The date range during which the interchangeNumber mapping is effective."}, {"name": "confidenceScore", "type": "decimal", "description": "Confidence level in the accuracy of the interchange mapping (0 to 1 scale)."}, {"name": "mappingType", "type": "enum", "description": "Classification of mapping type (e.g., direct, superseded, equivalent)."}]'::jsonb, '[{"type": "related", "label": "References equivalent or superseded part numbers", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Tracks sequences of superseded part numbers for lifecycle traceability", "targetId": "custom-automotive-parts-and-repair-data-supersessionchain"}, {"type": "related", "label": "Connects interchangeNumber to assemblies using the part in different configurations", "targetId": "custom-578980df-7123-44b3-b9e2-ff0d608bbff0"}, {"type": "depends_on", "label": "Relies on detailed part attributes to confirm compatibility across mappings", "targetId": "custom-automotive-parts-and-repair-data-partattribute"}]'::jsonb, 'cross-reference,alternative,compatibility,traceability,inventory-management,replacement,catalog-integration'::text[], 'Enables supply chain flexibility, accurate substitutions, and efficient inventory management.', '2026-03-11 15:12:06.268703', 'crossNumber,equivalentPart'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "interchangeNumber", "version": 1, "synonyms": ["crossNumber", "equivalentPart"], "updatedAt": "2026-03-11T15:15:04.342Z", "properties": [{"name": "interchangeId", "type": "string", "description": "Interchange reference code or identifier"}, {"name": "sourceSystem", "type": "string", "description": "Catalog or interchange database source"}], "description": "A cross-reference identifier that maps to equivalent or superseded part numbers across different brands, suppliers, or replacement standards. Supports cross-brand compatibility.", "relationships": [{"type": "related", "label": "References equivalent or superseded part numbers", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-oemcoverage', 'custom', 'Cross-Industry Ontology', 'oemCoverage', 'Component Identification', 'The ''oemCoverage'' concept details the specific applications and vehicle configurations validated by the original equipment manufacturer for a part''s fitment. It ensures that only compatible components are deployed during part replacements or repairs, reducing the risk of misfit and operational failures. In the context of custom operations, accurate OEM coverage enables AI agents to automate part selection, optimize inventory, and ensure compliance with manufacturer specifications. This data is also crucial for providing precise recommendations in service operations and for warranty and recall management. Extensive validation of oemCoverage prevents improper installations and ensures downstream process reliability.', '[{"name": "oemId", "type": "string", "description": "OEM brand or identifier"}, {"name": "modelList", "type": "string", "description": "Supported OEM models or platforms"}, {"name": "fitmentNotes", "type": "string", "description": "Detailed notes regarding exceptions or clarifications for fitment use."}, {"name": "approvalDate", "type": "date", "description": "The effective date when the part was approved for OEM coverage."}, {"name": "expiryDate", "type": "date", "description": "The expiration date for this OEM coverage, if applicable."}]'::jsonb, '[{"type": "parent", "label": "Coverage assigned to specific part numbers", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Linked recall campaigns for affected OEM coverage", "targetId": "custom-automotive-parts-and-repair-data-recallcampaign"}, {"type": "depends_on", "label": "Fitment validation depends on accurate VIN decoding", "targetId": "custom-vehicle-valuation-and-analytics-vindecoding"}, {"type": "child", "label": "Defines warranty coverage based on OEM application", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}]'::jsonb, 'fitment,oem,application,coverage,validation,traceability,compliance,recall,warranty'::text[], 'Crucial for assuring part compatibility and reducing returns due to fitment errors.', '2026-03-11 15:12:06.312778', 'applicationCoverage,OEM fitment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "oemCoverage", "version": 1, "synonyms": ["applicationCoverage", "OEM fitment"], "updatedAt": "2026-03-11T15:16:53.316Z", "properties": [{"name": "oemId", "type": "string", "description": "OEM brand or identifier"}, {"name": "modelList", "type": "string", "description": "Supported OEM models or platforms"}], "description": "Defines the original equipment manufacturer (OEM) applications and vehicle configurations for which a part is approved or fits. Used for ensuring proper fitment.", "relationships": [{"type": "parent", "label": "Coverage assigned to specific part numbers", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-supersessionchain', 'custom', 'Cross-Industry Ontology', 'supersessionChain', 'Component Identification', 'The supersessionChain concept captures a detailed, auditable timeline of part number replacements, documenting each transition as components are upgraded, discontinued, or substituted based on engineering directives or supply chain optimizations. This information is essential for custom AI agents tasked with maintaining up-to-date inventory accuracy, enabling automated repair planning, and optimizing procurement decisions. The chronological nature of supersession chains eliminates ambiguity concerning which part should be used, stocked, or ordered for a particular repair job. Furthermore, this concept provides traceability links critical for recalls, warranty validation, and backward compatibility checks. Supersession chains help reduce overstocking of obsolete items and prevent installation of incorrect or non-compliant parts.', '[{"name": "sequenceOrder", "type": "integer", "description": "Order of supersession change"}, {"name": "effectiveDate", "type": "date", "description": "Date the supersession occurred"}, {"name": "reasonForSupersession", "type": "string", "description": "Primary business, engineering, or compliance reason for part replacement."}, {"name": "initiatedBy", "type": "string", "description": "Name or role of organization/entity responsible for initiating the supersession."}, {"name": "isActive", "type": "boolean", "description": "Indicates if the current link in the chain is the part currently in use."}]'::jsonb, '[{"type": "child", "label": "Connects to part numbers in the supersession sequence", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Connects the supersession chain to affected assemblies", "targetId": "custom-578980df-7123-44b3-b9e2-ff0d608bbff0"}, {"type": "related", "label": "References the organizational or regulatory policy for part replacement", "targetId": "custom-automotive-parts-and-repair-data-replacementpolicy"}]'::jsonb, 'supersession,update,replacement,change,traceability,recall,billOfMaterials,inventoryOptimization,regulatoryAudit'::text[], 'Prevents obsolete part use, reduces inventory bloat, and supports repair accuracy.', '2026-03-11 15:12:06.357318', 'supersedeChain,replacementHistory'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "supersessionChain", "version": 1, "synonyms": ["supersedeChain", "replacementHistory"], "updatedAt": "2026-03-11T15:17:31.527Z", "properties": [{"name": "sequenceOrder", "type": "integer", "description": "Order of supersession change"}, {"name": "effectiveDate", "type": "date", "description": "Date the supersession occurred"}], "description": "Chronological sequence documenting how part numbers are replaced (superseded) due to engineering or supply changes. Vital for proper repairs and inventory reduction.", "relationships": [{"type": "child", "label": "Connects to part numbers in the supersession sequence", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-partattribute', 'custom', 'Cross-Industry Ontology', 'partAttribute', 'Part Attributes and Specifications', 'A partAttribute captures critical technical properties that define and differentiate physical components in manufacturing, automotive, and other engineering contexts. These attributes allow AI agents to accurately identify substitutions, verify engineering compatibility, and ensure traceability throughout the supply chain. When integrated into custom operations, partAttribute supports dynamic selection, validation, and performance tracking of components. It also enables comparative analysis across products for optimization and compliance. Comprehensive management of partAttribute ensures that changes in technical parameters are recorded and accessible for downstream workflows such as repair, maintenance, and regulatory reporting.', '[{"name": "attributeName", "type": "string", "description": "Name of the technical attribute"}, {"name": "value", "type": "string", "description": "Attribute value for the part"}, {"name": "unitOfMeasure", "type": "string", "description": "Measurement unit (e.g., mm, kg)"}, {"name": "attributeSource", "type": "string", "description": "Indicates whether the attribute is manufacturer-supplied, engineering-derived, or third-party certified"}, {"name": "attributeStatus", "type": "enum", "description": "Tracks if the attribute is provisional, validated, or obsolete"}, {"name": "certificationReference", "type": "string", "description": "Links the attribute to any certification or standards document"}]'::jsonb, '[{"type": "parent", "label": "Attributes describe physical/functional nature of parts", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Attribute required for bill of materials definitions", "targetId": "custom-578980df-7123-44b3-b9e2-ff0d608bbff0"}, {"type": "related", "label": "Informs attribute-specific repair guidelines", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}, {"type": "related", "label": "Attribute tracked across part supersession events", "targetId": "custom-automotive-parts-and-repair-data-supersessionchain"}]'::jsonb, 'attribute,specification,engineering,description,traceability,qualityAssurance,partsOptimization,SOPCompliance'::text[], 'Supports accurate fit, performance, and interchange decisions across catalogs and supply chains.', '2026-03-11 15:12:06.401578', 'characteristic,spec'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "partAttribute", "version": 1, "synonyms": ["characteristic", "spec"], "updatedAt": "2026-03-11T15:19:05.183Z", "properties": [{"name": "attributeName", "type": "string", "description": "Name of the technical attribute"}, {"name": "value", "type": "string", "description": "Attribute value for the part"}, {"name": "unitOfMeasure", "type": "string", "description": "Measurement unit (e.g., mm, kg)"}], "description": "Technical properties such as dimensions, materials, weight, finish, and performance ratings that define and differentiate parts. Used for accurate substitution and engineering comprehension.", "relationships": [{"type": "parent", "label": "Attributes describe physical/functional nature of parts", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-repairinstruction', 'custom', 'Cross-Industry Ontology', 'repairInstruction', 'Part Attributes and Specifications', 'A ''repairInstruction'' represents a highly structured set of procedural guidelines, often including annotated diagrams, provided by Original Equipment Manufacturers (OEMs) or certified publishers for the safe and effective servicing of vehicle parts and components. These instructions ensure precision in operations such as installation, removal, calibration, or troubleshooting, reducing human error and promoting standardization across service environments. In custom operations, AI agents leverage repairInstructions to automate job card generation, validate labor operations, and orchestrate predictive maintenance tasks. Instructions are frequently updated to reflect new safety compliance requirements, design changes, or operational best practices. Ultimately, accurate management and dissemination of repairInstructions underpins both operational efficiency and regulatory adherence.', '[{"name": "instructionId", "type": "string", "description": "Unique identifier for the repair instruction"}, {"name": "instructionType", "type": "enum", "description": "Type (e.g., removal, installation, safety)"}, {"name": "language", "type": "string", "description": "Language of the instruction"}, {"name": "revisionDate", "type": "date", "description": "The effective date of the current revision of the instruction."}, {"name": "applicableModelYears", "type": "string", "description": "Comma-separated list or range of model years to which the instruction applies."}, {"name": "associatedParts", "type": "string", "description": "List of part numbers or SKUs directly referenced in the instruction."}]'::jsonb, '[{"type": "related", "label": "Linked to relevant labor operations", "targetId": "custom-automotive-parts-and-repair-data-laboroperation"}, {"type": "related", "label": "References required torque specifications", "targetId": "custom-automotive-parts-and-repair-data-torquespecification"}, {"type": "depends_on", "label": "Relies on approved parts sourcing method", "targetId": "custom-automotive-parts-and-repair-data-partssourcingmethod"}, {"type": "related", "label": "Aligned with OEM coverage scope", "targetId": "custom-automotive-parts-and-repair-data-oemcoverage"}]'::jsonb, 'instruction,procedure,OEM,service,compliance,safety-critical,versioning,digitalManual,AR-enabled'::text[], 'Ensures technician safety, warranty compliance, and reduces repair errors.', '2026-03-11 15:12:06.445885', 'repairProcedure,workInstruction'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "repairInstruction", "version": 1, "synonyms": ["repairProcedure", "workInstruction"], "updatedAt": "2026-03-11T15:19:40.972Z", "properties": [{"name": "instructionId", "type": "string", "description": "Unique identifier for the repair instruction"}, {"name": "instructionType", "type": "enum", "description": "Type (e.g., removal, installation, safety)"}, {"name": "language", "type": "string", "description": "Language of the instruction"}], "description": "Step-by-step procedures or diagrams issued by OEMs or trusted publishers for proper installation, removal, or service of parts and components.", "relationships": [{"type": "related", "label": "Linked to relevant labor operations", "targetId": "custom-automotive-parts-and-repair-data-laboroperation"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-torquespecification', 'custom', 'Cross-Industry Ontology', 'torqueSpecification', 'Part Attributes and Specifications', 'The ''torqueSpecification'' concept precisely defines the tightening force required for bolts, screws, or other fasteners in assemblies, which is critical in custom operations for ensuring structural integrity and safety. Unified and accurate torque specifications prevent both under-tightening (which risks loosening and failure) and over-tightening (which could lead to thread stripping or part damage). In the context of AI agent lifecycle management, this specification allows agents to verify, recommend, or automate proper procedures during assembly, repair, and maintenance. Proper management and validation of torque specifications are essential for operational efficiency, minimizing errors, and facilitating transparent audit trails. Integration with digital workflows also supports traceability and compliance reporting.', '[{"name": "fastenerLocation", "type": "string", "description": "Specific fastener or location"}, {"name": "torqueValue", "type": "decimal", "description": "Required torque value"}, {"name": "unit", "type": "string", "description": "Unit of measurement (e.g., Nm, ft-lb)"}, {"name": "tolerance", "type": "decimal", "description": "Permissible variance from the specified torque value."}, {"name": "specificationSource", "type": "string", "description": "Reference to original documentation or OEM source for the specification."}]'::jsonb, '[{"type": "related", "label": "May be referenced within a repair instruction", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}, {"type": "related", "label": "Torque specification may be associated with a specific BOM item", "targetId": "custom-578980df-7123-44b3-b9e2-ff0d608bbff0"}, {"type": "depends_on", "label": "Torque requirement may depend on material or thread attributes", "targetId": "custom-automotive-parts-and-repair-data-partattribute"}, {"type": "related", "label": "Torque checks may be required as part of scheduled maintenance", "targetId": "custom-automotive-parts-and-repair-data-maintenancescheduleitem"}]'::jsonb, 'specification,safety,assembly,fastener,quality-control,traceability,compliance,assembly-instructions'::text[], 'Prevents parts failures and ensures safety through accurate technician guidance.', '2026-03-11 15:12:06.489669', 'torqueSetting'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "torqueSpecification", "version": 1, "synonyms": ["torqueSetting"], "updatedAt": "2026-03-11T15:20:20.915Z", "properties": [{"name": "fastenerLocation", "type": "string", "description": "Specific fastener or location"}, {"name": "torqueValue", "type": "decimal", "description": "Required torque value"}, {"name": "unit", "type": "string", "description": "Unit of measurement (e.g., Nm, ft-lb)"}], "description": "Detailed specification of tightening torque needed for fasteners and assemblies. Central to safe and effective repairs, and frequently included in OEM instructions.", "relationships": [{"type": "related", "label": "May be referenced within a repair instruction", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-laboroperation', 'custom', 'Cross-Industry Ontology', 'laborOperation', 'Labor & Service Data', 'A laborOperation represents a discrete, standardized unit of work performed during vehicle repair or maintenance. Each operation is meticulously defined to ensure consistency in repair estimates, job scheduling, and task tracking across various service centers. In custom operations contexts, the concept supports automation of workflow orchestration, allowing AI agents to dynamically assign, modify, and optimize repair tasks for efficiency and accuracy. This also enables real-time monitoring of operational performance, granular cost analysis, and resource allocation within labor-intensive environments. The structuring of laborOperation facilitates interoperability between systems, supporting both compliance and operational goals.', '[{"name": "operationCode", "type": "string", "description": "Code identifying the labor operation"}, {"name": "description", "type": "string", "description": "Description of the task"}, {"name": "laborCategory", "type": "string", "description": "Category such as engine, brakes, body"}, {"name": "estimatedLaborTimeMinutes", "type": "integer", "description": "The estimated time to complete the labor operation, expressed in minutes"}, {"name": "requiredSkillLevel", "type": "string", "description": "Specification of the minimum technician skill level or certification needed to perform the task"}, {"name": "isWarrantyEligible", "type": "boolean", "description": "Indicates whether completion of this operation qualifies for warranty reimbursement"}]'::jsonb, '[{"type": "parent", "label": "Labor operation has associated time estimate", "targetId": "custom-automotive-parts-and-repair-data-labortime"}, {"type": "child", "label": "Labor operation follows specific repair instructions", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}, {"type": "parent", "label": "Labor operation is part of a scheduled maintenance item", "targetId": "custom-automotive-parts-and-repair-data-maintenancescheduleitem"}, {"type": "depends_on", "label": "Labor operation depends on part sourcing method for completion", "targetId": "custom-automotive-parts-and-repair-data-partssourcingmethod"}]'::jsonb, 'labor,operation,repair,task,workflow,compliance,audit,costing'::text[], 'Forms basis of service pricing, quoting, and shop productivity metrics.', '2026-03-11 15:12:06.533479', 'operationCode,workItem'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "laborOperation", "version": 1, "synonyms": ["operationCode", "workItem"], "updatedAt": "2026-03-11T15:20:57.761Z", "properties": [{"name": "operationCode", "type": "string", "description": "Code identifying the labor operation"}, {"name": "description", "type": "string", "description": "Description of the task"}, {"name": "laborCategory", "type": "string", "description": "Category such as engine, brakes, body"}], "description": "Standardized line item representing a specific repair or maintenance task. Used for tracking shop workflow, estimating labor times, and calculating repair costs.", "relationships": [{"type": "parent", "label": "Labor operation has associated time estimate", "targetId": "custom-automotive-parts-and-repair-data-labortime"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-labortime', 'custom', 'Cross-Industry Ontology', 'laborTime', 'Labor & Service Data', 'The ''laborTime'' concept refers to the quantified duration necessary to perform a specific labor operation on a vehicle, typically measured in hours. It serves as a foundational data point for estimating costs in repair shop quotes, scheduling technician workloads efficiently, and standardizing billing processes. Accurate labor time determination drives operational transparency, reducing disputes over charges and facilitating workflow automation in service departments. Custom AI agents leverage ''laborTime'' to optimize resource allocation, automate labor cost predictions, and monitor performance against benchmarks. It is essential for integrating repair shop operations with parts ordering, service scheduling, and compliance tracking within cross-industry platforms.', '[{"name": "timeValue", "type": "decimal", "description": "The time estimated, usually in hours"}, {"name": "source", "type": "string", "description": "Standard labor guide or authority (e.g., MOTOR, OEM)"}, {"name": "operationContext", "type": "string", "description": "Describes the specific circumstances or complexities affecting labor time (e.g., vehicle model, equipment configuration)"}, {"name": "isWarrantyApplicable", "type": "boolean", "description": "Indicates if the labor time is subject to warranty terms or policies"}, {"name": "lastReviewedDate", "type": "date", "description": "The date when the labor time estimate was last validated or reviewed"}]'::jsonb, '[{"type": "child", "label": "Directly linked with the repair operation performed", "targetId": "custom-automotive-parts-and-repair-data-laboroperation"}, {"type": "related", "label": "Linked to supporting repair instructions", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}, {"type": "related", "label": "Refers to applicable warranty coverage policies", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}, {"type": "depends_on", "label": "Depends on torque values for relevant mechanical operations", "targetId": "custom-automotive-parts-and-repair-data-torquespecification"}]'::jsonb, 'time,estimate,labor,operations,serviceStandard,automation,scheduling,billing'::text[], 'Critical for accurate repair quoting, controlling customer billing, and shop resource allocation.', '2026-03-11 15:12:06.57752', 'standardTime,flatRate'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "laborTime", "version": 1, "synonyms": ["standardTime", "flatRate"], "updatedAt": "2026-03-11T15:22:11.682Z", "properties": [{"name": "timeValue", "type": "decimal", "description": "The time estimated, usually in hours"}, {"name": "source", "type": "string", "description": "Standard labor guide or authority (e.g., MOTOR, OEM)"}], "description": "Estimated or standard time required to complete a defined labor operation on a specific vehicle. Basis for repair shop billing, quoting, and technician scheduling.", "relationships": [{"type": "child", "label": "Directly linked with the repair operation performed", "targetId": "custom-automotive-parts-and-repair-data-laboroperation"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-maintenancescheduleitem', 'custom', 'Cross-Industry Ontology', 'maintenanceScheduleItem', 'Labor & Service Data', 'A maintenanceScheduleItem captures a specific recommended action based on OEM guidance or telematics data to ensure the ongoing safety and reliability of vehicles. These items are scheduled by mileage or elapsed time and may include tasks such as inspections, replacements, or oil changes. In the context of custom AI agent operations, this concept allows for automation of scheduling, resource allocation, and compliance verification—key for fleet managers and service providers. Predictive analytics can be layered on top to anticipate upcoming maintenance needs, minimizing vehicle downtime and optimizing operational efficiency. The detail granularity of each item enables proactive life-cycle management and evidence gathering for warranty or regulatory reporting.', '[{"name": "scheduleInterval", "type": "string", "description": "Mileage, time or both at which to perform the item"}, {"name": "maintenanceType", "type": "string", "description": "Type, such as inspection, replacement, lubrication"}, {"name": "oemReferenceId", "type": "string", "description": "Unique identifier linking the schedule item to the OEM''s official maintenance documentation"}, {"name": "isMandatory", "type": "boolean", "description": "Indicates if the maintenance item is mandatory for warranty or compliance"}, {"name": "estimatedLaborTime", "type": "decimal", "description": "Estimated time in hours required to complete the maintenance item"}]'::jsonb, '[{"type": "related", "label": "May require replacement part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "depends_on", "label": "Requires labor time estimation", "targetId": "custom-automotive-parts-and-repair-data-labortime"}, {"type": "related", "label": "Impacts warranty coverage", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}, {"type": "related", "label": "Is a component of a service process", "targetId": "custom-product-service-service"}]'::jsonb, 'maintenance,schedule,preventive,service,compliance,fleet,inspection,telematics'::text[], 'Enables timely preventive maintenance to minimize breakdowns and warranty costs.', '2026-03-11 15:12:06.621998', 'scheduledService,serviceInterval'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "maintenanceScheduleItem", "version": 1, "synonyms": ["scheduledService", "serviceInterval"], "updatedAt": "2026-03-11T15:22:58.809Z", "properties": [{"name": "scheduleInterval", "type": "string", "description": "Mileage, time or both at which to perform the item"}, {"name": "maintenanceType", "type": "string", "description": "Type, such as inspection, replacement, lubrication"}], "description": "A recommended service action from OEMs or data providers, identified by mileage or time, to keep vehicles safe and reliable.", "relationships": [{"type": "related", "label": "May require replacement part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-diagnostictroublecode', 'custom', 'Cross-Industry Ontology', 'diagnosticTroubleCode', 'Diagnostic & Failure Data', 'A diagnosticTroubleCode (DTC) is a standardized alphanumeric identifier output by a vehicle''s onboard diagnostics system when it detects a fault condition. In custom operations, DTCs enable AI agents to interpret real-time sensor data, correlate issues with structured parts or repair instructions, and automate troubleshooting workflows. AI agents can prioritize maintenance actions, track recurring issues, and integrate with broader asset management or warranty processes. The standardized structure of DTCs supports interoperability, allowing for consistent reporting and historical analysis across different vehicle makes and models. DTCs play a crucial role in predictive maintenance and remote diagnostics within connected vehicle ecosystems.', '[{"name": "dtcCode", "type": "string", "description": "Diagnostic Trouble Code"}, {"name": "description", "type": "string", "description": "Human-readable summary of the DTC"}, {"name": "type", "type": "enum", "description": "Type (e.g., generic, manufacturer-specific)"}, {"name": "severityLevel", "type": "enum", "description": "Indicates the criticality of the fault (e.g., informational, warning, critical)."}, {"name": "firstDetectedDate", "type": "date", "description": "Timestamp when the DTC was first reported."}, {"name": "occurrenceCount", "type": "integer", "description": "Number of times this DTC has been detected since last reset."}]'::jsonb, '[{"type": "related", "label": "May recommend repair procedures", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}, {"type": "related", "label": "Linked with high-level observable symptoms", "targetId": "custom-automotive-parts-and-repair-data-symptomcode"}, {"type": "related", "label": "Indicates probable failure modes based on code analysis", "targetId": "custom-automotive-parts-and-repair-data-failuremode"}, {"type": "depends_on", "label": "May influence scheduled or urgent maintenance actions", "targetId": "custom-automotive-parts-and-repair-data-maintenancescheduleitem"}]'::jsonb, 'diagnosis,DTC,OBD,fault,predictiveMaintenance,telematics,emissionsCompliance,remoteDiagnostics'::text[], 'Essential for modern service workflows and root-cause analysis of vehicle issues.', '2026-03-11 15:12:06.665973', 'DTC,errorCode,troubleCode'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "diagnosticTroubleCode", "version": 1, "synonyms": ["DTC", "errorCode", "troubleCode"], "updatedAt": "2026-03-11T15:23:53.652Z", "properties": [{"name": "dtcCode", "type": "string", "description": "Diagnostic Trouble Code"}, {"name": "description", "type": "string", "description": "Human-readable summary of the DTC"}, {"name": "type", "type": "enum", "description": "Type (e.g., generic, manufacturer-specific)"}], "description": "Standardized alphanumeric codes (DTCs) that identify faults or failures detected by a vehicle''s onboard diagnostics systems. Used for troubleshooting and repairs.", "relationships": [{"type": "related", "label": "May recommend repair procedures", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-symptomcode', 'custom', 'Cross-Industry Ontology', 'symptomCode', 'Diagnostic & Failure Data', 'The ''symptomCode'' concept provides a standardized and coded representation of observable symptoms related to equipment or system failures. It is integral for documenting initial user or technician complaints, enabling structured communication between service personnel, diagnostic tools, and support systems. In custom AI agent operations, symptomCode facilitates pattern recognition, predictive maintenance, and the mapping of user-reported issues to standardized diagnostic protocols. By codifying the early indicators of a problem, it streamlines data integration, accelerates root-cause analysis, and enhances interoperability between disparate diagnostic platforms. Timely and accurate symptom coding is essential for automated triage and assignment processes in service environments.', '[{"name": "symptomId", "type": "string", "description": "Unique code for the symptom"}, {"name": "description", "type": "string", "description": "Explanation of the symptom observed"}, {"name": "severityLevel", "type": "enum", "description": "Indicates the perceived severity of the symptom (e.g., minor, moderate, severe)."}, {"name": "firstObservedDate", "type": "date", "description": "Date when the symptom was first observed or reported."}, {"name": "associatedSystem", "type": "string", "description": "System or subsystem where the symptom is observed (e.g., engine, battery, HVAC)."}]'::jsonb, '[{"type": "related", "label": "May be mapped to known DTCs", "targetId": "custom-automotive-parts-and-repair-data-diagnostictroublecode"}, {"type": "depends_on", "label": "May be indicative of specific failure modes", "targetId": "custom-automotive-parts-and-repair-data-failuremode"}, {"type": "depends_on", "label": "Could trigger associated maintenance schedule item", "targetId": "custom-automotive-parts-and-repair-data-maintenancescheduleitem"}, {"type": "depends_on", "label": "Can be linked to recommended repair instructions", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}]'::jsonb, 'diagnosis,symptom,complaint,pre-diagnosis,service-intake,observable-state,complaint-coding,preliminary-assessment'::text[], 'Links customer complaints to diagnostic workflows, improving efficiency and accuracy.', '2026-03-11 15:12:06.710518', 'symptomDescriptor,complaintCode'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "symptomCode", "version": 1, "synonyms": ["symptomDescriptor", "complaintCode"], "updatedAt": "2026-03-11T15:25:09.655Z", "properties": [{"name": "symptomId", "type": "string", "description": "Unique code for the symptom"}, {"name": "description", "type": "string", "description": "Explanation of the symptom observed"}], "description": "Coded description of observable symptoms that accompany a failure, used by service personnel to describe issues prior to or during diagnosis.", "relationships": [{"type": "related", "label": "May be mapped to known DTCs", "targetId": "custom-automotive-parts-and-repair-data-diagnostictroublecode"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-failuremode', 'custom', 'Cross-Industry Ontology', 'failureMode', 'Diagnostic & Failure Data', 'The ''failureMode'' concept provides a standardized framework for cataloging the specific ways in which a part or system may fail during operation. It enables root cause analysis, supports data-driven warranty claims processing, and informs engineering teams about recurring issues for continuous improvement. In custom operations, tracking failure modes allows AI agents to correlate observed issues with prescribed maintenance routines and predict future failures based on part history. Detailed classification of failure modes underpins predictive maintenance, optimizes inventory strategies for replacement parts, and can be used to inform recall campaigns. Overall, this concept is fundamental for increasing operational reliability, reducing downtime, and improving product quality.', '[{"name": "failureModeId", "type": "string", "description": "Failure mode code or identifier"}, {"name": "failureType", "type": "string", "description": "Category/nature of the failure"}, {"name": "detectionMethod", "type": "string", "description": "The specific diagnostic method or tool used to identify the failure mode."}, {"name": "severityLevel", "type": "string", "description": "Categorization of the failure''s impact (e.g., minor, moderate, critical)."}, {"name": "occurrenceFrequency", "type": "decimal", "description": "Statistical measure of how often this failure mode occurs over time or usage cycles."}]'::jsonb, '[{"type": "related", "label": "Specifies the failed part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Mapped to diagnostic trouble code", "targetId": "custom-automotive-parts-and-repair-data-diagnostictroublecode"}, {"type": "depends_on", "label": "Resolved by repair instruction", "targetId": "custom-automotive-parts-and-repair-data-repairinstruction"}, {"type": "related", "label": "Impacts warranty coverage", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}]'::jsonb, 'failure,warranty,diagnosis,analysis,predictiveMaintenance,recall,qualityControl'::text[], 'Improves root-cause analysis and reduces repeat failures through strategic repairs.', '2026-03-11 15:12:06.756307', 'failureType,mode of failure'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "failureMode", "version": 1, "synonyms": ["failureType", "mode of failure"], "updatedAt": "2026-03-11T15:24:23.252Z", "properties": [{"name": "failureModeId", "type": "string", "description": "Failure mode code or identifier"}, {"name": "failureType", "type": "string", "description": "Category/nature of the failure"}], "description": "Standardized description of how a part or system fails in operation, such as wear, breakage, fluid leak, or short circuit. Basis for warranty analysis and engineering improvements.", "relationships": [{"type": "related", "label": "Specifies the failed part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-inventorystatus', 'custom', 'Cross-Industry Ontology', 'inventoryStatus', 'Parts Availability & Distribution', 'The ''inventoryStatus'' concept encapsulates the current state of parts availability across multiple distribution points, such as warehouses, retailers, and distributors. It supports both real-time and batch status updates, providing granular visibility essential for order fulfillment and inventory optimization operations. In custom AI agent scenarios, ''inventoryStatus'' data enables intelligent agents to automate stock monitoring, anticipate shortages, and trigger replenishment workflows as needed. This directly supports just-in-time supply chains and reduces overstocking or stockouts. The integration of inventoryStatus with agent operations creates a foundation for dynamic, data-driven inventory management in complex distribution networks.', '[{"name": "locationId", "type": "string", "description": "Warehouse or store identifier"}, {"name": "quantityOnHand", "type": "integer", "description": "Current inventory count"}, {"name": "statusTimestamp", "type": "date", "description": "The date and time when the inventory status was last updated"}, {"name": "statusType", "type": "enum", "description": "Type of status (e.g., In Stock, Out of Stock, Low Stock, Backordered)"}, {"name": "reservedQuantity", "type": "integer", "description": "Quantity of stock reserved for pending orders"}]'::jsonb, '[{"type": "depends_on", "label": "Status relates to a specific part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Inventory status by distribution channel", "targetId": "custom-automotive-parts-and-repair-data-distributionchannel"}, {"type": "related", "label": "Inventory status associated with specific SKU", "targetId": "custom-89de0b36-59bd-4481-b39d-18907166e877"}, {"type": "child", "label": "Inventory status as a component of inventory management processes", "targetId": "custom-process-workflow-businessprocess"}]'::jsonb, 'inventory,stock,availability,distribution,logistics,replenishment,real-time,supply chain'::text[], 'Drives rapid fulfillment and efficient supply chain management for shops and distributors.', '2026-03-11 15:12:06.80151', 'stockStatus,onHand,availability'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "inventoryStatus", "version": 1, "synonyms": ["stockStatus", "onHand", "availability"], "updatedAt": "2026-03-11T15:25:40.186Z", "properties": [{"name": "locationId", "type": "string", "description": "Warehouse or store identifier"}, {"name": "quantityOnHand", "type": "integer", "description": "Current inventory count"}], "description": "Real-time or batch status of a part''s availability at a distributor, warehouse, or retailer location. Used for order fulfillment and inventory optimization.", "relationships": [{"type": "depends_on", "label": "Status relates to a specific part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-distributionchannel', 'custom', 'Cross-Industry Ontology', 'distributionChannel', 'Parts Availability & Distribution', 'The ''distributionChannel'' concept captures the various routes and intermediaries that facilitate the movement of parts from manufacturers to end customers. It encompasses entities such as wholesalers, retailers, e-commerce platforms, and logistics providers that collectively ensure parts availability across diverse markets. In custom operations, tracking distribution channels is essential for optimizing inventory allocation, monitoring channel performance, and enabling adaptive supply chain strategies. This concept supports AI-driven orchestration of distribution processes, anomaly detection, and dynamic partner management. By structuring channel data, organizations enhance visibility and responsiveness in their parts distribution networks.', '[{"name": "channelType", "type": "string", "description": "Type (e.g., B2B, B2C, franchise)"}, {"name": "partnerId", "type": "string", "description": "Identifier for the channel partner"}, {"name": "regionalCoverage", "type": "string", "description": "Geographic regions served by this distribution channel"}, {"name": "activationDate", "type": "date", "description": "Date this distribution channel became operational"}, {"name": "channelPerformanceScore", "type": "decimal", "description": "Quantitative assessment of the channel''s effectiveness or reliability"}]'::jsonb, '[{"type": "related", "label": "Channels provide inventory to retailers", "targetId": "custom-automotive-parts-and-repair-data-inventorystatus"}, {"type": "child", "label": "External partners operating as part of this channel", "targetId": "custom-entity-management-externalpartner"}, {"type": "depends_on", "label": "Channel sourcing strategies dependent on part acquisition methods", "targetId": "custom-automotive-parts-and-repair-data-partssourcingmethod"}, {"type": "related", "label": "Relevant product lifecycle stages for this channel''s activity", "targetId": "custom-product-service-productlifecyclestage"}]'::jsonb, 'channel,distribution,retail,wholesale,supply chain,traceability,partner management,sales channel'::text[], 'Vital for tracking parts flow, optimizing routes, and managing supply constraints.', '2026-03-11 15:12:06.845629', 'salesChannel,resellerNetwork'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "distributionChannel", "version": 1, "synonyms": ["salesChannel", "resellerNetwork"], "updatedAt": "2026-03-11T15:27:14.592Z", "properties": [{"name": "channelType", "type": "string", "description": "Type (e.g., B2B, B2C, franchise)"}, {"name": "partnerId", "type": "string", "description": "Identifier for the channel partner"}], "description": "Defines the path and intermediary entities (e.g., distributors, retailers, web platforms) through which a part moves from manufacturer to end customer.", "relationships": [{"type": "related", "label": "Channels provide inventory to retailers", "targetId": "custom-automotive-parts-and-repair-data-inventorystatus"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-partssourcingmethod', 'custom', 'Cross-Industry Ontology', 'partsSourcingMethod', 'Parts Availability & Distribution', 'The ''partsSourcingMethod'' concept describes the specific procurement channel used to acquire vehicle parts, such as directly from OEMs, aftermarket suppliers, salvage yards, or remanufacturers. In the context of custom operations, it provides traceability and decision intelligence for AI agents optimizing parts inventory, cost management, and repair cycle times. The method chosen impacts not only cost and availability but also warranty coverage, part authenticity, and suitability for specific vehicle configurations. AI agents can leverage this concept to automate and optimize decision-making based on sourcing constraints, operational requirements, and real-time inventory levels. Proper modeling of sourcing methods supports proactive risk management, regulatory traceability, and dynamic supplier selection.', '[{"name": "methodType", "type": "enum", "description": "Sourcing type (OEM, aftermarket, reman, recycled)"}, {"name": "leadTimeDays", "type": "integer", "description": "Estimated delivery/fulfillment time"}, {"name": "supplierId", "type": "string", "description": "Unique identifier for the supplier providing the part"}, {"name": "complianceStatus", "type": "enum", "description": "Indicates if the sourcing method meets relevant compliance requirements"}, {"name": "warrantyEligible", "type": "boolean", "description": "Whether parts acquired via this sourcing method are eligible for warranty"}]'::jsonb, '[{"type": "related", "label": "Sourcing is executed through distribution channels", "targetId": "custom-automotive-parts-and-repair-data-distributionchannel"}, {"type": "depends_on", "label": "Sourcing method determines eligibility for warranty coverage", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}, {"type": "related", "label": "Linked sourcing method to specific supplier contracts", "targetId": "custom-b1daeba3-4b44-4faf-9ecb-243a666f2913"}]'::jsonb, 'procurement,sourcing,acquisition,inventory,supplierManagement,traceability,compliance,leadTimeOptimization,costOptimization'::text[], 'Impacts repair speed, part quality, and cost across repair operations.', '2026-03-11 15:12:06.889589', 'procurementMethod,acquisitionType'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "partsSourcingMethod", "version": 1, "synonyms": ["procurementMethod", "acquisitionType"], "updatedAt": "2026-03-11T15:26:03.684Z", "properties": [{"name": "methodType", "type": "enum", "description": "Sourcing type (OEM, aftermarket, reman, recycled)"}, {"name": "leadTimeDays", "type": "integer", "description": "Estimated delivery/fulfillment time"}], "description": "Method by which a repair facility or fleet acquires parts, such as direct OEM, aftermarket distributor, salvage, or remanufactured sources.", "relationships": [{"type": "related", "label": "Sourcing is executed through distribution channels", "targetId": "custom-automotive-parts-and-repair-data-distributionchannel"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-warrantycoverage', 'custom', 'Cross-Industry Ontology', 'warrantyCoverage', 'Warranty & Campaign Data', 'warrantyCoverage captures the specifics of what is protected under a manufacturer''s or supplier''s warranty for a vehicle part or system, including details about which costs (parts, labor) are covered, the time period and/or mileage limits, and any associated conditions or exclusions. In custom operations, this concept enables AI agents to automate warranty validation, claims adjudication, and compliance checks, streamlining service workflows and maximizing both customer satisfaction and regulatory adherence. AI-driven warranty analysis reduces manual errors, accelerates service delivery, and provides traceability by linking warranty events directly to covered components and services. warrantyCoverage serves as a critical data node connecting part provenance, fault analysis, and aftersales business rules in the automotive value chain.', '[{"name": "coverageType", "type": "string", "description": "Type of warranty (parts, labor, emission, drivetrain)"}, {"name": "durationMonths", "type": "integer", "description": "Warranty duration in months"}, {"name": "mileageLimit", "type": "integer", "description": "Maximum mileage covered under the warranty"}, {"name": "costResponsibility", "type": "string", "description": "Specification of which party (OEM, customer, dealer) is responsible for costs"}, {"name": "coveredConditions", "type": "string", "description": "Enumerates the specific failures, faults, or incidents covered"}, {"name": "startDate", "type": "date", "description": "Date when the warranty coverage begins"}]'::jsonb, '[{"type": "depends_on", "label": "Warranty is issued for a specific part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "related", "label": "Linked to overarching OEM warranty policy", "targetId": "custom-automotive-parts-and-repair-data-oemcoverage"}, {"type": "related", "label": "Warranty coverage may require adherence to specified maintenance items", "targetId": "custom-automotive-parts-and-repair-data-maintenancescheduleitem"}, {"type": "related", "label": "Coverage may be contingent on or trigger replacement policy conditions", "targetId": "custom-automotive-parts-and-repair-data-replacementpolicy"}]'::jsonb, 'warranty,coverage,service,oem,claimAdjudication,compliance,customerExperience'::text[], 'Reduces risk, builds confidence, and manages repairs under manufacturer conditions.', '2026-03-11 15:12:06.933704', 'warrantyPolicy,serviceCoverage'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "warrantyCoverage", "version": 1, "synonyms": ["warrantyPolicy", "serviceCoverage"], "updatedAt": "2026-03-11T15:28:40.110Z", "properties": [{"name": "coverageType", "type": "string", "description": "Type of warranty (parts, labor, emission, drivetrain)"}, {"name": "durationMonths", "type": "integer", "description": "Warranty duration in months"}], "description": "Detailed information on part/system warranty status, covered conditions, duration, mileage limits, and cost responsibilities as offered by OEM or part supplier.", "relationships": [{"type": "depends_on", "label": "Warranty is issued for a specific part", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-recallcampaign', 'custom', 'Cross-Industry Ontology', 'recallCampaign', 'Warranty & Campaign Data', 'A recallCampaign represents a structured intervention initiated by vehicle manufacturers (OEMs) or regulatory agencies to rectify safety or compliance defects identified in specific batches of vehicles. The campaign outlines the issue, targeted vehicle VINs, and specifies the remedial action, such as inspections, part replacements, or software updates. It activates a coordinated workflow involving manufacturer, dealer network, and affected vehicle owners to track resolution status and regulatory reporting. Recall campaigns are critical for public safety, brand integrity, and ongoing compliance with transportation laws. AI agents orchestrate campaign rollouts by automating notifications, scheduling fix appointments, and verifying remedy completion.', '[{"name": "campaignId", "type": "string", "description": "Unique identifier for the campaign"}, {"name": "remedyDescription", "type": "string", "description": "Corrective action required"}, {"name": "affectedVehicleVins", "type": "string", "description": "Comma-separated list or range of VINs affected by the campaign"}, {"name": "campaignStartDate", "type": "date", "description": "Date when the recall campaign is officially launched"}, {"name": "regulatoryAuthority", "type": "string", "description": "Name of the authority mandating or approving the recall"}]'::jsonb, '[{"type": "depends_on", "label": "Recall issued for specific affected parts", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}, {"type": "depends_on", "label": "Determines current owners for notification and remediation", "targetId": "custom-vehicle-valuation-and-analytics-ownershiphistory"}, {"type": "related", "label": "Originates from specific failure modes triggering the recall", "targetId": "custom-automotive-parts-and-repair-data-failuremode"}, {"type": "parent", "label": "Recall process managed through defined workflows", "targetId": "custom-process-workflow-workflow"}]'::jsonb, 'recall,campaign,safety,regulation,remediation,compliance,field-action'::text[], 'Ensures compliance with safety regulations and minimizes public/business risk.', '2026-03-11 15:12:06.977723', 'safetyRecall,recallNotice'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "recallCampaign", "version": 1, "synonyms": ["safetyRecall", "recallNotice"], "updatedAt": "2026-03-11T15:29:10.284Z", "properties": [{"name": "campaignId", "type": "string", "description": "Unique identifier for the campaign"}, {"name": "remedyDescription", "type": "string", "description": "Corrective action required"}], "description": "An official notice and workflow issued by OEMs or regulatory authorities to address safety or compliance issues on specific vehicle batches, requiring inspection or part replacement.", "relationships": [{"type": "depends_on", "label": "Recall issued for specific affected parts", "targetId": "custom-automotive-parts-and-repair-data-partnumber"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('custom-automotive-parts-and-repair-data-replacementpolicy', 'custom', 'Cross-Industry Ontology', 'replacementPolicy', 'Warranty & Campaign Data', 'The ''replacementPolicy'' concept establishes a comprehensive framework for determining when and how a part should be replaced or reimbursed, particularly in response to failures, recalls, or warranty claims. This policy specifies eligibility criteria, coverage limitations, and procedural workflows for executing replacements while factoring in manufacturer and regulatory requirements. In custom operations, it can also delineate exceptions, escalation procedures, and documentation standards to guide both automated and human-driven handling of claims. AI agents leveraging this concept can automate validation, process optimization, and compliance checks, ensuring accurate and timely resolution of part replacement scenarios. Integration of this policy with data systems supports traceability and risk mitigation regarding warranty costs and customer satisfaction.', '[{"name": "policyType", "type": "string", "description": "Type of policy (OEM, aftermarket, extended)"}, {"name": "claimProcess", "type": "string", "description": "Claim procedure identifier or description"}, {"name": "coveragePeriod", "type": "string", "description": "Defines the start and end dates or duration for which the policy is applicable"}, {"name": "maximumClaimLimit", "type": "decimal", "description": "The maximum financial value or number of replacements allowed under the policy"}, {"name": "geographicScope", "type": "string", "description": "The regions or markets where the replacement policy applies"}]'::jsonb, '[{"type": "related", "label": "Aligned with warranty limitations/entitlements", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}, {"type": "depends_on", "label": "Replacement policy conditions informed by active recall campaigns", "targetId": "custom-automotive-parts-and-repair-data-recallcampaign"}, {"type": "parent", "label": "Replacement policy relates to a specific product", "targetId": "custom-product-service-product"}]'::jsonb, 'policy,replacement,warranty,claim,compliance,recall,aftermarket,riskManagement'::text[], 'Aligns service provider, OEM, and customer expectations in the event of part failures.', '2026-03-11 15:12:07.021472', 'returnPolicy,claimPolicy'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "replacementPolicy", "version": 1, "synonyms": ["returnPolicy", "claimPolicy"], "updatedAt": "2026-03-11T15:29:52.178Z", "properties": [{"name": "policyType", "type": "string", "description": "Type of policy (OEM, aftermarket, extended)"}, {"name": "claimProcess", "type": "string", "description": "Claim procedure identifier or description"}], "description": "Defines the conditions and processes under which a failed or recalled part will be replaced or reimbursed, considering warranty and recall constraints.", "relationships": [{"type": "related", "label": "Aligned with warranty limitations/entitlements", "targetId": "custom-automotive-parts-and-repair-data-warrantycoverage"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-digitalidentity', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'digitalIdentity', 'Identity Lifecycle Management', 'A digital identity is the cornerstone of secure financial services operations, enabling unique identification and authentication for individuals, devices, or service accounts within an organization’s digital infrastructure. This concept facilitates access management, audit trails, and enables compliance with regulatory directives that mandate traceability and accountability for digital interactions. Managing the lifecycle of digital identities (creation, usage, suspension, termination) is essential for risk mitigation, especially around fraud, insider threats, and data breaches. Digital identities are foundational to enforcing entitlement and access controls, supporting automated onboarding, and ensuring that roles and permissions are accurately provisioned and monitored. Robust digital identity management empowers AI agents to maintain secure operations and adapt to evolving compliance mandates.', '[{"name": "uniqueIdentifier", "type": "string", "description": "Globally unique ID for the identity."}, {"name": "identityType", "type": "enum", "description": "Type of identity (employee, contractor, service account, device)."}, {"name": "status", "type": "enum", "description": "Current state (active, suspended, terminated)."}, {"name": "lastAuthenticationTime", "type": "date", "description": "Timestamp of the most recent authentication event for the digital identity."}, {"name": "associatedDevices", "type": "string", "description": "List of registered devices linked to the digital identity, aiding in device management and security."}, {"name": "credentialType", "type": "enum", "description": "Type of credential used (password, biometric, token, certificate) for primary authentication."}]'::jsonb, '[{"type": "related", "label": "Provisioning requests may create or update identities.", "targetId": "financial_services-access-and-identity-management-accessprovisioningrequest"}, {"type": "child", "label": "Identities are assigned roles.", "targetId": "financial_services-access-and-identity-management-roleassignment"}, {"type": "related", "label": "Digital identities rely on authentication factors for access control.", "targetId": "financial_services-access-and-identity-management-authenticationfactor"}, {"type": "depends_on", "label": "The digital identity lifecycle involves reconciliation processes to ensure integrity.", "targetId": "financial_services-access-and-identity-management-identityreconciliation"}, {"type": "related", "label": "Digital identities are governed by password policies to enforce security standards.", "targetId": "financial_services-access-and-identity-management-passwordpolicy"}]'::jsonb, 'identity,user,entity,account,accesscontrol,authentication,security,lifecycle,audit'::text[], 'Fundamental for authenticating and authorizing users and systems in complex financial environments.', '2026-03-12 11:47:13.571507', 'userIdentity,accountIdentity'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "digitalIdentity", "version": 1, "synonyms": ["userIdentity", "accountIdentity"], "updatedAt": "2026-03-13T10:15:26.749Z", "properties": [{"name": "uniqueIdentifier", "type": "string", "description": "Globally unique ID for the identity."}, {"name": "identityType", "type": "enum", "description": "Type of identity (employee, contractor, service account, device)."}, {"name": "status", "type": "enum", "description": "Current state (active, suspended, terminated)."}], "description": "A digital identity represents an individual or non-person entity within the organization’s systems, used to uniquely identify and authenticate users and systems.", "relationships": [{"type": "related", "label": "Provisioning requests may create or update identities.", "targetId": "financial_services-access-and-identity-management-accessprovisioningrequest"}, {"type": "child", "label": "Identities are assigned roles.", "targetId": "financial_services-access-and-identity-management-roleassignment"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-accessprovisioningrequest', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'accessProvisioningRequest', 'Identity Lifecycle Management', 'The ''accessProvisioningRequest'' concept represents a formal mechanism for granting, modifying, or revoking access privileges to digital resources within financial services organizations. This process is essential for onboarding new employees, adjusting roles and permissions, and ensuring secure offboarding, especially in environments that handle sensitive financial data and regulated activities. Automated workflows associated with access provisioning requests help maintain the integrity and timeliness of identity lifecycle management, reducing manual errors and increasing operational efficiency. Its critical function is to ensure that only authorized individuals have access to specific systems, applications, or data, aligning security controls with business requirements and regulatory mandates. Accurate and auditable provisioning is foundational for compliance and operational risk mitigation.', '[{"name": "requestId", "type": "string", "description": "Unique identifier for the provisioning request."}, {"name": "requestDate", "type": "date", "description": "When the request was submitted."}, {"name": "requestedBy", "type": "string", "description": "Identity of the individual submitting the request."}, {"name": "provisioningType", "type": "enum", "description": "Indicates whether the request is for grant, change, or revoke access."}, {"name": "targetResource", "type": "string", "description": "The specific resource, system, or application for which access is being provisioned."}, {"name": "urgencyLevel", "type": "enum", "description": "Priority or criticality of the provisioning request."}, {"name": "approvalStatus", "type": "enum", "description": "Current state of the request (e.g., pending, approved, rejected, completed)."}]'::jsonb, '[{"type": "depends_on", "label": "Tied to the identity being provisioned.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "depends_on", "label": "Provisioning request is associated with a specific access role.", "targetId": "financial_services-access-and-identity-management-accessrole"}, {"type": "parent", "label": "Request forms part of broader role assignment workflows.", "targetId": "financial_services-access-and-identity-management-roleassignment"}, {"type": "related", "label": "Provisioning requests are periodically evaluated in access review campaigns.", "targetId": "financial_services-access-and-identity-management-accessreviewcampaign"}]'::jsonb, 'provisioning,lifecycle,workflow,automation,security,identity,audit,compliance,authorization'::text[], 'Essential for controlled and auditable access management throughout an employee or system lifecycle.', '2026-03-12 11:47:13.622168', 'accessRequest,provisionRequest'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "accessProvisioningRequest", "version": 1, "synonyms": ["accessRequest", "provisionRequest"], "updatedAt": "2026-03-13T10:15:47.347Z", "properties": [{"name": "requestId", "type": "string", "description": "Unique identifier for the provisioning request."}, {"name": "requestDate", "type": "date", "description": "When the request was submitted."}, {"name": "requestedBy", "type": "string", "description": "Identity of the individual submitting the request."}], "description": "A formal request to grant, change, or revoke access to resources for a digital identity, including automated onboarding and offboarding workflows.", "relationships": [{"type": "depends_on", "label": "Tied to the identity being provisioned.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-identityreconciliation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'identityReconciliation', 'Identity Lifecycle Management', 'Identity reconciliation is a critical process within financial services operations that ensures digital identities from disparate systems are accurately matched and resolved. This step is essential in maintaining consistent entitlements, preventing access errors, and aligning regulatory requirements related to customer identity management. The reconciliation often involves comparing, validating, and updating identity records to eliminate duplication, uncover orphan accounts, and guarantee correct association of access privileges across enterprise applications. As financial institutions increasingly rely on automation and interconnected platforms, robust identity reconciliation reduces operational risk, bolsters regulatory compliance, and facilitates secure onboarding and lifecycle management.', '[{"name": "reconciliationId", "type": "string", "description": "Unique identifier for the reconciliation event."}, {"name": "sourceSystem", "type": "string", "description": "System from which identities are sourced."}, {"name": "recordCount", "type": "integer", "description": "Number of identities reconciled."}, {"name": "reconciliationTimestamp", "type": "date", "description": "Date and time when the reconciliation event occurred."}, {"name": "status", "type": "enum", "description": "Outcome status of the reconciliation (e.g., successful, failed, partial)."}, {"name": "discrepancyCount", "type": "integer", "description": "Number of discrepancies detected during the reconciliation process."}]'::jsonb, '[{"type": "parent", "label": "Ensures digital identity consistency.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "depends_on", "label": "Utilizes access log records for reconciliation validation.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "related", "label": "Links reconciliation outcomes to detected entitlement violations.", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}, {"type": "depends_on", "label": "Relies on secure credential entries for identity verification.", "targetId": "financial_services-access-and-identity-management-credentialvaultentry"}]'::jsonb, 'reconciliation,identity,integrity,audit-trail,entitlement-management,cross-system-integration,access-risk,identity-governance'::text[], 'Maintains accurate identity records, critical for compliance and reduce access risks.', '2026-03-12 11:47:13.667306', 'identitySync,accountReconciliation'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "identityReconciliation", "version": 1, "synonyms": ["identitySync", "accountReconciliation"], "updatedAt": "2026-03-13T10:16:04.043Z", "properties": [{"name": "reconciliationId", "type": "string", "description": "Unique identifier for the reconciliation event."}, {"name": "sourceSystem", "type": "string", "description": "System from which identities are sourced."}, {"name": "recordCount", "type": "integer", "description": "Number of identities reconciled."}], "description": "The process of matching and resolving digital identities across multiple systems to ensure consistency and correct entitlements.", "relationships": [{"type": "parent", "label": "Ensures digital identity consistency.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-identitytermination', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'identityTermination', 'Identity Lifecycle Management', 'The concept of ''identityTermination'' refers to the comprehensive process of deactivating and de-provisioning a digital identity within financial services operations. This ensures that all user access is revoked, associated credentials are disabled, and systematic audit trails are preserved for compliance and future reference. The process typically follows an offboarding request or results from detected anomalies necessitating immediate action. In high-stakes environments like banking or trading, prompt and thorough identity termination helps to secure sensitive financial data and mitigate risks associated with lingering access. Maintaining traceability during termination is critical for satisfying internal controls and regulatory audits.', '[{"name": "terminationDate", "type": "date", "description": "When the identity is terminated."}, {"name": "terminatedBy", "type": "string", "description": "Who authorized the termination."}, {"name": "terminationReason", "type": "string", "description": "Reason for de-provisioning the identity."}, {"name": "terminationAuditTrailId", "type": "string", "description": "Reference identifier for the audit trail associated with this identity termination event."}, {"name": "terminationStatus", "type": "enum", "description": "Status indicating whether termination was successful, pending, or failed."}, {"name": "associatedAccessRolesRevoked", "type": "integer", "description": "The number of access roles successfully revoked as part of the termination."}]'::jsonb, '[{"type": "depends_on", "label": "Triggered by offboarding requests.", "targetId": "financial_services-access-and-identity-management-accessprovisioningrequest"}, {"type": "depends_on", "label": "Ensures privileged access is revoked during termination.", "targetId": "financial_services-access-and-identity-management-privilegedaccessgrant"}, {"type": "related", "label": "Reconciled with identity records post-termination to confirm accuracy.", "targetId": "financial_services-access-and-identity-management-identityreconciliation"}, {"type": "related", "label": "Linked to potential entitlement violations if termination is incomplete.", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}]'::jsonb, 'termination,offboarding,deprovision,audit,accessRevocation,compliance,security,employeeExit'::text[], 'Prevents unauthorized access and reduces organizational risk during employee or system departures.', '2026-03-12 11:47:13.712139', 'identityDeactivation,offboarding'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "identityTermination", "version": 1, "synonyms": ["identityDeactivation", "offboarding"], "updatedAt": "2026-03-13T10:16:20.896Z", "properties": [{"name": "terminationDate", "type": "date", "description": "When the identity is terminated."}, {"name": "terminatedBy", "type": "string", "description": "Who authorized the termination."}, {"name": "terminationReason", "type": "string", "description": "Reason for de-provisioning the identity."}], "description": "The formal de-provisioning and disabling of a digital identity, ensuring all access is revoked and audit trails are maintained.", "relationships": [{"type": "depends_on", "label": "Triggered by offboarding requests.", "targetId": "financial_services-access-and-identity-management-accessprovisioningrequest"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-authenticationfactor', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'authenticationFactor', 'Authentication and Federation', 'The ''authenticationFactor'' concept refers to the specific mechanism(s) used to confirm the identity of an individual or entity within financial services operations, such as passwords, one-time passcodes (OTPs), biometrics (fingerprint, facial recognition), or physical security tokens. Given the sensitivity and regulatory environment of financial services, authentication factors are a critical element in protecting customer assets, facilitating secure transactions, and safeguarding privileged access. These factors often underpin multi-factor authentication approaches, helping institutions defend against cyber threats, insider risk, and unauthorized access. They are integral to establishing trust, streamlining customer onboarding, and ensuring transaction and access integrity throughout the organization. Additionally, authentication factors contribute to audit trails and regulatory controls, making their correct implementation pivotal for operations compliance.', '[{"name": "factorType", "type": "enum", "description": "Type of factor (password, OTP, biometric, hardware token)."}, {"name": "isRequired", "type": "boolean", "description": "If the factor is mandatory per policy."}, {"name": "factorStrength", "type": "string", "description": "Relative strength or assurance level of the authentication factor (e.g., low, medium, high)."}, {"name": "expirationDate", "type": "date", "description": "Date after which the authentication factor is no longer valid."}, {"name": "factorStatus", "type": "enum", "description": "Current status of the factor (active, revoked, expired, pending)."}]'::jsonb, '[{"type": "related", "label": "Authentication factors enforced by policy.", "targetId": "financial_services-access-and-identity-management-authenticationpolicy"}, {"type": "depends_on", "label": "Authentication factor depends on credentials stored in vault.", "targetId": "financial_services-access-and-identity-management-credentialvaultentry"}, {"type": "related", "label": "Authentication factor relates to password policy settings.", "targetId": "financial_services-access-and-identity-management-passwordpolicy"}, {"type": "related", "label": "Authentication factor is utilized within digital identity validation.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}]'::jsonb, 'authentication,mfa,security,pii,auditability,userExperience,riskMitigation'::text[], 'Key for secure user authentication and compliance with security regulations.', '2026-03-12 11:47:13.759217', 'authFactor,multifactor'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "authenticationFactor", "version": 1, "synonyms": ["authFactor", "multifactor"], "updatedAt": "2026-03-13T09:12:55.453Z", "properties": [{"name": "factorType", "type": "enum", "description": "Type of factor (password, OTP, biometric, hardware token)."}, {"name": "isRequired", "type": "boolean", "description": "If the factor is mandatory per policy."}], "description": "Methods used to validate a user''s identity during login processes, such as passwords, biometrics, or security tokens.", "relationships": [{"type": "related", "label": "Authentication factors enforced by policy.", "targetId": "financial_services-access-and-identity-management-authenticationpolicy"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-authenticationpolicy', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'authenticationPolicy', 'Authentication and Federation', 'The ''authenticationPolicy'' concept encapsulates organizational rules and guidelines that define how users and applications authenticate within financial services environments. These policies dictate requirements such as the use of multi-factor authentication, password complexity, authentication frequency, and the application of adaptive authentication methods across digital channels. In financial operations, authentication policies are fundamental to protecting sensitive client information, preventing unauthorized access to financial systems, and supporting secure digital transactions. They play a key role in enforcing security boundaries between privileged users, standard users, and third-party integrations, directly impacting operational risk and compliance posture.', '[{"name": "policyId", "type": "string", "description": "Unique identifier for the policy."}, {"name": "policyName", "type": "string", "description": "Human-readable policy name."}, {"name": "enforcementLevel", "type": "enum", "description": "Level of enforcement (strict, moderate, none)."}, {"name": "reviewFrequency", "type": "string", "description": "Frequency at which the policy is reviewed for effectiveness and compliance."}, {"name": "policyEffectiveDate", "type": "date", "description": "Date from which the policy is actively enforced."}, {"name": "applicabilityScope", "type": "string", "description": "Defines the applications, user roles, or business units to which the policy applies."}]'::jsonb, '[{"type": "parent", "label": "Specifies which factors are required.", "targetId": "financial_services-access-and-identity-management-authenticationfactor"}, {"type": "depends_on", "label": "Relies on password complexity and management requirements.", "targetId": "financial_services-access-and-identity-management-passwordpolicy"}, {"type": "related", "label": "Influences authorization of privileged access and related controls.", "targetId": "financial_services-access-and-identity-management-privilegedaccessgrant"}, {"type": "related", "label": "Works in conjunction with broader access control policies for enforcement.", "targetId": "financial_services-access-and-identity-management-policybasedaccesscontrol"}]'::jsonb, 'authentication,policy,mfa,access-control,identity-management,user-provisioning,security-governance'::text[], 'Ensures uniformity and compliance in authentication practices across business units.', '2026-03-12 11:47:13.804805', 'authPolicy,authnPolicy'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "authenticationPolicy", "version": 1, "synonyms": ["authPolicy", "authnPolicy"], "updatedAt": "2026-03-13T09:13:11.816Z", "properties": [{"name": "policyId", "type": "string", "description": "Unique identifier for the policy."}, {"name": "policyName", "type": "string", "description": "Human-readable policy name."}, {"name": "enforcementLevel", "type": "enum", "description": "Level of enforcement (strict, moderate, none)."}], "description": "A set of organizational rules that define authentication requirements for applications and user groups.", "relationships": [{"type": "parent", "label": "Specifies which factors are required.", "targetId": "financial_services-access-and-identity-management-authenticationfactor"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-federatedidentity', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'federatedIdentity', 'Authentication and Federation', 'The federatedIdentity concept in financial services refers to a digital identity authenticated and managed by an external provider (such as Azure AD or Okta), enabling users to access internal banking systems through trusted federation protocols. This is critical for streamlining access management across multiple platforms and institutions, ensuring seamless user experiences while maintaining robust security controls. Federated identity supports agile collaboration and secure integration with partner organizations, vendors, and regulatory bodies. By leveraging federation, financial institutions can maintain centralized control over access policies without directly handling credentials, reducing operational risks related to identity management. This approach is foundational for modern digital banking, cloud migration, and regulatory reporting frameworks.', '[{"name": "provider", "type": "string", "description": "Federation provider (e.g., Azure AD, Okta)."}, {"name": "federationProtocol", "type": "string", "description": "Federation standard (e.g., SAML, OIDC, OAuth2)."}, {"name": "authenticationLevel", "type": "string", "description": "Level of assurance provided by the federation protocol (e.g., MFA, password only)."}, {"name": "sessionExpiry", "type": "date", "description": "Expiration time of the federated identity session."}, {"name": "externalUserIdentifier", "type": "string", "description": "Unique user identifier provided by the external federation provider."}]'::jsonb, '[{"type": "related", "label": "Digital identity can have a federated source.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "related", "label": "Federated identity may be used for privileged access granting.", "targetId": "financial_services-access-and-identity-management-privilegedaccessgrant"}, {"type": "depends_on", "label": "Federated identity relies on defined authentication policies.", "targetId": "financial_services-access-and-identity-management-authenticationpolicy"}, {"type": "related", "label": "Federated identity authentication events are logged in access logs.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}]'::jsonb, 'federation,external,provider,identity,cross-institution,identity-verification,access-control,auditability,cloud-integration'::text[], 'Facilitates secure cross-organization and cloud identity access models.', '2026-03-12 11:47:13.849332', 'federatedAuth,federatedUser'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "federatedIdentity", "version": 1, "synonyms": ["federatedAuth", "federatedUser"], "updatedAt": "2026-03-13T10:16:32.341Z", "properties": [{"name": "provider", "type": "string", "description": "Federation provider (e.g., Azure AD, Okta)."}, {"name": "federationProtocol", "type": "string", "description": "Federation standard (e.g., SAML, OIDC, OAuth2)."}], "description": "An identity that is authenticated and managed by an external organization or provider, allowing access to internal systems via federation protocols.", "relationships": [{"type": "related", "label": "Digital identity can have a federated source.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-singlesignonsession', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'singleSignOnSession', 'Authentication and Federation', 'The singleSignOnSession concept represents the operational mechanism which allows authenticated users to seamlessly access multiple financial and banking systems within the institution or its trusted partners during a single session. This enhances user experience by minimizing repeated credential entry and streamlining access across trading, core banking, and compliance platforms. In financial services, SSO is critical for maintaining productivity, improving workflow efficiency, and managing secure user transitions between applications such as credit rating dashboards, regulatory reporting portals, and risk management tools. Its management and monitoring are essential for safeguarding customer data, maintaining transparency, and supporting audit actions for forensic investigations. Robust session governance ensures that the systems maintain compliance, mitigate risks of unauthorized access, and sustain operational integrity.', '[{"name": "sessionId", "type": "string", "description": "Unique session identifier."}, {"name": "startTime", "type": "date", "description": "Session start time."}, {"name": "expiresAt", "type": "date", "description": "Session expiration time."}, {"name": "userId", "type": "string", "description": "Identifier for the user to whom the session is assigned."}, {"name": "sessionSource", "type": "string", "description": "Origin of session initiation, such as device or application identifier."}, {"name": "lastActivityTime", "type": "date", "description": "Timestamp of the most recent session activity."}]'::jsonb, '[{"type": "depends_on", "label": "SSO sessions initiated by federated identities.", "targetId": "financial_services-access-and-identity-management-federatedidentity"}, {"type": "depends_on", "label": "Session relies on securely stored credentials for authentication.", "targetId": "financial_services-access-and-identity-management-credentialvaultentry"}, {"type": "depends_on", "label": "Session permissions are determined by access roles.", "targetId": "financial_services-access-and-identity-management-accessrole"}, {"type": "related", "label": "Sessions requiring elevated oversight are linked to privileged session monitoring.", "targetId": "financial_services-access-and-identity-management-privilegedsessionmonitoring"}]'::jsonb, 'sso,authentication,session,userExperience,identityManagement,securityMonitoring,userAudit,privilegedAccess,riskMitigation'::text[], 'Enhances productivity while upholding robust security controls during authentication events.', '2026-03-12 11:47:13.894931', 'SSOSession,singleSignOn'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "singleSignOnSession", "version": 1, "synonyms": ["SSOSession", "singleSignOn"], "updatedAt": "2026-03-13T10:16:53.713Z", "properties": [{"name": "sessionId", "type": "string", "description": "Unique session identifier."}, {"name": "startTime", "type": "date", "description": "Session start time."}, {"name": "expiresAt", "type": "date", "description": "Session expiration time."}], "description": "A session initiated upon successful authentication that allows access to multiple systems without re-authentication.", "relationships": [{"type": "depends_on", "label": "SSO sessions initiated by federated identities.", "targetId": "financial_services-access-and-identity-management-federatedidentity"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-roleassignment', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'roleAssignment', 'Authorization and Entitlement Management', 'The ''roleAssignment'' concept is fundamental in financial services for linking a digital identity to a specific access role, thus establishing precise authorization boundaries based on job functions, compliance mandates, or operational requirements. This enables effective segregation of duties, auditability of access privileges, and prevention of unauthorized actions by ensuring that only qualified persons undertake sensitive operations. It is especially important in environments where multiple roles and permissions interact with core banking, trading, or regulatory systems. In modern financial operations, managing role assignment is critical to supporting internal controls, streamlined onboarding, and dynamic access management. AI agents can be instrumental in automating, monitoring, and validating the lifecycle of role assignments to reduce manual errors and uphold compliance.', '[{"name": "roleName", "type": "string", "description": "Name of the assigned role."}, {"name": "assignedDate", "type": "date", "description": "Date the role was assigned."}, {"name": "isDelegated", "type": "boolean", "description": "Whether the role assignment is a delegation."}, {"name": "roleExpiryDate", "type": "date", "description": "Date beyond which the role assignment will cease to be valid."}, {"name": "assignmentReason", "type": "string", "description": "Business justification or policy basis for the role assignment."}, {"name": "approvalStatus", "type": "enum", "description": "Current approval workflow state (e.g., pending, approved, rejected)."}]'::jsonb, '[{"type": "depends_on", "label": "Assigned to a digital identity.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "parent", "label": "Relates to an access role definition.", "targetId": "financial_services-access-and-identity-management-accessrole"}, {"type": "depends_on", "label": "Enforces segregation of duties constraint for the assigned role.", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}, {"type": "related", "label": "May be referenced in case of detected entitlement violations.", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}, {"type": "related", "label": "Participates in access review campaigns for compliance.", "targetId": "financial_services-access-and-identity-management-accessreviewcampaign"}]'::jsonb, 'role,assignment,authorization,permissions,entitlement,accessControl,auditability,delegation,identityGovernance'::text[], 'Ensures users have least-privilege access required for their functions.', '2026-03-12 11:47:13.93988', 'userRoleMapping,entitlementAssignment'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "roleAssignment", "version": 1, "synonyms": ["userRoleMapping", "entitlementAssignment"], "updatedAt": "2026-03-12T11:50:51.991Z", "properties": [{"name": "roleName", "type": "string", "description": "Name of the assigned role."}, {"name": "assignedDate", "type": "date", "description": "Date the role was assigned."}, {"name": "isDelegated", "type": "boolean", "description": "Whether the role assignment is a delegation."}], "description": "Links a digital identity to an access role, specifying access rights based on defined duties or employment requirements.", "relationships": [{"type": "depends_on", "label": "Assigned to a digital identity.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "parent", "label": "Relates to an access role definition.", "targetId": "financial_services-access-and-identity-management-accessrole"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-accessrole', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'accessRole', 'Authorization and Entitlement Management', 'The ''accessRole'' concept defines a set of permissions granted to identities (users or systems) for the purpose of managing access to resources within financial services operations. Access roles are critical in ensuring that only authorized parties can initiate sensitive activities such as payment instructions, regulatory reporting, and transaction processing, thereby mitigating operational and fraud risks. In the context of financial services, access roles can be tailored to comply with segregation of duties requirements and policy-based access control structures, aligning operations with enterprise risk management. Roles often govern privileged access, application entitlements, and are regularly reviewed during access review campaigns for continued appropriateness. Accurate role definition and assignment underpin the effectiveness of all downstream security and audit processes.', '[{"name": "roleId", "type": "string", "description": "Unique role identifier."}, {"name": "description", "type": "string", "description": "Details about role’s intent or scope."}, {"name": "roleType", "type": "enum", "description": "Specifies whether the role is administrative, operational, audit, or privileged."}, {"name": "roleStatus", "type": "enum", "description": "Indicates the current state of the role (e.g., active, disabled, pending review)."}, {"name": "creationDate", "type": "date", "description": "The date when the role was established in the system."}]'::jsonb, '[{"type": "child", "label": "Assigned to one or more identities.", "targetId": "financial_services-access-and-identity-management-roleassignment"}, {"type": "related", "label": "Defines access policies governing this role", "targetId": "financial_services-access-and-identity-management-policybasedaccesscontrol"}, {"type": "depends_on", "label": "Role assignments are limited by SoD constraints", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}, {"type": "child", "label": "Role is subject to periodic review campaigns", "targetId": "financial_services-access-and-identity-management-accessreviewcampaign"}]'::jsonb, 'role,permissions,entitlement,accessControl,identityManagement,compliance,audit,riskMitigation'::text[], 'Manages groupings of permissions, supporting access consistency and regulatory auditability.', '2026-03-12 11:47:13.984908', 'entitlementRole,accessProfile'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "accessRole", "version": 1, "synonyms": ["entitlementRole", "accessProfile"], "updatedAt": "2026-03-12T11:49:20.873Z", "properties": [{"name": "roleId", "type": "string", "description": "Unique role identifier."}, {"name": "description", "type": "string", "description": "Details about role’s intent or scope."}], "description": "A defined set of permissions that encapsulates what operations a user or system can perform within resources.", "relationships": [{"type": "child", "label": "Assigned to one or more identities.", "targetId": "financial_services-access-and-identity-management-roleassignment"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-policybasedaccesscontrol', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'policyBasedAccessControl', 'Authorization and Entitlement Management', 'Policy-based access control (PBAC) is a dynamic authorization method used by financial institutions to ensure that access to sensitive systems, data, and financial resources is governed by organizational policies. PBAC enables granular access management based on contextual attributes such as user role, transaction purpose, time-of-day, and risk assessment, aligning access privileges with compliance requirements and operational objectives. It is highly adaptable, supporting real-time changes in access policies in response to evolving regulatory mandates, threat intelligence, and business needs. PBAC is critical in mitigating insider threats, preventing entitlement violations, and ensuring audited access to financial and customer information. In AI operations, PBAC allows agents to make access decisions based on current policies, thereby supporting secure automation in tasks like transaction monitoring, AML screening, and privileged access management.', '[{"name": "policyId", "type": "string", "description": "Unique identifier for the policy."}, {"name": "resourceType", "type": "string", "description": "Type of resource governed."}, {"name": "policyType", "type": "enum", "description": "Specifies the category or type of policy (e.g., access, entitlement, risk, compliance)."}, {"name": "policyEffect", "type": "string", "description": "Describes the effect of the policy (e.g., allow, deny, conditional)."}, {"name": "contextAttributes", "type": "string", "description": "List of contextual variables considered during access evaluation."}]'::jsonb, '[{"type": "related", "label": "Roles may enforce policy-based controls.", "targetId": "financial_services-access-and-identity-management-accessrole"}, {"type": "depends_on", "label": "Policy enforcement depends on proper segregation of duties configurations.", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}, {"type": "related", "label": "Policies govern recording of access log entries for audit.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "depends_on", "label": "PBAC relies on authentication policy for primary access validation.", "targetId": "financial_services-access-and-identity-management-authenticationpolicy"}]'::jsonb, 'pbac,accessControl,policy,authorization,attributeBased,dynamicAuthorization,contextAware,securityModel,riskMitigation'::text[], 'Supports dynamic, granular access aligned with regulatory and business requirements.', '2026-03-12 11:47:14.029954', 'attributeBasedAccessControl,PBAC,policyControl'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "policyBasedAccessControl", "version": 1, "synonyms": ["attributeBasedAccessControl", "PBAC", "policyControl"], "updatedAt": "2026-03-12T11:49:44.368Z", "properties": [{"name": "policyId", "type": "string", "description": "Unique identifier for the policy."}, {"name": "resourceType", "type": "string", "description": "Type of resource governed."}], "description": "Access determination governed by organizational policies, often dynamic, based on attributes and context.", "relationships": [{"type": "related", "label": "Roles may enforce policy-based controls.", "targetId": "financial_services-access-and-identity-management-accessrole"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-privilegedaccessgrant', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'privilegedAccessGrant', 'Authorization and Entitlement Management', 'In financial services operations, a privilegedAccessGrant is a mechanism for temporarily or permanently assigning elevated permissions to specific users or agents, typically above those granted to standard user roles. These grants are used to enable trusted individuals to perform sensitive actions such as system administration, confidential data access, or critical workflow interventions that affect financial and regulatory processes. Effective management of privilegedAccessGrants is essential to ensure that only authorized personnel can access highly sensitive systems or execute high-impact changes, preventing misuse or unauthorized disclosure. This process often requires multi-step approval workflows, audit trails, and continuous monitoring to ensure compliance, security, and operational integrity. Integrating privilegedAccessGrant management with AI agents can enhance real-time tracking, automate reviews, and detect anomalous activities.', '[{"name": "grantId", "type": "string", "description": "Identifier for the privileged access grant."}, {"name": "expirationDate", "type": "date", "description": "Date/time of privilege revocation."}, {"name": "approvedBy", "type": "string", "description": "Approver identity for elevated access."}, {"name": "reasonForGrant", "type": "string", "description": "Justification or business case for granting privileged access."}, {"name": "accessScope", "type": "string", "description": "Defines the systems, applications, or data domains covered by the grant."}, {"name": "isEmergency", "type": "boolean", "description": "Indicates if the privileged access grant was made under emergency circumstances."}, {"name": "auditTrailReference", "type": "string", "description": "Link or identifier to audit logs associated with the privileged access grant."}]'::jsonb, '[{"type": "depends_on", "label": "Privileged access is tied to specific roles.", "targetId": "financial_services-access-and-identity-management-accessrole"}, {"type": "related", "label": "Privileged access grants should be reviewed in scheduled access reviews", "targetId": "financial_services-access-and-identity-management-accessreviewcampaign"}, {"type": "related", "label": "Privileged access grants must be tracked via access log entries", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "depends_on", "label": "Privileged access grants must comply with SoD constraints", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}]'::jsonb, 'privilegedAccess,PAM,elevated,authorization,auditTrail,leastPrivilege,compliance,identityGovernance'::text[], 'Critical for operationally sensitive systems and regulatory controls (e.g., SOX, GLBA).', '2026-03-12 11:47:14.074792', 'PAMGrant,elevatedAccess'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "privilegedAccessGrant", "version": 1, "synonyms": ["PAMGrant", "elevatedAccess"], "updatedAt": "2026-03-12T11:50:20.401Z", "properties": [{"name": "grantId", "type": "string", "description": "Identifier for the privileged access grant."}, {"name": "expirationDate", "type": "date", "description": "Date/time of privilege revocation."}, {"name": "approvedBy", "type": "string", "description": "Approver identity for elevated access."}], "description": "Temporary or persistent assignment granting elevated permissions above standard user roles, often requiring additional approvals.", "relationships": [{"type": "depends_on", "label": "Privileged access is tied to specific roles.", "targetId": "financial_services-access-and-identity-management-accessrole"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-accessreviewcampaign', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'accessReviewCampaign', 'Access Governance and Segregation of Duties', 'An accessReviewCampaign is a structured process, typically initiated on a periodic basis, within financial services organizations to validate that access privileges granted to employees, contractors, and systems remain appropriate. These campaigns involve managers reviewing all role assignments and access privileges, attesting their accuracy, and identifying unnecessary or excessive permissions, ensuring access remains strictly aligned to job functions and compliance policies. Access review campaigns are critical for preventing entitlement violations, orphan accounts, and mitigating risks associated with privileged access. They directly support segregation of duties (SoD) constraints as part of broader access governance, helping to detect and remediate potential conflicts of interest and unauthorized access. This process is fundamental for maintaining a secure and compliant operational environment where financial data and sensitive assets are protected.', '[{"name": "campaignId", "type": "string", "description": "ID for this access review."}, {"name": "startDate", "type": "date", "description": "When the campaign begins."}, {"name": "endDate", "type": "date", "description": "When the campaign ends."}, {"name": "reviewFrequency", "type": "enum", "description": "Specifies how often the campaign is conducted (e.g., quarterly, annually)."}, {"name": "campaignStatus", "type": "enum", "description": "Current status of the campaign such as ''scheduled'', ''in progress'', or ''completed''."}, {"name": "managerAttestationRate", "type": "decimal", "description": "The percentage of reviewers who have completed attestations."}, {"name": "findingsSummary", "type": "string", "description": "Brief summary of key issues or findings identified during this campaign."}]'::jsonb, '[{"type": "related", "label": "Role assignments reviewed in each campaign.", "targetId": "financial_services-access-and-identity-management-roleassignment"}, {"type": "related", "label": "Campaign outcomes may uncover entitlement violations.", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}, {"type": "related", "label": "Campaign identifies orphan accounts for remediation.", "targetId": "financial_services-access-and-identity-management-orphanaccount"}, {"type": "depends_on", "label": "Review campaigns depend on SoD constraints for policy enforcement.", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}]'::jsonb, 'review,attestation,governance,compliance,identity-management,audit,user-access,remediation'::text[], 'Meets compliance mandates and prevents unauthorized access creep.', '2026-03-12 11:47:14.119144', 'accessCertification,entitlementReview'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "accessReviewCampaign", "version": 1, "synonyms": ["accessCertification", "entitlementReview"], "updatedAt": "2026-03-12T11:51:14.811Z", "properties": [{"name": "campaignId", "type": "string", "description": "ID for this access review."}, {"name": "startDate", "type": "date", "description": "When the campaign begins."}, {"name": "endDate", "type": "date", "description": "When the campaign ends."}], "description": "A formal, periodic process requiring managers and system owners to review and attest to the appropriateness of user access.", "relationships": [{"type": "related", "label": "Role assignments reviewed in each campaign.", "targetId": "financial_services-access-and-identity-management-roleassignment"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-segregationofdutiesconstraint', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'segregationOfDutiesConstraint', 'Access Governance and Segregation of Duties', 'The ''segregationOfDutiesConstraint'' concept is central to access governance in financial services, establishing rules to prevent the same individual from holding roles with conflicting responsibilities. These constraints are critical in operational areas like payment processing, transaction approvals, and risk management, where assigning overlapping duties may lead to unchecked activity and increased risk of fraud or errors. By formally documenting conflicting role assignments, organizations maintain robust internal controls and demonstrate adherence to best practices. AI agents can automate policy enforcement, detect violations, and optimize role assignments efficiently. The concept materially enhances organizational integrity by minimizing opportunities for collusion or manipulation.', '[{"name": "constraintId", "type": "string", "description": "SOD constraint unique identifier."}, {"name": "conflictDescription", "type": "string", "description": "Description of the conflict being prevented."}, {"name": "constraintSeverity", "type": "enum", "description": "Level or impact of violation if the constraint is breached (e.g., low, medium, high)."}, {"name": "remediationAction", "type": "string", "description": "Recommended actions when a constraint violation is detected."}, {"name": "lastReviewedDate", "type": "date", "description": "Date when the SOD constraint was last reviewed for relevance and accuracy."}]'::jsonb, '[{"type": "parent", "label": "Defines constraints between roles.", "targetId": "financial_services-access-and-identity-management-accessrole"}, {"type": "related", "label": "Potential violation detected relating to SOD constraints.", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}, {"type": "depends_on", "label": "Relies on accurate role assignment information.", "targetId": "financial_services-access-and-identity-management-roleassignment"}, {"type": "related", "label": "Connected to detection of anomalous access events linked to SOD breaches.", "targetId": "financial_services-access-and-identity-management-anomalousaccessevent"}]'::jsonb, 'sod,risk,conflict,internalControl,internalAudit,accessControl,fraudPrevention,compliance,policyEnforcement'::text[], 'Mitigates operational and compliance risks through control enforcement.', '2026-03-12 11:47:14.165039', 'SODRule,dutySeparation'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "segregationOfDutiesConstraint", "version": 1, "synonyms": ["SODRule", "dutySeparation"], "updatedAt": "2026-03-12T11:51:38.557Z", "properties": [{"name": "constraintId", "type": "string", "description": "SOD constraint unique identifier."}, {"name": "conflictDescription", "type": "string", "description": "Description of the conflict being prevented."}], "description": "A policy or rule that prevents the assignment of conflicting access roles to a single identity, reducing risk of fraud or error.", "relationships": [{"type": "parent", "label": "Defines constraints between roles.", "targetId": "financial_services-access-and-identity-management-accessrole"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-orphanaccount', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'orphanAccount', 'Access Governance and Segregation of Duties', 'An orphanAccount is a system account within financial services operations that lacks an active, valid user association, commonly arising from incomplete de-provisioning or employee changes. Its existence poses significant operational risk, as it may allow unauthorized access, privilege escalation, or misuse of sensitive financial systems. OrphanAccounts must be rapidly identified and remediated to ensure robust access governance, reduce the risk of fraudulent transactions, and satisfy audit requirements. Financial organizations routinely monitor for orphanAccounts as part of broader segregation of duties (SoD) and digital identity controls. Proactive management of orphanAccounts mitigates the likelihood of compromise and supports safe, compliant running of financial infrastructure.', '[{"name": "accountId", "type": "string", "description": "Unique identifier of the orphan account."}, {"name": "detectedDate", "type": "date", "description": "When the orphan status was discovered."}, {"name": "lastActivityTimestamp", "type": "date", "description": "Timestamp of the last activity or access attempt by the orphan account."}, {"name": "accountType", "type": "enum", "description": "Classification of the orphan account, such as service, privileged, or user account."}, {"name": "remediationStatus", "type": "enum", "description": "Current status of the remediation process (pending, in-progress, resolved, escalated)."}]'::jsonb, '[{"type": "child", "label": "Represents loss of linkage to identity.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "related", "label": "Tracks log records generated by the orphan account", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "related", "label": "Links orphan accounts to detected access entitlement violations", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}, {"type": "depends_on", "label": "Leverages privileged session monitoring for orphan account risk assessment", "targetId": "financial_services-access-and-identity-management-privilegedsessionmonitoring"}]'::jsonb, 'orphan,account,risk,remediation,identity-management,access-control,audit-trail,security-monitoring'::text[], 'Highlights risks due to lost ownership or offboarding failures.', '2026-03-12 11:47:14.21011', 'unlinkedAccount,rogueAccount'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "orphanAccount", "version": 1, "synonyms": ["unlinkedAccount", "rogueAccount"], "updatedAt": "2026-03-12T11:52:30.954Z", "properties": [{"name": "accountId", "type": "string", "description": "Unique identifier of the orphan account."}, {"name": "detectedDate", "type": "date", "description": "When the orphan status was discovered."}], "description": "An active system account without an associated or valid user, potentially exposing the system to unauthorized use.", "relationships": [{"type": "child", "label": "Represents loss of linkage to identity.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-entitlementviolation', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'entitlementViolation', 'Access Governance and Segregation of Duties', 'An entitlementViolation arises when a user or system accesses resources or functions that exceed their authorized entitlements or contravene defined segregation of duties (SoD) constraints. In financial services, such violations can expose institutions to significant risks including fraud, unauthorized trading, or data leakage, potentially undermining customer trust and operational integrity. Proactive detection and management of entitlementViolations are critical for maintaining secure access governance, especially in highly regulated environments. These events commonly trigger investigative workflows, access reviews, and remedial actions such as revocation of excessive privileges or tightening of access controls. Effective integration with AI-driven monitoring improves real-time detection and response capabilities, reducing manual workload and accelerating compliance workflows.', '[{"name": "violationId", "type": "string", "description": "Identifier for the violation."}, {"name": "detectedOn", "type": "date", "description": "Date/time the violation was detected."}, {"name": "violationType", "type": "enum", "description": "Categorizes the type of violation, such as excess privilege, SoD conflict, or unauthorized access."}, {"name": "severityLevel", "type": "enum", "description": "Indicates the risk impact or urgency level of the violation for remediation prioritization."}, {"name": "affectedEntityId", "type": "string", "description": "Identifier for the user, account, or system implicated in the violation."}, {"name": "remediationStatus", "type": "enum", "description": "Tracks whether the violation has been addressed, is pending, or unresolved."}]'::jsonb, '[{"type": "depends_on", "label": "Violations tied to role assignments.", "targetId": "financial_services-access-and-identity-management-roleassignment"}, {"type": "related", "label": "Relation to excessive or unauthorized privileged access grants.", "targetId": "financial_services-access-and-identity-management-privilegedaccessgrant"}, {"type": "related", "label": "Correlation with specific access events recorded in logs.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "depends_on", "label": "Violations tied to breaches of SoD constraints.", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}]'::jsonb, 'violation,entitlement,sod,compliance,auditability,accessControl,identityManagement,riskDetection,incidentResponse'::text[], 'Drives remediation and audit response for improper access.', '2026-03-12 11:47:14.256919', 'policyViolation,entitlementBreach'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "entitlementViolation", "version": 1, "synonyms": ["policyViolation", "entitlementBreach"], "updatedAt": "2026-03-12T11:52:07.567Z", "properties": [{"name": "violationId", "type": "string", "description": "Identifier for the violation."}, {"name": "detectedOn", "type": "date", "description": "Date/time the violation was detected."}], "description": "An event or detection where a user or system possesses access beyond their defined entitlements or in conflict with SOD policies.", "relationships": [{"type": "depends_on", "label": "Violations tied to role assignments.", "targetId": "financial_services-access-and-identity-management-roleassignment"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-accesslogentry', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'accessLogEntry', 'Access Analytics and Monitoring', 'An accessLogEntry serves as the foundational unit for auditing and monitoring within financial services environments, providing granular visibility into every access attempt made on critical systems and applications. Each entry chronicles the identity involved, the precise timestamp, and the specific action taken, thereby enabling traceability across operational workflows. Such records underpin forensic analysis, help meet regulatory audit requirements, and drive risk mitigation by highlighting unauthorized or suspicious access behaviors. In an era of heightened cybersecurity threats, the accessLogEntry plays a crucial role in securing sensitive financial data and ensuring accountability for privileged operations. It enables rapid incident response and ongoing compliance oversight, particularly in regulated financial institutions.', '[{"name": "timestamp", "type": "date", "description": "When the access occurred."}, {"name": "identityId", "type": "string", "description": "Identity associated with the using account."}, {"name": "action", "type": "string", "description": "Type of action (login, file access, admin command, privileged action, etc.)."}, {"name": "sourceIpAddress", "type": "string", "description": "IP address from which the access was attempted."}, {"name": "statusCode", "type": "enum", "description": "Result of the access attempt (success, failure, locked, etc.)."}, {"name": "userAgent", "type": "string", "description": "Application or tool used to perform the access action."}]'::jsonb, '[{"type": "depends_on", "label": "Entry relates to specific identity actions.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}, {"type": "related", "label": "Log entries contribute data to privileged session oversight.", "targetId": "financial_services-access-and-identity-management-privilegedsessionmonitoring"}, {"type": "child", "label": "Entry may trigger or be classified as an anomalous access event.", "targetId": "financial_services-access-and-identity-management-anomalousaccessevent"}, {"type": "depends_on", "label": "Entry creation is influenced by policy-based access control configurations.", "targetId": "financial_services-access-and-identity-management-policybasedaccesscontrol"}]'::jsonb, 'log,audit,access,security,auditTrail,incidentDetection,forensics,operationalAnalytics'::text[], 'Enables incident detection, forensics, and regulatory audit support.', '2026-03-12 11:47:14.301492', 'accessAudit,eventLog'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "accessLogEntry", "version": 1, "synonyms": ["accessAudit", "eventLog"], "updatedAt": "2026-03-12T13:23:35.532Z", "properties": [{"name": "timestamp", "type": "date", "description": "When the access occurred."}, {"name": "identityId", "type": "string", "description": "Identity associated with the using account."}, {"name": "action", "type": "string", "description": "Type of action (login, file access, admin command, privileged action, etc.)."}], "description": "A detailed record of each access attempt to systems or applications, including information about the identity, time, and action performed.", "relationships": [{"type": "depends_on", "label": "Entry relates to specific identity actions.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-anomalousaccessevent', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'anomalousAccessEvent', 'Access Analytics and Monitoring', 'An anomalousAccessEvent represents a detected access incident that diverges from expected user behavior, historical access patterns, or organizational access control policies. In financial services, this concept is critical for identifying potential insider threats, compromised credentials, or attempts at unauthorized data exfiltration. Such events trigger security operations and forensic investigation workflows, often resulting in escalated reviews and possible corporate response actions. The ability to track and analyze anomalousAccessEvents enhances organizational resilience and supports real-time threat mitigation, especially in highly regulated environments. AI agents can play a pivotal role by automating event correlation, risk scoring, and incident escalation throughout the operational lifecycle.', '[{"name": "eventId", "type": "string", "description": "Unique identifier for the anomalous event."}, {"name": "detectionDate", "type": "date", "description": "When the anomaly was detected."}, {"name": "eventType", "type": "string", "description": "Type or reason for anomaly (location mismatch, velocity rule, etc.)."}, {"name": "affectedUserId", "type": "string", "description": "Identifier for the user whose access triggered the anomaly."}, {"name": "riskScore", "type": "decimal", "description": "Quantitative assessment of the event''s severity or potential impact."}, {"name": "resolutionStatus", "type": "enum", "description": "Indicates current status of event investigation (open, in review, resolved)."}, {"name": "sourceDevice", "type": "string", "description": "Device or endpoint from which the anomalous access was attempted."}]'::jsonb, '[{"type": "related", "label": "Anomaly detected in access logs.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "depends_on", "label": "Anomaly assessed against policy-based access rules", "targetId": "financial_services-access-and-identity-management-policybasedaccesscontrol"}, {"type": "related", "label": "Cross-referenced with privileged session activity", "targetId": "financial_services-access-and-identity-management-privilegedsessionmonitoring"}, {"type": "depends_on", "label": "Evaluated for SoD policy violations", "targetId": "financial_services-access-and-identity-management-segregationofdutiesconstraint"}]'::jsonb, 'anomaly,monitoring,security,threat,incident,audit,forensic,accessViolations,identityRisk'::text[], 'Key for rapid detection and investigation of potential access-related security incidents.', '2026-03-12 11:47:14.346233', 'anomalyEvent,accessAlert'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "anomalousAccessEvent", "version": 1, "synonyms": ["anomalyEvent", "accessAlert"], "updatedAt": "2026-03-13T08:59:30.800Z", "properties": [{"name": "eventId", "type": "string", "description": "Unique identifier for the anomalous event."}, {"name": "detectionDate", "type": "date", "description": "When the anomaly was detected."}, {"name": "eventType", "type": "string", "description": "Type or reason for anomaly (location mismatch, velocity rule, etc.)."}], "description": "A flagged access event that deviates from historical patterns or violates access policies, indicating potential insider threat or compromise.", "relationships": [{"type": "related", "label": "Anomaly detected in access logs.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-privilegedsessionmonitoring', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'privilegedSessionMonitoring', 'Access Analytics and Monitoring', 'PrivilegedSessionMonitoring is a critical element in financial services operations for tracking and recording sessions initiated by users with privileged or administrative access. Such sessions often involve sensitive changes to configurations, access to confidential data, and the ability to execute high-impact actions, making their monitoring essential for both security and audit purposes. Automated monitoring helps detect and prevent misuse or unauthorized activities by privileged users, and facilitates forensic investigations in case of incidents. In financial institutions, privileged session oversight is mandated to ensure adherence to internal controls, support for regulatory auditing, and to safeguard client and transactional information. Advanced analytics can be deployed to flag anomalous actions in real-time, enabling timely escalation and response.', '[{"name": "sessionId", "type": "string", "description": "Session identifier being monitored."}, {"name": "startTime", "type": "date", "description": "Start time of session."}, {"name": "recordingStatus", "type": "enum", "description": "If session activity is being recorded (active, completed, error)."}, {"name": "endTime", "type": "date", "description": "Timestamp when the privileged session ended."}, {"name": "userId", "type": "string", "description": "Identifier of the user conducting the privileged session."}, {"name": "sessionType", "type": "enum", "description": "Nature of session (interactive, API, scheduled task)."}, {"name": "ipAddress", "type": "string", "description": "Network address from which the session was initiated."}]'::jsonb, '[{"type": "depends_on", "label": "Monitors sessions with elevated rights.", "targetId": "financial_services-access-and-identity-management-privilegedaccessgrant"}, {"type": "related", "label": "Links session monitoring to detailed access log entries.", "targetId": "financial_services-access-and-identity-management-accesslogentry"}, {"type": "related", "label": "Correlates monitored sessions with entitlement violations.", "targetId": "financial_services-access-and-identity-management-entitlementviolation"}, {"type": "related", "label": "Flags session activities that trigger anomalous access events.", "targetId": "financial_services-access-and-identity-management-anomalousaccessevent"}]'::jsonb, 'PAM,monitoring,sessionRecording,audit,cybersecurity,auditTrail,identityGovernance,realTimeAnalytics,regulatoryCompliance'::text[], 'Essential for compliance with regulations and deterring misuse by privileged actors.', '2026-03-12 11:47:14.390397', 'privSessionMonitor,PAMSession'::text[], 'ai-subdomain', 0, '[]'::jsonb, 2, '[{"label": "privilegedSessionMonitoring", "version": 1, "synonyms": ["privSessionMonitor", "PAMSession"], "updatedAt": "2026-03-13T08:59:49.720Z", "properties": [{"name": "sessionId", "type": "string", "description": "Session identifier being monitored."}, {"name": "startTime", "type": "date", "description": "Start time of session."}, {"name": "recordingStatus", "type": "enum", "description": "If session activity is being recorded (active, completed, error)."}], "description": "Monitoring and recording of live sessions by users with privileged or administrative access for audit and security.", "relationships": [{"type": "depends_on", "label": "Monitors sessions with elevated rights.", "targetId": "financial_services-access-and-identity-management-privilegedaccessgrant"}], "linkedRegulations": []}]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-credentialvaultentry', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'credentialVaultEntry', 'Credential and Secret Management', 'A record within a secure stores that manages credentials and secrets for identities, systems, and applications, with access controls and auditability.', '[{"name": "vaultId", "type": "string", "description": "Vault system managing the credential."}, {"name": "entryName", "type": "string", "description": "Name or label for the secret entry."}, {"name": "secretType", "type": "string", "description": "Type of secret (password, API key, SSH key, certificate)."}]'::jsonb, '[{"type": "related", "label": "Entry may belong to an identity.", "targetId": "financial_services-access-and-identity-management-digitalidentity"}]'::jsonb, 'credential,secret,vault,access'::text[], 'Centralizes secure management of credentials and machine secrets, reducing risk of exposure.', '2026-03-12 11:47:14.43591', 'secretEntry,vaultSecret'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-passwordpolicy', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'passwordPolicy', 'Credential and Secret Management', 'A set of rules governing how user and system passwords must be created, used, and rotated for security.', '[{"name": "minLength", "type": "integer", "description": "Minimum password length."}, {"name": "complexityRequirements", "type": "string", "description": "Requirements for special characters, numbers, etc."}, {"name": "rotationPeriodDays", "type": "integer", "description": "Password expiry/rotation interval."}]'::jsonb, '[{"type": "related", "label": "Password policy part of authentication requirements.", "targetId": "financial_services-access-and-identity-management-authenticationpolicy"}]'::jsonb, 'password,policy,security,credential'::text[], 'Prevents weak passwords and complies with organizational and regulatory security requirements.', '2026-03-12 11:47:14.480492', 'passwordRule,passcodePolicy'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-apikeymanagement', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'apiKeyManagement', 'Credential and Secret Management', 'Processes and tools for issuing, revoking, and managing API keys, ensuring service-level authentication is secure and auditable.', '[{"name": "apiKeyId", "type": "string", "description": "Unique API key identifier."}, {"name": "issuedTo", "type": "string", "description": "Identity or application the API key is issued to."}]'::jsonb, '[{"type": "related", "label": "API keys stored securely in vault.", "targetId": "financial_services-access-and-identity-management-credentialvaultentry"}]'::jsonb, 'apiKey,secrets,machineIdentity,access'::text[], 'Critical for secure digital infrastructure, microservices, and partner integrations.', '2026-03-12 11:47:14.524876', 'apiSecret,serviceCredential'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-access-and-identity-management-certificatelifecycleevent', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'certificateLifecycleEvent', 'Credential and Secret Management', 'Tracks issuance, renewal, expiration, and revocation of digital certificates used for identity and encrypted communication.', '[{"name": "certificateId", "type": "string", "description": "Identifier for the certificate."}, {"name": "eventType", "type": "enum", "description": "Type of lifecycle event (issued, renewed, revoked, expired)."}]'::jsonb, '[{"type": "depends_on", "label": "Certificate events tracked per vault entry.", "targetId": "financial_services-access-and-identity-management-credentialvaultentry"}]'::jsonb, 'certificate,PKI,lifecycle,encryption'::text[], 'Supports risk reduction and compliance for SSL/TLS, device, and user certificate management.', '2026-03-12 11:47:14.569324', 'certEvent,pkiEvent'::text[], 'ai-subdomain', 0, '[]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-issuer', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Issuer', 'Rated Entities', 'A legal entity whose debt obligations or financial instruments are subject to credit rating assessment. The Issuer entity is the central node in the credit assessment graph, linking financial periods, earnings data, peer comparisons, scorecards, credit events, and the final assessment package. Each issuer carries ESG IPS scores (Environmental, Social, Governance), a Credit Impact Score (CIS), sector/sub-sector classification, and is assigned to an analyst for ongoing surveillance.', '[{"name": "issuerId", "type": "string", "description": "Unique identifier for the rated entity"}, {"name": "name", "type": "string", "description": "Legal name of the issuer"}, {"name": "ticker", "type": "string", "description": "Stock ticker symbol (if publicly traded)"}, {"name": "sector", "type": "string", "description": "Primary sector classification per Moody s methodology"}, {"name": "subSector", "type": "string", "description": "Sub-sector classification for peer grouping"}, {"name": "country", "type": "string", "description": "Country of domicile (ISO 3166-1)"}, {"name": "currentRating", "type": "string", "description": "Currently assigned credit rating (e.g., Baa1, A3)"}, {"name": "outlook", "type": "enum", "description": "Rating outlook: Stable, Positive, Negative, Developing, Ratings Under Review"}, {"name": "lastReviewDate", "type": "date", "description": "Date of most recent rating committee review"}, {"name": "assignedAnalyst", "type": "string", "description": "Lead analyst responsible for ongoing surveillance"}, {"name": "ipsScores", "type": "object", "description": "ESG Issuer Profile Scores — Environmental (E), Social (S), Governance (G) on 1-5 scale"}, {"name": "cisScore", "type": "enum", "description": "Credit Impact Score from CIS-1 (positive) to CIS-5 (very highly negative)"}]'::jsonb, '[{"type": "parent", "label": "Has financial periods", "targetId": "financial_services-credit-rating-financial-period"}, {"type": "parent", "label": "Has earnings calls", "targetId": "financial_services-credit-rating-earnings-call"}, {"type": "related", "label": "Belongs to peer group", "targetId": "financial_services-credit-rating-peer-group"}, {"type": "parent", "label": "Evaluated by scorecard", "targetId": "financial_services-credit-rating-scorecard"}, {"type": "parent", "label": "Subject of credit events", "targetId": "financial_services-credit-rating-credit-event"}, {"type": "parent", "label": "Packaged in assessment", "targetId": "financial_services-credit-rating-assessment-package"}]'::jsonb, 'Credit Rating,Issuer,ESG,CIS,IPS,Rated Entity,Surveillance'::text[], NULL, '2026-03-17 02:11:33.638265', 'Rated Entity,Obligor,Debt Issuer'::text[], 'industry-standard', 0, '[{"name": "NRSRO", "description": "Nationally Recognized Statistical Rating Organization requirements"}, {"name": "SEC 17g-7", "description": "SEC Rule 17g-7 rating action disclosure requirements"}, {"name": "MiFID II", "description": "Markets in Financial Instruments Directive II — credit rating transparency"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-financial-period', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'FinancialPeriod', 'Quantitative & Qualitative Analysis', 'A discrete reporting period for an issuer containing spread financial statements, chart of accounts mappings, and computed credit metrics. Each period captures the accounting standard used (US GAAP or IFRS), the spreading status, and any anomaly flags detected during automated data ingestion. Financial periods feed directly into the rating scorecard as quantitative inputs and support 8-quarter trend analysis for credit metric trajectories.', '[{"name": "periodId", "type": "string", "description": "Unique identifier for the financial period"}, {"name": "issuerId", "type": "string", "description": "Reference to the parent Issuer entity"}, {"name": "periodEnd", "type": "date", "description": "End date of the reporting period (e.g., 2024-12-31)"}, {"name": "standard", "type": "enum", "description": "Accounting standard: USGAAP or IFRS, auto-detected during spreading"}, {"name": "spreadStatus", "type": "enum", "description": "Status of financial spreading: pending, in-progress, complete, error"}, {"name": "chartOfAccounts", "type": "object", "description": "Mapped line items from raw financials to standardized Chart of Accounts"}, {"name": "creditMetrics", "type": "object", "description": "Computed sector-specific credit metrics (leverage, coverage, profitability, liquidity)"}, {"name": "anomalyFlags", "type": "array", "description": "Data quality or outlier flags detected during automated spreading"}]'::jsonb, '[{"type": "depends_on", "label": "Belongs to issuer", "targetId": "financial_services-credit-rating-issuer"}, {"type": "related", "label": "Feeds into scorecard", "targetId": "financial_services-credit-rating-scorecard"}]'::jsonb, 'Financial Spreading,IFRS,US GAAP,Credit Metrics,Anomaly Detection,Chart of Accounts,Trend Analysis'::text[], NULL, '2026-03-17 02:11:33.957555', 'Reporting Period,Fiscal Period,Financial Statement Period'::text[], 'industry-standard', 0, '[{"name": "IFRS 9", "description": "International Financial Reporting Standard 9 — Financial Instruments"}, {"name": "US GAAP ASC 320", "description": "Accounting Standards Codification 320 — Investments in Debt Securities"}, {"name": "NRSRO", "description": "NRSRO analytical documentation requirements"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-earnings-call', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'EarningsCall', 'Quantitative & Qualitative Analysis', 'A quarterly earnings call transcript and its derived analytical artifacts for an issuer. Captures the full transcript text, AI-computed sentiment scores (overall, forward-looking, risk-aware), extracted key management quotes, and a structured guidance summary. Earnings calls provide critical qualitative signals for credit assessment including management tone shifts, forward guidance changes, and sector-specific risk disclosures that inform the rating scorecard.', '[{"name": "callId", "type": "string", "description": "Unique identifier for the earnings call record"}, {"name": "issuerId", "type": "string", "description": "Reference to the parent Issuer entity"}, {"name": "quarter", "type": "string", "description": "Fiscal quarter designation (e.g., Q3 2024, FY 2024)"}, {"name": "transcript", "type": "text", "description": "Full earnings call transcript text from FactSet/LSEG"}, {"name": "sentimentScores", "type": "object", "description": "AI-computed sentiment scores: overall, forward-looking, risk-aware, with quarter-over-quarter delta"}, {"name": "keyQuotes", "type": "array", "description": "Extracted notable management quotes with topic tags and credit relevance scores"}, {"name": "guidanceSummary", "type": "text", "description": "Structured summary of forward guidance: revenue, margins, capex, debt targets"}]'::jsonb, '[{"type": "depends_on", "label": "Belongs to issuer", "targetId": "financial_services-credit-rating-issuer"}, {"type": "related", "label": "Informs scorecard", "targetId": "financial_services-credit-rating-scorecard"}]'::jsonb, 'Earnings,Sentiment Analysis,Management Tone,Guidance,Transcript,Qualitative Signal'::text[], NULL, '2026-03-17 02:11:34.06118', 'Earnings Transcript,Quarterly Call,Investor Call'::text[], 'industry-standard', 0, '[{"name": "Reg FD", "description": "SEC Regulation Fair Disclosure — material information dissemination"}, {"name": "SEC 17g-7", "description": "SEC Rule 17g-7 — information sources disclosure"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-peer-group', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'PeerGroup', 'Quantitative & Qualitative Analysis', 'A curated set of 5-10 comparable issuers within the same sector/sub-sector classification used for relative credit metric benchmarking. The peer group is identified via Moody s sector taxonomy and contains a comparison matrix of key credit metrics with rankings, outlier flags, and percentile positions. Peer groups are refreshed at each assessment cycle and directly inform the scorecard through relative positioning of the target issuer against its peers.', '[{"name": "groupId", "type": "string", "description": "Unique identifier for the peer group"}, {"name": "sectorId", "type": "string", "description": "Sector/sub-sector classification used for peer selection"}, {"name": "memberIssuers", "type": "array", "description": "Array of issuer IDs comprising the peer group (5-10 members)"}, {"name": "benchmarkDate", "type": "date", "description": "Date when the peer comparison was computed"}, {"name": "metrics", "type": "object", "description": "Comparison matrix of credit metrics across all peers with rankings and outlier flags"}]'::jsonb, '[{"type": "related", "label": "Contains member issuers", "targetId": "financial_services-credit-rating-issuer"}, {"type": "related", "label": "Benchmarks against scorecard", "targetId": "financial_services-credit-rating-scorecard"}]'::jsonb, 'Peer Analysis,Benchmarking,Sector,Comparison Matrix,Relative Positioning'::text[], NULL, '2026-03-17 02:11:34.076863', 'Peer Set,Comparable Group,Peer Comparison Set'::text[], 'industry-standard', 0, '[{"name": "NRSRO", "description": "NRSRO analytical documentation — peer comparison justification"}, {"name": "IOSCO", "description": "IOSCO Code of Conduct for Credit Rating Agencies — comparability"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-scorecard', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'Scorecard', 'Rating Methodologies', 'A sector-specific rating scorecard that aggregates quantitative inputs (from FinancialPeriod data) and qualitative assessments (from EarningsCall signals, CreditEvents, and analyst judgment) to produce an indicated rating outcome. The scorecard follows a published methodology version, computes factor-weighted scores, produces a scorecard-indicated rating, and performs gap analysis against the currently assigned rating. It is the central analytical artifact in the credit assessment workflow.', '[{"name": "scorecardId", "type": "string", "description": "Unique identifier for the scorecard instance"}, {"name": "issuerId", "type": "string", "description": "Reference to the Issuer being evaluated"}, {"name": "methodologyVersion", "type": "string", "description": "Version of the published rating methodology applied"}, {"name": "quantitativeInputs", "type": "object", "description": "Numeric factor inputs from financial spreading and credit metrics"}, {"name": "qualitativeAssessments", "type": "object", "description": "Qualitative factor assessments from analyst judgment, earnings signals, and events"}, {"name": "indicatedOutcome", "type": "string", "description": "Scorecard-indicated rating based on weighted factor scores"}, {"name": "currentRating", "type": "string", "description": "Currently assigned rating for gap comparison"}, {"name": "gapAnalysis", "type": "text", "description": "Analysis of gap between scorecard-indicated and assigned rating with justification"}]'::jsonb, '[{"type": "depends_on", "label": "Evaluates issuer", "targetId": "financial_services-credit-rating-issuer"}, {"type": "depends_on", "label": "Draws from financial periods", "targetId": "financial_services-credit-rating-financial-period"}, {"type": "depends_on", "label": "Draws from earnings calls", "targetId": "financial_services-credit-rating-earnings-call"}, {"type": "depends_on", "label": "References peer group", "targetId": "financial_services-credit-rating-peer-group"}, {"type": "related", "label": "Component of assessment package", "targetId": "financial_services-credit-rating-assessment-package"}]'::jsonb, 'Rating Scorecard,Methodology,Gap Analysis,Quantitative,Qualitative,Factor Weighting'::text[], NULL, '2026-03-17 02:11:34.080837', 'Rating Grid,Credit Scorecard,Methodology Scorecard'::text[], 'industry-standard', 0, '[{"name": "NRSRO", "description": "NRSRO methodology consistency and documentation requirements"}, {"name": "MiFID II", "description": "MiFID II rating methodology transparency"}, {"name": "IOSCO", "description": "IOSCO Code — rating methodology application and disclosure"}, {"name": "SEC Reg AC", "description": "SEC Regulation AC — analyst certification of rating basis"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-credit-event', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'CreditEvent', 'Credit Event Monitoring', 'A credit-relevant event affecting an issuer detected through news scanning, regulatory filing monitoring, or market data analysis. Each event is classified by type (M&A, restructuring, default, regulatory action, litigation, earnings surprise), assessed for credit relevance (material, contextual, informational), and tagged with potential rating impact direction (positive, negative, neutral, developing). Credit events feed into the assessment package and may trigger ad-hoc rating reviews.', '[{"name": "eventId", "type": "string", "description": "Unique identifier for the credit event"}, {"name": "issuerId", "type": "string", "description": "Reference to the affected Issuer entity"}, {"name": "eventDate", "type": "date", "description": "Date the event occurred or was first reported"}, {"name": "eventType", "type": "enum", "description": "Classification: merger_acquisition, restructuring, default, regulatory_action, litigation, earnings_surprise, management_change"}, {"name": "description", "type": "text", "description": "Narrative description of the event and its context"}, {"name": "creditRelevance", "type": "enum", "description": "Relevance classification: material, contextual, informational"}, {"name": "impactDirection", "type": "enum", "description": "Potential rating impact: positive, negative, neutral, developing"}, {"name": "sources", "type": "array", "description": "Array of source references (news URLs, filing IDs, database entries)"}]'::jsonb, '[{"type": "depends_on", "label": "Affects issuer", "targetId": "financial_services-credit-rating-issuer"}, {"type": "related", "label": "Captured in assessment package", "targetId": "financial_services-credit-rating-assessment-package"}]'::jsonb, 'Credit Event,Default,Rating Action,Restructuring,News,Material Event,Surveillance'::text[], NULL, '2026-03-17 02:11:34.086646', 'Rating Event,Credit Incident,Material Credit Event'::text[], 'industry-standard', 0, '[{"name": "NRSRO", "description": "NRSRO event monitoring and timely rating action requirements"}, {"name": "SEC 17g-7", "description": "SEC Rule 17g-7 — event-driven rating action disclosure"}, {"name": "ISDA", "description": "ISDA Credit Derivatives Definitions — credit event taxonomy"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
INSERT INTO ontology_concepts (id, industry_id, ontology_name, label, category, description, properties, relationships, tags, industry_relevance, created_at, synonyms, source, usage_count, linked_regulations, version, version_history, sensitivity_classification) VALUES ('financial_services-credit-rating-assessment-package', 'financial_services', 'FIBO (Financial Industry Business Ontology) + Credit Rating Ontology', 'AssessmentPackage', 'Credit Rating Operations', 'The complete, review-ready credit assessment package assembled from all component analyses for an issuer. Contains references to financial spreading results, earnings call analysis, peer comparison, ESG profile, credit events, and the pre-populated scorecard. The package tracks its assembly status, component completeness, analyst review annotations, total completion time, and a quality score. It is the final deliverable presented to the rating committee for credit rating decisions.', '[{"name": "packageId", "type": "string", "description": "Unique identifier for the assessment package"}, {"name": "issuerId", "type": "string", "description": "Reference to the Issuer being assessed"}, {"name": "requestDate", "type": "date", "description": "Date the assessment was requested or triggered"}, {"name": "status", "type": "enum", "description": "Package status: requested, in_progress, components_complete, under_review, finalized"}, {"name": "components", "type": "object", "description": "References to component outputs: financials, earnings, peers, esg, events, scorecard"}, {"name": "analystReview", "type": "object", "description": "Analyst review annotations, sign-off status, and comments"}, {"name": "completionTime", "type": "number", "description": "Total elapsed time in minutes from request to package completion"}, {"name": "qualityScore", "type": "number", "description": "Automated quality score (0-100) based on data completeness, consistency, and coverage"}]'::jsonb, '[{"type": "depends_on", "label": "Packages for issuer", "targetId": "financial_services-credit-rating-issuer"}, {"type": "depends_on", "label": "Assembles financial periods", "targetId": "financial_services-credit-rating-financial-period"}, {"type": "depends_on", "label": "Assembles earnings calls", "targetId": "financial_services-credit-rating-earnings-call"}, {"type": "depends_on", "label": "Assembles peer group", "targetId": "financial_services-credit-rating-peer-group"}, {"type": "depends_on", "label": "Assembles scorecard", "targetId": "financial_services-credit-rating-scorecard"}, {"type": "depends_on", "label": "Assembles credit events", "targetId": "financial_services-credit-rating-credit-event"}]'::jsonb, 'Assessment Package,SOX,Audit Trail,Analyst Review,Quality Score,Rating Committee'::text[], NULL, '2026-03-17 02:11:34.090049', 'Credit Package,Rating Package,Assessment Bundle'::text[], 'industry-standard', 0, '[{"name": "NRSRO", "description": "NRSRO documentation and record-keeping requirements"}, {"name": "SEC 17g-7", "description": "SEC Rule 17g-7 — assessment documentation disclosure"}, {"name": "SOX", "description": "Sarbanes-Oxley Act — internal controls and audit trail"}, {"name": "SEC Reg AC", "description": "SEC Regulation AC — analyst certification and accountability"}]'::jsonb, 1, '[]'::jsonb, NULL::jsonb);
